/* D&D 5e Subclasses — Français — 104/104 traduits */
window.DND_SUBCLASSES_FR=[{"index":"barbarian-ancestral-guardian","name":"Barbare : Voie du Gardien Ancestral","class":"barbarian","source":"Xanathar's Guide to Everything","subclass_flavor":"Certains barbares sont issus de cultures qui vénèrent leurs ancêtres. Ces tribus enseignent que les guerriers du passé demeurent dans le monde en tant qu’esprits puissants, capables de guider et de protéger les vivants. Lorsqu'un barbare qui suit cette voie se met en colère, il contacte le monde des esprits et fait appel à ces esprits gardiens pour obtenir de l'aide.","desc":"","features":[{"name":"Protecteurs ancestraux","level":3,"desc":"Starting when you choose this path at 3rd level, spectral warriors appear when you enter your rage. While you're raging, the first creature you hit with an attack on your turn becomes the target of the warriors, which hinder its attacks. Jusqu'au début de votre prochain tour, cette cible a un désavantage sur tout jet d'attaque qui n'est pas contre vous, et lorsque la cible touche une créature autre que vous avec une attaque, cette créature a une résistance aux dégâts infligés par l'attaque. The effect on the target ends early if your rage ends.","name_en":"Ancestral Protectors"},{"name":"Bouclier spirituel","level":6,"desc":"À partir du niveau 6, les esprits gardiens qui vous aident peuvent offrir une protection surnaturelle à ceux que vous défendez. Si vous êtes enragé et qu'une autre créature que vous pouvez voir à moins de 9 mètres de vous subit des dégâts, vous pouvez utiliser votre réaction pour réduire ces dégâts de 2d6.\n\nLorsque vous atteignez certains niveaux dans cette classe, vous pouvez réduire davantage les dégâts : de 3d6 au niveau 10 et de 4d6 au niveau 14.","name_en":"Spirit Shield"},{"name":"Consulter les Esprits","level":10,"desc":"Au niveau 10, vous gagnez la capacité de consulter vos esprits ancestraux. Ce faisant, vous lancez le sort Augure ou Clairvoyance, sans utiliser d'emplacement de sort ni de composants matériels. Plutôt que de créer un capteur sphérique, cette utilisation de la clairvoyance invoque de manière invisible l'un de vos esprits ancestraux à l'endroit choisi. La sagesse est votre capacité à lancer des sorts pour ces sorts.\n\nAprès avoir lancé l'un ou l'autre sort de cette manière, vous ne pouvez plus utiliser cette fonctionnalité tant que vous n'avez pas terminé un repos court ou long.","name_en":"Consult the Spirits"},{"name":"Ancêtres vengeurs","level":14,"desc":"Au niveau 14, vos esprits ancestraux deviennent suffisamment puissants pour riposter. Lorsque vous utilisez votre Bouclier spirituel pour réduire les dégâts d'une attaque, l'attaquant subit une quantité de dégâts de force que votre Bouclier spirituel empêche.","name_en":"Vengeful Ancestors"}],"name_en":"Barbarian: Path of the Ancestral Guardian","_translated":true},{"index":"barbarian-battlerager","name":"Barbare : la Voie du Battlerager","class":"barbarian","source":"Sword Coast Adventurer's Guide","subclass_flavor":"Connus sous le nom de Kuldjargh (littéralement « idiot de la hache ») en nain, les Battleragers sont des adeptes nains des dieux de la guerre et empruntent la Voie du Battlerager. Ils se spécialisent dans le port d'armures volumineuses à pointes et dans le combat, frappant avec leur corps lui-même et s'abandonnant à la fureur du combat.","desc":"","features":[{"name":"Restriction : Nains uniquement","level":null,"desc":"Seuls les nains peuvent suivre la Voie du Battlerager. Le Battlerager occupe une niche particulière dans la société et la culture naine.\n\nVotre DM peut lever cette restriction pour mieux l'adapter à la campagne. La restriction existe pour les Royaumes Oubliés. Cela peut ne pas s'appliquer aux paramètres de votre DM ou à la version des royaumes de votre DM.","name_en":"Restriction: Dwarves Only"},{"name":"Armure de Battlerager","level":3,"desc":"Lorsque vous choisissez cette voie au niveau 3, vous obtenez la possibilité d’utiliser une armure à pointes comme arme.\n\nPendant que vous portez une armure à pointes et que vous êtes enragé, vous pouvez utiliser une action bonus pour effectuer une attaque au corps à corps avec vos pointes d'armure contre une cible à moins de 1,50 mètre de vous. Si l'attaque réussit, les pointes infligent 1d4 dégâts perforants. Vous utilisez votre modificateur de Force pour les jets d'attaque et de dégâts.\n\nDe plus, lorsque vous utilisez l'action Attaque pour agripper une créature, la cible subit 3 dégâts perforants si votre test de lutte réussit.","name_en":"Battlerager Armor"},{"name":"Abandon imprudent","level":6,"desc":"À partir du niveau 6, lorsque vous utilisez Attaque téméraire en étant enragé, vous gagnez également des points de vie temporaires égaux à votre modificateur de Constitution (minimum de 1). Ils disparaissent s’il en reste à la fin de votre rage.","name_en":"Reckless Abandon"},{"name":"Charge de Battlerager","level":10,"desc":"À partir du niveau 10, vous pouvez effectuer l’action Dash comme action bonus pendant que vous êtes en rage.","name_en":"Battlerager Charge"},{"name":"Châtiment enrichi","level":14,"desc":"À partir du niveau 14, lorsqu'une créature à moins de 1,50 mètre de vous vous frappe avec une attaque de mêlée, l'attaquant subit 3 dégâts perforants si vous êtes en colère, n'êtes pas incapable d'agir et portez une armure à pointes.","name_en":"Spiked Retribution"}],"name_en":"Barbarian: Path of the Battlerager","_translated":true},{"index":"barbarian-beast","name":"Barbare : le chemin de la bête","class":"barbarian","source":"Tasha's Cauldron of Everything","subclass_flavor":"Les barbares qui empruntent la Voie de la Bête tirent leur rage d'une étincelle bestiale qui brûle dans leur âme. Cette bête éclate de rage, transformant physiquement le barbare.","desc":"","features":[{"name":"Forme de la bête","level":3,"desc":"À partir du moment où vous choisissez cette voie au niveau 3, lorsque vous entrez dans votre rage, vous pouvez vous transformer, révélant le pouvoir bestial qui est en vous. Jusqu'à la fin de la rage, vous manifestez une arme naturelle. Cela compte comme une simple arme de mêlée pour vous, et vous ajoutez votre modificateur de Force aux jets d'attaque et de dégâts lorsque vous attaquez avec, comme d'habitude.\n\nVous choisissez la forme de l’arme à chaque fois que vous faites rage :\n\nMordez. Votre bouche se transforme en museau bestial ou en grandes mandibules (au choix). Il inflige 1d8 dégâts perforants en cas de coup. Une fois à chacun de vos tours lorsque vous blessez une créature avec cette morsure, vous récupérez un nombre de points de vie égal à votre bonus de maîtrise, à condition d'avoir moins de la moitié de vos points de vie lorsque vous frappez.\n\nDes griffes. Chacune de vos mains se transforme en griffe, que vous pouvez utiliser comme arme si elle est vide. Il inflige 1d6 dégâts tranchants en cas de coup. Une fois à chacun de vos tours, lorsque vous attaquez avec une griffe en utilisant l'action Attaque, vous pouvez effectuer une attaque de griffe supplémentaire dans le cadre de la même action.\n\nQueue. Vous faites pousser une queue épineuse et fouettée, qui inflige 1d8 dégâts perforants en cas de coup et possède la propriété de portée. Si une créature que vous pouvez voir à moins de 3 mètres de vous vous frappe avec un jet d'attaque, vous pouvez utiliser votre réaction pour faire glisser votre queue et lancer un d8, appliquant un bonus à votre CA égal au nombre obtenu, ce qui pourrait faire que l'attaque vous manque.","name_en":"Form of the Beast"},{"name":"Âme bestiale","level":6,"desc":"À partir du niveau 6, la puissance sauvage en vous augmente, ce qui fait que les armes naturelles de votre Forme de Bête sont considérées comme magiques dans le but de vaincre la résistance et l'immunité aux attaques et dégâts non magiques.\n\nVous pouvez également modifier votre forme pour vous aider à vous adapter à votre environnement. Lorsque vous terminez un repos court ou long, choisissez l'un des avantages suivants, qui perdurent jusqu'à la fin d'un repos court ou long :\n• Vous gagnez une vitesse de nage égale à votre vitesse de marche et vous pouvez respirer sous l'eau.\n• Vous gagnez une vitesse de montée égale à votre vitesse de marche et vous pouvez escalader des surfaces difficiles, y compris à l'envers sur les plafonds, sans avoir besoin de faire un test de capacité.\n• Lorsque vous sautez, vous pouvez effectuer un test de Force (Athlétisme) et prolonger votre saut d'un nombre de pieds égal au total du test. Vous ne pouvez effectuer cette vérification spéciale qu'une seule fois par tour.","name_en":"Bestial Soul"},{"name":"Fureur contagieuse","level":10,"desc":"Au niveau 10, lorsque vous frappez une créature avec vos armes naturelles alors que vous êtes enragé, la bête en vous peut maudire votre cible avec une fureur enragée. La cible doit réussir un jet de sauvegarde de Sagesse (DD égal à 8 + votre modificateur de Constitution + votre bonus de maîtrise) ou subir l'un des effets suivants (au choix) :\n• La cible doit utiliser sa réaction pour effectuer une attaque au corps à corps contre une autre créature de votre choix que vous pouvez voir.\n• La cible subit 2d12 dégâts psychiques.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Infectious Fury"},{"name":"Appelez la chasse","level":14,"desc":"Au niveau 14, la bête en vous devient si puissante que vous pouvez transmettre sa férocité aux autres et gagner en résilience en se joignant à votre chasse. Lorsque vous entrez dans votre rage, vous pouvez choisir un nombre d'autres créatures volontaires que vous pouvez voir dans un rayon de 9 mètres autour de vous, égal à votre modificateur de Constitution (au minimum une créature). Vous gagnez 5 points de vie temporaires pour chaque créature qui accepte cette fonctionnalité. Jusqu'à la fin de la rage, les créatures choisies peuvent utiliser l'avantage suivant une fois à chacun de leurs tours : lorsque la créature touche une cible avec un jet d'attaque et lui inflige des dégâts, la créature peut lancer un d6 et gagner un bonus aux dégâts égal au nombre obtenu.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Call the Hunt"}],"name_en":"Barbarian: Path Of The Beast","_translated":true},{"index":"barbarian-berserker","name":"Barbare : Voie du Berserker","class":"barbarian","source":"Player's Handbook","subclass_flavor":"Pour certains barbares, la rage est un moyen pour parvenir à une fin – cette fin étant la violence. La Voie du Berserker est une voie de fureur sans entrave, recouverte de sang. Alors que vous entrez dans la rage du berserker, vous vibrez dans le chaos de la bataille, sans vous soucier de votre propre santé ou de votre bien-être.","desc":"","features":[{"name":"Frénésie","level":3,"desc":"À partir du moment où vous choisissez cette voie au niveau 3, vous pouvez entrer dans une frénésie lorsque vous êtes en colère. Si vous le faites, pendant toute la durée de votre rage, vous pouvez effectuer une seule attaque avec une arme de mêlée comme une action bonus à chacun de vos tours suivants celui-ci. Lorsque votre rage prend fin, vous souffrez d’un niveau d’épuisement.","name_en":"Frenzy"},{"name":"Rage insensée","level":6,"desc":"À partir du niveau 6, vous ne pouvez plus être charmé ou effrayé lorsque vous êtes en colère. Si vous êtes charmé ou effrayé lorsque vous entrez dans votre rage, l'effet est suspendu pour la durée de la rage.","name_en":"Mindless Rage"},{"name":"Présence intimidante","level":10,"desc":"À partir du niveau 10, vous pouvez utiliser votre action pour effrayer quelqu'un avec votre présence menaçante. Ce faisant, choisissez une créature que vous pouvez voir à moins de 9 mètres de vous. Si la créature peut vous voir ou vous entendre, elle doit réussir un jet de sauvegarde de Sagesse (DD égal à 8 + votre bonus de maîtrise + votre modificateur de Charisme) ou avoir peur de vous jusqu'à la fin de votre prochain tour. Aux tours suivants, vous pouvez utiliser votre action pour prolonger la durée de cet effet sur la créature effrayée jusqu'à la fin de votre prochain tour. Cet effet prend fin si la créature termine son tour hors de votre champ de vision ou à plus de 20 mètres de vous.\n\nSi la créature réussit son jet de sauvegarde, vous ne pourrez plus utiliser cette fonctionnalité sur cette créature pendant 24 heures.","name_en":"Intimidating Presence"},{"name":"Représailles","level":14,"desc":"À partir du niveau 14, lorsque vous subissez des dégâts d'une créature située à moins de 1,50 mètre de vous, vous pouvez utiliser votre réaction pour lancer une attaque au corps à corps avec une arme contre cette créature.","name_en":"Retaliation"}],"name_en":"Barbarian: Path of the Berserker","_translated":true},{"index":"barbarian-storm-herald","name":"Barbare : La voie du héraut de la tempête","class":"barbarian","source":"Xanathar's Guide to Everything","subclass_flavor":"Les barbares typiques abritent une fureur qui les habite. Leur rage leur confère une force, une durabilité et une vitesse supérieures. Les barbares qui suivent la voie du Storm Herald apprennent à transformer leur rage en un manteau de magie primitive qui tourbillonne autour d'eux. Lorsqu'il est en colère, un barbare de cette voie puise dans la nature pour créer des effets magiques puissants.","desc":"","features":[{"name":"Aura de tempête","level":3,"desc":"Lorsque vous sélectionnez cette voie au niveau 3, vous dégagez une aura magique orageuse tandis que vous êtes en colère. L'aura s'étend à 3 mètres de vous dans toutes les directions, mais pas à travers une couverture totale.\n\nVotre aura a un effet qui s'active lorsque vous entrez dans votre rage, et vous pouvez réactiver l'effet à chacun de vos tours sous forme d'action bonus. Choisissez le désert, la mer ou la toundra. L'effet de votre aura dépend de l'environnement choisi, comme détaillé ci-dessous. Vous pouvez modifier votre choix d'environnement à chaque fois que vous gagnez un niveau dans cette classe.\n\nSi les effets de votre aura nécessitent un jet de sauvegarde, le DD est égal à 8 + votre bonus de maîtrise + votre modificateur de Constitution.\n\nDésert. Lorsque cet effet est activé, toutes les autres créatures de votre aura subissent chacune 2 dégâts de feu. Les dégâts augmentent lorsque vous atteignez certains niveaux dans cette classe, passant à 3 au niveau 5, 4 au niveau 10, 5 au niveau 15 et 6 au niveau 20.\n\nMer. Lorsque cet effet est activé, vous pouvez choisir une autre créature que vous pouvez voir dans votre aura. La cible doit effectuer un jet de sauvegarde de Dextérité. La cible subit 1d6 dégâts de foudre en cas d'échec, ou la moitié de ces dégâts en cas de réussite. Les dégâts augmentent lorsque vous atteignez certains niveaux dans cette classe, passant à 2d6 au niveau 10, 3d6 au niveau 15 et 4d6 au niveau 20.\n\nToundra. Lorsque cet effet est activé, chaque créature de votre choix dans votre aura gagne 2 points de vie temporaires, à mesure que les esprits de glace l'habituent à la souffrance. Les points de vie temporaires augmentent lorsque vous atteignez certains niveaux dans cette classe, passant à 3 au niveau 5, 4 au niveau 10, 5 au niveau 15 et 6 au niveau 20.","name_en":"Storm Aura"},{"name":"Âme de tempête","level":6,"desc":"Au niveau 6, la tempête vous accorde des bénéfices même lorsque votre aura n'est pas active. Les avantages dépendent de l'environnement que vous avez choisi pour votre Storm Aura.\n\nDésert. Vous gagnez une résistance aux dégâts de feu et vous ne subissez pas les effets de la chaleur extrême, comme décrit dans le Dungeon Master's Guide. De plus, en tant qu'action, vous pouvez toucher un objet inflammable qui n'est porté par personne d'autre et y mettre le feu.\n\nMer. Vous gagnez en résistance aux dégâts de la foudre et vous pouvez respirer sous l'eau. Vous gagnez également une vitesse de nage de 30 pieds.\n\nToundra. Vous gagnez en résistance aux dégâts du froid et vous ne subissez pas les effets du froid extrême, comme décrit dans le Dungeon Master's Guide. De plus, par une action, vous pouvez toucher de l'eau et en transformer un cube de 1,50 mètre en glace, qui fond après 1 minute. Cette action échoue si une créature est dans le cube.","name_en":"Storm Soul"},{"name":"Tempête de protection","level":10,"desc":"Au niveau 10, vous apprenez à utiliser votre maîtrise de la tempête pour protéger les autres. Chaque créature de votre choix a la résistance aux dégâts que vous avez acquise grâce à la fonction Storm Soul tant que la créature est dans votre Storm Aura.","name_en":"Shielding Storm"},{"name":"Tempête déchaînée","level":14,"desc":"Au niveau 14, la puissance de la tempête que vous canalisez devient plus puissante et s'abat sur vos ennemis. L'effet est basé sur l'environnement que vous avez choisi pour votre Storm Aura.\n\nDésert. Immédiatement après qu'une créature dans votre aura vous frappe avec une attaque, vous pouvez utiliser votre réaction pour forcer cette créature à effectuer un jet de sauvegarde de Dextérité. En cas d'échec, la créature subit des dégâts de feu égaux à la moitié de votre niveau de barbare.\n\nMer. Lorsque vous touchez une créature dans votre aura avec une attaque, vous pouvez utiliser votre réaction pour forcer cette créature à effectuer un jet de sauvegarde de Force. En cas d'échec, la créature est projetée à terre, comme si elle avait été frappée par une vague.\n\nToundra. Chaque fois que l'effet de votre Storm Aura est activé, vous pouvez choisir une créature que vous pouvez voir dans l'aura. Cette créature doit réussir un jet de sauvegarde de Force, sinon sa vitesse est réduite à 0 jusqu'au début de votre prochain tour, car le givre magique la recouvre.","name_en":"Raging Storm"}],"name_en":"Barbarian: Path of the Storm Herald","_translated":true},{"index":"barbarian-totem-warrior","name":"Barbare : la voie du guerrier totem","class":"barbarian","source":"Player's Handbook","subclass_flavor":"Le chemin du guerrier totem est un voyage spirituel, dans le cadre duquel le barbare accepte un animal spirituel comme guide, protecteur et source d'inspiration. Au combat, votre esprit totémique vous remplit d'une puissance surnaturelle, ajoutant du carburant magique à votre rage barbare.","desc":"","features":[{"name":"Chercheur d'esprit","level":3,"desc":"Votre voie recherche l’harmonisation avec le monde naturel, vous donnant une parenté avec les bêtes. Au niveau 3, lorsque vous adoptez cette voie, vous gagnez la possibilité de lancer les sorts Sens de la bête et Parler avec les animaux, mais uniquement sous forme de rituels.","name_en":"Spirit Seeker"},{"name":"Esprit totémique","level":3,"desc":"Au niveau 3, lorsque vous adoptez cette voie, vous choisissez un esprit totem et gagnez sa fonctionnalité. Vous devez fabriquer ou acquérir un objet totem physique – une amulette ou un ornement similaire – qui incorpore de la fourrure ou des plumes, des griffes, des dents ou des os de l'animal totem. À votre choix, vous gagnez également des attributs physiques mineurs qui rappellent votre esprit totémique. Par exemple, si vous avez un esprit totem ours, vous pourriez être inhabituellement poilu et à la peau épaisse, ou si votre totem est l'aigle, vos yeux deviennent jaune vif.\n\nVotre animal totem pourrait être un animal apparenté à ceux répertoriés ici, mais plus approprié à votre pays d'origine. Par exemple, vous pourriez choisir un faucon ou un vautour à la place d’un aigle.\n\nOurs. En rage, vous avez une résistance à tous les dégâts, à l'exception des dégâts psychiques. L’esprit de l’ours vous rend suffisamment résistant pour résister à n’importe quelle punition.\n\nAigle. Pendant que vous êtes en colère et que vous ne portez pas d'armure lourde, d'autres créatures ont un désavantage aux jets d'attaque d'opportunité contre vous, et vous pouvez utiliser l'action Dash comme action bonus pendant votre tour. L’esprit de l’aigle fait de vous un prédateur capable de se faufiler facilement dans la mêlée.\n\nWapiti. Tant que vous êtes en rage et que vous ne portez pas d'armure lourde, votre vitesse de marche augmente de 15 pieds. L'esprit de l'élan vous rend extraordinairement rapide.\n\nTigre. En rage, vous pouvez ajouter 10 pieds à votre distance de saut en longueur et 3 pieds à votre distance de saut en hauteur. L'esprit du tigre donne du pouvoir à vos sauts.\n\nLoup. Pendant que vous êtes en rage, vos amis ont un avantage aux jets d'attaque au corps à corps contre toute créature à moins de 1,50 mètre de vous qui vous est hostile. L'esprit du loup fait de vous un chef de chasseurs.","name_en":"Totem Spirit"},{"name":"Aspect de la bête","level":6,"desc":"Au niveau 6, vous gagnez un bénéfice magique basé sur l'animal totem de votre choix. Vous pouvez choisir le même animal que vous avez sélectionné au niveau 3 ou un autre.\n\nOurs. Vous gagnez la puissance d'un ours. Votre capacité de charge (y compris la charge maximale et la portance maximale) est doublée et vous bénéficiez d'un avantage aux tests de Force effectués pour pousser, tirer, soulever ou casser des objets.\n\nAigle. Vous obtenez la vue d'un aigle. Vous pouvez voir jusqu'à 1,6 km sans difficulté, capable de discerner même les détails les plus fins, comme si vous regardiez quelque chose à moins de 100 pieds de vous. De plus, une faible lumière n’impose pas de désavantage à vos tests de Sagesse (Perception).\n\nWapiti. Que vous soyez à cheval ou à pied, votre rythme de déplacement est doublé, tout comme le rythme de déplacement d'un maximum de dix compagnons tant qu'ils se trouvent à moins de 60 pieds de vous et que vous n'êtes pas incapable. L'esprit du wapiti vous aide à vous déplacer loin et rapidement.\n\nTigre. Vous maîtrisez deux compétences de la liste suivante : Athlétisme, Acrobatie, Furtivité et Survie. L'esprit du chat aiguise votre instinct de survie.\n\nLoup. Vous acquérez la sensibilité de chasse d'un loup. Vous pouvez suivre d'autres créatures tout en voyageant à un rythme rapide, et vous pouvez vous déplacer furtivement tout en voyageant à un rythme normal.","name_en":"Aspect of the Beast"},{"name":"Marcheur spirituel","level":10,"desc":"Au niveau 10, vous pouvez lancer le sort Communion avec la nature, mais uniquement sous forme de rituel. Lorsque vous faites cela, une version spirituelle de l'un des animaux que vous avez choisi pour Totem Spirit ou Aspect of the Beast vous apparaît pour vous transmettre les informations que vous recherchez.","name_en":"Spirit Walker"},{"name":"Harmonisation totémique","level":14,"desc":"Au niveau 14, vous bénéficiez d'un bénéfice magique basé sur un animal totem de votre choix. Vous pouvez choisir le même animal que vous avez sélectionné précédemment ou un autre.\n\nOurs. Pendant que vous êtes en rage, toute créature hostile à moins de 1,50 mètre de vous a un désavantage aux jets d'attaque contre des cibles autres que vous ou un autre personnage doté de cette fonctionnalité. Un ennemi est immunisé contre cet effet s'il ne peut pas vous voir ou vous entendre ou s'il ne peut pas être effrayé.\n\nAigle. En rage, vous avez une vitesse de vol égale à votre vitesse de marche actuelle. Cet avantage ne fonctionne que par courtes périodes ; vous tombez si vous terminez votre tour dans les airs et que rien d'autre ne vous retient en l'air.\n\nWapiti. En rage, vous pouvez utiliser une action bonus pendant votre déplacement pour traverser l'espace d'une créature de taille G ou plus petite. Cette créature doit réussir un jet de sauvegarde de Force (DD 8 + votre bonus de Force + votre bonus de maîtrise) ou être mise à terre et subir des dégâts contondants égaux à 1d12 + votre modificateur de Force.\n\nTigre. Pendant que vous êtes en rage, si vous vous déplacez d'au moins 6 mètres en ligne droite vers une cible de taille G ou plus petite juste avant de lancer une attaque au corps à corps contre elle, vous pouvez utiliser une action bonus pour effectuer une attaque au corps à corps supplémentaire contre elle.\n\nLoup. Pendant que vous êtes en rage, vous pouvez utiliser une action bonus pendant votre tour pour mettre à terre une créature de taille G ou plus petite lorsque vous la touchez avec une attaque au corps à corps avec une arme.","name_en":"Totemic Attunement"}],"name_en":"Barbarian: Path of the Totem Warrior","_translated":true},{"index":"barbarian-zealot","name":"Barbare : la Voie du Zélote","class":"barbarian","source":"Xanathar's Guide to Everything","subclass_flavor":"Certaines divinités incitent leurs adeptes à se lancer dans une fureur de combat féroce. Ces barbares sont des fanatiques – des guerriers qui canalisent leur rage dans de puissantes démonstrations de pouvoir divin.","desc":"","features":[{"name":"Fureur divine","level":3,"desc":"À partir du moment où vous choisissez cette voie au niveau 3, vous pouvez canaliser la fureur divine dans vos frappes avec vos armes. Pendant que vous êtes en rage, la première créature que vous touchez à chacun de vos tours avec une attaque avec une arme subit des dégâts supplémentaires égaux à 1d6 + la moitié de votre niveau de barbare. Les dégâts supplémentaires sont nécrotiques ou radiants ; vous choisissez le type de dégâts lorsque vous obtenez cette fonctionnalité.","name_en":"Divine Fury"},{"name":"Guerrier des Dieux","level":3,"desc":"Au niveau 3, votre âme est prête à se battre sans fin. Si un sort, tel que Raise Dead, a pour seul effet de vous redonner la vie (mais pas la non-mort), le lanceur n'a pas besoin de composants matériels pour lancer le sort sur vous.","name_en":"Warrior of the Gods"},{"name":"Concentration fanatique","level":6,"desc":"À partir du niveau 6, le pouvoir divin qui alimente votre rage peut vous protéger. Si vous échouez à un jet de sauvegarde alors que vous êtes en rage, vous pouvez le relancer et vous devez utiliser le nouveau jet. Vous ne pouvez utiliser cette capacité qu’une seule fois par rage.","name_en":"Fanatical Focus"},{"name":"Présence zélée","level":10,"desc":"Au niveau 10, vous apprenez à canaliser le pouvoir divin pour inspirer le fanatisme chez les autres. Par une action bonus, vous lancez un cri de guerre imprégné d'énergie divine. Jusqu'à dix autres créatures de votre choix dans un rayon de 60 pieds autour de vous et qui peuvent vous entendre bénéficient d'un avantage aux jets d'attaque et aux jets de sauvegarde jusqu'au début de votre prochain tour.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Zealous Presence"},{"name":"La rage au-delà de la mort","level":14,"desc":"À partir du niveau 14, le pouvoir divin qui alimente votre rage vous permet d'ignorer les coups fatals.\n\nPendant que vous êtes en rage, avoir 0 point de vie ne vous fait pas perdre connaissance. Vous devez toujours effectuer des jets de sauvegarde contre la mort et vous subissez les effets normaux des dégâts subis alors que vous êtes à 0 point de vie. Cependant, si vous mourez suite à l’échec d’un jet de sauvegarde contre la mort, vous ne mourrez pas avant la fin de votre rage, et vous ne mourrez alors que si vous n’avez toujours aucun point de vie.","name_en":"Rage Beyond Death"}],"name_en":"Barbarian: Path of the Zealot","_translated":true},{"index":"barbarian-wild-magic","name":"Barbare : la voie de la magie sauvage","class":"barbarian","source":"Tasha's Cauldron of Everything","subclass_flavor":"De nombreux endroits du multivers regorgent de beauté, d’émotions intenses et de magie effrénée ; le Feywild, les plans supérieurs et d’autres royaumes de pouvoir surnaturel rayonnent de telles forces et peuvent profondément influencer les gens. En tant que gens dotés de sentiments profonds, les barbares sont particulièrement sensibles à ces influences sauvages, certains barbares étant transformés par la magie. Ces barbares imprégnés de magie parcourent le Chemin de la Magie Sauvage. Les barbares elfes, tieffelins, aasimars et genasis recherchent souvent cette voie, désireux de manifester la magie surnaturelle de leurs ancêtres.","desc":"","features":[{"name":"Conscience magique","level":3,"desc":"Lorsque vous choisissez cette voie au niveau 3, en tant qu'action, vous pouvez ouvrir votre conscience à la présence de magie concentrée. Jusqu'à la fin de votre prochain tour, vous connaissez l'emplacement de tout sort ou objet magique dans un rayon de 20 mètres autour de vous et qui n'est pas à couvert. Lorsque vous ressentez un sort, vous apprenez à quelle école de magie il appartient.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Magic Awareness"},{"name":"Vague sauvage","level":3,"desc":"Également au niveau 3, l’énergie magique qui bouillonne en vous jaillit parfois de vous. Lorsque vous entrez dans votre rage, lancez un jet sur le tableau Wild Magic pour déterminer l'effet magique produit.\n\nSi l'effet nécessite un jet de sauvegarde, le DD est égal à 8 + votre bonus de maîtrise + votre modificateur de Constitution.\nMagie sauvage\nd8 | Effet\n1 | Chaque créature de votre choix que vous pouvez voir à moins de 9 mètres de vous doit réussir un jet de sauvegarde de Constitution ou subir 1d12 dégâts nécrotiques. Vous gagnez également 1d12 points de vie temporaires.\n2 | Vous vous téléportez jusqu'à 9 mètres dans un espace inoccupé que vous pouvez voir. Jusqu'à la fin de votre rage, vous pouvez réutiliser cet effet à chacun de vos tours comme action bonus.\n3 | Un esprit intangible, qui ressemble à un flumph ou à un lutin (votre choix), apparaît à moins de 1,50 mètre d'une créature de votre choix que vous pouvez voir à moins de 9 mètres de vous. À la fin du tour en cours, l'esprit explose et chaque créature à moins de 1,50 mètre de lui doit réussir un jet de sauvegarde de Dextérité ou subir 1d6 dégâts de force. Jusqu'à la fin de votre rage, vous pouvez utiliser à nouveau cet effet, en invoquant un autre esprit, à chacun de vos tours comme une action bonus.\n4 | La magie infuse une arme de votre choix que vous tenez. Jusqu'à la fin de votre rage, le type de dégâts de l'arme se transforme en force et elle acquiert les propriétés de lumière et de projection, avec une portée normale de 20 pieds et une longue portée de 60 pieds. Si l'arme quitte votre main, elle réapparaît dans votre main à la fin du tour en cours.\n5 | Chaque fois qu'une créature vous frappe avec un jet d'attaque avant la fin de votre rage, cette créature subit 1d6 dégâts de force, tandis que la magie se déchaîne en représailles.\n6 | Jusqu'à ce que votre rage prenne fin, vous êtes entouré de lumières protectrices multicolores ; vous gagnez un bonus de +1 à la CA, et à moins de 3 mètres de vous, vos alliés bénéficient du même bonus.\n7 | Des fleurs et des vignes poussent temporairement autour de vous ; jusqu'à ce que votre rage prenne fin, le sol à moins de 15 pieds de vous constitue un terrain difficile pour vos ennemis.\n8 | Un éclair de lumière jaillit de votre poitrine. Une autre créature de votre choix que vous pouvez voir à moins de 9 mètres de vous doit réussir un jet de sauvegarde de Constitution ou subir 1d6 dégâts radiants et être aveuglée jusqu'au début de votre prochain tour. Jusqu'à la fin de votre rage, vous pouvez réutiliser cet effet à chacun de vos tours comme action bonus.","name_en":"Wild Surge"},{"name":"Renforcer la magie","level":6,"desc":"À partir du niveau 6, vous pouvez exploiter votre magie sauvage pour vous renforcer ou renforcer un compagnon. Par une action, vous pouvez toucher une créature (qui peut être vous-même) et conférer à cette créature l'un des avantages suivants de votre choix :\n• Pendant 10 minutes, la créature peut lancer un d3 à chaque fois qu'elle effectue un jet d'attaque ou un test de capacité et ajouter le nombre obtenu au jet de d20.\n• Lancez un d3. La créature récupère un emplacement de sort dépensé, dont le niveau est égal ou inférieur au nombre obtenu (au choix de la créature). Une fois qu’une créature reçoit cet avantage, elle ne peut plus le recevoir avant un long repos.\n\nVous pouvez effectuer cette action un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Bolstering Magic"},{"name":"Jeu instable","level":10,"desc":"Au niveau 10, lorsque vous êtes en danger pendant votre rage, la magie en vous peut se déchaîner ; immédiatement après avoir subi des dégâts ou échoué à un jet de sauvegarde alors que vous êtes enragé, vous pouvez utiliser votre réaction pour lancer un jet sur la table Wild Magic et produire immédiatement l'effet obtenu. Cet effet remplace votre effet Wild Magic actuel.","name_en":"Unstable Backlash"},{"name":"Surtension contrôlée","level":14,"desc":"Au niveau 14, chaque fois que vous lancez un jet sur la table Wild Magic, vous pouvez lancer le dé deux fois et choisir lequel des deux effets déclencher. Si vous obtenez le même nombre sur les deux dés, vous pouvez ignorer le nombre et choisir n’importe quel effet sur la table.","name_en":"Controlled Surge"}],"name_en":"Barbarian: Path of Wild Magic","_translated":true},{"index":"bard-creation","name":"Barde : Collège de Création","class":"bard","source":"Tasha's Cauldron of Everything","subclass_flavor":"Les bardes croient que le cosmos est une œuvre d’art – la création des premiers dragons et dieux. Ce travail créatif comprenait des harmonies qui continuent de résonner à travers l’existence aujourd’hui, une puissance connue sous le nom de Chant de la Création. Les bardes du Collège de la Création s'inspirent de ce chant primordial à travers la danse, la musique et la poésie, et leurs professeurs partagent cette leçon : « Avant le soleil et la lune, il y avait le chant, et sa musique a réveillé les premières aurores. Ses mélodies ont tellement ravi les pierres et les arbres que certains d'entre eux ont acquis leur propre voix. Et maintenant, ils chantent aussi. Apprenez le chant, étudiants, et vous aussi pourrez apprendre aux montagnes à chanter et à danser.","desc":"","features":[{"name":"Une parcelle de potentiel","level":3,"desc":"Lorsque vous rejoignez le Collège de la Création au niveau 3, chaque fois que vous donnez à une créature un dé d'Inspiration bardique, vous pouvez prononcer une note du Chant de la Création pour créer un minuscule grain de potentiel, qui orbite à moins de 1,50 mètre de cette créature. La particule est intangible et invulnérable, et elle dure jusqu'à ce que le dé d'Inspiration bardique soit perdu. La paille ressemble à une note de musique, une étoile, une fleur ou tout autre symbole d'art ou de vie que vous choisissez.\n\nLorsque la créature utilise le dé d'inspiration bardique, la paille fournit un effet supplémentaire selon que le dé bénéficie d'un test de capacité, d'un jet d'attaque ou d'un jet de sauvegarde, comme détaillé ci-dessous :\n\nVérification des capacités. Lorsque la créature lance le dé d'inspiration bardique pour l'ajouter à un test de capacité, la créature peut lancer à nouveau le dé d'inspiration bardique et choisir le jet à utiliser, tandis que la paille éclate et émet des étincelles colorées et inoffensives pendant un instant.\n\nJet d'attaque. Immédiatement après que la créature ait lancé le dé d'Inspiration bardique pour l'ajouter à un jet d'attaque contre une cible, la paille se brise avec un tonnerre. La cible et chaque créature de votre choix que vous pouvez voir à moins de 1,50 mètre d'elle doivent réussir un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort ou subir des dégâts de tonnerre égaux au nombre obtenu sur le dé d'Inspiration bardique.\n\nJet de sauvegarde. Immédiatement après que la créature a lancé le dé d'Inspiration bardique et l'a ajouté à un jet de sauvegarde, la particule disparaît avec le son d'une musique douce, ce qui fait que la créature gagne des points de vie temporaires égaux au nombre obtenu sur le dé d'Inspiration bardique plus votre modificateur de Charisme (minimum de 1 point de vie temporaire).","name_en":"Mote of Potential"},{"name":"Performance de la Création","level":3,"desc":"Également au niveau 3, par une action, vous pouvez canaliser la magie du Chant de la Création pour créer un objet non magique de votre choix dans un espace inoccupé à moins de 3 mètres de vous. L'objet doit apparaître sur une surface ou dans un liquide pouvant le supporter. La valeur en PO de l'objet ne peut pas être supérieure à 20 fois votre niveau de barde, et l'objet doit être moyen ou inférieur. L'objet scintille doucement et une créature peut faiblement entendre de la musique lorsqu'elle le touche. L'objet créé disparaît après un nombre d'heures égal à votre bonus de maîtrise. Pour des exemples d'objets que vous pouvez créer, consultez le chapitre sur l'équipement du Manuel du joueur.\n\nUne fois que vous avez créé un objet avec cette fonctionnalité, vous ne pouvez plus le refaire avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort de niveau 2 ou supérieur pour utiliser à nouveau cette fonctionnalité. Vous ne pouvez créer qu'un seul élément à la fois grâce à cette fonctionnalité ; si vous utilisez cette action et possédez déjà un élément de cette fonctionnalité, le premier disparaît immédiatement.\n\nLa taille de l'élément que vous pouvez créer avec cette fonctionnalité augmente d'une catégorie de taille lorsque vous atteignez le niveau 6 (Grand) et le niveau 14 (Énorme).","name_en":"Performance of Creation"},{"name":"Animation de performances","level":6,"desc":"Au niveau 6, par une action, vous pouvez animer un objet non magique de taille grande ou plus petite à moins de 9 mètres de vous qui n'est pas porté ou transporté. L'objet animé utilise le bloc de statistiques Dancing Item, qui utilise votre bonus de maîtrise (PB). L'objet est amical avec vous et vos compagnons et obéit à vos commandes. Il vit 1 heure, jusqu'à ce qu'il soit réduit à 0 point de vie, ou jusqu'à votre mort.\n\nEn combat, l'objet partage votre nombre d'initiative, mais il prend son tour immédiatement après le vôtre. Il peut se déplacer et utiliser sa réaction tout seul, mais la seule action qu'il entreprend à son tour est l'action d'Esquive, à moins que vous n'effectuiez une action bonus à votre tour pour lui ordonner d'effectuer une autre action. Cette action peut être une action dans son bloc de statistiques ou une autre action. Si vous êtes frappé d'incapacité, l'objet peut entreprendre n'importe quelle action de son choix, pas seulement Esquiver.\n\nLorsque vous utilisez votre fonction Bardic Inspiration, vous pouvez commander l'objet dans le cadre de la même action bonus que vous utilisez pour Bardic Inspiration.\n\nUne fois que vous avez animé un objet avec cette fonctionnalité, vous ne pouvez plus le faire avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort de niveau 3 ou supérieur pour utiliser à nouveau cette fonctionnalité. Vous ne pouvez avoir qu’un seul élément animé par cette fonctionnalité à la fois ; si vous utilisez cette action et possédez déjà un objet dansant de cette fonctionnalité, le premier devient immédiatement inanimé.\nObjet de danse\nConstruction grande ou petite\nClasse d'armure : 16 (armure naturelle)\nPoints de vie : 10 + 5 fois votre niveau de barde\nVitesse : 30 pieds, vol 30 pieds (vol stationnaire)\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n18 (+4) | 14 (+2) | 16 (+3) | 4 (−3) | 10 (+0) | 6 (−2)\nImmunités aux dégâts : poison, psychique\nImmunités aux conditions : charmé, épuisement, empoisonné, effrayé\nSens : vision dans le noir à 18 pieds, perception passive 10\nLangues : comprend les langues que vous parlez\nDéfi : –\nBonus de compétence (PB) : équivaut à votre bonus\nForme immuable. L'objet est immunisé contre tout sort ou effet susceptible d'altérer sa forme.\nDanse irrépressible. Lorsqu'une créature commence son tour à moins de 10 pieds de l'objet, l'objet peut augmenter ou diminuer (votre choix) la vitesse de marche de cette créature de 10 pieds jusqu'à la fin du tour, à condition que l'objet ne soit pas incapable d'agir.\nActions\nSlam renforcé par la Force. Attaque au corps à corps avec une arme : votre modificateur d'attaque de sort pour toucher, atteignez 1,50 m, une cible que vous pouvez voir. Touché : 1d10 + PB dégâts de force.","name_en":"Animating Performance"},{"name":"Crescendo créatif","level":14,"desc":"Au niveau 14, lorsque vous utilisez votre fonctionnalité Performance de création, vous pouvez créer plusieurs éléments à la fois. Le nombre d'objets est égal à votre modificateur de Charisme (minimum de deux objets). Si vous créez un élément qui dépasserait ce nombre, vous choisissez lequel des éléments créés précédemment disparaît. Un seul de ces éléments peut avoir la taille maximale que vous pouvez créer ; le reste doit être petit ou minuscule.\n\nVous n'êtes plus limité par la valeur GP lors de la création d'éléments avec Performance of Creation.","name_en":"Creative Crescendo"}],"name_en":"Bard: College of Creation","_translated":true},{"index":"bard-eloquence","name":"Barde : Collège d'éloquence","class":"bard","source":"Mythic Odysseys of Theros, Tasha's Cauldron of Everything","subclass_flavor":"Les adeptes du Collège d'Éloquence maîtrisent l'art de l'oratoire. La persuasion est considérée comme un grand art, et un argument bien argumenté et bien formulé s’avère souvent plus puissant que la vérité objective. Ces bardes manient un mélange de logique et de jeux de mots théâtraux, convainquant les sceptiques et les détracteurs avec des arguments logiques, et touchant les cordes sensibles pour faire appel aux émotions d'un public entier.","desc":"","features":[{"name":"Langue d'argent","level":3,"desc":"À partir du niveau 3, vous maîtrisez parfaitement l’art de dire la bonne chose au bon moment. Lorsque vous effectuez un test de Charisme (Persuasion) ou de Charisme (Déception), vous pouvez traiter un résultat d20 de 9 ou moins comme un 10.","name_en":"Silver Tongue"},{"name":"Des mots troublants","level":3,"desc":"Également au niveau 3, vous pouvez lancer des mots empreints de magie qui déstabilisent une créature et la font douter d'elle-même. Par une action bonus, vous pouvez dépenser une utilisation de votre Inspiration bardique et choisir une créature que vous pouvez voir à moins de 20 mètres de vous. Lancez le dé Inspiration Bardique. La créature doit soustraire le nombre obtenu lors du prochain jet de sauvegarde qu'elle effectue avant le début de votre prochain tour.","name_en":"Unsettling Words"},{"name":"Une inspiration sans faille","level":6,"desc":"Au niveau 6, vos paroles inspirantes sont si convaincantes que les autres se sentent poussés à réussir. Lorsqu'une créature ajoute l'un de vos dés d'Inspiration bardique à son test de capacité, son jet d'attaque ou son jet de sauvegarde et que le jet échoue, la créature peut conserver le dé d'Inspiration bardique.","name_en":"Unfailing Inspiration"},{"name":"Discours universel","level":6,"desc":"Au niveau 6 également, vous avez acquis la capacité de rendre votre discours intelligible à n'importe quelle créature. Par une action, choisissez une ou plusieurs créatures à moins de 60 pieds de vous, jusqu'à un nombre égal à votre modificateur de Charisme (au minimum une créature). Les créatures choisies peuvent vous comprendre comme par magie, quelle que soit la langue que vous parlez, pendant 1 heure.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort pour l'utiliser à nouveau.","name_en":"Universal Speech"},{"name":"Inspiration infectieuse","level":14,"desc":"Au niveau 14, lorsque vous parvenez à inspirer quelqu'un, le pouvoir de votre éloquence peut désormais s'étendre à quelqu'un d'autre. Lorsqu'une créature à moins de 20 mètres de vous ajoute un de vos dés d'Inspiration bardique à son test de capacité, à son jet d'attaque ou à son jet de sauvegarde et que le jet réussit, vous pouvez utiliser votre réaction pour encourager une créature différente (autre que vous) qui peut vous entendre à moins de 60 pieds de vous, lui donnant un dé d'Inspiration bardique sans dépenser aucune de vos utilisations d'Inspiration bardique.\n\nVous pouvez utiliser cette réaction un nombre de fois égal à votre modificateur de Charisme (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Infectious Inspiration"}],"name_en":"Bard: College of Eloquence","_translated":true},{"index":"bard-glamour","name":"Barde : Collège du Glamour","class":"bard","source":"Xanathar's Guide to Everything","subclass_flavor":"Le Collège du Glamour est la demeure des bardes qui ont maîtrisé leur métier dans le royaume vibrant de Feywild ou sous la tutelle de quelqu'un qui y a vécu. Encadrés par des satyres, des éladrins et d'autres fées, ces bardes apprennent à utiliser leur magie pour ravir et captiver les autres.","desc":"","features":[{"name":"Manteau d'inspiration","level":3,"desc":"Lorsque vous rejoignez le Collège du Glamour au niveau 3, vous obtenez la capacité de tisser un chant de magie féerique qui imprègne vos alliés de vigueur et de vitesse.\n\nPar une action bonus, vous pouvez dépenser une utilisation de votre Inspiration bardique pour vous accorder une apparence merveilleuse. Ce faisant, choisissez un nombre de créatures que vous pouvez voir et qui peuvent vous voir dans un rayon de 60 pieds autour de vous, jusqu'à un nombre égal à votre modificateur de Charisme (au minimum un). Chacun d'eux gagne 5 points de vie temporaires. Lorsqu'une créature gagne ces points de vie temporaires, elle peut immédiatement utiliser sa réaction pour se déplacer à sa vitesse, sans provoquer d'attaques d'opportunité.\n\nLe nombre de points de vie temporaires augmente lorsque vous atteignez certains niveaux dans cette classe, passant à 8 au niveau 5, 11 au niveau 10 et 14 au niveau 15.","name_en":"Mantle of Inspiration"},{"name":"Des performances passionnantes","level":3,"desc":"À partir du niveau 3, vous pouvez charger votre performance avec une magie féerique et séduisante.\n\nSi vous jouez pendant au moins 1 minute, vous pouvez tenter d'émerveiller votre public en chantant, en récitant un poème ou en dansant. À la fin de la représentation, choisissez un nombre d'humanoïdes à moins de 60 pieds de vous qui ont tout regardé et écouté, jusqu'à un nombre égal à votre modificateur de Charisme (au minimum un). Chaque cible doit réussir un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de sorts ou être charmée par vous. Pendant qu'elle est ainsi charmée, la cible vous idolâtre, elle parle de vous avec enthousiasme à quiconque lui parle et elle gêne quiconque s'oppose à vous, évitant la violence à moins qu'elle ne soit déjà encline à se battre en votre nom. Cet effet se termine sur une cible après 1 heure, si elle subit des dégâts, si vous l'attaquez ou si elle vous voit attaquer ou endommager l'un de ses alliés.\n\nSi une cible réussit son jet de sauvegarde, elle n'a aucune idée que vous avez essayé de la charmer.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un repos court ou long.","name_en":"Enthralling Performance"},{"name":"Manteau de majesté","level":6,"desc":"Au niveau 6, vous acquérez la capacité de vous envelopper d’une magie féerique qui donne envie aux autres de vous servir. Par une action bonus, vous lancez Commandement, sans dépenser d'emplacement de sort, et vous prenez une apparence d'une beauté surnaturelle pendant 1 minute ou jusqu'à la fin de votre concentration (comme si vous vous concentriez sur un sort). Pendant ce temps, vous pouvez lancer Commandement comme une action bonus à chacun de vos tours, sans dépenser d'emplacement de sort.\n\nToute créature charmée par vous échoue automatiquement à son jet de sauvegarde contre le commandement que vous lancez avec cette fonctionnalité.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Mantle of Majesty"},{"name":"Majesté incassable","level":14,"desc":"Au niveau 14, votre apparence acquiert définitivement un aspect surnaturel qui vous rend plus belle et plus féroce.\n\nDe plus, par une action bonus, vous pouvez assumer une présence magiquement majestueuse pendant 1 minute ou jusqu'à ce que vous soyez incapable d'agir. Pendant toute la durée du sort, chaque fois qu'une créature tente de vous attaquer pour la première fois au cours d'un tour, l'attaquant doit effectuer un jet de sauvegarde de Charisme contre votre DD de sauvegarde de sort. En cas d'échec, il ne peut pas vous attaquer ce tour-ci et doit choisir une nouvelle cible pour son attaque, sinon l'attaque est inutile. En cas de sauvegarde réussie, il peut vous attaquer ce tour-ci, mais il est désavantagé à tout jet de sauvegarde qu'il effectue contre vos sorts lors de votre prochain tour.\n\nUne fois que vous assumez cette présence majestueuse, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.","name_en":"Unbreakable Majesty"}],"name_en":"Bard: College of Glamour","_translated":true},{"index":"bard-lore","name":"Barde : Collège du savoir","class":"bard","source":"Player's Handbook","subclass_flavor":"Les bardes du Collège du savoir savent quelque chose sur la plupart des choses, rassemblant des bribes de connaissances provenant de sources aussi diverses que des tomes savants et des contes paysans. Qu'il s'agisse de chanter des ballades folkloriques dans les tavernes ou des compositions élaborées dans les cours royales, ces bardes utilisent leurs dons pour captiver le public. Lorsque les applaudissements s'apaisent, les membres du public pourraient se retrouver à remettre en question tout ce qu'ils tenaient pour vrai, depuis leur foi dans le sacerdoce du temple local jusqu'à leur loyauté envers le roi.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous rejoignez le Collège du savoir au niveau 3, vous maîtrisez trois compétences de votre choix.","name_en":"Bonus Proficiencies"},{"name":"Couper les mots","level":3,"desc":"Au niveau 3 également, vous apprenez à utiliser votre esprit pour distraire, confondre et saper la confiance et la compétence des autres. Lorsqu'une créature que vous pouvez voir à moins de 60 pieds de vous effectue un jet d'attaque, un test de capacité ou un jet de dégâts, vous pouvez utiliser votre réaction pour dépenser l'une de vos utilisations d'Inspiration bardique, en lançant un dé d'Inspiration bardique et en soustrayant le nombre obtenu au jet de la créature. Vous pouvez choisir d'utiliser cette fonctionnalité après que la créature a effectué son jet, mais avant que le MD ne détermine si le jet d'attaque ou le test de capacité réussit ou échoue, ou avant que la créature n'inflige ses blessures. La créature est immunisée si elle ne peut pas vous entendre ou si elle est immunisée contre les charmes.","name_en":"Cutting Words"},{"name":"Secrets magiques supplémentaires","level":6,"desc":"Au niveau 6, vous apprenez deux sorts de votre choix dans n'importe quelle classe. Un sort que vous choisissez doit être d'un niveau que vous pouvez lancer, comme indiqué sur la table des bardes, ou un sort mineur. Les sorts choisis comptent pour vous comme des sorts de barde mais ne comptent pas dans le nombre de sorts de barde que vous connaissez.","name_en":"Additional Magical Secrets"},{"name":"Compétence inégalée","level":14,"desc":"À partir du niveau 14, lorsque vous effectuez un test de caractéristique, vous pouvez dépenser une utilisation d'Inspiration bardique. Lancez un dé d’inspiration bardique et ajoutez le nombre obtenu à votre test de capacité. Vous pouvez choisir de le faire après avoir lancé le dé pour le test de capacité, mais avant que le DM ne vous dise si vous réussissez ou échouez.","name_en":"Peerless Skill"}],"name_en":"Bard: College of Lore","_translated":true},{"index":"bard-spirits","name":"Barde : Collège des Esprits","class":"bard","source":"Van Richten's Guide to Ravenloft","subclass_flavor":"Les bardes du Collège des Esprits recherchent des contes dotés d'un pouvoir inhérent - qu'il s'agisse de légendes, d'histoires ou de fictions - et donnent vie à leurs sujets. Utilisant des pièges occultes, ces bardes évoquent des incarnations spirituelles de forces puissantes pour changer une fois de plus le monde. Ces esprits sont cependant capricieux, et ce qu'un barde invoque n'est pas toujours entièrement sous leur contrôle.","desc":"","features":[{"name":"Murmures guidantes","level":3,"desc":"Au niveau 3, vous pouvez contacter les esprits pour vous guider, vous et les autres. Vous apprenez le sort mineur Guidage, qui ne compte pas dans le nombre de sorts mineurs de barde que vous connaissez. Pour vous, il a une portée de 60 pieds lorsque vous le lancez.","name_en":"Guiding Whispers"},{"name":"Concentration spirituelle","level":3,"desc":"Au niveau 3, vous utilisez des outils qui vous aident à canaliser les esprits, qu'il s'agisse de personnages historiques ou d'archétypes fictifs. Vous pouvez utiliser les objets suivants comme foyer de lancement de sorts pour vos sorts de barde : une bougie, une boule de cristal, un crâne, une planche spirituelle ou un jeu de tarokka.\n\nÀ partir du niveau 6, lorsque vous lancez un sort de barde qui inflige des dégâts ou restaure des points de vie grâce à la concentration spirituelle, lancez un d6 et vous gagnez un bonus à un jet de dégâts ou de soins du sort égal au nombre obtenu.","name_en":"Spiritual Focus"},{"name":"Contes d'au-delà","level":3,"desc":"Au niveau 3, vous contactez les esprits qui racontent leurs histoires à travers vous. Pendant que vous maintenez votre Concentration Spirituelle, vous pouvez utiliser une action bonus pour dépenser une utilisation de votre Inspiration Bardique et lancer un jet sur la table Contes Spirituels en utilisant votre dé d'Inspiration Bardique pour déterminer l'histoire que les esprits vous demandent de raconter. Vous gardez le conte à l’esprit jusqu’à ce que vous lui accordiez l’effet ou que vous terminiez un repos court ou long.\n\nVous pouvez utiliser une action pour choisir une créature que vous pouvez voir à moins de 9 mètres de vous (cela peut être vous) pour être la cible de l’effet du conte. Une fois que vous l’avez fait, vous ne pouvez plus redonner l’effet du conte jusqu’à ce que vous l’ayez relancé.\n\nVous ne pouvez retenir qu’une seule de ces histoires à la fois, et lancer un jet sur le tableau des Contes spirituels met immédiatement fin à l’effet de l’histoire précédente.\n\nSi le conte nécessite un jet de sauvegarde, le DD est égal à votre DD de sauvegarde de sort.\nContes d'esprit\nInsp. bardique. Mourir | Conte raconté à travers vous\n1 | Conte de l'animal intelligent. Pendant les 10 minutes suivantes, chaque fois que la cible effectue un test d'Intelligence, de Sagesse ou de Charisme, la cible peut lancer un dé supplémentaire immédiatement après avoir lancé le d20 et ajouter le numéro du dé supplémentaire au test. Le dé supplémentaire est du même type que votre dé d’Inspiration Bardique.\n2 | Conte du célèbre duelliste. Vous lancez une attaque magique au corps à corps contre la cible. Sur un coup, la cible subit des dégâts de force égaux à deux lancers de votre dé d'Inspiration bardique + votre modificateur de Charisme.\n3 | Conte des amis bien-aimés. La cible et une autre créature de son choix qu'elle peut voir à moins de 1,50 mètre d'elle gagnent des points de vie temporaires égaux à un jet de votre dé d'Inspiration bardique + votre modificateur de Charisme.\n4 | Conte du fugitif. La cible peut immédiatement utiliser sa réaction pour se téléporter jusqu'à 9 mètres dans un espace inoccupé qu'elle peut voir. Lorsque la cible se téléporte, elle peut choisir un nombre de créatures qu'elle peut voir dans un rayon de 9 mètres autour d'elle jusqu'à concurrence de votre modificateur de Charisme (minimum de 0) pour utiliser immédiatement la même réaction.\n5 | Conte du Vengeur. Pendant 1 minute, toute créature qui touche la cible avec une attaque de mêlée subit des dégâts de force égaux à un jet de votre dé d'inspiration bardique.\n6 | Conte du Voyageur. La cible gagne des points de vie temporaires égaux à un lancer de votre dé d'inspiration bardique + votre niveau de barde. Tant qu'elle dispose de ces points de vie temporaires, la vitesse de marche de la cible augmente de 3 mètres et elle gagne un bonus de +1 à sa CA.\n7 | Conte du séducteur. La cible doit réussir un jet de sauvegarde de Sagesse ou subir des dégâts psychiques égaux à deux lancers de votre dé d'Inspiration bardique, et la cible est frappée d'incapacité jusqu'à la fin de son prochain tour.\n8 | Conte du fantôme. La cible devient invisible jusqu'à la fin de son prochain tour ou jusqu'à ce qu'elle touche une créature avec une attaque. Si elle touche une créature avec une attaque pendant cette invisibilité, la créature qu'elle touche subit des dégâts nécrotiques égaux à un jet de votre dé d'inspiration bardique et est effrayée par la cible jusqu'à la fin du prochain tour de la créature effrayée.\n9 | Conte de la Brute. Chaque créature au choix de la cible qu’elle peut voir dans un rayon de 9 mètres autour d’elle doit effectuer un jet de sauvegarde de Force. En cas d'échec, une créature subit des dégâts de tonnerre égaux à trois lancers de votre dé d'inspiration bardique et est mise à terre. Une créature qui réussit son jet de sauvegarde subit la moitié de dégâts et n’est pas mise à terre.\n10 | Conte du Dragon. La cible crache du feu depuis la bouche dans un cône de 30 pieds. Chaque créature dans cette zone doit effectuer un jet de sauvegarde de Dextérité, subissant des dégâts de feu égaux à quatre lancers de votre dé d'Inspiration bardique en cas d'échec, ou la moitié de ces dégâts en cas de réussite.\n11 | Conte de l'Ange. La cible récupère des points de vie égaux à deux lancers de votre dé d'Inspiration bardique + votre modificateur de Charisme, et vous mettez fin à une condition de la liste suivante affectant la cible : aveuglée, assourdie, paralysée, pétrifiée ou empoisonnée.\n12 | Tale of the Mind-Bender Vous évoquez une fable incompréhensible d'un être d'un autre monde. La cible doit réussir un jet de sauvegarde d'Intelligence ou subir des dégâts psychiques égaux à trois lancers de votre dé d'Inspiration bardique et être étourdie jusqu'à la fin de son prochain tour.","name_en":"Tales from Beyond"},{"name":"Séance spirituelle","level":6,"desc":"Au niveau 6, les esprits vous fournissent des informations surnaturelles. Vous pouvez mener un rituel d'une heure pour canaliser les esprits (qui peut être effectué pendant un repos court ou long) en utilisant votre concentration spirituelle. Vous pouvez mener le rituel avec un nombre de créatures volontaires égal à votre bonus de maîtrise (y compris vous-même). À la fin du rituel, vous apprenez temporairement un sort de votre choix dans n'importe quelle classe.\n\nLe sort que vous choisissez doit être d'un niveau égal ou inférieur au nombre de créatures qui ont mené le rituel, le sort doit être d'un niveau que vous pouvez lancer et il doit appartenir à l'école de divination ou de nécromancie. Le sort choisi compte pour vous comme un sort de barde mais ne compte pas dans le nombre de sorts de barde que vous connaissez.\n\nUne fois que vous avez effectué le rituel, vous ne pouvez plus le refaire tant que vous n’avez pas commencé un repos long, et vous connaissez le sort choisi jusqu’à ce que vous ayez commencé un repos long.","name_en":"Spirit Session"},{"name":"Connexion mystique","level":14,"desc":"Au niveau 14, vous avez désormais la possibilité de pousser les esprits de Tales from Beyond vers certains contes. Chaque fois que vous lancez un jet sur la table Spirit Tales, vous pouvez lancer le dé deux fois et choisir lequel des deux effets accorder. Si vous obtenez le même nombre sur les deux dés, vous pouvez ignorer le nombre et choisir n’importe quel effet sur la table.","name_en":"Mystical Connection"}],"name_en":"Bard: College of Spirits","_translated":true},{"index":"bard-swords","name":"Barde : Collège des Épées","class":"bard","source":"Xanathar's Guide to Everything","subclass_flavor":"Les bardes du Collège des Épées sont appelés des lames, et ils divertissent grâce à des prouesses audacieuses en matière d'armes. Les lames effectuent des cascades telles que avaler des épées, lancer des couteaux, jongler et simuler des combats. Bien qu’ils utilisent leurs armes pour se divertir, ils sont également des guerriers hautement qualifiés et compétents.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous rejoignez le Collège des Épées au niveau 3, vous maîtrisez l'armure moyenne et le cimeterre.\n\nSi vous maîtrisez une arme de mêlée simple ou martiale, vous pouvez l’utiliser comme cible de lancement de sorts pour vos sorts de barde.","name_en":"Bonus Proficiencies"},{"name":"Style de combat","level":3,"desc":"Au niveau 3, vous adoptez un style de combat particulier comme spécialité. Choisissez l'une des options suivantes. Vous ne pouvez pas choisir une option de style de combat plus d'une fois, même si vous devez ensuite choisir à nouveau.\n• Duel. Lorsque vous maniez une arme de mêlée dans une main et aucune autre arme, vous gagnez un bonus de +2 aux jets de dégâts avec cette arme.\n• Combat à deux armes. Lorsque vous vous engagez dans un combat à deux armes, vous pouvez ajouter votre modificateur de capacité aux dégâts de la deuxième attaque.","name_en":"Fighting Style"},{"name":"Épanouissement de la lame","level":3,"desc":"Au niveau 3, vous apprenez à réaliser des démonstrations impressionnantes de prouesses martiales et de vitesse.\n\nChaque fois que vous effectuez l'action d'attaque à votre tour, votre vitesse de marche augmente de 10 pieds jusqu'à la fin du tour, et si une attaque avec une arme que vous effectuez dans le cadre de cette action touche une créature, vous pouvez utiliser l'une des options suivantes de Blade Flourish de votre choix. Vous ne pouvez utiliser qu’une seule option Blade Flourish par tour.\n\nÉpanouissement défensif. Vous pouvez dépenser une utilisation de votre Inspiration bardique pour que l'arme inflige des dégâts supplémentaires à la cible que vous touchez. Les dégâts sont égaux au nombre obtenu sur le dé d’inspiration bardique. Vous ajoutez également le nombre obtenu à votre CA jusqu'au début de votre prochain tour.\n\nS'épanouir. Vous pouvez dépenser une utilisation de votre Inspiration bardique pour que l'arme inflige des dégâts supplémentaires à la cible que vous touchez et à toute autre créature de votre choix que vous pouvez voir à moins de 1,50 mètre de vous. Les dégâts sont égaux au nombre obtenu sur le dé d’inspiration bardique.\n\nÉpanouissement mobile. Vous pouvez dépenser une utilisation de votre Inspiration bardique pour que l'arme inflige des dégâts supplémentaires à la cible que vous touchez. Les dégâts sont égaux au nombre obtenu sur le dé d’inspiration bardique. Vous pouvez également pousser la cible jusqu'à 1,50 m de vous, plus un nombre de pieds égal au nombre obtenu sur ce dé. Vous pouvez alors immédiatement utiliser votre réaction pour vous déplacer à votre vitesse de marche vers un espace inoccupé à moins de 1,50 mètre de la cible.","name_en":"Blade Flourish"},{"name":"Attaque supplémentaire","level":6,"desc":"À partir du niveau 6, vous pouvez attaquer deux fois, au lieu d'une, chaque fois que vous effectuez l'action Attaque pendant votre tour.","name_en":"Extra Attack"},{"name":"L'épanouissement du Maître","level":14,"desc":"À partir du niveau 14, chaque fois que vous utilisez une option Blade Flourish, vous pouvez lancer un d6 et l’utiliser au lieu de dépenser un dé d’inspiration bardique.","name_en":"Master's Flourish"}],"name_en":"Bard: College of Swords","_translated":true},{"index":"bard-dirge-singer","name":"Barde : Collège du Dirge Singer (HB)","class":"bard","source":"Exploring Eberron","subclass_flavor":"Les bardes du Collège du Dirge Singer sont formés pour inspirer leur peuple et diriger les soldats sur le champ de bataille. Étudiants à la fois en histoire et en guerre, les chanteurs funéraires utilisent les récits de gloire passée et leur connaissance des grandes victoires pour inspirer leurs alliés et leur fournir une vision stratégique approfondie, leur ordonnant de frapper lorsque les ennemis sont faibles.","desc":"Les bardes du Collège du Dirge Singer sont formés pour inspirer leur peuple et diriger les soldats sur le champ de bataille. Étudiants à la fois en histoire et en guerre, les chanteurs funéraires utilisent les récits de gloire passée et leur connaissance des grandes victoires pour inspirer leurs alliés et leur fournir une vision stratégique approfondie, leur ordonnant de frapper lorsque les ennemis sont faibles.\n\nCette ancienne tradition s'est développée dans l'Empire de Dhakaan et est largement inconnue au-delà des gobelinoïdes du Kech Dhakaan. Les duur'kala – Gobelin pour chanteur de chant funèbre – sont les historiens, les diplomates et les chefs spirituels de l'empire. Si vous ne faites pas partie des dar, réfléchissez à la façon dont vous avez appris cette tradition. Vous êtes-vous entraîné avec un mentor ghaal’dar ? Ou avez-vous trouvé votre propre chemin vers ces techniques ?","features":[{"name":"Large inspiration","level":3,"desc":"Lorsque vous rejoignez le Collège des Chanteurs Dirge au niveau 3, vous apprenez à renforcer le cœur de vos troupes et à les amener à la grandeur. Vous apprenez le sort mineur Guidage, qui est considéré comme un sort de barde pour vous, mais ne compte pas dans votre nombre de sorts mineurs connus.\n\nDe plus, par une action bonus, vous pouvez dépenser une utilisation de votre Inspiration bardique pour inspirer plusieurs alliés. Lorsque vous faites cela, choisissez deux créatures à moins de 60 pieds de vous qui peuvent vous entendre. Chaque créature gagne un dé d'inspiration bardique.\n\nVotre dé d'Inspiration bardique ne change pas au niveau 5, mais reste un d6 ; il devient un d8 au niveau 10 et un d10 au niveau 15.","name_en":"Broad Inspiration"},{"name":"Gardien de l'Histoire","level":3,"desc":"Au 3ème niveau également, vous acquérez des compétences en histoire ou en performance. Si vous maîtrisez déjà ces deux compétences, vous maîtrisez l'une des compétences suivantes de votre choix : Arcanes, Intimidation ou Persuasion.\n\nDe plus, choisissez Historique ou Performances. Votre bonus de maîtrise est doublé pour tout test de capacité que vous effectuez et qui utilise cette compétence.","name_en":"Keeper of History"},{"name":"Voix imposante","level":6,"desc":"À partir du niveau 6, vous excellez dans l’art d’inspirer et de diriger les soldats au combat. Lorsqu'une créature qui a un dé d'Inspiration bardique de votre part effectue l'action d'attaque à son tour, vous pouvez utiliser votre réaction pour lui permettre une attaque d'arme supplémentaire. La créature lance le dé d'inspiration bardique, en ajoutant le nombre obtenu à son jet de dégâts d'arme.","name_en":"Commanding Voice"},{"name":"Maître commandant","level":14,"desc":"À partir du niveau 14, vous maintenez sans relâche le moral et la discipline de votre unité. Pendant votre tour, vous pouvez utiliser Contre-charme comme action bonus. Lorsque vous démarrez une performance de Contre-charme, si une créature qui bénéficie de son bénéfice est actuellement charmée ou effrayée, elle peut immédiatement effectuer un autre jet de sauvegarde contre l'effet qui a imposé la condition.\n\nDe plus, lorsqu'une créature qui bénéficie de votre performance Contre-charme effectue un test de capacité ou un jet de sauvegarde, elle peut lancer un d4 et ajouter le nombre obtenu au test de capacité ou au jet de sauvegarde.","name_en":"Master Commander"}],"name_en":"Bard: College of the Dirge Singer (HB)","_translated":true},{"index":"bard-valor","name":"Barde : Collège de la Valeur","class":"bard","source":"Player's Handbook","subclass_flavor":"Les bardes du Collège de la Valeur sont des scaldes audacieux dont les récits entretiennent la mémoire des grands héros du passé et inspirent ainsi une nouvelle génération de héros. Ces bardes se rassemblent dans les hydromels ou autour de grands feux de joie pour chanter les exploits des puissants, passés et présents. Ils parcourent le pays pour être témoins de grands événements et pour s'assurer que le souvenir de ces événements ne disparaisse pas du monde. Avec leurs chansons, ils inspirent les autres à atteindre les mêmes sommets d’accomplissement que les héros d’autrefois.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous rejoignez le Collège de la Valeur au niveau 3, vous maîtrisez les armures moyennes, les boucliers et les armes martiales.","name_en":"Bonus Proficiencies"},{"name":"Inspiration de combat","level":3,"desc":"Au niveau 3 également, vous apprenez à inspirer les autres au combat. Une créature qui a un dé d'Inspiration bardique de votre part peut lancer ce dé et ajouter le nombre obtenu à un jet de dégâts d'arme qu'elle vient de faire. Alternativement, lorsqu'un jet d'attaque est effectué contre la créature, elle peut utiliser sa réaction pour lancer le dé d'inspiration bardique et ajouter le nombre obtenu à sa CA contre cette attaque, après avoir vu le jet mais avant de savoir si elle touche ou rate.","name_en":"Combat Inspiration"},{"name":"Attaque supplémentaire","level":6,"desc":"À partir du niveau 6, vous pouvez attaquer deux fois, au lieu d'une, chaque fois que vous effectuez l'action Attaque pendant votre tour.","name_en":"Extra Attack"},{"name":"Magie de combat","level":14,"desc":"Au niveau 14, vous maîtrisez l’art de combiner le lancement de sorts et l’utilisation d’armes en un seul acte harmonieux. Lorsque vous utilisez votre action pour lancer un sort de barde, vous pouvez effectuer une attaque avec une arme en tant qu'action bonus.","name_en":"Battle Magic"}],"name_en":"Bard: College of Valor","_translated":true},{"index":"bard-whispers","name":"Barde : Collège des Murmures","class":"bard","source":"Xanathar's Guide to Everything","subclass_flavor":"La plupart des gens sont heureux d’accueillir un barde parmi eux. Les bardes du Collège des Murmures utilisent cela à leur avantage. Ils ressemblent à n’importe quel autre barde, partageant des nouvelles, chantant des chansons et racontant des histoires au public qu’ils rassemblent. En vérité, le Collège des Murmures enseigne à ses étudiants qu'ils sont des loups parmi les moutons. Ces bardes utilisent leurs connaissances et leur magie pour découvrir des secrets et les retourner contre les autres par l'extorsion et les menaces.","desc":"","features":[{"name":"Lames psychiques","level":3,"desc":"Lorsque vous rejoignez le Collège des Murmures au niveau 3, vous obtenez la capacité de rendre vos attaques avec des armes magiquement toxiques pour l'esprit d'une créature.\n\nLorsque vous touchez une créature avec une attaque avec une arme, vous pouvez dépenser une utilisation de votre Inspiration bardique pour infliger 2d6 dégâts psychiques supplémentaires à cette cible. Vous ne pouvez le faire qu’une fois par tour, pendant votre tour.\n\nLes dégâts psychiques augmentent lorsque vous atteignez certains niveaux dans cette classe, passant à 3d6 au niveau 5, 5d6 au niveau 10 et 8d6 au niveau 15.","name_en":"Psychic Blades"},{"name":"Mots de terreur","level":3,"desc":"Au niveau 3, vous apprenez à insuffler à des mots apparemment innocents une magie insidieuse qui peut inspirer la terreur.\n\nSi vous parlez seul à un humanoïde pendant au moins 1 minute, vous pouvez tenter de semer la paranoïa et la peur dans son esprit. A la fin de la conversation, la cible doit réussir un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de sort sous peine d'avoir peur de vous ou d'une autre créature de votre choix. La cible est ainsi effrayée pendant 1 heure, jusqu'à ce qu'elle soit attaquée ou endommagée, ou jusqu'à ce qu'elle voit ses alliés être attaqués ou endommagés.\n\nSi la cible réussit son jet de sauvegarde, elle n'a aucune idée que vous avez essayé de l'effrayer.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou un repos long.","name_en":"Words of Terror"},{"name":"Manteau des murmures","level":6,"desc":"Au niveau 6, vous gagnez la capacité d'adopter le personnage d'un humanoïde. Lorsqu'un humanoïde meurt à moins de 9 mètres de vous, vous pouvez capturer son ombre comme par magie en utilisant votre réaction. Vous conservez cette ombre jusqu'à ce que vous l'utilisiez ou que vous terminiez un long repos.\n\nVous pouvez utiliser l'ombre comme une action. Lorsque vous le faites, il disparaît, se transformant comme par magie en un déguisement qui apparaît sur vous. Vous ressemblez maintenant à la personne décédée, mais en bonne santé et vivante. Ce déguisement dure 1 heure ou jusqu'à ce que vous y mettiez fin par une action bonus.\n\nPendant que vous êtes déguisé, vous avez accès à toutes les informations que l'humanoïde partagerait librement avec une connaissance occasionnelle. Ces informations comprennent des détails généraux sur son parcours et sa vie personnelle, mais n'incluent pas de secrets. Les informations sont suffisantes pour que vous puissiez vous faire passer pour la personne en puisant dans ses souvenirs.\n\nUne autre créature peut voir à travers ce déguisement en réussissant un test de Sagesse (Perspicacité) contesté par votre test de Charisme (Tromperie). Vous gagnez un bonus de +5 à votre chèque.\n\nUne fois que vous avez capturé une ombre avec cette fonctionnalité, vous ne pouvez pas en capturer une autre avant d'avoir terminé un repos court ou long.","name_en":"Mantle of Whispers"},{"name":"Connaissance des ombres","level":14,"desc":"Au niveau 14, vous acquérez la capacité d’intégrer la magie noire dans vos mots et d’exploiter les peurs les plus profondes d’une créature.\n\nPar une action, vous murmurez comme par magie une phrase qu'une seule créature de votre choix à moins de 9 mètres de vous peut entendre. La cible doit effectuer un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de sort. Il réussit automatiquement s’il ne partage pas de langue avec vous ou s’il ne vous entend pas. Lors d'un jet de sauvegarde réussi, votre murmure ressemble à un marmonnement inintelligible et n'a aucun effet.\n\nSi la cible échoue à son jet de sauvegarde, vous la charmez pendant les 8 heures suivantes ou jusqu'à ce que vous ou vos alliés l'attaquiez ou l'endommagez. Il interprète les murmures comme une description de son secret le plus mortifiant.\n\nMême si vous n'obtenez aucune connaissance de ce secret, la cible est convaincue que vous le connaissez. Ainsi charmée, la créature obéit à vos ordres de peur que vous ne révéliez son secret. Il ne risquera pas sa vie pour vous et ne se battra pas pour vous, à moins qu’il ne soit déjà enclin à le faire. Il vous accorde des faveurs et des cadeaux qu'il offrirait à un ami proche.\n\nLorsque l’effet prend fin, la créature ne comprend pas pourquoi elle vous a fait si peur.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Shadow Lore"}],"name_en":"Bard: College of Whispers","_translated":true},{"index":"cleric-arcana","name":"Clerc : Domaine Arcana","class":"cleric","source":"Sword Coast Adventurer's Guide","subclass_flavor":"La magie est une énergie qui imprègne le multivers et qui alimente à la fois la destruction et la création. Les dieux du domaine Arcana connaissent intimement les secrets et le potentiel de la magie. Pour certains de ces dieux, la connaissance magique est une grande responsabilité qui s’accompagne d’une compréhension particulière de la nature de la réalité. D’autres dieux d’Arcana voient la magie comme un pouvoir pur, à utiliser comme bon lui semble.","desc":"","features":[{"name":"Initié arcanique","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous maîtrisez la compétence Arcana et vous gagnez deux sorts mineurs de votre choix dans la liste des sorts du sorcier. Pour vous, ces petits sorts comptent comme des petits sorts de clerc.","name_en":"Arcane Initiate"},{"name":"Divinité de canal : Abjuration arcanique","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour abjurer des créatures d'un autre monde.\n\nPar une action, vous présentez votre symbole sacré, et un céleste, élémentaire, fée ou démon de votre choix qui se trouve à moins de 9 mètres de vous doit effectuer un jet de sauvegarde de sagesse, à condition que la créature puisse vous voir ou vous entendre. Si la créature échoue à son jet de sauvegarde, elle est retournée pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts.\n\nUne créature transformée doit passer son tour à essayer de s'éloigner le plus possible de vous, et elle ne peut pas volontairement terminer son mouvement dans un espace situé à moins de 9 mètres de vous. Il ne peut pas non plus accepter de réactions. Pour son action, il ne peut utiliser que l'action Dash ou tenter d'échapper à un effet qui l'empêche de bouger. S'il n'y a nulle part où se déplacer, la créature peut utiliser l'action Esquiver.\n\nAprès avoir atteint le niveau 5, lorsqu'une créature échoue à son jet de sauvegarde contre votre fonction Abjuration arcanique, la créature est bannie pendant 1 minute (comme dans le sort Bannissement, aucune concentration requise) si elle n'est pas sur son plan d'origine et que son niveau de défi est égal ou inférieur à un certain seuil, comme indiqué sur le tableau de bannissement arcanique.\nBannissement des Arcanes\nNiveau clerc | Bannit les créatures de CR…\n5ème | 1/2 ou moins\n8ème | 1 ou moins\n11e | 2 ou moins\n14e | 3 ou moins\n17e | 4 ou moins","name_en":"Channel Divinity: Arcane Abjuration"},{"name":"Brise-sort","level":6,"desc":"À partir du niveau 6, lorsque vous redonnez des points de vie à un allié possédant un sort de niveau 1 ou supérieur, vous pouvez également mettre fin à un sort de votre choix sur cette créature. Le niveau du sort que vous mettez fin doit être égal ou inférieur au niveau de l'emplacement de sort que vous utilisez pour lancer le sort de guérison.","name_en":"Spell Breaker"},{"name":"Lancement de sorts puissant","level":8,"desc":"À partir du niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Maîtrise des arcanes","level":17,"desc":"Au niveau 17, vous choisissez quatre sorts dans la liste des sorts du magicien, un de chacun des niveaux suivants : 6e, 7e, 8e et 9e. Vous les ajoutez à votre liste de sorts de domaine. Comme vos autres sorts de domaine, ils sont toujours préparés et comptent pour vous comme des sorts de clerc.","name_en":"Arcane Mastery"}],"name_en":"Cleric: Arcana Domain","_translated":true},{"index":"cleric-death","name":"Clerc : Domaine de la Mort","class":"cleric","source":"Dungeon Master's Guide","subclass_flavor":"Le domaine de la Mort concerne les forces qui causent la mort, ainsi que l'énergie négative qui donne naissance aux créatures mortes-vivantes. Des divinités telles que Chemosh, Myrkul et Wee Jas sont les patrons des nécromanciens, des chevaliers de la mort, des liches, des seigneurs momies et des vampires. Le domaine des Dieux de la Mort incarne également le meurtre (Anubis, Bhaal et Pyremius), la douleur (Iuz ou Loviatar), la maladie ou le poison (Incabulos, Talona ou Morgion) et le monde souterrain (Hadès et Hel).","desc":"","features":[{"name":"Compétence bonus","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous gagnez en maîtrise des armes martiales.","name_en":"Bonus Proficiency"},{"name":"Moissonneuse","level":1,"desc":"Au niveau 1, vous apprenez un sort mineur de nécromancie de votre choix dans n'importe quelle liste de sorts. Lorsque vous lancez un sort mineur de nécromancie qui cible normalement une seule créature, le sort peut à la place cibler deux créatures à portée et à moins de 1,50 mètre l'une de l'autre.","name_en":"Reaper"},{"name":"Channel Divinity : Toucher de la mort","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser Channel Divinity pour détruire la force vitale d'une autre créature par le toucher. Lorsque vous touchez une créature avec une attaque de mêlée, vous pouvez utiliser Channel Divinity pour infliger des dégâts nécrotiques supplémentaires à la cible. Les dégâts sont égaux à 5 + deux fois votre niveau de clerc.","name_en":"Channel Divinity: Touch of Death"},{"name":"Destruction inévitable","level":6,"desc":"À partir du niveau 6, votre capacité à canaliser l’énergie négative devient plus puissante. Les dégâts nécrotiques infligés par vos sorts de clerc et vos options Channel Divinity ignorent la résistance aux dégâts nécrotiques.","name_en":"Inescapable Destruction"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d'imprégner vos frappes d'arme d'énergie nécrotique. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts nécrotiques supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Faucheur amélioré","level":17,"desc":"À partir du niveau 17, lorsque vous lancez un sort de nécromancie du niveau 1 au niveau 5 qui cible une seule créature, le sort peut à la place cibler deux créatures à portée et à 1,50 mètre l'une de l'autre. Si le sort consomme ses composants matériels, vous devez les fournir pour chaque cible.","name_en":"Improved Reaper"}],"name_en":"Cleric: Death Domain","_translated":true},{"index":"cleric-forge","name":"Clerc : Domaine Forge","class":"cleric","source":"Xanathar's Guide to Everything","subclass_flavor":"Les dieux de la forge sont les patrons des artisans qui travaillent le métal, depuis un humble forgeron qui entretient un village avec des fers à cheval et des lames de charrue jusqu'au puissant artisan elfe dont les flèches de mithral à pointe de diamant ont abattu des seigneurs démons. Les dieux de la forge enseignent qu'avec de la patience et un travail acharné, même le métal le plus intraitable peut être transformé d'un morceau de minerai en un objet magnifiquement ouvré. Les prêtres de ces divinités recherchent des objets perdus par les forces des ténèbres, libèrent des mines envahies par les orcs et découvrent des matériaux rares et merveilleux nécessaires à la création de puissants objets magiques. Les adeptes de ces dieux sont très fiers de leur travail et sont prêts à fabriquer et à utiliser des armures lourdes et des armes puissantes pour les protéger. Les divinités de ce domaine incluent Gond, Reorx, Onatar, Moradin, Hephaestus et Goibhniu.","desc":"","features":[{"name":"Compétences bonus","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous gagnez en maîtrise des armures lourdes et des outils de forgeron.","name_en":"Bonus Proficiencies"},{"name":"Bénédiction de la Forge","level":1,"desc":"Au niveau 1, vous gagnez la capacité d’imprégner de magie une arme ou une armure. À la fin d'un long repos, vous pouvez toucher un objet non magique qui est une armure ou une arme simple ou martiale. Jusqu'à la fin de votre prochain repos long ou jusqu'à votre mort, l'objet devient un objet magique, conférant un bonus de +1 à la CA s'il s'agit d'une armure ou un bonus de +1 aux jets d'attaque et de dégâts s'il s'agit d'une arme.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Blessing of the Forge"},{"name":"Channel Divinity : Bénédiction de l'artisan","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre Channel Divinity pour créer des objets simples.\n\nVous effectuez un rituel d'une heure qui fabrique un objet non magique qui doit contenir du métal : une arme simple ou martiale, une armure, dix pièces de munitions, un ensemble d'outils ou un autre objet métallique. La création est terminée à la fin de l'heure, fusionnant dans un espace inoccupé de votre choix sur une surface à moins de 5 pieds de vous.\n\nLa chose que vous créez ne peut pas valoir plus de 100 po. Dans le cadre de ce rituel, vous devez disposer du métal, qui peut inclure des pièces de monnaie, d'une valeur égale à la création. Le métal fusionne irrémédiablement et se transforme en la création à la fin du rituel, formant par magie même des parties non métalliques de la création.\n\nLe rituel peut créer une copie d'un objet non magique contenant du métal, comme une clé, si vous possédez l'original pendant le rituel.","name_en":"Channel Divinity: Artisan's Blessing"},{"name":"Âme de la Forge","level":6,"desc":"Dès le niveau 6, votre maîtrise de la forge vous confère des capacités spéciales :\n• Vous gagnez en résistance aux dégâts de feu.\n• Lorsque vous portez une armure lourde, vous gagnez un bonus de +1 à la CA.","name_en":"Soul of the Forge"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d'imprégner vos frappes d'armes de la puissance ardente de la forge. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts de feu supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Saint de la Forge et du Feu","level":17,"desc":"Au niveau 17, votre affinité bénie avec le feu et le métal devient plus puissante :\n• Vous gagnez l'immunité contre les dégâts de feu.\n• Lorsque vous portez une armure lourde, vous bénéficiez d'une résistance aux dégâts contondants, perforants et tranchants des attaques non magiques.","name_en":"Saint of Forge and Fire"}],"name_en":"Cleric: Forge Domain","_translated":true},{"index":"cleric-grave","name":"Clerc : Domaine des tombes","class":"cleric","source":"Xanathar's Guide to Everything","subclass_flavor":"Les dieux de la tombe veillent sur la frontière entre la vie et la mort. Pour ces divinités, la mort et l’au-delà constituent un élément fondamental du fonctionnement du multivers. Résister à la mort ou profaner le repos des morts est une abomination. Les divinités de la tombe incluent Kelemvor, Wee Jas, les esprits ancestraux de la Cour éternelle, Hadès, Anubis et Osiris. Ces divinités enseignent à leurs adeptes à respecter les morts et à leur rendre hommage. Les adeptes de ces divinités cherchent à mettre au repos les esprits agités, à détruire les morts-vivants partout où ils les trouvent et à soulager les souffrances des créatures mourantes. Leur magie leur permet également d’éviter la mort d’une créature, bien qu’ils refusent d’utiliser une telle magie pour prolonger la durée de vie d’une créature au-delà de ses limites mortelles.","desc":"","features":[{"name":"Cercle de mortalité","level":1,"desc":"Au niveau 1, vous gagnez la capacité de manipuler la frontière entre la vie et la mort. Alors que vous lanceriez normalement un ou plusieurs dés pour redonner des points de vie avec un sort à une créature à 0 point de vie, vous utilisez à la place le nombre le plus élevé possible pour chaque dé.\n\nDe plus, vous apprenez le cantrip Spare the Dying, qui ne compte pas dans le nombre de cantrips de clerc que vous connaissez. Pour vous, il a une portée de 9 mètres, et vous pouvez le lancer comme une action bonus.","name_en":"Circle of Mortality"},{"name":"Les yeux de la tombe","level":1,"desc":"Au niveau 1, vous gagnez la capacité de ressentir occasionnellement la présence de morts-vivants, dont l'existence est une insulte au cycle naturel de la vie. Par une action, vous pouvez ouvrir votre conscience pour détecter comme par magie les morts-vivants. Jusqu'à la fin de votre prochain tour, vous connaissez l'emplacement de tout mort-vivant dans un rayon de 20 mètres autour de vous qui n'est pas à couvert et qui n'est pas protégé de la magie divinatoire. Ce sens ne vous dit rien sur les capacités ou l’identité d’une créature.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Eyes of the Grave"},{"name":"Channel Divinity : Le chemin vers la tombe","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal de divinité pour marquer la force vitale d'une autre créature en vue de sa terminaison.\n\nPar une action, vous choisissez une créature que vous pouvez voir dans un rayon de 9 mètres autour de vous, en la maudissant jusqu'à la fin de votre prochain tour. La prochaine fois que vous ou un de vos alliés frappez la créature maudite avec une attaque, la créature devient vulnérable à tous les dégâts de cette attaque, et la malédiction prend alors fin.","name_en":"Channel Divinity: Path to the Grave"},{"name":"Sentinelle aux portes de la mort","level":6,"desc":"Au niveau 6, vous gagnez la capacité d’empêcher la mort de progresser. En réaction, lorsque vous ou un allié que vous pouvez voir à moins de 9 mètres de vous subissez un coup critique, vous pouvez transformer cette attaque en coup normal. Tous les effets déclenchés par un coup critique sont annulés.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Sentinel at Death's Door"},{"name":"Lancement de sorts puissant","level":8,"desc":"À partir du niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Gardien des âmes","level":17,"desc":"Au niveau 17, vous pouvez saisir une trace de vitalité d'une âme qui se sépare et l'utiliser pour guérir les vivants. Lorsqu'un ennemi que vous pouvez voir meurt à moins de 9 mètres de vous, vous ou un allié de votre choix qui se trouve à moins de 9 mètres de vous récupérez des points de vie égaux au nombre de dés de vie de l'ennemi. Vous ne pouvez utiliser cette fonctionnalité que si vous n’êtes pas incapable. Une fois que vous l'avez utilisé, vous ne pouvez plus le faire avant le début de votre prochain tour.","name_en":"Keeper of Souls"}],"name_en":"Cleric: Grave Domain","_translated":true},{"index":"cleric-knowledge","name":"Clerc : Domaine de connaissances","class":"cleric","source":"Player's Handbook","subclass_flavor":"Les dieux de la connaissance – dont Oghma, Boccob, Gilean, Aureon et Thot – valorisent avant tout l’apprentissage et la compréhension. Certains enseignent que le savoir doit être rassemblé et partagé dans les bibliothèques et les universités, ou promeuvent la connaissance pratique de l’artisanat et de l’invention. Certaines divinités accumulent des connaissances et gardent leurs secrets pour elles. Et certains promettent à leurs adeptes qu’ils obtiendront un pouvoir énorme s’ils découvrent les secrets du multivers. Les adeptes de ces dieux étudient les traditions ésotériques, collectionnent de vieux tomes, se plongent dans les lieux secrets de la terre et apprennent tout ce qu'ils peuvent. Certains dieux de la connaissance promeuvent la connaissance pratique de l'artisanat et de l'invention, notamment des divinités forgerons comme Gond, Reorx, Onatar, Moradin, Héphaïstos et Goibhniu.","desc":"","features":[{"name":"Bénédictions de la connaissance","level":1,"desc":"Au 1er niveau, vous apprenez deux langues de votre choix. Vous maîtrisez également votre choix dans deux des compétences suivantes : Arcanes, Histoire, Nature ou Religion.\n\nVotre bonus de maîtrise est doublé pour tout test de capacité que vous effectuez et qui utilise l'une de ces compétences.","name_en":"Blessings of Knowledge"},{"name":"Channel Divinity : Connaissance des âges","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour puiser dans un puits divin de connaissances. En tant qu'action, vous choisissez une compétence ou un outil. Pendant 10 minutes, vous maîtrisez la compétence ou l’outil choisi.","name_en":"Channel Divinity: Knowledge of the Ages"},{"name":"Channel Divinity : Lire les pensées","level":6,"desc":"Au niveau 6, vous pouvez utiliser votre canal divinité pour lire les pensées d'une créature. Vous pouvez alors utiliser votre accès à l'esprit de la créature pour la commander.\n\nPar une action, choisissez une créature que vous pouvez voir dans un rayon de 20 mètres autour de vous. Cette créature doit réussir un jet de sauvegarde de Sagesse. Si la créature réussit son jet de sauvegarde, vous ne pourrez plus utiliser cette fonctionnalité sur elle tant que vous n'aurez pas terminé un repos long.\n\nSi la créature échoue à son jet de sauvegarde, vous pouvez lire ses pensées superficielles (celles qui se trouvent au premier plan dans son esprit, reflétant ses émotions actuelles et ce à quoi elle pense activement) lorsqu'elle se trouve à moins de 20 pieds de vous. Cet effet dure 1 minute.\n\nPendant ce temps, vous pouvez utiliser votre action pour mettre fin à cet effet et lancer le sort Suggestion sur la créature sans dépenser d'emplacement de sort. La cible échoue automatiquement à son jet de sauvegarde contre le sort.","name_en":"Channel Divinity: Read Thoughts"},{"name":"Lancement de sorts puissant","level":8,"desc":"À partir du niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Visions du passé","level":17,"desc":"À partir du niveau 17, vous pouvez évoquer des visions du passé liées à un objet que vous tenez ou à votre environnement immédiat. Vous passez au moins 1 minute en méditation et en prière, puis recevez des aperçus oniriques et sombres des événements récents. Vous pouvez méditer de cette manière pendant un nombre de minutes égal à votre score de Sagesse et devez maintenir votre concentration pendant ce temps, comme si vous jetiez un sort.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.\n\nLecture d'objets. En tenant un objet pendant que vous méditez, vous pouvez voir des visions de l’ancien propriétaire de l’objet. Après avoir médité pendant 1 minute, vous apprenez comment le propriétaire a acquis et perdu l'objet, ainsi que l'événement important le plus récent impliquant l'objet et ce propriétaire. Si l'objet appartenait à une autre créature dans un passé récent (dans un nombre de jours égal à votre score de Sagesse), vous pouvez consacrer 1 minute supplémentaire à chaque propriétaire pour apprendre les mêmes informations sur cette créature.\n\nZone de lecture. Pendant que vous méditez, vous avez des visions d'événements récents dans votre voisinage immédiat (une pièce, une rue, un tunnel, une clairière ou autre, jusqu'à un cube de 50 pieds), remontant à un nombre de jours égal à votre score de Sagesse. Pour chaque minute que vous méditez, vous découvrez un événement important, en commençant par le plus récent. Les événements importants impliquent généralement des émotions fortes, telles que des batailles et des trahisons, des mariages et des meurtres, des naissances et des funérailles. Cependant, ils peuvent également inclure des événements plus banals mais néanmoins importants dans votre situation actuelle.","name_en":"Visions of the Past"}],"name_en":"Cleric: Knowledge Domain","_translated":true},{"index":"cleric-life","name":"Clerc : Domaine de la vie","class":"cleric","source":"Player's Handbook","subclass_flavor":"Le domaine Vie se concentre sur l’énergie positive vibrante – l’une des forces fondamentales de l’univers – qui soutient toute vie. Les dieux de la vie promeuvent la vitalité et la santé en guérissant les malades et les blessés, en prenant soin de ceux qui en ont besoin et en chassant les forces de mort et de non-vie. Presque toutes les divinités non maléfiques peuvent revendiquer une influence sur ce domaine, en particulier les divinités agricoles (telles que Chauntea, Arawai et Déméter), les dieux du soleil (tels que Lathandre, Pelor et Re-Horakhty), les dieux de la guérison ou de l'endurance (tels que Ilmater, Mishakal, Apollo et Diancecht) et les dieux de la maison et de la communauté (tels que Hestia, Hathor et Boldrci).","desc":"","features":[{"name":"Compétence bonus","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous gagnez en maîtrise des armures lourdes.","name_en":"Bonus Proficiency"},{"name":"Disciple de Vie","level":1,"desc":"Dès le niveau 1 également, vos sorts de soins sont plus efficaces. À chaque fois que vous utilisez un sort de niveau 1 ou supérieur pour redonner des points de vie à une créature, la créature récupère des points de vie supplémentaires égaux à 2 + le niveau du sort.","name_en":"Disciple of Life"},{"name":"Channel Divinity : Préserver la vie","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour soigner les blessés graves.\n\nPar une action, vous présentez votre symbole sacré et évoquez une énergie de guérison qui peut restaurer un nombre de points de vie égal à cinq fois votre niveau de clerc. Choisissez n'importe quelle créature à moins de 9 mètres de vous et répartissez ces points de vie entre elles. Cette fonctionnalité ne peut restaurer une créature qu'à la moitié de son maximum de points de vie. Vous ne pouvez pas utiliser cette fonctionnalité sur un mort-vivant ou une construction.","name_en":"Channel Divinity: Preserve Life"},{"name":"Guérisseur béni","level":6,"desc":"À partir du niveau 6, les sorts de guérison que vous lancez sur les autres vous soignent également. Lorsque vous lancez un sort de niveau 1 ou supérieur qui redonne des points de vie à une créature autre que vous, vous récupérez des points de vie égaux à 2 + le niveau du sort.","name_en":"Blessed Healer"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts radiants supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Guérison Suprême","level":17,"desc":"À partir du niveau 17, alors que vous lanceriez normalement un ou plusieurs dés pour restaurer des points de vie avec un sort, vous utilisez à la place le nombre le plus élevé possible pour chaque dé. Par exemple, au lieu de redonner 2d6 points de vie à une créature, vous en restaurez 12.","name_en":"Supreme Healing"}],"name_en":"Cleric: Life Domain","_translated":true},{"index":"cleric-light","name":"Clerc : Domaine de Lumière","class":"cleric","source":"Player's Handbook","subclass_flavor":"Les dieux de la lumière, notamment Helm, Lathandre, Pholtus, Branchala, la Flamme d'argent, Belenus, Apollo et Re-Horakhty, promeuvent les idéaux de renaissance et de renouveau, de vérité, de vigilance et de beauté, en utilisant souvent le symbole du soleil. Certains de ces dieux sont représentés comme le soleil lui-même ou comme un conducteur de char qui guide le soleil à travers le ciel. D’autres sont des sentinelles infatigables dont les yeux percent chaque ombre et voient à travers chaque tromperie. Certaines sont des divinités de la beauté et du talent artistique, qui enseignent que l’art est un véhicule pour l’amélioration de l’âme. Les prêtres d'un dieu de la lumière sont des âmes illuminées imprégnées du rayonnement et du pouvoir de la vision perspicace de leurs dieux, chargées de chasser les mensonges et de brûler les ténèbres.","desc":"","features":[{"name":"Cantrip bonus","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous gagnez le cantrip Lumière si vous ne le connaissez pas déjà. Ce sort mineur ne compte pas dans le nombre de sorts mineurs de clerc que vous connaissez.","name_en":"Bonus Cantrip"},{"name":"Fusée de protection","level":1,"desc":"Au niveau 1 également, vous pouvez interposer une lumière divine entre vous et un ennemi attaquant. Lorsque vous êtes attaqué par une créature visible à moins de 9 mètres de vous, vous pouvez utiliser votre réaction pour imposer un désavantage au jet d'attaque, provoquant l'éclat de la lumière devant l'attaquant avant qu'il ne touche ou ne rate. Un attaquant qui ne peut pas être aveuglé est immunisé contre cette fonctionnalité.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Warding Flare"},{"name":"Channel Divinity: Radiance of the Dawn","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour exploiter la lumière du soleil, bannir les ténèbres et infliger des dégâts radiants à vos ennemis.\n\nPar une action, vous présentez votre symbole sacré et toute obscurité magique dans un rayon de 9 mètres autour de vous est dissipée. De plus, chaque créature hostile dans un rayon de 9 mètres autour de vous doit effectuer un jet de sauvegarde de Constitution. Une créature subit des dégâts radiants égaux à 2d10 + votre niveau de clerc en cas d'échec d'un jet de sauvegarde, et la moitié de ces dégâts en cas de réussite. Une créature qui b��néficie d'une couverture totale contre vous n'est pas affectée.","name_en":"Channel Divinity: Radiance of the Dawn"},{"name":"Flare améliorée","level":6,"desc":"À partir du niveau 6, vous pouvez également utiliser votre fonction Warding Flare lorsqu'une créature que vous pouvez voir à moins de 9 mètres de vous attaque une créature autre que vous.","name_en":"Improved Flare"},{"name":"Lancement de sorts puissant","level":8,"desc":"À partir du niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Couronne de Lumière","level":17,"desc":"À partir du niveau 17, vous pouvez utiliser votre action pour activer une aura de soleil qui dure 1 minute ou jusqu'à ce que vous la dissipiez en utilisant une autre action. Vous émettez une lumière vive dans un rayon de 60 pieds et une lumière tamisée 30 pieds au-delà. Vos ennemis dans la lumière vive ont un désavantage aux jets de sauvegarde contre tout sort qui inflige des dégâts de feu ou de rayonnement.","name_en":"Corona of Light"}],"name_en":"Cleric: Light Domain","_translated":true},{"index":"cleric-mind","name":"Clerc : Domaine mental (HB)","class":"cleric","source":"Exploring Eberron","subclass_flavor":"Ce chemin allie dévotion divine et pouvoir psychique. Les forces liées au domaine de l’Esprit enseignent aux adeptes que l’esprit est le meilleur outil et l’arme la plus puissante de la création. Un prêtre du domaine Esprit apprend à exploiter son propre pouvoir mental, puis utilise ce don pour protéger ses fidèles et châtier ses ennemis.","desc":"Ce chemin allie dévotion divine et pouvoir psychique. Les forces liées au domaine de l’Esprit enseignent aux adeptes que l’esprit est le meilleur outil et l’arme la plus puissante de la création. Un prêtre du domaine Esprit apprend à exploiter son propre pouvoir mental, puis utilise ce don pour protéger ses fidèles et châtier ses ennemis.\n\nÀ Eberron, le domaine de l’Esprit est le plus associé à la Voie de la Lumière de Kalashtar et à la Voie de l’Inspiration de Riedran. Cependant, les adeptes des cultes du Dragon d’En-Bas pourraient également suivre cette voie. Si les visions de Xoriat peuvent certainement conduire un prêtre à la folie, elles peuvent également révéler des secrets plus profonds et des pouvoirs mentaux.","features":[{"name":"Flash de perspicacité","level":1,"desc":"À partir du niveau 1, vous pouvez invoquer la puissance d’un puits d’énergie mentale situé en votre sein. Lorsque vous effectuez un test de capacité, vous pouvez choisir de le relancer après avoir vu le résultat, mais avant de savoir s'il réussit ou échoue. Vous obtenez un bonus à cette relance égal à la moitié de votre niveau de clerc (minimum de 1).\n\nVous pouvez utiliser cette fonctionnalité deux fois. Vous récupérez les utilisations dépensées lorsque vous terminez un repos court ou long.","name_en":"Flash of Insight"},{"name":"Force psychique","level":1,"desc":"Au niveau 1 également, vous apprenez à secouer vos ennemis avec votre puissance mentale. Lorsque vous lancez un sort de clerc ou un cantrip qui inflige des dégâts radiants, vous pouvez choisir de lui faire infliger des dégâts psychiques à la place.","name_en":"Psychic Force"},{"name":"Channel Divinity : rétroaction psychique","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour perturber l’esprit d’un ennemi. Lorsqu'une créature à moins de 9 mètres de vous doit effectuer un jet de sauvegarde de Sagesse, vous pouvez utiliser votre réaction pour lui imposer un désavantage en utilisant votre Canal Divinité. Vous devez utiliser cette fonctionnalité avant de connaître le résultat du lancer.\n\nSi le sort ou l'effet qui a provoqué le jet de sauvegarde de Sagesse n'est pas créé par un sort que vous lancez, vous pouvez également choisir d'infliger des dégâts psychiques à la cible, égaux à la moitié de votre niveau de clerc, immédiatement avant que la cible n'effectue son jet de sauvegarde.","name_en":"Channel Divinity: Psychic Feedback"},{"name":"Ancre Gestalt","level":6,"desc":"À partir du niveau 6, votre puissance mentale augmente, apaisant l'esprit de ceux qui vous entourent grâce à votre simple présence. Chaque fois que vous ou une créature amie à moins de 3 mètres de vous devez effectuer un jet de sauvegarde d'Intelligence, de Sagesse ou de Charisme, la créature gagne un bonus de +2 au jet de sauvegarde. Vous devez en être conscient pour accorder ce bonus.","name_en":"Gestalt Anchor"},{"name":"Lancement de sorts puissant","level":8,"desc":"À partir du niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Plier la réalité","level":17,"desc":"À partir du niveau 17, lorsque vous voyez un allié à moins de 9 mètres de vous échouer à un jet de sauvegarde, vous pouvez remplacer le jet par un 20, ce qui peut potentiellement changer le résultat. Une fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un repos court ou long.","name_en":"Bend Reality"}],"name_en":"Cleric: Mind Domain (HB)","_translated":true},{"index":"cleric-nature","name":"Clerc : Domaine de la Nature","class":"cleric","source":"Player's Handbook","subclass_flavor":"Les dieux de la nature sont aussi variés que le monde naturel lui-même ; des dieux impénétrables des forêts profondes (comme Silvanus, Obad-Hai, Chislev, Balinor et Pan) aux divinités amicales associées à des sources et des bosquets particuliers (comme Eldath). Les druides vénèrent la nature dans son ensemble et peuvent servir l'une de ces divinités, pratiquant des rites mystérieux et récitant des prières presque oubliées dans leur propre langue secrète. Mais beaucoup de ces dieux ont également des prêtres, des champions qui jouent un rôle plus actif dans la promotion des intérêts d’un dieu de la nature particulier. Ces prêtres peuvent chasser les monstruosités maléfiques qui ravagent les forêts, bénir les récoltes des fidèles ou flétrir les récoltes de ceux qui irritent leurs dieux.","desc":"","features":[{"name":"Acolyte de la Nature","level":1,"desc":"Au niveau 1, vous apprenez un sort mineur de votre choix dans la liste des sorts du druide. Ce cantrip compte pour vous comme un cantrip de clerc, mais il ne compte pas dans le nombre de cantrips de clerc que vous connaissez. Vous acquérez également la maîtrise de l'une des compétences suivantes de votre choix : manipulation des animaux, nature ou survie.","name_en":"Acolyte of Nature"},{"name":"Compétence bonus","level":1,"desc":"Au niveau 1 également, vous maîtrisez le maniement des armures lourdes.","name_en":"Bonus Proficiency"},{"name":"Channel Divinity : Charmer les animaux et les plantes","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour charmer les animaux et les plantes.\n\nPar une action, vous présentez votre symbole sacré et invoquez le nom de votre divinité. Chaque bête ou créature végétale qui peut vous voir dans un rayon de 9 mètres autour de vous doit effectuer un jet de sauvegarde de Sagesse. Si la créature échoue à son jet de sauvegarde, vous la charmez pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Bien qu'il soit charmé par vous, il est amical envers vous et les autres créatures que vous désignez.","name_en":"Channel Divinity: Charm Animals and Plants"},{"name":"Éléments amortissants","level":6,"desc":"À partir du niveau 6, lorsque vous ou une créature à moins de 9 mètres de vous subissez des dégâts d'acide, de froid, de feu, de foudre ou de tonnerre, vous pouvez utiliser votre réaction pour accorder une résistance à la créature contre cette instance de dégâts.","name_en":"Dampen Elements"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts supplémentaires de froid, de feu ou de foudre (votre choix) à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Maître de la Nature","level":17,"desc":"Au niveau 17, vous acquérez la capacité de commander des animaux et des créatures végétales. Pendant que les créatures sont charmées par votre fonction Charmer les animaux et les plantes, vous pouvez effectuer une action bonus pendant votre tour pour ordonner verbalement ce que chacune de ces créatures fera lors de son prochain tour.","name_en":"Master of Nature"}],"name_en":"Cleric: Nature Domain","_translated":true},{"index":"cleric-order","name":"Clerc : domaine de commande","class":"cleric","source":"Guildmaster's Guide to Ravnica, Tasha's Cauldron of Everything","subclass_flavor":"Le Domaine de l'Ordre représente la discipline, ainsi que le dévouement aux lois qui régissent une société, une institution ou une philosophie. Les prêtres de l'Ordre méditent sur la logique et la justice lorsqu'ils servent leurs dieux, dont des exemples apparaissent dans le tableau des divinités de l'Ordre.","desc":"","features":[{"name":"Compétences bonus","level":1,"desc":"Lorsque vous choisissez ce domaine au niveau 1, vous gagnez en maîtrise des armures lourdes. Vous acquérez également la maîtrise de la compétence Intimidation ou Persuasion (votre choix).","name_en":"Bonus Proficiencies"},{"name":"Voix de l'autorité","level":1,"desc":"À partir du niveau 1, vous pouvez invoquer le pouvoir de la loi pour encourager un allié à attaquer. Si vous lancez un sort avec un emplacement de sort de niveau 1 ou supérieur et ciblez un allié avec le sort, cet allié peut utiliser sa réaction immédiatement après le sort pour lancer une attaque avec une arme contre une créature de votre choix que vous pouvez voir.\n\nSi le sort cible plus d’un allié, vous choisissez celui qui peut lancer l’attaque.","name_en":"Voice of Authority"},{"name":"Channel Divinity : demande de l'ordre","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre canal divinité pour exercer une présence intimidante sur les autres.\n\nEn tant qu'action, vous présentez votre symbole sacré, et chaque créature de votre choix qui peut vous voir ou vous entendre dans un rayon de 9 mètres autour de vous doit réussir un jet de sauvegarde de sagesse ou être charmée par vous jusqu'à la fin de votre prochain tour ou jusqu'à ce que la créature charmée subisse des dégâts. Vous pouvez également faire en sorte que n'importe quelle créature charmée lâche ce qu'elle tient lorsqu'elle échoue au jet de sauvegarde.","name_en":"Channel Divinity: Order's Demand"},{"name":"Incarnation de la loi","level":6,"desc":"Au niveau 6, vous devenez remarquablement habile à canaliser l'énergie magique pour contraindre les autres.\n\nSi vous lancez un sort de l'école d'enchantement en utilisant un emplacement de sort de niveau 1 ou supérieur, vous pouvez modifier le temps d'incantation du sort à 1 action bonus pour ce lancement, à condition que le temps d'incantation du sort soit normalement de 1 action.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Embodiment of the Law"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts psychiques supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"La colère de l'ordre","level":17,"desc":"À partir du niveau 17, les ennemis que vous désignez pour la destruction se fanent sous les efforts combinés de vous et de vos alliés. Si vous infligez des dégâts de votre Frappe divine à une créature pendant votre tour, vous pouvez maudire cette créature jusqu'au début de votre prochain tour. La prochaine fois qu'un de vos alliés frappe la créature maudite avec une attaque, la cible subit également 2d8 dégâts psychiques et la malédiction prend fin. Vous ne pouvez maudire une créature de cette manière qu'une seule fois par tour.","name_en":"Order's Wrath"}],"name_en":"Cleric: Order Domain","_translated":true},{"index":"cleric-peace","name":"Clerc : Domaine de la Paix","class":"cleric","source":"Tasha's Cauldron of Everything","subclass_flavor":"Le baume de la paix prospère au cœur de communautés saines, entre nations amies et dans les âmes de ceux qui ont bon cœur. Les dieux de la paix inspirent les gens de toutes sortes à résoudre les conflits et à s’opposer aux forces qui tentent d’empêcher l’épanouissement de la paix. Voir le tableau des divinités de la paix pour une liste de certains des dieux associés à ce domaine.","desc":"","features":[{"name":"Instrument de paix","level":1,"desc":"Lorsque vous choisissez ce domaine au 1er niveau, vous maîtrisez la compétence Insight, Performance ou Persuasion (votre choix).","name_en":"Implement of Peace"},{"name":"Lien enhardissant","level":1,"desc":"À partir du 1er niveau, vous pouvez forger un lien stimulant entre des personnes en paix les unes avec les autres. Par une action, vous choisissez un nombre de créatures volontaires dans un rayon de 9 mètres autour de vous (cela peut vous inclure) égal à votre bonus de maîtrise. Vous créez un lien magique entre eux pendant 10 minutes ou jusqu'à ce que vous utilisiez à nouveau cette fonctionnalité. Tant qu'une créature liée se trouve à moins de 9 mètres d'une autre, la créature peut lancer un d4 et ajouter le nombre obtenu à un jet d'attaque, un test de capacité ou un jet de sauvegarde qu'elle effectue. Chaque créature ne peut pas ajouter le d4 plus d'une fois par tour.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Emboldening Bond"},{"name":"Channel Divinity : Baume de Paix","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre Channel Divinity pour faire de votre présence un baume apaisant. Par une action, vous pouvez vous déplacer à votre vitesse, sans provoquer d'attaques d'opportunité, et lorsque vous vous déplacez à moins de 1,50 mètre d'une autre créature pendant cette action, vous pouvez redonner à cette créature un nombre de points de vie égal à 2d6 + votre modificateur de Sagesse (minimum de 1 point de vie). Une créature ne peut recevoir ces soins qu'une seule fois à chaque fois que vous effectuez cette action.","name_en":"Channel Divinity: Balm of Peace"},{"name":"Lien de protection","level":6,"desc":"À partir du niveau 6, le lien que vous forgez entre les gens les aide à se protéger mutuellement. Lorsqu'une créature affectée par votre fonction Lien enhardissant est sur le point de subir des dégâts, une deuxième créature liée à moins de 9 mètres de la première peut utiliser sa réaction pour se téléporter dans un espace inoccupé à moins de 1,50 mètre de la première créature. La deuxième créature subit alors tous les dégâts à la place.","name_en":"Protective Bond"},{"name":"Lancement de sorts puissant","level":8,"desc":"Au niveau 8, vous ajoutez votre modificateur de Sagesse aux dégâts que vous infligez avec n'importe quel cantrip de clerc.","name_en":"Potent Spellcasting"},{"name":"Lien expansif","level":17,"desc":"Au niveau 17, les avantages de vos capacités Lien d’enhardissement et Lien protecteur fonctionnent désormais lorsque les créatures sont à moins de 20 pieds l’une de l’autre. De plus, lorsqu'une créature utilise Lien protecteur pour subir les dégâts de quelqu'un d'autre, la créature a une résistance à ces dégâts.","name_en":"Expansive Bond"}],"name_en":"Cleric: Peace Domain","_translated":true},{"index":"cleric-tempest","name":"Clerc : Domaine de la Tempête","class":"cleric","source":"Player's Handbook","subclass_flavor":"Les dieux dont les portefeuilles incluent le domaine Tempest – notamment Talos, Umberlee, Kord, Zeboim, le Dévoreur, Zeus et Thor – gouvernent les tempêtes, la mer et le ciel. Ils comprennent les dieux de la foudre et du tonnerre, les dieux des tremblements de terre, certains dieux du feu et certains dieux de la violence, de la force physique et du courage. Dans certains panthéons, un dieu de ce domaine règne sur d'autres divinités et est connu pour sa justice rapide rendue par la foudre. Dans les panthéons des marins, les dieux de ce domaine sont des divinités océaniques et les patrons des marins. Les dieux de la tempête envoient leurs prêtres pour inspirer la peur aux gens ordinaires, soit pour les maintenir sur le chemin de la justice, soit pour les encourager à offrir des sacrifices de propitiation pour conjurer la colère divine.","desc":"","features":[{"name":"Compétences bonus","level":1,"desc":"Au niveau 1, vous maîtrisez les armes de combat et les armures lourdes.","name_en":"Bonus Proficiencies"},{"name":"Colère de la tempête","level":1,"desc":"Au niveau 1 également, vous pouvez réprimander les attaquants avec un tonnerre. Lorsqu'une créature à moins de 1,50 mètre de vous et que vous pouvez voir vous frappe avec une attaque, vous pouvez utiliser votre réaction pour que la créature effectue un jet de sauvegarde de Dextérité. La créature subit 2d8 dégâts de foudre ou de tonnerre (au choix) en cas d'échec d'un jet de sauvegarde, et la moitié de ces dégâts en cas de réussite.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Wrath of the Storm"},{"name":"Channel Divinity : Colère Destructrice","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre Divinité canalisée pour exercer le pouvoir de la tempête avec une férocité incontrôlée.\n\nLorsque vous lancez des dégâts de foudre ou de tonnerre, vous pouvez utiliser votre canal divinité pour infliger un maximum de dégâts, au lieu de lancer.","name_en":"Channel Divinity: Destructive Wrath"},{"name":"Frappe tonitruante","level":6,"desc":"Au niveau 6, lorsque vous infligez des dégâts de foudre à une créature de taille G ou inférieure, vous pouvez également la pousser jusqu'à 3 mètres de vous.","name_en":"Thunderous Strike"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts de tonnerre supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Né de la tempête","level":17,"desc":"Au niveau 17, vous avez une vitesse de vol égale à votre vitesse de marche actuelle lorsque vous n'êtes pas sous terre ou à l'intérieur.","name_en":"Stormborn"}],"name_en":"Cleric: Tempest Domain","_translated":true},{"index":"cleric-trickery","name":"Clerc : Domaine de la supercherie","class":"cleric","source":"Player's Handbook","subclass_flavor":"Les dieux de la supercherie – tels que Tymora, Beshaba, Olidammara, le Voyageur, Garl Glittergold et Loki – sont des fauteurs de troubles et des instigateurs qui constituent un défi constant à l'ordre accepté parmi les dieux et les mortels. Ils sont les patrons des voleurs, des canailles, des joueurs, des rebelles et des libérateurs. Leurs religieux sont une force perturbatrice dans le monde, brisant l’orgueil, se moquant des tyrans, volant les riches, libérant les captifs et bafouant les traditions creuses. Ils préfèrent les subterfuges, les farces, la tromperie et le vol plutôt que la confrontation directe.","desc":"","features":[{"name":"Bénédiction du filou","level":1,"desc":"À partir du choix de ce domaine au niveau 1, vous pouvez utiliser votre action pour toucher une créature volontaire autre que vous afin de lui donner un avantage aux tests de Dextérité (Discrétion). Cette bénédiction dure 1 heure ou jusqu'à ce que vous utilisiez à nouveau cette fonctionnalité.","name_en":"Blessing of the Trickster"},{"name":"Channel Divinity : Invoquer la duplicité","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre Divinité Canalisée pour créer une copie illusoire de vous-même.\n\nPar une action, vous créez une illusion parfaite de vous-même qui dure 1 minute, ou jusqu'à ce que vous perdiez votre concentration (comme si vous vous concentriez sur un sort). L'illusion apparaît dans un espace inoccupé que vous pouvez voir à moins de 9 mètres de vous. Par une action bonus pendant votre tour, vous pouvez déplacer l'illusion jusqu'à 9 mètres vers un espace que vous pouvez voir, mais elle doit rester à moins de 120 pieds de vous.\n\nPendant toute la durée de l'illusion, vous pouvez lancer des sorts comme si vous étiez dans l'espace de l'illusion, mais vous devez utiliser vos propres sens. De plus, lorsque vous et votre illusion êtes tous les deux à moins de 1,50 mètre d'une créature qui peut voir l'illusion, vous avez un avantage aux jets d'attaque contre cette créature, étant donné à quel point l'illusion est distrayante pour la cible.","name_en":"Channel Divinity: Invoke Duplicity"},{"name":"Channel Divinity : Cape des ombres","level":6,"desc":"À partir du niveau 6, vous pouvez utiliser votre Channel Divinity pour disparaître.\n\nPar une action, vous devenez invisible jusqu'à la fin de votre prochain tour. Vous devenez visible si vous attaquez ou lancez un sort.","name_en":"Channel Divinity: Cloak of Shadows"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous obtenez la capacité d'imprégner vos frappes d'armes de poison, un cadeau de votre divinité. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts de poison supplémentaires à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Duplicité améliorée","level":17,"desc":"Au niveau 17, vous pouvez créer jusqu'à quatre copies de vous-même, au lieu d'une, lorsque vous utilisez Invoquer la duplicité. Par une action bonus pendant votre tour, vous pouvez déplacer n'importe quel nombre d'entre eux jusqu'à 9 mètres, pour une portée maximale de 120 pieds.","name_en":"Improved Duplicity"}],"name_en":"Cleric: Trickery Domain","_translated":true},{"index":"cleric-twilight","name":"Clerc : Domaine du Crépuscule","class":"cleric","source":"Tasha's Cauldron of Everything","subclass_flavor":"Le passage crépusculaire de la lumière à l'obscurité apporte souvent du calme, voire de la joie, alors que les travaux de la journée se terminent et que les heures de repos commencent. L'obscurité peut aussi apporter la terreur, mais les dieux du crépuscule protègent contre les horreurs de la nuit.","desc":"","features":[{"name":"Compétences bonus","level":1,"desc":"Au niveau 1, vous maîtrisez les armes de combat et les armures lourdes.","name_en":"Bonus Proficiencies"},{"name":"Yeux de la nuit","level":1,"desc":"À partir du 1er niveau, vous pouvez voir au-delà des ténèbres les plus profondes. Vous avez une vision dans le noir jusqu'à une portée de 300 pieds. Dans ce rayon, vous pouvez voir dans une lumière faible comme s’il s’agissait d’une lumière vive et dans l’obscurité comme s’il s’agissait d’une lumière faible.\n\nPar une action, vous pouvez partager comme par magie la vision sombre de cette fonctionnalité avec des créatures volontaires que vous pouvez voir dans un rayon de 3 mètres autour de vous, jusqu'à un nombre de créatures égal à votre modificateur de Sagesse (au minimum une créature). La vision dans le noir partagée dure 1 heure. Une fois que vous l'avez partagé, vous ne pouvez plus le faire avant d'avoir terminé un long repos, à moins que vous ne dépensiez un emplacement de sort de n'importe quel niveau pour le partager à nouveau.","name_en":"Eyes of Night"},{"name":"Bénédiction vigilante","level":1,"desc":"Au niveau 1, la nuit vous a appris à être vigilant. Par une action, vous donnez à une créature que vous touchez (y compris éventuellement vous-même) un avantage lors du prochain jet d'initiative effectué par la créature. Cet avantage prend fin immédiatement après le lancer ou si vous utilisez à nouveau cette fonctionnalité.","name_en":"Vigilant Blessing"},{"name":"Channel Divinity : Sanctuaire du Crépuscule","level":2,"desc":"Au niveau 2, vous pouvez utiliser votre canal divinité pour rafraîchir vos alliés avec un crépuscule apaisant.\n\nPar une action, vous présentez votre symbole sacré et une sphère de crépuscule émane de vous. La sphère est centrée sur vous, a un rayon de 9 mètres et est remplie d’une faible lumière. La sphère se déplace avec vous et dure 1 minute ou jusqu'à ce que vous soyez frappé d'incapacité ou mouriez. À chaque fois qu'une créature (vous y compris) termine son tour dans la sphère, vous pouvez accorder à cette créature l'un de ces avantages :\n• Vous lui accordez des points de vie temporaires égaux à 1d6 plus votre niveau de clerc.\n• Vous mettez fin à un effet sur lui, le charmant ou l'effrayant.","name_en":"Channel Divinity: Twilight Sanctuary"},{"name":"Étapes de la nuit","level":6,"desc":"À partir du niveau 6, vous pouvez faire appel au pouvoir mystique de la nuit pour vous élever dans les airs. Par une action bonus, lorsque vous êtes dans une faible lumière ou dans l'obscurité, vous pouvez par magie vous donner une vitesse de vol égale à votre vitesse de marche pendant 1 minute. Vous pouvez utiliser cette action bonus un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Steps of Night"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts radiants supplémentaires. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Linceul du Crépuscule","level":17,"desc":"Au niveau 17, le Crépuscule que vous invoquez offre une étreinte protectrice : vous et vos alliés êtes à moitié couverts lorsque vous êtes dans la sphère créée par votre Sanctuaire du Crépuscule.","name_en":"Twilight Shroud"}],"name_en":"Cleric: Twilight Domain","_translated":true},{"index":"cleric-war","name":"Clerc : Domaine de guerre","class":"cleric","source":"Player's Handbook","subclass_flavor":"La guerre a de nombreuses manifestations. Cela peut faire des gens ordinaires des héros. Cela peut être désespéré et horrible, avec des actes de cruauté et de lâcheté éclipsant les exemples d’excellence et de courage. Dans les deux cas, les dieux de la guerre veillent sur les guerriers et les récompensent pour leurs hauts faits. Les prêtres de ces dieux excellent au combat, inspirant les autres à mener le bon combat ou offrant des actes de violence sous forme de prières. Les dieux de la guerre comprennent des champions d'honneur et de chevalerie (tels que Torm, Heironeous et Kiri-Jolith), ainsi que des dieux de la destruction et du pillage (tels qu'Erythnul, la Furie, Gruumsh et Ares) et des dieux de la conquête et de la domination (tels que Bane, Hextor et Maglubiyet). D'autres dieux de la guerre (tels que Tempus, Ni","desc":"","features":[{"name":"Compétence bonus","level":1,"desc":"Au niveau 1, vous maîtrisez les armes de combat et les armures lourdes.","name_en":"Bonus Proficiency"},{"name":"Prêtre de guerre","level":1,"desc":"Dès le niveau 1, votre dieu vous délivre des éclairs d'inspiration pendant que vous êtes engagé dans un combat. Lorsque vous utilisez l’action Attaque, vous pouvez effectuer une attaque avec une arme comme action bonus.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"War Priest"},{"name":"Channel Divinity : Frappe guidée","level":2,"desc":"À partir du niveau 2, vous pouvez utiliser votre Channel Divinity pour frapper avec une précision surnaturelle. Lorsque vous effectuez un jet d'attaque, vous pouvez utiliser votre Canal Divinité pour gagner un bonus de +10 au jet. Vous faites ce choix après avoir vu le jet, mais avant que le DM ne vous dise si l'attaque réussit ou rate.","name_en":"Channel Divinity: Guided Strike"},{"name":"Channel Divinity : La bénédiction de Dieu de la guerre","level":6,"desc":"Au niveau 6, lorsqu'une créature à moins de 9 mètres de vous effectue un jet d'attaque, vous pouvez utiliser votre réaction pour accorder à cette créature un bonus de +10 au jet, en utilisant votre Canalisation Divinité. Vous faites ce choix après avoir vu le jet, mais avant que le DM ne vous dise si l'attaque réussit ou rate.","name_en":"Channel Divinity: War God's Blessing"},{"name":"Frappe divine","level":8,"desc":"Au niveau 8, vous gagnez la capacité d’imprégner vos frappes d’énergie divine. Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque avec une arme, vous pouvez faire en sorte que l'attaque inflige 1d8 dégâts supplémentaires du même type infligé par l'arme à la cible. Lorsque vous atteignez le niveau 14, les dégâts supplémentaires passent à 2d8.","name_en":"Divine Strike"},{"name":"Avatar de bataille","level":17,"desc":"Au niveau 17, vous gagnez la résistance aux dégâts contondants, perçants et tranchants des attaques non magiques.","name_en":"Avatar of Battle"}],"name_en":"Cleric: War Domain","_translated":true},{"index":"druid-dreams","name":"Druide : Cercle des rêves","class":"druid","source":"Xanathar's Guide to Everything","subclass_flavor":"Les druides membres du Cercle des Rêves sont originaires de régions ayant des liens étroits avec le Feywild et ses royaumes oniriques. La tutelle des druides sur le monde naturel crée une alliance naturelle entre eux et les fées d’alignement bon. Ces druides cherchent à remplir le monde d’émerveillements oniriques. Leur magie guérit les blessures et apporte de la joie aux cœurs abattus, et les royaumes qu’ils protègent sont des lieux brillants et féconds, où le rêve et la réalité se confondent et où les fatigués peuvent trouver le repos.","desc":"","features":[{"name":"Baume de la Cour d'Été","level":2,"desc":"Au niveau 2, vous êtes imprégné des bénédictions de la Cour d'Été. Vous êtes une source d’énergie qui offre un répit après les blessures. Vous disposez d'une réserve d'énergie féerique représentée par un nombre de d6 égal à votre niveau de druide.\n\nPar une action bonus, vous pouvez choisir un allié que vous pouvez voir à moins de 120 pieds de vous et dépenser un nombre de ces dés égal à la moitié de votre niveau de druide ou moins. Lancez les dés dépensés et additionnez-les. La cible récupère un nombre de points de vie égal au total. La cible gagne également 1 point de vie temporaire par dé dépensé.\n\nVous récupérez les dés dépensés lorsque vous terminez un repos long.","name_en":"Balm of the Summer Court"},{"name":"Foyer du clair de lune et de l'ombre","level":6,"desc":"Au niveau 6, la maison peut être où que vous soyez. Pendant un repos court ou long, vous pouvez invoquer le pouvoir obscur de la Cour Gloaming pour vous aider à garder votre répit. Au début du reste, vous touchez un point dans l'espace et une sphère magique invisible d'un rayon de 9 mètres apparaît, centrée sur ce point. La couverture totale bloque la sphère.\n\nÀ l'intérieur de la sphère, vous et vos alliés bénéficiez d'un bonus de +5 aux tests de Dextérité (Discrétion) et de Sagesse (Perception), et toute lumière provenant de flammes nues dans la sphère (un feu de camp, des torches ou autre) n'est pas visible à l'extérieur.\n\nLa sphère disparaît à la fin du reste ou lorsque vous quittez la sphère.","name_en":"Hearth of Moonlight and Shadow"},{"name":"Chemins cachés","level":10,"desc":"À partir du niveau 10, vous pouvez utiliser les chemins cachés et magiques qu'utilisent certaines fées pour traverser l'espace en un clin d'œil. Par une action bonus pendant votre tour, vous pouvez vous téléporter jusqu'à 60 pieds vers un espace inoccupé que vous pouvez voir. Alternativement, vous pouvez utiliser votre action pour téléporter une créature volontaire que vous touchez jusqu'à 9 mètres vers un espace inoccupé que vous pouvez voir.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Hidden Paths"},{"name":"Marcheur dans les rêves","level":14,"desc":"Au niveau 14, la magie du Feywild vous confère la capacité de voyager mentalement ou physiquement à travers les pays des rêves.\n\nLorsque vous terminez un court repos, vous pouvez lancer l'un des sorts suivants, sans dépenser d'emplacement de sort ni nécessiter de composants matériels : Rêve (avec vous comme messager), Clairvoyance ou Cercle de téléportation.\n\nCette utilisation du Cercle de Téléportation est particulière. Plutôt que d'ouvrir un portail vers un cercle de téléportation permanent, il ouvre un portail vers le dernier endroit où vous avez terminé un long repos sur votre plan d'existence actuel. Si vous ne vous êtes pas reposé longtemps sur votre plan actuel, le sort échoue mais n'est pas inutile.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Walker in Dreams"}],"name_en":"Druid: Circle of Dreams","_translated":true},{"index":"druid-spores","name":"Druide : Cercle de spores","class":"druid","source":"Guildmaster's Guide to Ravnica, Tasha's Cauldron of Everything","subclass_flavor":"Les druides du Cercle des Spores trouvent la beauté dans la décadence. Ils voient dans la moisissure et d’autres champignons la capacité de transformer des matériaux sans vie en une vie abondante, quoique quelque peu étrange. Ces druides croient que la vie et la mort font partie d'un grand cycle, l'une menant à l'autre puis inversement. La mort n’est pas la fin de la vie, mais plutôt un changement d’état qui voit la vie prendre une nouvelle forme.","desc":"","features":[{"name":"Sorts de cercle","level":2,"desc":"Votre lien symbiotique avec les champignons et votre capacité à puiser dans le cycle de la vie et de la mort vous donnent accès à certains sorts. Au niveau 2, vous apprenez le cantrip Chill Touch.\n\nAux niveaux 3, 5, 7 et 9, vous avez accès aux sorts répertoriés pour ce niveau dans le tableau des sorts du Cercle des Spores. Une fois que vous avez accès à l'un de ces sorts, vous l'avez toujours préparé, et cela ne compte pas dans le nombre de sorts que vous pouvez préparer chaque jour. Si vous accédez à un sort qui n'apparaît pas dans la liste des sorts de druide, le sort n'en est pas moins un sort de druide pour vous.\nSorts du Cercle des Spores\nNiveau Druide | Sorts de cercle\n2ème | Toucher froid\n3ème | Cécité/Surdité, Repos en douceur\n5ème | Animer une forme gazeuse morte\n7ème | Fléau, Confusion\n9ème | Tuerie des nuages, Contagion","name_en":"Circle Spells"},{"name":"Halo de spores","level":2,"desc":"À partir du niveau 2, vous êtes entouré de spores nécrotiques invisibles qui sont inoffensives jusqu'à ce que vous les lâchiez sur une créature à proximité. Lorsqu'une créature que vous pouvez voir se déplace dans un espace à moins de 3 mètres de vous ou y commence son tour, vous pouvez utiliser votre réaction pour infliger 1d4 dégâts nécrotiques à cette créature, à moins qu'elle ne réussisse un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort. Les dégâts nécrotiques augmentent à 1d6 au niveau 6, 1d8 au niveau 10 et 1d10 au niveau 14.","name_en":"Halo of Spores"},{"name":"Entité Symbiotique","level":2,"desc":"Au niveau 2 également, vous gagnez la capacité de canaliser la magie dans vos spores. Par une action, vous pouvez dépenser une utilisation de votre fonction Forme Sauvage pour réveiller ces spores, plutôt que de vous transformer en forme de bête, et vous gagnez 4 points de vie temporaires pour chaque niveau que vous avez dans cette classe. Tant que cette fonctionnalité est active, vous bénéficiez des avantages suivants :\n• Lorsque vous infligez des dégâts de Halo de Spores, lancez le dé de dégâts une seconde fois et ajoutez-le au total.\n• Vos attaques avec des armes de mêlée infligent 1d6 dégâts nécrotiques supplémentaires à toute cible touchée.\n\nCes avantages durent 10 minutes, jusqu'à ce que vous perdiez tous ces points de vie temporaires. ou jusqu'à ce que vous utilisiez à nouveau votre Wild Shape.","name_en":"Symbiotic Entity"},{"name":"Infestation fongique","level":6,"desc":"Au niveau 6, vos spores acquièrent la capacité d'infester un cadavre et de l'animer. Si une bête ou un humanoïde de taille Petite ou Moyenne meurt à moins de 3 mètres de vous, vous pouvez utiliser votre réaction pour l'animer, le faisant se relever immédiatement avec 1 point de vie. La créature utilise le bloc de statistiques Zombie dans le Monster Manual. Il reste animé pendant 1 heure, après quoi il s'effondre et meurt.\n\nEn combat, le tour du zombie vient immédiatement après le vôtre. Il obéit à vos ordres mentaux et la seule action qu'il peut entreprendre est l'action d'Attaque, en effectuant une attaque au corps à corps.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Fungal Infestation"},{"name":"Spores qui se propagent","level":10,"desc":"Au niveau 10, vous gagnez la capacité d'ensemencer une zone de spores mortelles. Par une action bonus lorsque votre fonction Entité Symbiotique est active, vous pouvez lancer des spores jusqu'à 9 mètres de distance, où elles tourbillonnent dans un cube de 3 mètres pendant 1 minute. Les spores disparaissent prématurément si vous utilisez à nouveau cette fonctionnalité, si vous les rejetez comme une action bonus ou si votre fonctionnalité Entité Symbiotique n'est plus active.\n\nChaque fois qu'une créature entre dans le cube ou y commence son tour, cette créature subit les dégâts de votre Halo de spores, à moins qu'elle ne réussisse un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort. Une créature ne peut pas subir ces dégâts plus d'une fois par tour.\n\nTant que le cube de spores persiste, vous ne pouvez pas utiliser votre réaction Halo de spores.","name_en":"Spreading Spores"},{"name":"Corps fongique","level":14,"desc":"Au niveau 14, les spores fongiques présentes dans votre corps vous altèrent : vous ne pouvez pas être aveuglé, assourdi, effrayé ou empoisonné, et tout coup critique contre vous compte comme un coup normal, à moins que vous ne soyez incapable d'agir.","name_en":"Fungal Body"}],"name_en":"Druid: Circle of Spores","_translated":true},{"index":"druid-stars","name":"Druide : Cercle d'étoiles","class":"druid","source":"Tasha's Cauldron of Everything","subclass_flavor":"Le Cercle des Étoiles permet aux druides de tirer parti du pouvoir de la lumière des étoiles. Ces druides traquent les schémas célestes depuis des temps immémoriaux, découvrant des secrets cachés au milieu des constellations. En révélant et en comprenant ces secrets, le Cercle des Étoiles cherche à exploiter les puissances du cosmos.","desc":"","features":[{"name":"Carte des étoiles","level":2,"desc":"Au niveau 2, vous avez créé une carte des étoiles dans le cadre de vos études célestes. C'est un objet minuscule et peut servir de foyer de lancement de sorts pour vos sorts de druide. Vous déterminez sa forme en lançant sur la table Star Map ou en en choisissant une.\n\nEn détenant cette carte, vous bénéficiez des avantages suivants :\n• Vous connaissez le sort mineur Guidage.\n• Vous avez préparé le sort Trait de Guidage. Cela compte comme un sort de druide pour vous, et cela ne compte pas dans le nombre de sorts que vous pouvez préparer.\n• Vous pouvez lancer Trait de guidage sans dépenser d'emplacement de sort. Vous pouvez le faire un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.\n\nSi vous perdez la carte, vous pouvez effectuer une cérémonie d'une heure pour créer comme par magie une carte de remplacement. Cette cérémonie peut être effectuée lors d'un repos court ou long, et elle détruit la carte précédente.\nd6 | Formulaire de carte\n1 | Un parchemin couvert de représentations de constellations\n2 | Une tablette de pierre percée de fins trous\n3 | Une peau d'ours-hibou mouchetée, ornée de marques en relief\n4 | Une collection de cartes reliées sous une couverture en ébène\n5 | Un cristal qui projette des motifs étoilés lorsqu'il est placé devant une lumière\n6 | Disques de verre représentant des constellations","name_en":"Star Map"},{"name":"Forme étoilée","level":2,"desc":"Au niveau 2, vous obtenez la capacité d'exploiter le pouvoir des constellations pour modifier votre forme. En tant qu'action bonus, vous pouvez dépenser une utilisation de votre fonction Forme sauvage pour prendre une forme étoilée, plutôt que de vous transformer en bête.\n\nSous votre forme étoilée, vous conservez vos statistiques de jeu, mais votre corps devient lumineux ; vos articulations brillent comme des étoiles et des lignes lumineuses les relient comme sur une carte des étoiles. Cette forme projette une lumière vive dans un rayon de 10 pieds et une lumière tamisée sur 10 pieds supplémentaires. Le formulaire dure 10 minutes. Il se termine plus tôt si vous le rejetez (aucune action requise), si vous êtes frappé d'incapacité, si vous mourez ou si vous utilisez à nouveau cette fonctionnalité.\n\nChaque fois que vous prenez votre forme étoilée, choisissez laquelle des constellations suivantes scintille sur votre corps ; votre choix vous offre certains avantages sous la forme :\n\nArcher. Une constellation d'archer apparaît sur vous. Lorsque vous activez cette forme, et comme une action bonus lors de vos tours suivants pendant qu'elle dure, vous pouvez effectuer une attaque magique à distance, lançant une flèche lumineuse qui cible une créature à moins de 60 pieds de vous. En cas de coup, l'attaque inflige des dégâts radiants égaux à 1d8 + votre modificateur de Sagesse.\n\nCalice. Une constellation de coupe vivifiante apparaît sur vous. Chaque fois que vous lancez un sort en utilisant un emplacement de sort qui redonne des points de vie à une créature, vous ou une autre créature à moins de 9 mètres de vous pouvez récupérer des points de vie égaux à 1d8 + votre modificateur de Sagesse.\n\nDragon. Une constellation d'un dragon sage apparaît sur vous. Lorsque vous effectuez un test d'Intelligence ou de Sagesse ou un jet de sauvegarde de Constitution pour rester concentré sur un sort, vous pouvez traiter un résultat de 9 ou moins sur le d20 comme un 10.","name_en":"Starry Form"},{"name":"Présage cosmique","level":null,"desc":"Lorsque vous atteignez le niveau 6, vous apprenez à utiliser votre carte des étoiles pour deviner la volonté du cosmos. Chaque fois que vous terminez un long repos, vous pouvez consulter votre carte des étoiles pour rechercher des présages. Lorsque vous le faites, lancez un dé. Jusqu'à la fin de votre prochain repos long, vous avez accès à une réaction spéciale selon que vous avez obtenu un nombre pair ou impair sur le dé :\n\nRichesse (même). Chaque fois qu'une créature que vous pouvez voir à moins de 9 mètres de vous est sur le point d'effectuer un jet d'attaque, un jet de sauvegarde ou un test de capacité, vous pouvez utiliser votre réaction pour lancer un d6 et ajouter le nombre obtenu au total.\n\nMalheur (étrange). Chaque fois qu'une créature que vous pouvez voir à moins de 9 mètres de vous est sur le point d'effectuer un jet d'attaque, un jet de sauvegarde ou un test de capacité, vous pouvez utiliser votre réaction pour lancer un d6 et soustraire le nombre obtenu du total.\n\nVous pouvez utiliser cette réaction un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Cosmic Omen"},{"name":"Constellations scintillantes","level":10,"desc":"Au niveau 10, les constellations de votre Forme Étoilée s'améliorent. Les 1d8 de l'Archer et du Calice deviennent 2d8, et tant que le Dragon est actif, vous avez une vitesse de vol de 20 pieds et pouvez planer.\n\nDe plus, au début de chacun de vos tours, sous votre forme étoilée, vous pouvez changer la constellation qui brille sur votre corps.","name_en":"Twinkling Constellations"},{"name":"Plein d'étoiles","level":14,"desc":"Au niveau 14, lorsque vous êtes sous votre forme étoilée, vous devenez partiellement incorporel, vous conférant une résistance aux dégâts contondants, perçants et tranchants.","name_en":"Full of Stars"}],"name_en":"Druid: Circle of Stars","_translated":true},{"index":"druid-forged-hb","name":"Druide : Cercle des Forgés (HB)","class":"druid","source":"Exploring Eberron","subclass_flavor":"Qu’est-ce qui est vraiment naturel ? Les forgeliers sont des créatures vivantes, bien qu'ils soient construits en bois et en acier. Les druides qui adoptent le Cercle des Forgés explorent le potentiel de la forme des forgerons, mêlant formes animales et durabilité. Il s’agit d’une voie jeune, lancée par une poignée de forgeliers qui cherchaient à mieux comprendre leur rôle dans le monde. Au cours des dernières décennies, un certain nombre de forgeliers ont adopté le Cercle des Forgés ; cependant, cela ne se limite pas aux forgeliers ; un héritier Cannith ou un aspirant artisan pourrait rechercher le pouvoir primordial comme moyen de transcender la chair limitée avec laquelle il est né.","desc":"Qu’est-ce qui est vraiment naturel ? Les forgeliers sont des créatures vivantes, bien qu'ils soient construits en bois et en acier. Les druides qui adoptent le Cercle des Forgés explorent le potentiel de la forme des forgerons, mêlant formes animales et durabilité. Il s’agit d’une voie jeune, lancée par une poignée de forgeliers qui cherchaient à mieux comprendre leur rôle dans le monde. Au cours des dernières décennies, un certain nombre de forgeliers ont adopté le Cercle des Forgés ; cependant, cela ne se limite pas aux forgeliers ; un héritier Cannith ou un aspirant artisan pourrait rechercher le pouvoir primordial comme moyen de transcender la chair limitée avec laquelle il est né.\n\nSeule une poignée de druides suivent ce Cercle. Avez-vous appris ces techniques auprès d'un mentor ? Êtes-vous motivé par l'instinct et êtes-vous encore en train d'apprendre de quoi vous êtes capable ? Ou, si vous êtes un forgeron de guerre, avez-vous été conçu avec le potentiel de prendre plusieurs formes… et si oui, qui vous a créé et pourquoi ?","features":[{"name":"Formes de cercle","level":2,"desc":"Les rites de votre cercle vous confèrent la capacité de vous transformer en formes animales plus dangereuses. À partir du niveau 2, vous pouvez utiliser votre Forme Sauvage pour vous transformer en une bête avec un indice de défi aussi élevé que 1 (vous ignorez la colonne CR Max. du tableau Formes de Bête, mais devez respecter les autres limitations qui s'y trouvent).\n\nÀ partir du niveau 6, vous pouvez vous transformer en bête avec un niveau de défi aussi élevé que votre niveau de druide divisé par 3, arrondi à l'inférieur.","name_en":"Circle Forms"},{"name":"Peau d'acier","level":2,"desc":"À partir du niveau 2, pendant que vous êtes transformé par Wild Shape, vous bénéficiez des avantages suivants :\n• Vous gagnez un bonus de +2 à la Classe d'Armure.\n• Vous avez un avantage aux jets de sauvegarde contre l'empoisonnement et vous avez une résistance aux dégâts de poison.\n• Vous n'avez pas besoin de manger, de boire ou de respirer.\n• Vous êtes immunisé contre la maladie.\n• Vous n'avez pas besoin de dormir et la magie ne peut pas vous endormir.\n\nSous forme de bête, votre corps est fabriqué à partir des mêmes matériaux que ceux d'un forgeron ; vos muscles sont des vrilles semblables à des racines protégées par des plaques blindées. Il est évident pour un observateur que vous n'êtes pas un animal normal.","name_en":"Skin of Steel"},{"name":"Fureur élémentaire","level":6,"desc":"À partir du niveau 6, vous acquérez la capacité d'imprégner vos attaques de dégâts élémentaires, en chargeant vos griffes d'électricité ou en libérant des flammes de vos crocs. Lorsque vous utilisez Wild Shape, choisissez l’un des types de dégâts suivants : acide, froid, feu ou foudre. Sous votre forme de bête, la première fois que vous frappez une créature avec une attaque de mêlée à votre tour, vous pouvez dépenser un emplacement de sort pour infliger des dégâts supplémentaires de ce type à la cible, en plus des dégâts normaux de l'attaque. Les dégâts supplémentaires sont de 1d6 par niveau d'emplacement de sort dépensé, jusqu'à un maximum de 5d6.\n\nLorsque vous utilisez cette capacité sur une créature, votre attaque a un effet supplémentaire, déterminé par le type de dégâts que vous avez sélectionné lorsque vous avez utilisé Wild Shape. Si une créature est à nouveau affectée par cette capacité lors des tours suivants, les effets ne se cumulent pas et la nouvelle durée remplace l'ancienne.\n\nAcide. La cible doit effectuer un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort de druide. En cas d'échec, sa CA est réduite pendant une minute d'un montant égal à la moitié de votre modificateur de Sagesse (minimum de 1). Au début de chacun de ses tours pour la minute suivante, la cible peut effectuer un nouveau jet de sauvegarde de Constitution. En cas de sauvegarde réussie, l'effet prend fin.\n\nFroid. Au début de chacun de ses tours pendant 1 minute, la cible doit effectuer un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort de druide. En cas d'échec, leur vitesse de déplacement est réduite à 0 et ils sont désavantagés aux tests de Force et de Dextérité. En cas de sauvegarde réussie, l'effet prend fin.\n\nFeu. Au début de chacun de ses tours pendant 1 minute, la cible doit effectuer un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort de druide. En cas d'échec, il subit des dégâts de feu égaux à votre modificateur de Sagesse. En cas de sauvegarde réussie, le feu s'éteint. Si la cible ou une créature à moins de 1,50 mètre d'elle utilise une action pour éteindre les flammes, ou si un autre effet éteint les flammes (comme par exemple si la cible est immergée dans l'eau), l'effet prend fin.\n\nFoudre. Au début de chacun de ses tours pendant 1 minute, la cible doit effectuer un jet de sauvegarde de Constitution contre votre DD de sauvegarde de sort de druide. En cas d'échec, il perd sa réaction jusqu'au début de son prochain tour et la première attaque qu'il effectue à son tour est effectuée en désavantage. En cas de sauvegarde réussie, l'effet prend fin.","name_en":"Elemental Fury"},{"name":"Peau adamantine","level":10,"desc":"À partir du niveau 10, pendant que vous êtes transformé par Wild Shape, vous gagnez une résistance aux dégâts contondants, perçants et tranchants des attaques non magiques. De plus, vous obtenez la possibilité d'utiliser Wild Shape en réaction lorsque vous subissez des dégâts, et les dégâts de cette attaque sont appliqués aux points de vie de votre forme de bête.","name_en":"Adamantine Hide"},{"name":"La perfection construite","level":14,"desc":"À partir du niveau 14, pendant que vous êtes transformé par Wild Shape, vous ne pouvez pas être charmé, effrayé, paralysé, pétrifié ou empoisonné. De plus, vous êtes immunisé contre les dégâts de poison.","name_en":"Constructed Perfection"}],"name_en":"Druid: Circle Of The Forged (HB)","_translated":true},{"index":"druid-land","name":"Druide : Cercle de la Terre","class":"druid","source":"Player's Handbook","subclass_flavor":"Le Cercle de la Terre est composé de mystiques et de sages qui sauvegardent les savoirs et les rites anciens à travers une vaste tradition orale. Ces druides se réunissent dans des cercles sacrés d'arbres ou de pierres dressées pour murmurer des secrets primordiaux en druidique. Les membres les plus sages du cercle président en tant que prêtres en chef des communautés attachées à l'ancienne foi et servent de conseillers aux dirigeants de ces gens. En tant que membre de ce cercle, votre magie est influencée par le pays où vous avez été initié aux rites mystérieux du cercle.","desc":"","features":[{"name":"Cantrip bonus","level":2,"desc":"Lorsque vous choisissez ce cercle au niveau 2, vous apprenez un cantrip de druide supplémentaire de votre choix. Ce petit sort ne compte pas dans le nombre de petits sorts de druide que vous connaissez.","name_en":"Bonus Cantrip"},{"name":"Récupération naturelle","level":2,"desc":"À partir du 2ème niveau, vous pouvez retrouver une partie de votre énergie magique en vous asseyant en méditation et en communiquant avec la nature. Pendant un court repos, vous choisissez des emplacements de sorts dépensés à récupérer. Les emplacements de sorts peuvent avoir un niveau combiné égal ou inférieur à la moitié de votre niveau de druide (arrondi au supérieur), et aucun des emplacements ne peut être de niveau 6 ou supérieur. Vous ne pouvez plus utiliser cette fonctionnalité tant que vous n'avez pas terminé un repos long.\n\nPar exemple, lorsque vous êtes un druide de niveau 4, vous pouvez récupérer jusqu'à deux niveaux d'emplacements de sorts. Vous pouvez récupérer soit un emplacement de 2ème niveau, soit deux emplacements de 1er niveau.","name_en":"Natural Recovery"},{"name":"Sorts de cercle","level":null,"desc":"Votre lien mystique avec la terre vous confère la capacité de lancer certains sorts. Aux niveaux 3, 5, 7 et 9, vous avez accès aux sorts de cercle liés au terrain où vous êtes devenu druide. Choisissez cette terre (Arctique, côte, désert, forêt, prairie, montagne, marais ou Underdark) et consultez la liste de sorts associée.\n\nUne fois que vous avez accès à un sort de cercle, vous l'avez toujours préparé, et il ne compte pas dans le nombre de sorts que vous pouvez préparer chaque jour. Si vous accédez à un sort qui n'apparaît pas dans la liste des sorts de druide, le sort n'en est pas moins un sort de druide pour vous.\nArctique\nNiveau Druide | Sorts de cercle\n3ème | Tenez la personne, augmentez la croissance\n5ème | Tempête de neige fondue, lente\n7ème | Liberté de mouvement, tempête de verglas\n9ème | Communier avec la nature, Cône de froid\nCôte\nNiveau Druide | Sorts de cercle\n3ème | Image miroir, étape brumeuse\n5ème | Respiration aquatique, marche sur l'eau\n7ème | Contrôle de l'eau, liberté de mouvement\n9ème | Invocation d'élémentaire, divination\nDésert\nNiveau Druide | Sorts de cercle\n3ème | Flou, Silence\n5ème | Créer de la nourriture et de l'eau, une protection contre l'énergie\n7ème | Fléau, terrain hallucinatoire\n9ème | Peste d'insectes, mur de pierre\nForêt\nNiveau Druide | Sorts de cercle\n3ème | Écorce, escalade d'araignée\n5ème | Appelez la foudre, la croissance des plantes\n7ème | Divination, Liberté de Mouvement\n9ème | Communiquer avec la nature, Tree Stride\nPrairie\nNiveau Druide | Sorts de cercle\n3ème | Invisibilité, passage sans trace\n5ème | Lumière du jour, hâte\n7ème | Divination, Liberté de Mouvement\n9ème | Rêve, peste d'insectes\nMontagne\nNiveau Druide | Sorts de cercle\n3ème | Escalade d'araignée, croissance en pointe\n5ème | Éclair, fondu dans la pierre\n7ème | Forme de pierre, peau de pierre\n9ème | Passwall, mur de pierre\nMarais\nNiveau Druide | Sorts de cercle\n3ème | Ténèbres, flèche acide de Melf\n5ème | Promenade aquatique, nuage puant\n7ème | Liberté de mouvement, localisation de la créature\n9ème | Peste d'insectes, divination\nTénèbres\nNiveau Druide | Sorts de cercle\n3ème | Escalade d'araignée, toile\n5ème | Forme gazeuse, nuage puant\n7ème | Plus grande invisibilité, forme de pierre\n9ème | Cloudkill, peste d'insectes","name_en":"Circle Spells"},{"name":"La foulée de la terre","level":6,"desc":"À partir du niveau 6, se déplacer sur un terrain difficile non magique ne vous coûte aucun mouvement supplémentaire. Vous pouvez également traverser des plantes non magiques sans être ralenti par elles et sans subir de dégâts si elles ont des épines, des épines ou un danger similaire.\n\nDe plus, vous avez un avantage aux jets de sauvegarde contre les plantes créées ou manipulées par magie pour entraver le mouvement, comme celles créées par le sort Entangle.","name_en":"Land's Stride"},{"name":"Le quartier de la nature","level":null,"desc":"Lorsque vous atteignez le niveau 10, vous ne pouvez plus être charmé ou effrayé par les élémentaires ou les fées, et vous êtes immunisé contre le poison et la maladie.","name_en":"Nature's Ward"},{"name":"Sanctuaire de la nature","level":null,"desc":"Lorsque vous atteignez le niveau 14, les créatures du monde naturel sentent votre lien avec la nature et hésitent à vous attaquer. Lorsqu'une créature animale ou végétale vous attaque, cette créature doit effectuer un jet de sauvegarde de Sagesse contre le DD de sauvegarde de votre sort de druide. En cas d'échec, la créature doit choisir une cible différente, sinon l'attaque rate automatiquement. En cas de sauvegarde réussie, la créature est immunisée contre cet effet pendant 24 heures.\n\nLa créature est consciente de cet effet avant de lancer son attaque contre vous.","name_en":"Nature's Sanctuary"}],"name_en":"Druid: Circle of the Land","_translated":true},{"index":"druid-moon","name":"Druide : Cercle de la Lune","class":"druid","source":"Player's Handbook","subclass_flavor":"Les druides du Cercle de la Lune sont de féroces gardiens de la nature. Leur ordre se rassemble sous la pleine lune pour partager des nouvelles et des avertissements commerciaux. Ils hantent les parties les plus profondes de la nature sauvage, où ils peuvent passer des semaines entières avant de croiser la route d'une autre créature humanoïde, sans parler d'un autre druide.","desc":"","features":[{"name":"Combattre la forme sauvage","level":2,"desc":"Lorsque vous choisissez ce cercle au niveau 2, vous gagnez la possibilité d'utiliser Forme Sauvage à votre tour comme une action bonus, plutôt que comme une action.\n\nDe plus, pendant que vous êtes transformé par Wild Shape, vous pouvez utiliser une action bonus pour dépenser un emplacement de sort afin de regagner 1d8 points de vie par niveau d'emplacement de sort dépensé.","name_en":"Combat Wild Shape"},{"name":"Formes de cercle","level":2,"desc":"Les rites de votre cercle vous confèrent la capacité de vous transformer en formes animales plus dangereuses. À partir du niveau 2, vous pouvez utiliser votre Forme Sauvage pour vous transformer en bête avec un indice de défi allant jusqu'à 1. Vous ignorez le Max. Colonne CR du tableau Formes de bêtes, mais doit respecter les autres limitations qui s'y trouvent.\n\nÀ partir du niveau 6, vous pouvez vous transformer en bête avec un niveau de défi aussi élevé que votre niveau de druide divisé par 3, arrondi à l'inférieur.","name_en":"Circle Forms"},{"name":"Frappe primordiale","level":6,"desc":"À partir du niveau 6, vos attaques sous forme de bête sont considérées comme magiques dans le but de vaincre la résistance et l'immunité aux attaques et dégâts non magiques.","name_en":"Primal Strike"},{"name":"Forme sauvage élémentaire","level":10,"desc":"Au niveau 10, vous pouvez dépenser deux utilisations de Forme sauvage en même temps pour vous transformer en élémentaire d'air, en élémentaire de terre, en élémentaire de feu ou en élémentaire d'eau.","name_en":"Elemental Wild Shape"},{"name":"Mille formes","level":14,"desc":"Au niveau 14, vous avez appris à utiliser la magie pour modifier votre forme physique de manière plus subtile. Vous pouvez lancer le sort Alter Self à volonté.","name_en":"Thousand Forms"}],"name_en":"Druid: Circle of the Moon","_translated":true},{"index":"druid-shepherd","name":"Druide : Cercle du Berger","class":"druid","source":"Xanathar's Guide to Everything","subclass_flavor":"Les druides du Cercle du Berger communient avec les esprits de la nature, en particulier les esprits des bêtes et des fées, et appellent ces esprits à l'aide. Ces druides reconnaissent que tous les êtres vivants jouent un rôle dans le monde naturel, mais ils se concentrent sur la protection des animaux et des créatures féeriques qui ont du mal à se défendre. Les bergers, comme on les appelle, considèrent ces créatures comme leurs protégés. Ils repoussent les monstres qui les menacent, réprimandent les chasseurs qui tuent plus de proies que nécessaire et empêchent la civilisation d'empiéter sur les habitats d'animaux rares et sur les sites sacrés pour les fées.","desc":"","features":[{"name":"Discours des bois","level":2,"desc":"Au niveau 2, vous gagnez la capacité de converser avec des bêtes et de nombreuses fées.\n\nVous apprenez à parler, lire et écrire Sylvan. De plus, les bêtes peuvent comprendre votre discours et vous acquérez la capacité de déchiffrer leurs bruits et leurs mouvements. La plupart des bêtes n'ont pas l'intelligence nécessaire pour transmettre ou comprendre des concepts sophistiqués, mais une bête amicale pourrait transmettre ce qu'elle a vu ou entendu dans un passé récent. Cette capacité ne vous accorde aucune amitié particulière avec les bêtes, bien que vous puissiez combiner cette capacité avec des cadeaux pour gagner leurs faveurs comme vous le feriez avec n'importe quel personnage non-joueur.","name_en":"Speech of the Woods"},{"name":"Totem spirituel","level":2,"desc":"À partir du niveau 2, vous acquérez la capacité d'invoquer les esprits de la nature et de les utiliser pour influencer le monde qui vous entoure.\n\nPar une action bonus, vous pouvez invoquer par magie un esprit incorporel jusqu'à un point que vous pouvez voir à moins de 20 mètres de vous. L'esprit crée une aura dans un rayon de 9 mètres autour de ce point. Il ne compte ni comme une créature ni comme un objet, bien qu'il ait l'apparence spectrale de la créature qu'il représente. Par une action bonus, vous pouvez déplacer l'esprit jusqu'à 60 pieds jusqu'à un point que vous pouvez voir.\n\nL'esprit persiste pendant 1 minute. Une fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un repos court ou long.\n\nL’effet de l’aura de l’esprit dépend du type d’esprit que vous invoquez parmi les options ci-dessous.\n\nEsprit de l'ours. L'esprit de l'ours vous accorde, à vous et à vos alliés, sa puissance et son endurance. Chaque créature de votre choix dans l'aura lorsque l'esprit apparaît gagne des points de vie temporaires égaux à 5 + votre niveau de druide. De plus, vous et vos alliés bénéficiez d'un avantage aux tests de Force et aux jets de sauvegarde de Force lorsque vous êtes dans l'aura.\n\nEsprit de faucon. L'esprit du faucon est un chasseur accompli, vous aidant ainsi que vos alliés grâce à sa vue perçante. Lorsqu'une créature effectue un jet d'attaque contre une cible dans l'aura de l'esprit, vous pouvez utiliser votre réaction pour accorder un avantage à ce jet d'attaque. De plus, vous et vos alliés avez un avantage aux tests de Sagesse (Perception) lorsque vous êtes dans l'aura.\n\nEsprit Licorne. L'esprit licorne prête sa protection à ceux qui se trouvent à proximité. Vous et vos alliés bénéficiez d’un avantage à tous les tests de capacité effectués pour détecter les créatures dans l’aura de l’esprit. De plus, si vous lancez un sort en utilisant un emplacement de sort qui redonne des points de vie à n'importe quelle créature à l'intérieur ou à l'extérieur de l'aura, chaque créature de votre choix dans l'aura récupère également des points de vie égaux à votre niveau de druide.","name_en":"Spirit Totem"},{"name":"Puissant invocateur","level":6,"desc":"Au niveau 6, les bêtes et les fées que vous invoquez sont plus résistantes que la normale. Toute bête ou fée invoquée ou créée par un sort que vous lancez bénéficie de deux avantages :\n• La créature apparaît avec plus de points de vie que d'habitude : 2 points de vie supplémentaires par dé de vie qu'elle possède.\n• Les dégâts causés par ses armes naturelles sont considérés comme magiques dans le but de vaincre l'immunité et la résistance aux attaques et dégâts non magiques.","name_en":"Mighty Summoner"},{"name":"Esprit gardien","level":10,"desc":"À partir du niveau 10, votre totem spirituel protège les bêtes et les fées que vous invoquez avec votre magie. Lorsqu'une bête ou une fée que vous avez invoquée ou créée avec un sort termine son tour dans votre aura de Totem spirituel, cette créature récupère un nombre de points de vie égal à la moitié de votre niveau de druide.","name_en":"Guardian Spirit"},{"name":"Invocation fidèle","level":14,"desc":"À partir du niveau 14, les esprits de la nature avec lesquels vous communiez vous protègent lorsque vous êtes le plus sans défense. Si vous êtes réduit à 0 point de vie ou êtes frappé d'incapacité contre votre volonté, vous pouvez immédiatement bénéficier des avantages de Conjuration d'animaux comme s'il était lancé avec un emplacement de sort de niveau 9. Il invoque quatre bêtes de votre choix dont le niveau de défi est de 2 ou moins. Les bêtes invoquées apparaissent à moins de 20 pieds de vous. S'ils ne reçoivent aucun ordre de votre part, ils vous protègent du mal et attaquent vos ennemis. Le sort dure 1 heure, ne nécessitant aucune concentration, ou jusqu'à ce que vous le rejetiez (aucune action requise).\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Faithful Summons"}],"name_en":"Druid: Circle of the Shepherd","_translated":true},{"index":"druid-wildfire","name":"Druide : Cercle de feux de forêt","class":"druid","source":"Tasha's Cauldron of Everything","subclass_flavor":"Les druides du Cercle des Feux de forêt comprennent que la destruction est parfois le précurseur de la création, comme lorsqu'un incendie de forêt favorise une croissance ultérieure. Ces druides se lient à un esprit primordial qui recèle un pouvoir à la fois destructeur et créatif, leur permettant de créer des flammes contrôlées qui brûlent une chose mais donnent vie à une autre.","desc":"","features":[{"name":"Sorts de cercle","level":2,"desc":"Lorsque vous rejoignez ce cercle au niveau 2, vous avez formé un lien avec un esprit de feu de forêt, un être primordial de création et de destruction. Votre lien avec cet esprit vous donne accès à certains sorts lorsque vous atteignez certains niveaux dans cette classe, comme indiqué sur le tableau des sorts du Cercle des Feu de forêt.\n\nUne fois que vous avez accès à l'un de ces sorts, vous l'avez toujours préparé, et cela ne compte pas dans le nombre de sorts que vous pouvez préparer chaque jour. Si vous accédez à un sort qui n'apparaît pas dans la liste des sorts de druide, le sort est néanmoins un sort de druide pour vous.\nNiveau Druide | Sorts\n2ème | Brûler les mains, guérir les blessures\n3ème | Sphère enflammée, rayon brûlant\n5ème | Croissance des plantes, revivifier\n7ème | Aura de vie, bouclier de feu\n9ème | Frappe de flammes, guérison de masse des blessures","name_en":"Circle Spells"},{"name":"Invoquer un esprit de feu sauvage","level":2,"desc":"Au niveau 2, vous pouvez invoquer l'esprit primordial lié à votre âme. Par une action, vous pouvez dépenser une utilisation de votre fonction Forme sauvage pour invoquer votre esprit de feu de forêt, plutôt que de prendre une forme de bête.\n\nL'esprit apparaît dans un espace inoccupé de votre choix que vous pouvez voir à moins de 9 mètres de vous. Chaque créature à moins de 3 mètres de l'esprit (autre que vous) lorsqu'il apparaît doit réussir un jet de sauvegarde de Dextérité contre votre DD de sauvegarde de sort ou subir 2d6 dégâts de feu.\n\nL’esprit est amical envers vous et vos compagnons et obéit à vos ordres. Consultez les statistiques de jeu de cette créature dans le bloc de statistiques Wildfire Spirit, qui utilise votre bonus de maîtrise (PB) à plusieurs endroits. Vous déterminez l'apparence de l'esprit. Certains esprits prennent la forme d'une figure humanoïde faite de branches noueuses couvertes de flammes, tandis que d'autres ressemblent à des bêtes entourées de feu.\n\nAu combat, l'esprit partage votre nombre d'initiatives, mais il prend son tour immédiatement après le vôtre. La seule action qu'il effectue à son tour est l'action Esquiver, à moins que vous n'effectuiez une action bonus à votre tour pour lui ordonner d'effectuer une autre action. Cette action peut être une action dans son bloc de statistiques ou une autre action. Si vous êtes frappé d'incapacité, l'esprit peut entreprendre n'importe quelle action de son choix, pas seulement Esquiver.\n\nL'esprit se manifeste pendant 1 heure, jusqu'à ce qu'il soit réduit à 0 point de vie, jusqu'à ce que vous utilisiez cette fonctionnalité pour invoquer à nouveau l'esprit, ou jusqu'à votre mort.\nEsprit de feu de forêt\nPetit élémentaire\nClasse d'armure : 13 (armure naturelle)\nPoints de vie : 5 + cinq fois votre niveau de druide\nVitesse : 30 pieds, vol 30 pieds (vol stationnaire)\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n10 (+0) | 14 (+2) | 14 (+2) | 13 (+1) | 15 (+2) | 11 (+0)\nImmunités aux dégâts : feu\nImmunités aux conditions : charmé, effrayé, aux prises, à terre, retenu\nSens : vision dans le noir à 18 pieds, perception passive 12\nLangues : comprend les langues que vous parlez\nDéfi : –\nBonus de compétence : équivaut à votre bonus\nActions\nGraine de flamme. Attaque avec arme à distance : votre modificateur d'attaque de sort pour toucher, portée de 60 pieds, une cible que vous pouvez voir. Touché : 1d6 + PB dégâts de feu.\nTéléportation enflammée. L'esprit et chaque créature volontaire de votre choix à moins de 1,50 mètre de lui se téléportent jusqu'à 15 pieds vers des espaces inoccupés que vous pouvez voir. Ensuite, chaque créature à moins de 1,50 mètre de l'espace laissé par l'esprit doit réussir un jet de sauvegarde de Dextérité contre votre DD de sauvegarde de sort ou subir 1d6 + PB de dégâts de feu.","name_en":"Summon Wildfire Spirit"},{"name":"Lien amélioré","level":6,"desc":"Au niveau 6, le lien avec votre esprit de feu de forêt améliore vos sorts destructeurs et réparateurs. Chaque fois que vous lancez un sort qui inflige des dégâts de feu ou restaure des points de vie pendant que votre esprit de feu de forêt est invoqué, lancez un d8 et vous gagnez un bonus égal au nombre obtenu pour un jet de dégâts ou de guérison du sort.\n\nDe plus, lorsque vous lancez un sort avec une portée autre que vous-même, le sort peut provenir de vous ou de votre esprit de feu de forêt.","name_en":"Enhanced Bond"},{"name":"Flammes cautérisantes","level":10,"desc":"Au niveau 10, vous acquérez la capacité de transformer la mort en flammes magiques capables de guérir ou d'incinérer. Lorsqu'une créature de petite taille ou plus grande meurt à moins de 9 mètres de vous ou de votre esprit de feu de forêt, une flamme spectrale inoffensive jaillit dans l'espace de la créature morte et y scintille pendant 1 minute. Lorsqu'une créature que vous pouvez voir entre dans cet espace, vous pouvez utiliser votre réaction pour éteindre la flamme spectrale et soit soigner la créature, soit lui infliger des dégâts de feu. Les soins ou dégâts sont égaux à 2d10 + votre modificateur de Sagesse.\n\nVous pouvez utiliser cette réaction un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Cauterizing Flames"},{"name":"Un renouveau flamboyant","level":14,"desc":"Au niveau 14, le lien avec votre esprit de feu de forêt peut vous sauver de la mort. Si l'esprit se trouve à moins de 120 pieds de vous lorsque vous êtes réduit à 0 point de vie et que vous tombez ainsi inconscient, vous pouvez faire tomber l'esprit à 0 point de vie. Vous récupérez alors la moitié de vos points de vie et vous relevez immédiatement.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Blazing Revival"}],"name_en":"Druid: Circle of Wildfire","_translated":true},{"index":"fighter-arcane-archer","name":"Combattant : Archer arcanique","class":"fighter","source":"Xanathar's Guide to Everything","subclass_flavor":"Un archer arcanique étudie une méthode elfique unique de tir à l'arc qui intègre la magie dans des attaques pour produire des effets surnaturels. Les archers arcaniques font partie des guerriers les plus élites parmi les elfes. Ils surveillent les limites des domaines elfiques, surveillant de près les intrus et utilisant des flèches magiques pour vaincre les monstres et les envahisseurs avant qu'ils ne puissent atteindre les colonies elfiques. Au fil des siècles, les méthodes de ces archers elfes ont été apprises par des membres d'autres races qui peuvent également équilibrer leurs aptitudes arcaniques avec le tir à l'arc.","desc":"","features":[{"name":"Connaissance des archers arcaniques","level":3,"desc":"Au niveau 3, vous apprenez la théorie magique ou certains secrets de la nature – typiques des pratiquants de cette tradition martiale elfique. Vous choisissez de maîtriser soit la compétence Arcanes, soit la compétence Nature, et vous choisissez d'apprendre le cantrip Prestidigitation ou Druidcraft.","name_en":"Arcane Archer Lore"},{"name":"Tir arcanique","level":3,"desc":"Au niveau 3, vous apprenez à déclencher des effets magiques spéciaux avec certains de vos tirs. Lorsque vous obtenez cette fonctionnalité, vous apprenez deux options de tir arcanique de votre choix (voir « Options de tir arcanique » ci-dessous).\n\nUne fois par tour, lorsque vous tirez une flèche avec un arc court ou un arc long dans le cadre de l'action d'attaque, vous pouvez appliquer l'une de vos options Tir arcanique à cette flèche. Vous décidez d’utiliser l’option lorsque la flèche touche, à moins que l’option n’implique pas de jet d’attaque. Vous disposez de deux utilisations de cette capacité, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos court ou long.\n\nVous obtenez une option Arcane Shot supplémentaire de votre choix lorsque vous atteignez certains niveaux de cette classe : 7e, 10e, 15e et 18e niveau. Chaque option s'améliore également lorsque vous devenez un combattant de niveau 18.","name_en":"Arcane Shot"},{"name":"Flèche magique","level":7,"desc":"Au niveau 7, vous gagnez la capacité d’imprégner de magie les flèches. Chaque fois que vous tirez une flèche non magique avec un arc court ou un arc long, vous pouvez la rendre magique dans le but de vaincre la résistance et l'immunité aux attaques et dégâts non magiques. La magie disparaît de la flèche immédiatement après qu'elle ait atteint ou raté sa cible.","name_en":"Magic Arrow"},{"name":"Tir courbe","level":7,"desc":"Au niveau 7, vous apprenez à diriger une flèche errante vers une nouvelle cible. Lorsque vous effectuez un jet d'attaque avec une flèche magique et que vous le ratez, vous pouvez utiliser une action bonus pour relancer le jet d'attaque contre une cible différente à moins de 60 pieds de la cible d'origine.","name_en":"Curving Shot"},{"name":"Prise de vue toujours prête","level":15,"desc":"À partir du niveau 15, votre tir à l'arc magique est disponible dès que la bataille commence. Si vous lancez un jet d'initiative et qu'il ne vous reste plus aucune utilisation de Tir arcanique, vous en récupérez une utilisation.","name_en":"Ever-Ready Shot"},{"name":"Options de tir arcanique","level":null,"desc":"La fonction Arcane Shot vous permet de choisir des options à certains niveaux. Les options sont présentées ici par ordre alphabétique. Ce sont tous des effets magiques, et chacun est associé à l’une des écoles de magie.\n\nSi une option nécessite un jet de sauvegarde, votre DD de sauvegarde Arcane Shot est égal à 8 + votre bonus de maîtrise + votre modificateur d'Intelligence.\n\nFlèche de bannissement. Vous utilisez la magie d'abjuration pour tenter de bannir temporairement votre cible dans un endroit inoffensif du Feywild. La créature touchée par la flèche doit également réussir un jet de sauvegarde de Charisme ou être bannie. Lorsqu'il est banni de cette manière, sa vitesse est de 0 et il est frappé d'incapacité. A la fin de son prochain tour, la cible réapparaît dans l'espace qu'elle a quitté ou dans l'espace inoccupé le plus proche si cet espace est occupé.\n\nAprès avoir atteint le niveau 18 dans cette classe, une cible subit également 2d6 dégâts de force lorsque la flèche la touche.\n\nFlèche séduisante. Votre magie d'enchantement fait que cette flèche séduit temporairement sa cible. La créature touchée par la flèche subit 2d6 dégâts psychiques supplémentaires et choisissez l'un de vos alliés à moins de 9 mètres de la cible. La cible doit réussir un jet de sauvegarde de Sagesse, sinon elle est charmée par l'allié choisi jusqu'au début de votre prochain tour. Cet effet se termine prématurément si l'allié choisi attaque la cible charmée, lui inflige des dégâts ou l'oblige à effectuer un jet de sauvegarde.\n\nLes dégâts psychiques augmentent à 4d6 lorsque vous atteignez le niveau 18 dans cette classe.\n\nFlèche éclatante. Vous imprégnez votre flèche d’énergie de force tirée de l’école de l’évocation. La flèche explose après votre attaque. Immédiatement après que la flèche a touché la créature, la cible et toutes les autres créatures à moins de 3 mètres autour d'elle subissent chacune 2d6 dégâts de force.\n\nLes dégâts de force passent à 4d6 lorsque vous atteignez le niveau 18 dans cette classe.\n\nFlèche affaiblissante. Vous insérez de la magie nécromantique dans votre flèche. La créature touchée par la flèche subit 2d6 dégâts nécrotiques supplémentaires. La cible doit également réussir un jet de sauvegarde de Constitution, sinon les dégâts infligés par ses attaques avec une arme sont réduits de moitié jusqu'au début de votre prochain tour.\n\nLes dégâts nécrotiques augmentent à 4d6 lorsque vous atteignez le niveau 18 dans cette classe.\n\nFlèche saisissante. Lorsque cette flèche atteint sa cible, la magie de conjuration crée des ronces venimeuses et agrippantes qui s'enroulent autour de la cible. La créature touchée par la flèche subit 2d6 dégâts de poison supplémentaires, sa vitesse est réduite de 3 mètres et elle subit 2d6 dégâts tranchants la première fois à chaque tour où elle se déplace d'un pied ou plus sans se téléporter. La cible ou toute créature pouvant l'atteindre peut utiliser son action pour éliminer les ronces en réussissant un test de Force (Athlétisme) contre votre DD de sauvegarde Arcane Shot. Sinon, les ronces durent 1 minute ou jusqu'à ce que vous utilisiez à nouveau cette option.\n\nLes dégâts de poison et les dégâts tranchants augmentent tous deux à 4d6 lorsque vous atteignez le niveau 18 dans cette classe.\n\nFlèche perçante. Vous utilisez la magie de transmutation pour donner à votre flèche une qualité éthérée. Lorsque vous utilisez cette option, vous n’effectuez pas de jet d’attaque pour l’attaque. Au lieu de cela, la flèche tire vers l'avant sur une ligne de 1 pied de large et 30 pieds de long, avant de disparaître. La flèche traverse sans danger les objets, ignorant la couverture. Chaque créature de cette ligne doit effectuer un jet de sauvegarde de Dextérité. En cas d'échec, la créature subit des dégâts comme si elle avait été touchée par la flèche, plus 1d6 dégâts perforants supplémentaires. En cas de sauvegarde réussie, la cible subit deux fois moins de dégâts.\n\nLes dégâts perçants augmentent à 2d6 lorsque vous atteignez le niveau 18 dans cette classe.\n\nFlèche à la recherche. En utilisant la magie divinatoire, vous accordez à votre flèche la capacité de rechercher votre cible, lui permettant ainsi de se courber et de tordre sa trajectoire à la recherche de sa proie. Lorsque vous utilisez cette option, vous n’effectuez pas de jet d’attaque pour l’attaque. Choisissez plutôt une créature que vous avez vue au cours de la dernière minute. La flèche vole vers cette créature, se déplaçant dans les coins si nécessaire et ignorant les trois quarts et la moitié de la couverture. Si la cible est à portée de l’arme et qu’il existe un chemin suffisamment large pour que la flèche puisse atteindre la cible, la cible doit effectuer un jet de sauvegarde de Dextérité. En cas d'échec, il subit des dégâts comme s'il était touché par la flèche, plus 1d6 dégâts de force supplémentaires, et vous apprenez l'emplacement actuel de la cible. En cas de sauvegarde réussie, la cible subit deux fois moins de dégâts et vous ne connaissez pas son emplacement.\n\nLes dégâts de force augmentent à 2d6 lorsque vous atteignez le niveau 18 dans cette classe.\nFlèche d'ombre. Vous insérez de la magie d’illusion dans votre flèche, l’amenant à obstruer la vision de votre ennemi avec des ombres. La créature touchée par la flèche subit 2d6 dégâts psychiques supplémentaires, et elle doit réussir un jet de sauvegarde de Sagesse ou être incapable de voir quoi que ce soit à plus de 1,50 mètre jusqu'au début de votre prochain tour.\n\nLes dégâts psychiques augmentent à 4d6 lorsque vous atteignez le niveau 18 dans cette classe.","name_en":"Arcane Shot Options"}],"name_en":"Fighter: Arcane Archer","_translated":true},{"index":"fighter-banneret","name":"Combattant : Banneret","class":"fighter","source":"Sword Coast Adventurer's Guide","subclass_flavor":"Un Banneret est un chevalier qui inspire la grandeur aux autres en commettant des actes courageux au combat. La simple présence d'un individu dans un hameau suffit à inciter certains orques et bandits à rechercher des proies plus faciles. Un Banneret solitaire est un guerrier habile, mais un Banneret menant une bande d'alliés peut transformer même la milice la plus mal équipée en une bande de guerre féroce.","desc":"","features":[{"name":"Cri de ralliement","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous apprenez à inciter vos alliés à se battre au-delà de leurs blessures.\n\nLorsque vous utilisez votre fonction Second souffle, vous pouvez choisir jusqu'à trois créatures alliées à vous dans un rayon de 60 pieds autour de vous. Chacun récupère des points de vie égaux à votre niveau de combattant, à condition que la créature puisse vous voir ou vous entendre.","name_en":"Rallying Cry"},{"name":"Envoyé Royal","level":7,"desc":"Les chevaliers de haut rang sont censés se conduire avec grâce.\n\nAu niveau 7, vous maîtrisez la compétence Persuasion. Si vous le maîtrisez déjà, vous maîtrisez l'une des compétences suivantes de votre choix : manipulation des animaux, perspicacité, intimidation ou performance.\n\nVotre bonus de maîtrise est doublé pour tout test de capacité que vous effectuez qui utilise la persuasion. Vous bénéficiez de cet avantage quelle que soit la maîtrise des compétences acquises grâce à cette fonctionnalité.","name_en":"Royal Envoy"},{"name":"Une poussée inspirante","level":10,"desc":"À partir du niveau 10, lorsque vous utilisez votre fonction Action Surge, vous pouvez choisir une créature à moins de 60 pieds de vous qui est alliée avec vous. Cette créature peut effectuer une attaque au corps à corps ou à distance avec sa réaction, à condition qu'elle puisse vous voir ou vous entendre.\n\nÀ partir du niveau 18, vous pouvez choisir deux alliés à moins de 20 mètres de vous, au lieu d'un.","name_en":"Inspiring Surge"},{"name":"Rempart","level":15,"desc":"À partir du niveau 15, vous pouvez étendre les avantages de votre fonctionnalité Indomptable à un allié. Lorsque vous décidez d'utiliser Indomptable pour relancer un jet de sauvegarde d'Intelligence, de Sagesse ou de Charisme et que vous n'êtes pas incapable d'agir, vous pouvez choisir un allié à moins de 60 pieds de vous qui a également échoué à son jet de sauvegarde contre le même effet. Si cette créature peut vous voir ou vous entendre, elle peut relancer son jet de sauvegarde et doit utiliser le nouveau jet.","name_en":"Bulwark"}],"name_en":"Fighter: Banneret","_translated":true},{"index":"fighter-battle-master","name":"Combattant : Maître de bataille","class":"fighter","source":"Player's Handbook","subclass_flavor":"Ceux qui imitent l’archétype du Battle Master emploient des techniques martiales transmises de génération en génération. Pour un Battle Master, le combat est un domaine académique, incluant parfois des sujets allant au-delà du combat, comme la fabrication d'armes et la calligraphie. Tous les combattants n’absorbent pas les leçons d’histoire, de théorie et d’art qui se reflètent dans l’archétype Battle Master, mais ceux qui le font sont des combattants complets dotés de grandes compétences et connaissances.","desc":"","features":[{"name":"Supériorité au combat","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous apprenez des manœuvres qui sont alimentées par des dés spéciaux appelés dés de supériorité.\n\nManœuvres. Vous apprenez trois manœuvres de votre choix. De nombreuses manœuvres améliorent une attaque d’une manière ou d’une autre. Vous ne pouvez utiliser qu'une seule manœuvre par attaque. Vous apprenez deux manœuvres supplémentaires de votre choix aux niveaux 7, 10 et 15. Chaque fois que vous apprenez de nouvelles manœuvres, vous pouvez également remplacer une manœuvre que vous connaissez par une autre.\n\nDés de supériorité. Vous disposez de quatre dés de supériorité, qui sont des d8. Un dé de supériorité est dépensé lorsque vous l’utilisez. Vous récupérez tous vos dés de supériorité dépensés lorsque vous terminez un repos court ou long. Vous gagnez un autre dé de supériorité au niveau 7 et un autre au niveau 15.\n\nJets de sauvegarde. Certaines de vos manœuvres nécessitent que votre cible effectue un jet de sauvegarde pour résister aux effets de la manœuvre. Le DC du jet de sauvegarde est calculé comme suit :\n\nDD de sauvegarde de manœuvre = 8 + votre bonus de maîtrise + votre modificateur de Force ou de Dextérité (au choix)","name_en":"Combat Superiority"},{"name":"Étudiant en guerre","level":3,"desc":"Au niveau 3, vous maîtrisez un type d'outils d'artisan de votre choix.","name_en":"Student of War"},{"name":"Connaissez votre ennemi","level":7,"desc":"À partir du niveau 7, si vous passez au moins 1 minute à observer ou à interagir avec une autre créature en dehors du combat, vous pouvez apprendre certaines informations sur ses capacités par rapport aux vôtres. Le DM vous indique si la créature est votre égale, supérieure ou inférieure en ce qui concerne deux des caractéristiques suivantes de votre choix :\n• Indice de force\n• Score de dextérité\n• Note constitutionnelle\n• Classe d'armure\n• Points de vie actuels\n• Niveaux totaux de classe, le cas échéant\n• Niveaux de classe de combattant, le cas échéant","name_en":"Know Your Enemy"},{"name":"Supériorité de combat améliorée","level":10,"desc":"Au niveau 10, vos dés de supériorité se transforment en d10. Au niveau 18, ils se transforment en d12.","name_en":"Improved Combat Superiority"},{"name":"Sans relâche","level":15,"desc":"À partir du niveau 15, lorsque vous lancez un jet d’initiative et qu’il ne vous reste plus de dé de supériorité, vous récupérez 1 dé de supériorité.","name_en":"Relentless"}],"name_en":"Fighter: Battle Master","_translated":true},{"index":"fighter-cavalier","name":"Combattant : Cavalier","class":"fighter","source":"Xanathar's Guide to Everything","subclass_flavor":"L'archétype du cavalier excelle au combat monté. Habituellement né dans la noblesse et élevé à la cour, un cavalier est aussi à l'aise pour diriger une charge de cavalerie que pour échanger des réparties lors d'un dîner d'État. Les cavaliers apprennent également à protéger ceux dont ils ont la charge du danger, servant souvent de protecteurs à leurs supérieurs et aux faibles. Contraints de réparer les torts ou d’acquérir du prestige, nombre de ces combattants abandonnent leur vie de confort pour se lancer dans de glorieuses aventures.","desc":"","features":[{"name":"Compétence bonus","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous maîtrisez l'une des compétences suivantes de votre choix : manipulation des animaux, histoire, perspicacité, performance ou persuasion. Alternativement, vous apprenez une langue de votre choix.","name_en":"Bonus Proficiency"},{"name":"Né en selle","level":3,"desc":"Dès le niveau 3, votre maîtrise du cavalier devient apparente. Vous avez un avantage sur les jets de sauvegarde effectués pour éviter de tomber de votre monture. Si vous tombez de votre monture et ne descendez pas de plus de 10 pieds, vous pouvez atterrir sur vos pieds si vous n'êtes pas incapable.\n\nEnfin, monter ou descendre d'une créature ne vous coûte que 1,50 mètre de mouvement, au lieu de la moitié de votre vitesse.","name_en":"Born to the Saddle"},{"name":"Marque inébranlable","level":3,"desc":"À partir du niveau 3, vous pouvez menacer vos ennemis, déjouer leurs attaques et les punir pour avoir blessé autrui. Lorsque vous touchez une créature avec une attaque au corps à corps avec une arme, vous pouvez marquer la créature jusqu'à la fin de votre prochain tour. Cet effet se termine plus tôt si vous êtes frappé d'incapacité ou si vous mourez, ou si quelqu'un d'autre marque la créature.\n\nTant qu'elle se trouve à moins de 1,50 mètre de vous, une créature marquée par vous a un désavantage à tout jet d'attaque qui ne vous cible pas.\n\nDe plus, si une créature marquée par vous inflige des blessures à quelqu'un d'autre que vous, vous pouvez effectuer une attaque spéciale avec une arme de mêlée contre la créature marquée en tant qu'action bonus lors de votre prochain tour. Vous avez un avantage au jet d'attaque, et si elle touche, l'arme de l'attaque inflige des dégâts supplémentaires à la cible égaux à la moitié de votre niveau de combattant.\n\nQuel que soit le nombre de créatures que vous marquez, vous pouvez effectuer cette attaque spéciale un nombre de fois égal à votre modificateur de Force (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Unwavering Mark"},{"name":"Manœuvre de protection","level":7,"desc":"Au niveau 7, vous apprenez à repousser les attaques dirigées contre vous, votre monture ou d'autres créatures à proximité. If you or a creature you can see within 5 feet of you is hit by an attack, you can roll 1d8 as a reaction if you're wielding a melee weapon or a shield. Lancez le dé et ajoutez le nombre obtenu à la CA de la cible contre cette attaque. Si l'attaque réussit toujours, la cible possède une résistance aux dégâts de l'attaque.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Constitution (au minimum une fois), et vous en récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Warding Maneuver"},{"name":"Tenez la ligne","level":10,"desc":"Au niveau 10, vous devenez maître dans l’art de verrouiller vos ennemis. Les créatures provoquent une attaque d'opportunité de votre part lorsqu'elles se déplacent de 1,50 mètre ou plus à votre portée, et si vous touchez une créature avec une attaque d'opportunité, la vitesse de la cible est réduite à 0 jusqu'à la fin du tour en cours.","name_en":"Hold the Line"},{"name":"Destrier féroce","level":15,"desc":"À partir du niveau 15, vous pouvez écraser vos ennemis, que vous soyez monté ou non. Si vous vous déplacez d'au moins 3 mètres en ligne droite juste avant d'attaquer une créature et que vous la touchez avec l'attaque, cette cible doit réussir un jet de sauvegarde de Force (DD 8 + votre bonus de maîtrise + votre modificateur de Force) ou être mise à terre. Vous ne pouvez utiliser cette fonctionnalité qu’une seule fois à chacun de vos tours.","name_en":"Ferocious Charger"},{"name":"Défenseur vigilant","level":18,"desc":"À partir du niveau 18, vous réagissez au danger avec une vigilance extraordinaire. Au combat, vous obtenez une réaction spéciale que vous pouvez effectuer une fois à chaque tour de créature, sauf votre tour. Vous ne pouvez utiliser cette réaction spéciale que pour effectuer une attaque d'opportunité, et vous ne pouvez pas l'utiliser le même tour que celui où vous effectuez votre réaction normale.","name_en":"Vigilant Defender"}],"name_en":"Fighter: Cavalier","_translated":true},{"index":"fighter-champion","name":"Combattant : Champion","class":"fighter","source":"Player's Handbook","subclass_flavor":"Le Champion archétypal se concentre sur le développement d’une puissance physique brute aiguisée à une perfection mortelle. Ceux qui se modèlent sur cet archétype allient entraînement rigoureux et excellence physique pour porter des coups dévastateurs.","desc":"","features":[{"name":"Critique amélioré","level":3,"desc":"À partir du moment où vous choisissez cet archétype au niveau 3, vos attaques avec votre arme infligent un coup critique sur un résultat de 19 ou 20.","name_en":"Improved Critical"},{"name":"Athlète remarquable","level":7,"desc":"À partir du niveau 7, vous pouvez ajouter la moitié de votre bonus de maîtrise (arrondi au supérieur) à tout test de Force, de Dextérité ou de Constitution que vous effectuez et qui n'utilise pas déjà votre bonus de maîtrise.\n\nDe plus, lorsque vous effectuez un saut en longueur en courant, la distance que vous pouvez parcourir augmente d'un nombre de pieds égal à votre modificateur de Force.","name_en":"Remarkable Athlete"},{"name":"Style de combat supplémentaire","level":10,"desc":"Au niveau 10, vous pouvez choisir une deuxième option dans la fonctionnalité de classe Style de combat.","name_en":"Additional Fighting Style"},{"name":"Critique supérieur","level":15,"desc":"À partir du niveau 15, vos attaques avec des armes infligent un coup critique sur un résultat de 18-20.","name_en":"Superior Critical"},{"name":"Survivant","level":18,"desc":"Au niveau 18, vous atteignez le summum de la résilience au combat. Au début de chacun de vos tours, vous récupérez des points de vie égaux à 5 + votre modificateur de Constitution s'il ne vous reste plus que la moitié de vos points de vie. Vous ne bénéficiez pas de cet avantage si vous avez 0 point de vie.","name_en":"Survivor"}],"name_en":"Fighter: Champion","_translated":true},{"index":"fighter-echo-knight","name":"Combattant : Echo Knight","class":"fighter","source":"Explorer's Guide to Wildemount","subclass_flavor":"Guerrier de première ligne mystérieux et redouté de la dynastie Kryn, l'Echo Knight maîtrise l'art d'utiliser les dunamis pour invoquer les ombres décolorées des lignes temporelles non réalisées afin de les aider au combat. Entourés des échos de leur propre puissance, ils chargent dans la mêlée comme un essaim cyclique d'ombres et de frappes.","desc":"","features":[{"name":"Écho manifeste","level":3,"desc":"Au niveau 3, vous pouvez utiliser une action bonus pour manifester comme par magie un écho de vous-même dans un espace inoccupé que vous pouvez voir à moins de 4,50 mètres de vous. Cet écho est une image magique, translucide et grise de vous qui dure jusqu'à ce qu'elle soit détruite, jusqu'à ce que vous la rejetiez par une action bonus, jusqu'à ce que vous manifestiez un autre écho ou jusqu'à ce que vous soyez incapable d'agir.\n\nVotre écho a une CA de 14 + votre bonus de maîtrise, 1 point de vie et une immunité à toutes les conditions. S'il doit effectuer un jet de sauvegarde, il utilise votre bonus de jet de sauvegarde pour le lancer. Il fait la même taille que vous et occupe son espace. À votre tour, vous pouvez commander mentalement à l'écho de se déplacer jusqu'à 9 mètres dans n'importe quelle direction (aucune action requise). Si votre écho se trouve à plus de 9 mètres de vous à la fin de votre tour, il est détruit.\n• Par une action bonus, vous pouvez vous téléporter, en échangeant comme par magie vos places avec votre écho pour un coût de 15 pieds de mouvement, quelle que soit la distance qui vous sépare.\n• Lorsque vous effectuez l'action Attaque à votre tour, toute attaque que vous effectuez avec cette action peut provenir de votre espace ou de l'espace de l'écho. Vous faites ce choix pour chaque attaque.\n• Lorsqu'une créature que vous pouvez voir à moins de 1,50 mètre de votre écho s'éloigne d'au moins 1,50 mètre, vous pouvez utiliser votre réaction pour lancer une attaque d'opportunité contre cette créature comme si vous étiez dans l'espace de l'écho.","name_en":"Manifest Echo"},{"name":"Libérez l'incarnation","level":3,"desc":"Au niveau 3, vous pouvez augmenter la fureur de votre écho. Chaque fois que vous effectuez l'action Attaque, vous pouvez effectuer une attaque de mêlée supplémentaire depuis la position de l'écho.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Constitution (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Unleash Incarnation"},{"name":"Avatar Écho","level":7,"desc":"À partir du niveau 7, vous pouvez transférer temporairement votre conscience vers votre écho. Par une action, vous pouvez voir à travers les yeux de votre écho et entendre à travers ses oreilles. Pendant ce temps, vous êtes devenus sourds et aveuglés. Vous pouvez maintenir cet effet jusqu’à 10 minutes et y mettre fin à tout moment (ne nécessite aucune action). Pendant que votre écho est utilisé de cette manière, il peut se trouver jusqu'à 1 000 pieds de vous sans être détruit.","name_en":"Echo Avatar"},{"name":"Martyre de l'Ombre","level":10,"desc":"À partir du niveau 10, vous pouvez faire en sorte que votre écho se projette devant une attaque dirigée sur une autre créature que vous pouvez voir. Avant que le jet d'attaque ne soit effectué, vous pouvez utiliser votre réaction pour téléporter l'écho dans un espace inoccupé à moins de 1,50 mètre de la créature ciblée. Le jet d'attaque qui a déclenché la réaction est plutôt effectué contre votre écho.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Shadow Martyr"},{"name":"Potentiel de récupération","level":15,"desc":"Au niveau 15, vous avez appris à absorber la magie éphémère de votre écho. Lorsqu'un de vos échos est détruit en subissant des dégâts, vous pouvez gagner un nombre de points de vie temporaires égal à 2d6 + votre modificateur de Constitution, à condition que vous ne disposiez pas déjà de points de vie temporaires.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Constitution (au minimum une fois). Vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Reclaim Potential"},{"name":"Légion d'Un","level":18,"desc":"Au niveau 18, vous pouvez utiliser une action bonus pour créer deux échos avec votre fonction Écho manifeste, et ces échos peuvent coexister. Si vous essayez de créer un troisième écho, les deux échos précédents sont détruits. Tout ce que vous pouvez faire à partir de la position d'un écho peut être fait à partir de celle de l'autre.\n\nDe plus, lorsque vous lancez un jet d'initiative et que vous n'avez plus aucune utilisation de votre fonctionnalité Libérer l'incarnation, vous récupérez une utilisation de cette fonctionnalité.","name_en":"Legion of One"}],"name_en":"Fighter: Echo Knight","_translated":true},{"index":"fighter-eldritch-knight","name":"Combattant : Chevalier surnaturel","class":"fighter","source":"Player's Handbook","subclass_flavor":"L'archétype du Chevalier Eldritch combine la maîtrise martiale commune à tous les combattants avec une étude minutieuse de la magie. Les chevaliers surnaturels utilisent des techniques magiques similaires à celles pratiquées par les sorciers. Ils concentrent leur étude sur deux des huit écoles de magie : l'abjuration et l'évocation. Les sorts d'abjuration confèrent au chevalier surnaturel une protection supplémentaire au combat, et les sorts d'évocation infligent des dégâts à plusieurs ennemis à la fois, étendant ainsi la portée du combattant au combat. Ces chevaliers apprennent un nombre relativement restreint de sorts, les mémorisant au lieu de les conserver dans un livre de sorts.","desc":"","features":[{"name":"Lancement de sorts","level":10,"desc":"Lorsque vous atteignez le niveau 3, vous augmentez vos prouesses martiales grâce à la capacité de lancer des sorts.\n\nVous apprenez deux sorts mineurs de votre choix dans la liste des sorts du sorcier. Vous apprenez un sort mineur supplémentaire de sorcier de votre choix au niveau 10.\n\nLe tableau de lancement de sorts Eldritch Knight indique le nombre d'emplacements de sorts dont vous disposez pour lancer vos sorts de sorcier de niveau 1 et supérieur. Pour lancer l'un de ces sorts, vous devez dépenser un emplacement du niveau du sort ou supérieur. Vous récupérez tous les emplacements de sorts dépensés lorsque vous terminez un repos long.\n\nPar exemple, si vous connaissez le sort Bouclier de niveau 1 et que vous disposez d'un emplacement de sort de niveau 1 et de niveau 2, vous pouvez lancer Bouclier en utilisant l'un ou l'autre emplacement.\n\nVous connaissez trois sorts de sorcier de niveau 1 de votre choix, dont deux que vous devez choisir parmi les sorts d'abjuration et d'évocation de la liste des sorts de sorcier.\n\nLa colonne Sorts connus du tableau de lancement de sorts Eldritch Knight indique quand vous apprenez plus de sorts de sorcier de niveau 1 ou supérieur. Chacun de ces sorts doit être un sort d'abjuration ou d'évocation de votre choix, et doit être d'un niveau pour lequel vous disposez d'emplacements de sorts. Par exemple, lorsque vous atteignez le niveau 7 dans cette classe, vous pouvez apprendre un nouveau sort de niveau 1 ou 2.\n\nLes sorts que vous apprenez aux niveaux 8, 14 et 20 peuvent provenir de n’importe quelle école de magie.\n\nÀ chaque fois que vous gagnez un niveau dans cette classe, vous pouvez remplacer l'un des sorts de sorcier que vous connaissez par un autre sort de votre choix dans la liste des sorts de sorcier. Le nouveau sort doit être d'un niveau pour lequel vous disposez d'emplacements de sort, et il doit s'agir d'un sort d'abjuration ou d'évocation, à moins que vous ne remplaciez le sort que vous avez acquis au niveau 3, 8, 14 ou 20 dans n'importe quelle école de magie.\n\nL'intelligence est votre capacité à lancer des sorts pour vos sorts de sorcier, puisque vous apprenez vos sorts par l'étude et la mémorisation. Vous utilisez votre Intelligence chaque fois qu'un sort fait référence à votre capacité de lancer des sorts. De plus, vous utilisez votre modificateur d'Intelligence lorsque vous définissez le DD du jet de sauvegarde pour un sort de sorcier que vous lancez et lorsque vous effectuez un jet d'attaque avec celui-ci.\n\nDD de sauvegarde des sorts = 8 + votre bonus de maîtrise + votre modificateur d'Intelligence\n\nModificateur d'attaque des sorts = votre bonus de maîtrise + votre modificateur d'Intelligence","name_en":"Spellcasting"},{"name":"Lien d'arme","level":3,"desc":"Au niveau 3, vous apprenez un rituel qui crée un lien magique entre vous et une arme. Vous effectuez le rituel sur une durée d'1 heure, qui peut être réalisé lors d'un court repos. L'arme doit être à votre portée tout au long du rituel, à l'issue duquel vous touchez l'arme et forgez le lien.\n\nUne fois que vous avez lié une arme à vous-même, vous ne pouvez pas être désarmé de cette arme à moins que vous ne soyez frappé d'incapacité. Si elle se trouve sur le même plan d'existence, vous pouvez invoquer cette arme comme une action bonus pendant votre tour, la faisant se téléporter instantanément dans votre main.\n\nVous pouvez avoir jusqu'à deux armes liées, mais vous ne pouvez en invoquer qu'une à la fois grâce à votre action bonus. Si vous tentez de créer un lien avec une troisième arme, vous devez rompre le lien avec l'une des deux autres.","name_en":"Weapon Bond"},{"name":"Magie de guerre","level":7,"desc":"À partir du niveau 7, lorsque vous utilisez votre action pour lancer un sort mineur, vous pouvez effectuer une attaque avec une arme en tant qu'action bonus.","name_en":"War Magic"},{"name":"Frappe surnaturelle","level":10,"desc":"Au niveau 10, vous apprenez à faire en sorte que vos frappes avec votre arme sapent la résistance d'une créature à vos sorts. Lorsque vous touchez une créature avec une attaque avec une arme, cette créature est désavantagée lors de son prochain jet de sauvegarde contre un sort que vous avez lancé avant la fin de votre prochain tour.","name_en":"Eldritch Strike"},{"name":"Charge arcanique","level":15,"desc":"Au niveau 15, vous obtenez la possibilité de vous téléporter jusqu'à 9 mètres vers un espace inoccupé que vous pouvez voir lorsque vous utilisez votre Action Surge. Vous pouvez vous téléporter avant ou après l'action supplémentaire.","name_en":"Arcane Charge"},{"name":"Magie de guerre améliorée","level":18,"desc":"À partir du niveau 18, lorsque vous utilisez votre action pour lancer un sort, vous pouvez effectuer une attaque avec une arme en tant qu'action bonus.","name_en":"Improved War Magic"}],"name_en":"Fighter: Eldritch Knight","_translated":true},{"index":"fighter-psi-warrior","name":"Combattant : Guerrier Psi","class":"fighter","source":"Tasha's Cauldron of Everything","subclass_flavor":"Éveillé par le pouvoir psionique intérieur, un guerrier psi est un combattant qui augmente sa puissance physique avec des frappes d'armes infusées psi, des cils télékinésiques et des barrières de force mentale. De nombreux githyanki s’entraînent pour devenir de tels guerriers, tout comme certains des hauts elfes les plus disciplinés. Dans le monde d'Eberron, de nombreux jeunes kalashtar rêvent de devenir des Guerriers Psi.","desc":"","features":[{"name":"Pouvoir psionique","level":3,"desc":"Au niveau 3, vous abritez en vous une source d’énergie psionique. Cette énergie est représentée par vos dés d’Énergie Psionique, qui sont chacun un d6. Vous disposez d'un nombre de ces dés égal à deux fois votre bonus de maîtrise, et ils alimentent divers pouvoirs psioniques dont vous disposez, qui sont détaillés ci-dessous.\n\nCertains de vos pouvoirs dépensent le dé d'énergie psionique qu'ils utilisent, comme spécifié dans la description d'un pouvoir, et vous ne pouvez pas utiliser un pouvoir s'il nécessite que vous utilisiez un dé lorsque vos dés sont tous dépensés. Vous récupérez tous vos d��s d'énergie psionique dépensés lorsque vous terminez un repos long. De plus, par une action bonus, vous pouvez récupérer un dé d'énergie psionique dépensé, mais vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n\nLorsque vous atteignez certains niveaux dans cette classe, la taille de vos dés d'énergie psionique augmente : au niveau 5 (d8), au niveau 11 (d10) et au niveau 17 (d12).\n\nLes pouvoirs ci-dessous utilisent vos dés d'énergie psionique.\n\nChamp de protection. Lorsque vous ou une autre créature que vous pouvez voir à moins de 9 mètres de vous subissez des dégâts, vous pouvez utiliser votre réaction pour dépenser un dé d'énergie psionique, lancer le dé et réduire les dégâts subis du nombre obtenu plus votre modificateur d'Intelligence (réduction minimale de 1), tout en créant un bouclier momentané de force télékinésique.\n\nFrappe psionique. Vous pouvez propulser vos armes avec une force psionique. Une fois à chacun de vos tours, immédiatement après avoir touché une cible à moins de 9 mètres de vous avec une attaque et lui avoir infligé des dégâts avec une arme, vous pouvez dépenser un dé d'énergie psionique, le lancer et infliger des dégâts de force à la cible égaux au nombre obtenu plus votre modificateur d'Intelligence.\n\nMouvement télékinésique. Vous pouvez déplacer un objet ou une créature avec votre esprit. Par une action, vous ciblez un objet libre de grande taille ou plus petit ou une créature volontaire, autre que vous-même. Si vous pouvez voir la cible et qu'elle se trouve à moins de 9 mètres de vous, vous pouvez la déplacer jusqu'à 9 mètres vers un espace inoccupé que vous pouvez voir. Alternativement, s’il s’agit d’un objet minuscule, vous pouvez le déplacer vers ou depuis votre main. Dans tous les cas, vous pouvez déplacer la cible horizontalement, verticalement ou les deux. Une fois que vous avez effectué cette action, vous ne pouvez plus la refaire jusqu'à ce que vous ayez terminé un repos court ou long, à moins que vous ne dépensiez un dé d'énergie psionique pour la reprendre.","name_en":"Psionic Power"},{"name":"Adepte télékinésique","level":null,"desc":"Au niveau 7, vous maîtrisez de nouvelles façons d’utiliser vos capacités télékinésiques, détaillées ci-dessous.\n\nSaut alimenté par le Psi. En guise d’action bonus, vous pouvez propulser votre corps grâce à votre esprit. Vous gagnez une vitesse de vol égale à deux fois votre vitesse de marche jusqu'à la fin du tour en cours. Une fois que vous avez effectué cette action bonus, vous ne pouvez plus la refaire avant d'avoir terminé un repos court ou long, à moins que vous ne dépensiez un dé d'énergie psionique pour la reprendre.\n\nPoussée télékinésique. Lorsque vous infligez des dégâts à une cible avec votre Frappe Psionique, vous pouvez forcer la cible à effectuer un jet de sauvegarde de Force contre un DD égal à 8 + votre bonus de maîtrise + votre modificateur d'Intelligence. Si la sauvegarde échoue, vous pouvez mettre la cible à terre ou la déplacer jusqu'à 10 pieds dans n'importe quelle direction horizontalement.","name_en":"Telekinetic Adept"},{"name":"Esprit gardé","level":10,"desc":"À partir du niveau 10, l’énergie psionique qui vous traverse a renforcé votre esprit. Vous avez une résistance aux dégâts psychiques. De plus, si vous commencez votre tour charmé ou effrayé, vous pouvez dépenser un dé d'énergie psionique et mettre fin à tous les effets sur vous-même en vous soumettant à ces conditions.","name_en":"Guarded Mind"},{"name":"Rempart de force","level":15,"desc":"Au niveau 15, vous pouvez vous protéger et protéger les autres grâce à la force télékinésique. Par une action bonus, vous pouvez choisir des créatures, qui peuvent vous inclure, que vous pouvez voir dans un rayon de 9 mètres autour de vous, jusqu'à un nombre de créatures égal à votre modificateur d'Intelligence (minimum d'une créature). Chacune des créatures choisies est protégée par une demi-couverture pendant 1 minute ou jusqu'à ce que vous soyez incapable d'agir.\n\nUne fois que vous avez effectué cette action bonus, vous ne pouvez plus la refaire avant d'avoir terminé un repos long, à moins que vous ne dépensiez un dé d'énergie psionique pour la reprendre.","name_en":"Bulwark of Force"},{"name":"Maître télékinésique","level":18,"desc":"Au niveau 18, votre capacité à déplacer des créatures et des objets avec votre esprit est rarement égalée. Vous pouvez lancer le sort Télékinésie, ne nécessitant aucun composant, et votre capacité de lancement de sorts pour le sort est l'Intelligence. À chacun de vos tours pendant que vous vous concentrez sur le sort, y compris le tour où vous le lancez, vous pouvez effectuer une attaque avec une arme en guise d'action bonus.\n\nUne fois que vous avez lancé le sort avec cette fonctionnalité, vous ne pouvez plus le refaire avant d'avoir terminé un long repos, à moins que vous ne dépensiez un dé d'énergie psionique pour le lancer à nouveau.","name_en":"Telekinetic Master"}],"name_en":"Fighter: Psi Warrior","_translated":true},{"index":"fighter-rune-knight","name":"Combattant : Chevalier runique","class":"fighter","source":"Tasha's Cauldron of Everything","subclass_flavor":"Les chevaliers runiques améliorent leurs prouesses martiales en utilisant le pouvoir surnaturel des runes, une pratique ancienne originaire des géants. Les tailleurs de runes peuvent être trouvés parmi n'importe quelle famille de géants, et vous avez probablement appris vos méthodes de première main ou de seconde main auprès d'un artisan aussi mystique. Que vous ayez trouvé l'œuvre du géant sculptée dans une colline ou une grotte, que vous ayez appris les runes auprès d'un sage ou que vous ayez rencontré le géant en personne, vous avez étudié le métier du géant et appris à appliquer des runes magiques pour renforcer votre équipement.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous maîtrisez les outils de forgeron et vous apprenez à parler, lire et écrire en géant.","name_en":"Bonus Proficiencies"},{"name":"Sculpteur de runes","level":3,"desc":"À partir du niveau 3, vous pouvez utiliser des runes magiques pour améliorer votre équipement. Vous apprenez deux runes de votre choix, parmi les runes décrites ci-dessous, et à chaque fois que vous gagnez un niveau dans cette classe, vous pouvez remplacer une rune que vous connaissez par une autre issue de cette fonctionnalité. Lorsque vous atteignez certains niveaux dans cette classe, vous apprenez des runes supplémentaires, comme indiqué dans le tableau des runes connues.\nRunes connues | \nNiveau de combattant | Nombre de runes\n3ème | 2\n7ème | 3\n10e | 4\n15e | 5\n\nChaque fois que vous terminez un repos long, vous pouvez toucher un nombre d'objets égal au nombre de runes que vous connaissez, et vous inscrivez une rune différente sur chacun des objets. Pour être éligible, un objet doit être une arme, une armure, un bouclier, un bijou ou tout autre objet que vous pouvez porter ou tenir dans une main. Votre rune reste sur un objet jusqu'à ce que vous ayez terminé un long repos, et un objet ne peut porter qu'une seule de vos runes à la fois.\n\nLes runes suivantes sont disponibles lorsque vous apprenez une rune. Si une rune a un niveau requis, vous devez avoir au moins ce niveau dans cette classe pour apprendre la rune. Si une rune nécessite un jet de sauvegarde, votre DD de sauvegarde de Magie runique est égal à 8 + votre bonus de maîtrise + votre modificateur de Constitution.\n• Rune de nuage. Cette rune imite la magie trompeuse utilisée par certains géants des nuages. Lorsque vous portez ou transportez un objet inscrit avec cette rune, vous avez un avantage aux tests de Dextérité (Tour de passe-passe) et de Charisme (Tromperie). De plus, lorsque vous ou une créature que vous pouvez voir à moins de 9 mètres de vous êtes touché par un jet d'attaque, vous pouvez utiliser votre réaction pour invoquer la rune et choisir une créature différente à moins de 9 mètres de vous, autre que l'attaquant. La créature choisie devient la cible de l'attaque, en utilisant le même jet. Cette magie peut transférer les effets de l'attaque quelle que soit la portée de l'attaque. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, lorsque vous ou une créature que vous pouvez voir à moins de 9 mètres de vous êtes touché par un jet d'attaque, vous pouvez utiliser votre réaction pour invoquer la rune et choisir une créature différente à moins de 9 mètres de vous, autre que l'attaquant. La créature choisie devient la cible de l'attaque, en utilisant le même jet. Cette magie peut transférer les effets de l'attaque quelle que soit la portée de l'attaque. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• Rune de Feu. La magie de cette rune canalise le savoir-faire magistral des grands forgerons. Lorsque vous portez ou transportez un objet portant cette rune, votre bonus de maîtrise est doublé pour tout test de capacité que vous effectuez qui utilise votre maîtrise d'un outil. De plus, lorsque vous touchez une créature avec une attaque utilisant une arme, vous pouvez invoquer la rune pour invoquer des chaînes enflammées : la cible subit 2d6 dégâts de feu supplémentaires, et elle doit réussir un jet de sauvegarde de Force ou être retenue pendant 1 minute. Lorsqu'elle est retenue par les chaînes, la cible subit 2d6 dégâts de feu au début de chacun de ses tours. La cible peut refaire le jet de sauvegarde à la fin de chacun de ses tours, bannissant les chaînes en cas de réussite. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, lorsque vous touchez une créature avec une attaque utilisant une arme, vous pouvez invoquer la rune pour invoquer des chaînes de feu : la cible subit 2d6 dégâts de feu supplémentaires, et elle doit réussir un jet de sauvegarde de Force ou être retenue pendant 1 minute. Lorsqu'elle est retenue par les chaînes, la cible subit 2d6 dégâts de feu au début de chacun de ses tours. La cible peut refaire le jet de sauvegarde à la fin de chacun de ses tours, bannissant les chaînes en cas de réussite. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• Rune de givre. La magie de cette rune évoque la puissance de ceux qui survivent dans les déserts hivernaux, comme les géants des glaces. Lorsque vous portez ou transportez un objet inscrit avec cette rune, vous avez un avantage aux tests de Sagesse (Manipulation des animaux) et de Charisme (Intimidation). De plus, vous pouvez invoquer la rune comme action bonus pour augmenter votre robustesse. Pendant 10 minutes, vous bénéficiez d'un bonus de +2 à tous les tests de caractéristiques et jets de sauvegarde utilisant la Force ou la Constitution. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, vous pouvez invoquer la rune comme une action bonus pour augmenter votre robustesse. Pendant 10 minutes, vous bénéficiez d'un bonus de +2 à tous les tests de caractéristiques et jets de sauvegarde utilisant la Force ou la Constitution. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• Rune de pierre. La magie de cette rune canalise le sens associé aux géants de pierre. Lorsque vous portez ou transportez un objet inscrit avec cette rune, vous avez un avantage aux tests de Sagesse (Perspicacité) et vous avez une vision dans le noir jusqu'à une portée de 120 pieds. De plus, lorsqu'une créature que vous pouvez voir termine son tour à moins de 9 mètres de vous, vous pouvez utiliser votre réaction pour invoquer la rune et forcer la créature à effectuer un jet de sauvegarde de Sagesse. À moins que la sauvegarde ne réussisse, la créature est charmée par vous pendant 1 minute. Pendant qu'elle est ainsi charmée, la créature a une vitesse de 0 et est incapable d'agir, tombant dans une stupeur rêveuse. La créature répète le jet de sauvegarde à la fin de chacun de ses tours, mettant fin à l'effet en cas de réussite. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, lorsqu'une créature que vous pouvez voir termine son tour à moins de 9 mètres de vous, vous pouvez utiliser votre réaction pour invoquer la rune et forcer la créature à effectuer un jet de sauvegarde de Sagesse. À moins que la sauvegarde ne réussisse, la créature est charmée par vous pendant 1 minute. Pendant qu'elle est ainsi charmée, la créature a une vitesse de 0 et est incapable d'agir, tombant dans une stupeur rêveuse. La créature répète le jet de sauvegarde à la fin de chacun de ses tours, mettant fin à l'effet en cas de réussite. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• Hill Rune (niveau 7 ou supérieur). La magie de cette rune confère une résilience rappelant celle d'un géant des collines. Lorsque vous portez ou transportez un objet portant cette rune, vous avez un avantage aux jets de sauvegarde contre l'empoisonnement et vous avez une résistance contre les dégâts de poison. De plus, vous pouvez invoquer la rune comme une action bonus, gagnant ainsi une résistance aux dégâts contondants, perçants et tranchants pendant 1 minute. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, vous pouvez invoquer la rune comme une action bonus, gagnant ainsi une résistance aux dégâts contondants, perçants et tranchants pendant 1 minute. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• Rune de tempête (niveau 7 ou supérieur). En utilisant cette rune, vous pouvez entrevoir l’avenir comme un voyant géant des tempêtes. Lorsque vous portez ou transportez un objet inscrit avec cette rune, vous avez un avantage aux tests d'Intelligence (Arcanes), et vous ne pouvez pas être surpris tant que vous n'êtes pas incapable d'agir. De plus, vous pouvez invoquer la rune comme une action bonus pour entrer dans un état prophétique pendant 1 minute ou jusqu'à ce que vous soyez incapable d'agir. Jusqu'à la fin de l'état, lorsque vous ou une autre créature que vous pouvez voir à moins de 60 pieds de vous effectuez un jet d'attaque, un jet de sauvegarde ou un test de capacité, vous pouvez utiliser votre réaction pour que le jet ait un avantage ou un désavantage. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n• De plus, vous pouvez invoquer la rune comme une action bonus pour entrer dans un état prophétique pendant 1 minute ou jusqu'à ce que vous soyez incapable d'agir. Jusqu'à la fin de l'état, lorsque vous ou une autre créature que vous pouvez voir à moins de 60 pieds de vous effectuez un jet d'attaque, un jet de sauvegarde ou un test de capacité, vous pouvez utiliser votre réaction pour que le jet ait un avantage ou un désavantage. Une fois que vous avez invoqué cette rune, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.","name_en":"Rune Carver"},{"name":"La puissance du géant","level":3,"desc":"Au niveau 3, vous avez appris à vous imprégner de la puissance des géants. Par une action bonus, vous bénéficiez comme par magie des avantages suivants, qui durent 1 minute :\n• Si vous êtes plus petit que Large, vous devenez Grand, ainsi que tout ce que vous portez. Si vous n’avez pas l’espace nécessaire pour devenir Grand, votre taille ne change pas.\n• Vous avez un avantage aux tests de Force et aux jets de sauvegarde de Force.\n• Une fois à chacun de vos tours, une de vos attaques avec une arme ou une frappe à mains nues peut infliger 1d6 dégâts supplémentaires à une cible en cas de coup sûr.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous en récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Giant's Might"},{"name":"Bouclier runique","level":7,"desc":"Au niveau 7, vous apprenez à invoquer votre magie runique pour protéger vos alliés. Lorsqu'une autre créature que vous pouvez voir à moins de 60 pieds de vous est touchée par un jet d'attaque, vous pouvez utiliser votre réaction pour forcer l'attaquant à relancer le d20 et à utiliser le nouveau jet.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Runic Shield"},{"name":"Grande stature","level":10,"desc":"Au niveau 10, la magie de vos runes vous altère de façon permanente. Lorsque vous obtenez cette fonctionnalité, lancez 3d4. Vous grandissez d’un nombre de pouces de hauteur égal au rouleau.\n\nDe plus, les dégâts supplémentaires que vous infligez avec votre fonction Giant's Might passent à 1d8.","name_en":"Great Stature"},{"name":"Maître des Runes","level":15,"desc":"Au niveau 15, vous pouvez invoquer chaque rune que vous connaissez grâce à votre fonction Rune Carver deux fois, plutôt qu'une, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos court ou long.","name_en":"Master of Runes"},{"name":"Juggernaut runique","level":18,"desc":"Au niveau 18, vous apprenez à amplifier votre transformation runique. En conséquence, les dégâts supplémentaires que vous infligez avec la fonction Puissance du géant augmentent à 1d10. De plus, lorsque vous utilisez cette fonctionnalité, votre taille peut atteindre Énorme, et tant que vous avez cette taille, votre portée augmente de 5 pieds.","name_en":"Runic Juggernaut"}],"name_en":"Fighter: Rune Knight","_translated":true},{"index":"fighter-samurai","name":"Combattant : Samouraï","class":"fighter","source":"Xanathar's Guide to Everything","subclass_flavor":"Le Samouraï est un combattant qui fait appel à un esprit combatif implacable pour vaincre ses ennemis. La détermination d’un samouraï est presque inébranlable, et les ennemis sur son chemin ont deux choix : céder ou mourir au combat.","desc":"","features":[{"name":"Compétence bonus","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous maîtrisez l'une des compétences suivantes de votre choix : Histoire, Perspicacité, Performance ou Persuasion. Alternativement, vous apprenez une langue de votre choix.","name_en":"Bonus Proficiency"},{"name":"Esprit combatif","level":3,"desc":"À partir du niveau 3, votre intensité au combat peut vous protéger et vous aider à frapper juste. Par une action bonus lors de votre tour, vous pouvez vous donner un avantage sur tous les jets d'attaque avec arme jusqu'à la fin du tour en cours. Ce faisant, vous gagnez également 5 points de vie temporaires. Le nombre de points de vie augmente lorsque vous atteignez certains niveaux dans cette classe, passant à 10 au niveau 10 et 15 au niveau 15.\n\nVous pouvez utiliser cette fonctionnalité trois fois. Vous en récupérez toutes les utilisations dépensées lorsque vous terminez un long repos.","name_en":"Fighting Spirit"},{"name":"Courtisan élégant","level":7,"desc":"À partir du niveau 7, votre discipline et votre souci du détail vous permettent d'exceller dans les situations sociales. Chaque fois que vous effectuez un test de Charisme (Persuasion), vous gagnez un bonus au test égal à votre modificateur de Sagesse.\n\nVotre maîtrise de soi vous permet également de maîtriser les jets de sauvegarde de Sagesse. Si vous possédez déjà cette compétence, vous gagnez à la place la maîtrise des jets de sauvegarde d'Intelligence ou de Charisme (au choix).","name_en":"Elegant Courtier"},{"name":"Esprit infatigable","level":10,"desc":"À partir du niveau 10, lorsque vous lancez un jet d’initiative et qu’il ne vous reste plus aucune utilisation d’Esprit combatif, vous récupérez une utilisation.","name_en":"Tireless Spirit"},{"name":"Frappe rapide","level":15,"desc":"À partir du niveau 15, vous apprenez à troquer la précision contre des frappes rapides. Si vous effectuez l'action Attaque à votre tour et avez l'avantage sur un jet d'attaque contre l'une des cibles, vous pouvez renoncer à l'avantage de ce jet pour effectuer une attaque avec une arme supplémentaire contre cette cible, dans le cadre de la même action. Vous ne pouvez pas le faire plus d'une fois par tour.","name_en":"Rapid Strike"},{"name":"La force avant la mort","level":18,"desc":"À partir du niveau 18, votre esprit combatif peut retarder l’approche de la mort. Si vous subissez des dégâts qui vous réduisent à 0 point de vie, vous pouvez utiliser votre réaction pour retarder votre perte de conscience et vous pouvez immédiatement prendre un tour supplémentaire. Tant que vous avez 0 point de vie pendant ce tour supplémentaire, subir des dégâts provoque des échecs de jet de sauvegarde contre la mort comme d'habitude, et trois échecs de jet de sauvegarde contre la mort peuvent toujours vous tuer. À la fin du tour supplémentaire, vous perdez connaissance si vous n’avez toujours aucun point de vie.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Strength Before Death"}],"name_en":"Fighter: Samurai","_translated":true},{"index":"monk-mercy","name":"Moine : Voie de la Miséricorde","class":"monk","source":"Tasha's Cauldron of Everything","subclass_flavor":"Les moines de la Voie de la Miséricorde apprennent à manipuler la force vitale des autres pour apporter de l'aide à ceux qui en ont besoin. Ce sont des médecins itinérants auprès des pauvres et des blessés. Cependant, à ceux qui n’ont pas leur aide, ils apportent une fin rapide en guise d’acte de miséricorde.","desc":"","features":[{"name":"Instruments de miséricorde","level":3,"desc":"Lorsque vous choisissez cette tradition au niveau 3, vous gagnez la maîtrise des compétences Insight et Médecine, ainsi que la maîtrise du kit d'herboristerie.\n\nVous obtenez également un masque spécial, que vous portez souvent lorsque vous utilisez les fonctionnalités de cette sous-classe. Vous déterminez son apparence, ou la générez aléatoirement en lançant sur le tableau du Masque Miséricordieux.\nMasque miséricordieux | \nd6 | Apparence du masque\n1 | Corbeau\n2 | Vide et blanc\n3 | Visage qui pleure\n4 | Visage rieur\n5 | Crâne\n6 | Papillon","name_en":"Implements of Mercy"},{"name":"Mains de guérison","level":3,"desc":"Au niveau 3, votre touche mystique peut panser les blessures. Par une action, vous pouvez dépenser 1 point de ki pour toucher une créature et restaurer un nombre de points de vie égal à un lancer de votre dé d'Arts Martiaux + votre modificateur de Sagesse.\n\nLorsque vous utilisez votre Rafale de Coups, vous pouvez remplacer l'une des frappes à mains nues par une utilisation de cette fonctionnalité sans dépenser de point de ki pour la guérison.","name_en":"Hands of Healing"},{"name":"Mains de mal","level":3,"desc":"Au niveau 3, vous utilisez votre ki pour infliger des blessures. Lorsque vous frappez une créature avec une frappe à mains nues, vous pouvez dépenser 1 point de ki pour infliger des dégâts nécrotiques supplémentaires égaux à un lancer de votre dé d'arts martiaux + votre modificateur de Sagesse. Vous ne pouvez utiliser cette fonctionnalité qu'une seule fois par tour.","name_en":"Hands of Harm"},{"name":"Le contact du médecin","level":6,"desc":"À partir du niveau 6, vous pouvez administrer des remèdes encore plus puissants d'un simple toucher, et si vous le jugez nécessaire, vous pouvez utiliser vos connaissances pour causer du mal.\n\nLorsque vous utilisez Mains de guérison sur une créature, vous pouvez également mettre fin à une maladie ou à l'une des conditions suivantes affectant la créature : aveuglée, assourdie, paralysée, empoisonnée ou étourdie.\n\nLorsque vous utilisez Hands of Harm sur une créature, vous pouvez soumettre cette créature à l'état empoisonné jusqu'à la fin de votre prochain tour.","name_en":"Physician's Touch"},{"name":"Déferlante de guérison et de préjudice","level":11,"desc":"À partir du niveau 11, vous pouvez désormais infliger une vague de réconfort et de souffrance. Lorsque vous utilisez Rafale de Coups, vous pouvez désormais remplacer chacune des frappes à mains nues par une utilisation de vos Mains de Guérison, sans dépenser de points de ki pour la guérison.\n\nDe plus, lorsque vous effectuez une frappe à mains nues avec Flurry of Blows, vous pouvez utiliser Hand of Harm avec cette frappe sans dépenser le point de ki pour Hands of Harm. Vous ne pouvez toujours utiliser Hands of Harm qu’une seule fois par tour.","name_en":"Flurry of Healing and Harm"},{"name":"Main de la Miséricorde Ultime","level":17,"desc":"Au niveau 17, votre maîtrise de l’énergie vitale ouvre la porte à la miséricorde ultime. Par une action, vous pouvez toucher le cadavre d'une créature décédée au cours des dernières 24 heures et dépenser 5 points de ki. La créature revient alors à la vie, récupérant un nombre de points de vie égal à 4d10 + votre modificateur de Sagesse. Si la créature meurt alors qu'elle est soumise à l'une des conditions suivantes, elle ressuscite sans ces conditions : aveuglée, assourdie, paralysée, empoisonnée et étourdie.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Hand of Ultimate Mercy"}],"name_en":"Monk: Way of Mercy","_translated":true},{"index":"monk-shadow","name":"Moine : Voie de l'Ombre","class":"monk","source":"Player's Handbook","subclass_flavor":"Les moines de la Voie de l'Ombre suivent une tradition qui valorise la furtivité et le subterfuge. Ces moines pourraient être appelés ninjas ou danseurs de l’ombre, et ils servent d’espions et d’assassins. Parfois, les membres d'un monastère ninja sont des membres de la famille, formant un clan juré de garder le secret sur leurs arts et leurs missions. D'autres monastères ressemblent davantage à des guildes de voleurs, louant leurs services à des nobles, de riches marchands ou à toute autre personne pouvant payer leurs honoraires. Quelles que soient leurs méthodes, les chefs de ces monastères attendent l’obéissance inconditionnelle de leurs étudiants.","desc":"","features":[{"name":"Arts de l'Ombre","level":3,"desc":"Dès que vous choisissez cette tradition au niveau 3, vous pouvez utiliser votre ki pour dupliquer les effets de certains sorts. En tant qu'action, vous pouvez dépenser 2 points de ki pour lancer Ténèbres, Vision dans le noir, Passer sans trace ou Silence, sans fournir de composants matériels. De plus, vous gagnez le cantrip Minor Illusion si vous ne le connaissez pas déjà.","name_en":"Shadow Arts"},{"name":"Étape de l'ombre","level":6,"desc":"Au niveau 6, vous gagnez la capacité de passer d’une ombre à une autre. Lorsque vous êtes dans une faible lumière ou dans l'obscurité, par une action bonus, vous pouvez vous téléporter jusqu'à 60 pieds dans un espace inoccupé que vous pouvez voir et qui est également dans une faible lumière ou dans l'obscurité. Vous avez alors l'avantage sur la première attaque de mêlée que vous effectuez avant la fin du tour.","name_en":"Shadow Step"},{"name":"Cape des ombres","level":11,"desc":"Au niveau 11, vous avez appris à ne faire qu'un avec les ombres. Lorsque vous vous trouvez dans une zone de faible luminosité ou d’obscurité, vous pouvez utiliser votre action pour devenir invisible. Vous restez invisible jusqu'à ce que vous effectuiez une attaque, que vous lanciez un sort ou que vous soyez dans une zone de lumière vive.","name_en":"Cloak of Shadows"},{"name":"Opportuniste","level":17,"desc":"Au niveau 17, vous pouvez exploiter la distraction momentanée d'une créature lorsqu'elle est touchée par une attaque. Chaque fois qu'une créature à moins de 1,50 mètre de vous est touchée par une attaque lancée par une créature autre que vous, vous pouvez utiliser votre réaction pour lancer une attaque au corps à corps contre cette créature.","name_en":"Opportunist"}],"name_en":"Monk: Way of Shadow","_translated":true},{"index":"monk-astral-self","name":"Moine : Voie du Soi Astral","class":"monk","source":"Tasha's Cauldron of Everything","subclass_flavor":"Un moine qui suit la Voie du Soi Astral croit que son corps est une illusion. Ils voient leur ki comme une représentation de leur véritable forme, un moi astral. Ce moi astral a la capacité d'être une force d'ordre ou de désordre, certains monastères formant les étudiants à utiliser leur pouvoir pour protéger les faibles et d'autres instruisant les aspirants sur la manière de se manifester au service des puissants.","desc":"","features":[{"name":"Bras du Soi Astral","level":3,"desc":"Au niveau 3, votre maîtrise de votre ki vous permet d'invoquer une partie de votre moi astral. Par une action bonus, vous pouvez dépenser 1 point de ki pour invoquer les bras de votre moi astral. Lorsque vous faites cela, chaque créature de votre choix que vous pouvez voir à moins de 3 mètres de vous doit réussir un jet de sauvegarde de Dextérité ou subir des dégâts de force égaux à deux lancers de votre dé d'Arts Martiaux.\n\nPendant 10 minutes, ces bras spectraux planent près de vos épaules ou entourent vos bras (au choix). Vous déterminez l'apparence des armes et elles disparaissent prématurément si vous êtes frappé d'incapacité ou si vous mourez.\n\nTant que les bras spectraux sont présents, vous bénéficiez des avantages suivants :\n• Vous pouvez utiliser votre modificateur de Sagesse à la place de votre modificateur de Force lorsque vous effectuez des tests de Force et des jets de sauvegarde de Force.\n• Vous pouvez utiliser les bras spectraux pour effectuer des frappes à mains nues.\n• Lorsque vous effectuez une frappe à mains nues avec les bras pendant votre tour, votre portée est de 1,50 mètre supérieure à la normale.\n• Les frappes à mains nues que vous effectuez avec les bras peuvent utiliser votre modificateur de Sagesse à la place de votre modificateur de Force ou de Dextérité pour les jets d'attaque et de dégâts, et leur type de dégâts est la force.","name_en":"Arms of the Astral Self"},{"name":"Visage du Soi Astral","level":null,"desc":"Lorsque vous atteignez le niveau 6, vous pouvez invoquer le visage de votre moi astral. En tant qu'action bonus, ou dans le cadre de l'action bonus que vous effectuez pour activer les Armes du Soi Astral, vous pouvez dépenser 1 point de ki pour invoquer ce visage pendant 10 minutes. Il disparaît prématurément si vous êtes frappé d'incapacité ou si vous mourez.\n\nLe visage spectral couvre votre visage comme un casque ou un masque. Vous déterminez son apparence.\n\nTant que le visage spectral est présent, vous bénéficiez des avantages suivants.\n\nVue Astrale. Vous pouvez voir normalement dans l'obscurité, à la fois magique et non magique, jusqu'à une distance de 120 pieds.\n\nSagesse de l'Esprit. Vous avez un avantage aux tests de Sagesse (Perspicacité) et de Charisme (Intimidation).\n\nParole de l'Esprit. Lorsque vous parlez, vous pouvez diriger vos paroles vers une créature de votre choix que vous pouvez voir à moins de 60 pieds de vous, de manière à ce que seule cette créature puisse vous entendre. Alternativement, vous pouvez amplifier votre voix afin que toutes les créatures à moins de 600 pieds puissent vous entendre.","name_en":"Visage of the Astral Self"},{"name":"Corps du Soi Astral","level":11,"desc":"À partir du niveau 11, lorsque vos bras astraux et votre visage sont invoqués, vous pouvez faire apparaître le corps de votre moi astral (aucune action requise). Ce corps spectral recouvre votre forme physique comme une armure, se connectant aux bras et au visage. Vous déterminez son apparence.\n\nTant que le corps spectral est présent, vous bénéficiez des avantages suivants.\n\nDévier l’énergie. Lorsque vous subissez des dégâts d'acide, de froid, de feu, de force, de foudre ou de tonnerre, vous pouvez utiliser votre réaction pour les dévier. Lorsque vous faites ainsi, les dégâts que vous subissez sont réduits de 1d10 + votre modificateur de Sagesse (réduction minimum de 1).\n\nDes armes puissantes. Une fois à chacun de vos tours, lorsque vous touchez une cible avec les bras du Soi astral, vous pouvez infliger à la cible des dégâts supplémentaires égaux à votre dé d'arts martiaux.","name_en":"Body of the Astral Self"},{"name":"Soi astral éveillé","level":17,"desc":"À partir du niveau 17, votre connexion à votre moi astral est complète, vous permettant de libérer tout son potentiel. Par une action bonus, vous pouvez dépenser 5 points de ki pour invoquer les bras, le visage et le corps de votre moi astral et le réveiller pendant 10 minutes. Cet éveil se termine tôt si vous êtes frappé d’incapacité ou si vous mourez.\n\nPendant que votre moi astral est éveillé, vous bénéficiez des avantages suivants.\n\nArmure de l'Esprit. Vous gagnez un bonus de +2 à la classe d'armure.\n\nBarrage astral. Chaque fois que vous utilisez la fonction Extra Attack pour attaquer deux fois, vous pouvez attaquer trois fois si toutes les attaques sont effectuées avec vos bras astraux.","name_en":"Awakened Astral Self"}],"name_en":"Monk: Way of the Astral Self","_translated":true},{"index":"monk-drunken-master","name":"Moine : Voie du Maître Ivre","class":"monk","source":"Xanathar's Guide to Everything","subclass_flavor":"La Voie du Maître Ivre apprend à ses étudiants à se déplacer avec les mouvements saccadés et imprévisibles d'un ivrogne. Un maître ivre se balance, chancelant sur des pieds instables, pour présenter ce qui semble être un combattant incompétent dont l'engagement s'avère frustrant. Les trébuchements erratiques du maître ivre cachent une danse soigneusement exécutée de blocages, de parades, d’avancées, d’attaques et de retraites.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous choisissez cette tradition au niveau 3, vous gagnez la maîtrise de la compétence Performance si vous ne la possédez pas déjà. Votre technique d'arts martiaux mélange l'entraînement au combat avec la précision d'un danseur et les pitreries d'un bouffon. Vous gagnez également en maîtrise avec les fournitures de brasseur si vous ne les possédez pas déjà.","name_en":"Bonus Proficiencies"},{"name":"Technique ivre","level":3,"desc":"Au niveau 3, vous apprenez à vous tordre et à vous retourner rapidement dans le cadre de votre Rafale de coups. Chaque fois que vous utilisez Rafale de coups, vous bénéficiez de l'action Désengagement et votre vitesse de marche augmente de 3 mètres jusqu'à la fin du tour en cours.","name_en":"Drunken Technique"},{"name":"Balancement éméché","level":6,"desc":"À partir du niveau 6, vous pouvez vous déplacer de manière soudaine et instable. Vous bénéficiez des avantages suivants.\n• Sautez sur vos pieds. Lorsque vous êtes couché, vous pouvez vous lever en effectuant 1,50 mètre de mouvement, plutôt que la moitié de votre vitesse.\n• Rediriger l'attaque. Lorsqu'une créature vous manque avec un jet d'attaque au corps à corps, vous pouvez dépenser 1 point de ki en réaction pour que cette attaque touche une créature de votre choix, autre que l'attaquant, que vous pouvez voir à moins de 1,50 mètre de vous.","name_en":"Tipsy Sway"},{"name":"La chance de l'ivrogne","level":11,"desc":"À partir du niveau 11, vous semblez toujours avoir un coup de chance au bon moment. Lorsque vous effectuez un test de caractéristique, un jet d'attaque ou un jet de sauvegarde et que vous avez un désavantage, vous pouvez dépenser 2 points de ki pour annuler le désavantage de ce jet.","name_en":"Drunkard's Luck"},{"name":"Frénésie ivre","level":17,"desc":"Au niveau 17, vous obtenez la capacité de lancer un nombre écrasant d’attaques contre un groupe d’ennemis. Lorsque vous utilisez votre Rafale de coups, vous pouvez effectuer jusqu'à trois attaques supplémentaires avec (jusqu'à un total de cinq attaques Rafale de coups), à condition que chaque attaque Rafale de coups cible une créature différente ce tour-ci.","name_en":"Intoxicated Frenzy"}],"name_en":"Monk: Way of the Drunken Master","_translated":true},{"index":"monk-four-elements","name":"Moine : Voie des Quatre Éléments","class":"monk","source":"Player's Handbook","subclass_flavor":"Vous suivez une tradition monastique qui vous apprend à maîtriser les éléments. Lorsque vous concentrez votre ki, vous pouvez vous aligner sur les forces de création et plier les quatre éléments à votre volonté, en les utilisant comme une extension de votre corps. Certains membres de cette tradition se consacrent à un seul élément, mais d'autres tissent les éléments ensemble.","desc":"","features":[{"name":"Disciple des éléments","level":3,"desc":"Lorsque vous choisissez cette tradition au niveau 3, vous apprenez des disciplines magiques qui exploitent la puissance des quatre éléments. Une discipline vous oblige à dépenser des points de ki à chaque fois que vous l'utilisez.\n\nVous connaissez la discipline d'harmonisation élémentaire et une autre discipline élémentaire de votre choix. Vous apprenez une discipline élémentaire supplémentaire de votre choix aux niveaux 6, 11 et 17.\n\nChaque fois que vous apprenez une nouvelle discipline élémentaire, vous pouvez également remplacer une discipline élémentaire que vous connaissez déjà par une discipline différente.\n\nLancer des sorts élémentaires. Certaines disciplines élémentaires permettent de lancer des sorts. Voir le chapitre 10 pour les règles générales du lancement de sorts. Pour lancer l'un de ces sorts, vous utilisez son temps d'incantation et d'autres règles, mais vous n'avez pas besoin de lui fournir de composants matériels.\n\nUne fois que vous atteignez le niveau 5 dans cette classe, vous pouvez dépenser des points de ki supplémentaires pour augmenter le niveau d'un sort de discipline élémentaire que vous lancez, à condition que le sort ait un effet amélioré à un niveau supérieur, comme le fait Burning Hands. Le niveau du sort augmente de 1 pour chaque point de ki supplémentaire dépensé. Par exemple, si vous êtes un moine de niveau 5 et que vous utilisez Frappe de cendre balayante pour lancer Mains brûlantes, vous pouvez dépenser 3 points de ki pour le lancer comme un sort de niveau 2 (le coût de base de la discipline est de 2 points de ki plus 1).\n\nLe nombre maximum de points ki que vous pouvez dépenser pour lancer un sort de cette manière (y compris son coût de base en points ki et tous les points ki supplémentaires que vous dépensez pour augmenter son niveau) est déterminé par votre niveau de moine, comme indiqué dans le tableau des sorts et des points Ki.\nSorts et points Ki\nNiveaux de moine | Points Ki maximum pour un sort\n5e-8e | 3\n9-12 | 4\n13-16 | 5\n17-20 | 6","name_en":"Disciple of the Elements"}],"name_en":"Monk: Way of the Four Elements","_translated":true},{"index":"monk-kensei","name":"Moine : Voie du Kensei","class":"monk","source":"Xanathar's Guide to Everything","subclass_flavor":"Les moines de la Voie du Kensei s'entraînent sans relâche avec leurs armes, au point que l'arme devient comme une extension du corps. Fondée sur la maîtrise du combat à l’épée, la tradition s’est élargie pour inclure de nombreuses armes différentes.","desc":"","features":[{"name":"Chemin du Kensei","level":3,"desc":"Lorsque vous choisissez cette tradition au niveau 3, votre formation particulière en arts martiaux vous amène à maîtriser l'usage de certaines armes. Ce parcours comprend également un enseignement des traits habiles de la calligraphie ou de la peinture. Vous bénéficiez des avantages suivants :\n• Armes Kensei. Choisissez deux types d'armes comme armes kensei : une arme de mêlée et une arme à distance. Chacune de ces armes peut être n’importe quelle arme simple ou martiale dépourvue de propriétés lourdes et spéciales. L'arc long est également un choix valable. Vous maîtrisez ces armes si vous ne les possédez pas déjà. Les armes des types choisis sont des armes de moine pour vous. La plupart des fonctionnalités de cette tradition ne fonctionnent qu'avec vos armes Kensei. Lorsque vous atteignez les niveaux 6, 11 et 17 dans cette classe, vous pouvez choisir un autre type d'arme – de mêlée ou à distance – comme arme de kensei, en suivant les critères ci-dessus.\n• Parade agile. Si vous effectuez une frappe à mains nues dans le cadre de l'action d'attaque de votre tour et que vous tenez une arme kensei, vous pouvez l'utiliser pour vous défendre s'il s'agit d'une arme de mêlée. Vous gagnez un bonus de +2 à la CA jusqu’au début de votre prochain tour, tant que l’arme est dans votre main et que vous n’êtes pas incapable d’agir.\n• Le tir de Kensei. Vous pouvez utiliser une action bonus à votre tour pour rendre vos attaques à distance avec une arme kensei plus meurtrières. Lorsque vous faites cela, toute cible touchée avec une attaque à distance utilisant une arme Kensei subit 1d4 dégâts supplémentaires du type de l'arme. Vous conservez cet avantage jusqu'à la fin du tour en cours.\n• Chemin du Pinceau. Vous gagnez en maîtrise avec votre choix de fournitures de calligraphe ou de fournitures de peintre.","name_en":"Path of the Kensei"},{"name":"Un avec la lame","level":6,"desc":"Au niveau 6, vous étendez votre ki dans vos armes Kensei, vous accordant les avantages suivants.\n• Armes magiques Kensei. Vos attaques avec vos armes Kensei sont considérées comme magiques dans le but de vaincre la résistance et l'immunité aux attaques et dégâts non magiques.\n• Frappe habile. Lorsque vous touchez une cible avec une arme Kensei, vous pouvez dépenser 1 point ki pour que l'arme inflige des dégâts supplémentaires à la cible égaux à votre dé d'arts martiaux. Vous ne pouvez utiliser cette fonctionnalité qu’une seule fois à chacun de vos tours.","name_en":"One with the Blade"},{"name":"Affûter la lame","level":11,"desc":"Au niveau 11, vous obtenez la possibilité d'augmenter davantage vos armes avec votre ki. En tant qu'action bonus, vous pouvez dépenser jusqu'à 3 points de ki pour accorder à une arme Kensei que vous touchez un bonus aux jets d'attaque et de dégâts lorsque vous attaquez avec elle. Le bonus est égal au nombre de points ki que vous avez dépensés. Ce bonus dure 1 minute ou jusqu'à ce que vous utilisiez à nouveau cette fonctionnalité. Cette fonctionnalité n'a aucun effet sur une arme magique qui possède déjà un bonus aux jets d'attaque et de dégâts.","name_en":"Sharpen the Blade"},{"name":"Précision infaillible","level":17,"desc":"Au niveau 17, votre maîtrise des armes vous confère une précision extraordinaire. Si vous ratez un jet d'attaque utilisant une arme de moine à votre tour, vous pouvez le relancer. Vous ne pouvez utiliser cette fonctionnalité qu’une seule fois à chacun de vos tours.","name_en":"Unerring Accuracy"}],"name_en":"Monk: Way of the Kensei","_translated":true},{"index":"monk-living-weapon","name":"Moine : Voie de l'arme vivante (HB)","class":"monk","source":"Exploring Eberron","subclass_flavor":"Un moine suivant la Voie de l'Arme Vivante recherche la perfection physique, aiguisant son corps comme un forgeron aiguise une épée. Ses traditions sont tirées de cultures de métamorphes et de créatures qui se battent avec leurs dents et leurs griffes. Ce sont quelques-unes des techniques martiales qui ont évolué vers la Voie de l’Arme Vivante.","desc":"Un moine suivant la Voie de l'Arme Vivante recherche la perfection physique, aiguisant son corps comme un forgeron aiguise une épée. Ses traditions sont tirées de cultures de métamorphes et de créatures qui se battent avec leurs dents et leurs griffes. Ce sont quelques-unes des techniques martiales qui ont évolué vers la Voie de l’Arme Vivante.","features":[{"name":"Poings d'os et d'acier","level":3,"desc":"Au niveau 3, lorsque vous choisissez cette tradition, votre dé de dégâts d'Arts Martiaux augmente pour les frappes à mains nues. Vous pouvez lancer un d6 à la place des dégâts normaux de votre frappe à mains nues. Ce dé se transforme en d8 au niveau 5 ; un d10 au niveau 11 ; et un d12 au niveau 17. Cette augmentation des dégâts ne peut être appliquée qu'à une frappe à mains nues, et non à une arme de moine.","name_en":"Fists of Bone and Steel"},{"name":"Discipline martiale","level":3,"desc":"Dès le niveau 3, lorsque vous adoptez cette tradition, choisissez une discipline et gagnez sa particularité.\n• Cœur Forgé. Vos frappes à mains nues sont considérées comme des armes adamantines. De plus, lorsque vous touchez une créature avec une attaque à mains nues, vous pouvez dépenser 1 point de ki pour lui faire effectuer un jet de sauvegarde de Force. En cas d'échec, la créature subit 2d6 dégâts supplémentaires du même type que la frappe à mains nues et peut être repoussée jusqu'à 4,50 mètres de vous. En cas de sauvegarde réussie, la créature ne subit que 1d6 points de dégâts supplémentaires et n'est pas repoussée.\n• Linceul de cauchemar. Lorsque vous touchez une créature avec une attaque à mains nues, vous pouvez dépenser 1 point de ki pour l'assaillir de peur, lui permettant ainsi d'effectuer un jet de sauvegarde de Sagesse. En cas d'échec, il subit 1d6 points de dégâts psychiques et a peur de vous jusqu'à la fin de votre prochain tour. Si une créature réussit ce jet, elle est immunisée contre l'effet de peur de cette capacité pendant 24 heures.\n�� Lame du voyageur. Votre portée s'étend de 5 pieds. De plus, au début de votre tour, vous pouvez dépenser jusqu'à 4 points de ki pour étendre davantage votre portée. Pour chaque point de ki que vous dépensez, votre portée s'étend de 1,50 mètre supplémentaire jusqu'à la fin de votre tour.\n• Nous avons été touchés. Une fois par tour, lorsque vous touchez une créature avec une attaque à mains nues, vous pouvez dépenser 1 point de ki pour déchirer votre cible et lui infliger de profondes blessures saignantes. Au début de chacun des tours de la créature pendant la minute suivante, elle subit 1d4 points de dégâts tranchants dus à cet effet. L'effet se termine plus tôt si la créature a un ou plusieurs points de vie restaurés, si une créature utilise son action pour dépenser une utilisation d'un kit de guérisseur, ou réussit un test de Sagesse (Médecine) avec un DD égal à votre DD de sauvegarde de ki. Lorsque vous atteignez le niveau 6, ces dégâts tranchants sont considérés comme magiques dans le but de vaincre la résistance et l'immunité aux attaques et dégâts non magiques.","name_en":"Martial Discipline"},{"name":"Frappe mutable","level":3,"desc":"Vous avez le pouvoir de modifier vos armes naturelles, de faire pousser des griffes ou de renforcer vos poings. À partir du niveau 3, lorsque vous utilisez les arts martiaux pour effectuer une frappe à mains nues, vous pouvez choisir si vous infligez des dégâts tranchants, contondants ou perçants avec l'attaque.","name_en":"Mutable Strike"},{"name":"Coup manifeste","level":6,"desc":"À partir du niveau 6, choisissez l'un des types de dégâts suivants à la fin d'un repos long : contondant, perçant, tranchant, froid, éclair, nécrotique, psychique ou tonnerre. À votre tour, la première créature que vous touchez avec une frappe à mains nues subit 1d6 points de dégâts supplémentaires de ce type. Si vous sélectionnez des dégâts contondants, perçants ou tranchants, ils bénéficient de votre fonctionnalité de classe Ki-Empowered Strikes et comptent comme des dégâts magiques. Les moines de Nightmare Shroud infligent généralement des dégâts psychiques avec cette capacité, les moines Forged Heart améliorent leurs dégâts contondants et les Weretouched ont des griffes plus acérées. Cependant, vous pouvez choisir n’importe quel type de dégâts, quelle que soit votre(vos) discipline(s).","name_en":"Manifest Blow"},{"name":"Adaptation réflexive","level":11,"desc":"À partir du niveau 11, lorsque vous effectuez un test de Force (Athlétisme) ou de Dextérité (Acrobatie), vous pouvez dépenser 1 point de ki pour lancer un d20 supplémentaire. Vous pouvez choisir d’utiliser cette capacité après avoir lancé le test, mais avant que le résultat ne soit déterminé. Vous choisissez lequel des d20 est utilisé pour le test de capacité, en omettant le plus élevé si ce test a été lancé avec un désavantage.\nDe plus, les dégâts supplémentaires infligés par la fonction de classe Manifest Blow passent à 2d6.","name_en":"Reflexive Adaptation"},{"name":"Forme parfaite","level":17,"desc":"Au niveau 17, vous transformez votre corps pour devenir une arme de guerre. Vous gagnez une fonctionnalité basée sur une discipline de votre choix. Vous pouvez choisir la même discipline que celle que vous avez sélectionnée au niveau 3 ou une autre.\n• Cœur Forgé. Lorsque vous êtes touché par une attaque, vous pouvez utiliser votre réaction pour ajouter votre modificateur de Sagesse (minimum de 1) à votre CA, y compris contre l'attaque déclenchante. Cet effet dure jusqu'au début de votre prochain tour.\n• Linceul de cauchemar. Lorsque vous blessez une créature avec votre Coup manifeste, l'excès d'énergie psionique se répercute sur jusqu'à 3 créatures différentes de votre choix dans un rayon de 9 mètres. Ces créatures subissent un montant de dégâts psychiques égal à la moitié de votre niveau de moine.\n• Lame du voyageur. Lorsque vous infligez des dégâts perçants ou tranchants à une créature avec une frappe à mains nues, elle subit 1d8 dégâts de poison supplémentaires et doit réussir un jet de sauvegarde de Constitution contre votre DD de sauvegarde de ki sous peine d'être empoisonnée jusqu'à la fin de son prochain tour.\n• Nous avons été touchés. Lorsque vous utilisez votre Rafale de coups, vous pouvez effectuer trois frappes à mains nues comme action bonus au lieu de deux. Vous avez l'avantage sur ces attaques.","name_en":"Perfect Form"}],"name_en":"Monk: Way of the Living Weapon (HB)","_translated":true},{"index":"monk-long-death","name":"Moine : Voie de la longue mort","class":"monk","source":"Sword Coast Adventurer's Guide","subclass_flavor":"Les moines de la Voie de la Longue Mort sont obsédés par le sens et les mécanismes de la mort. Ils capturent des créatures et préparent des expériences élaborées pour capturer, enregistrer et comprendre les moments de leur disparition. Ils utilisent ensuite ces connaissances pour guider leur compréhension des arts martiaux, créant ainsi un style de combat mortel.","desc":"","features":[{"name":"Toucher de la mort","level":3,"desc":"À partir du moment où vous choisissez cette tradition au niveau 3, votre étude de la mort vous permet d'extraire la vitalité d'une autre créature alors qu'elle approche de sa disparition. Lorsque vous réduisez une créature à moins de 1,50 mètre de vous à 0 point de vie, vous gagnez des points de vie temporaires égaux à votre modificateur de Sagesse + votre niveau de moine (minimum de 1 point de vie temporaire).","name_en":"Touch of Death"},{"name":"L'heure de la récolte","level":6,"desc":"Au niveau 6, vous gagnez la capacité de déstabiliser ou de terrifier ceux qui vous entourent par une action, car votre âme a été touchée par l'ombre de la mort. Lorsque vous effectuez cette action, chaque créature à moins de 9 mètres de vous et qui peut vous voir doit réussir un jet de sauvegarde de Sagesse ou avoir peur de vous jusqu'à la fin de votre prochain tour.","name_en":"Hour of Reaping"},{"name":"Maîtrise de la mort","level":11,"desc":"À partir du niveau 11, vous utilisez votre familiarité avec la mort pour échapper à son emprise. Lorsque vous êtes réduit à 0 point de vie, vous pouvez dépenser 1 point de ki (aucune action requise) pour avoir 1 point de vie à la place.","name_en":"Mastery of Death"},{"name":"Toucher de la longue mort","level":17,"desc":"À partir du niveau 17, votre contact peut canaliser l'énergie de la mort vers une créature. Par une action, vous touchez une créature à moins de 1,50 mètre de vous et vous dépensez 1 à 10 points de ki. La cible doit effectuer un jet de sauvegarde de Constitution, et elle subit 2d10 dégâts nécrotiques par point de ki dépensé en cas d'échec, ou la moitié de ces dégâts en cas de réussite.","name_en":"Touch of the Long Death"}],"name_en":"Monk: Way of the Long Death","_translated":true},{"index":"monk-open-hand","name":"Moine : Voie de la main ouverte","class":"monk","source":"Player's Handbook","subclass_flavor":"Les moines de la Voie de la Main Ouverte sont les maîtres ultimes du combat dans les arts martiaux, qu'ils soient armés ou non. Ils apprennent des techniques pour pousser et faire trébucher leurs adversaires, manipuler le ki pour soigner les dommages causés à leur corps et pratiquer une méditation avancée qui peut les protéger du mal.","desc":"","features":[{"name":"Technique de la main ouverte","level":3,"desc":"À partir du moment où vous choisissez cette tradition au niveau 3, vous pouvez manipuler le ki de votre ennemi lorsque vous exploitez le vôtre. À chaque fois que vous touchez une créature avec l'une des attaques accordées par votre Rafale de coups, vous pouvez imposer l'un des effets suivants à cette cible :\n• Il doit réussir un jet de sauvegarde de Dextérité ou être mis à terre.\n• Il doit effectuer un jet de sauvegarde de Force. S'il échoue, vous pouvez le pousser jusqu'à 15 pieds de vous.\n• Il ne peut pas réagir avant la fin de votre prochain tour.","name_en":"Open Hand Technique"},{"name":"Intégrité du corps","level":6,"desc":"Au niveau 6, vous gagnez la capacité de vous soigner. Par une action, vous pouvez récupérer des points de vie égaux à trois fois votre niveau de moine. Vous devez terminer un long repos avant de pouvoir utiliser à nouveau cette fonctionnalité.","name_en":"Wholeness of Body"},{"name":"Tranquillité","level":11,"desc":"À partir du niveau 11, vous pouvez entrer dans une méditation spéciale qui vous entoure d’une aura de paix. À la fin d'un repos long, vous bénéficiez de l'effet d'un sort Sanctuaire qui dure jusqu'au début de votre prochain repos long (le sort peut se terminer plus tôt que d'habitude). Le DD du jet de sauvegarde du sort est égal à 8 + votre modificateur de Sagesse + votre bonus de maîtrise.","name_en":"Tranquility"},{"name":"Paume frémissante","level":17,"desc":"Au niveau 17, vous obtenez la capacité de créer des vibrations mortelles dans le corps de quelqu'un. Lorsque vous frappez une créature avec une frappe à mains nues, vous pouvez dépenser 3 points de ki pour déclencher ces vibrations imperceptibles, qui durent un nombre de jours égal à votre niveau de moine. Les vibrations sont inoffensives à moins que vous n'utilisiez votre action pour y mettre fin. Pour ce faire, vous et la cible devez être sur le même plan d’existence. Lorsque vous utilisez cette action, la créature doit effectuer un jet de sauvegarde de Constitution. En cas d'échec, il est réduit à 0 point de vie. S'il réussit, il subit 10d10 dégâts nécrotiques.\n\nVous ne pouvez avoir qu'une seule créature sous l'effet de cette fonctionnalité à la fois. Vous pouvez choisir de mettre fin aux vibrations de manière inoffensive sans recourir à une action.","name_en":"Quivering Palm"}],"name_en":"Monk: Way of the Open Hand","_translated":true},{"index":"monk-ascendant-dragon","name":"Voie du Dragon Ascendant","class":"monk","source":"Fizban's Treasury of Dragons","subclass_flavor":"L'enseignement fondamental de cette tradition veut qu'en imitant les dragons, un moine devient une partie plus intégrée du monde et de sa magie. En modifiant leur esprit pour qu'il résonne avec la puissance draconique, les moines qui suivent cette tradition augmentent leurs prouesses au combat, renforcent leurs alliés et peuvent même voler dans les airs sur des ailes draconiques. Mais toute cette puissance est au service d’un objectif plus vaste : parvenir à une unité spirituelle avec l’essence du plan Matériel.","desc":"En tant qu'adepte de cette tradition monastique, vous décidez comment vous débloquez le pouvoir des dragons grâce à votre ki. La table Ascendant Dragon Origin offre quelques possibilités.","features":[{"name":"Disciple draconique","level":3,"desc":"Au niveau 3, vous pouvez canaliser le pouvoir draconique pour amplifier votre présence et imprégner vos frappes à mains nues de l’essence du souffle d’un dragon. Vous bénéficiez des avantages suivants :\n• Présence draconique. Si vous échouez à un test de Charisme (Intimidation) ou de Charisme (Persuasion), vous pouvez utiliser votre réaction pour relancer le test, tout en profitant de la puissante présence des dragons. Une fois que cette fonctionnalité transforme un échec en succès, vous ne pouvez plus l'utiliser avant d'avoir terminé un long repos.\n• Frappe draconique. Lorsque vous endommagez une cible avec une frappe à mains nues, vous pouvez modifier le type de dégâts en acide, froid, feu, foudre ou poison.\n• Langue des Dragons. Vous apprenez à parler, lire et écrire le draconique ou une autre langue de votre choix.","name_en":"Draconic Disciple"},{"name":"Souffle du Dragon","level":3,"desc":"Au niveau 3, vous pouvez canaliser des vagues d'énergie destructrices, comme celles créées par les dragons que vous émulez. Lorsque vous effectuez l'action Attaque à votre tour, vous pouvez remplacer l'une des attaques par une expiration d'énergie draconique dans un cône de 20 pieds ou une ligne de 30 pieds et 5 pieds de large (votre choix). Choisissez un type de dégâts : acide, froid, feu, foudre ou poison. Chaque créature dans cette zone doit effectuer un jet de sauvegarde de Dextérité contre votre DD de sauvegarde de ki, subissant des dégâts du type choisi égaux à deux lancers de votre dé d'arts martiaux en cas d'échec, ou la moitié de dégâts en cas de réussite.\n\nAu niveau 11, les dégâts de cette fonctionnalité s'élèvent à trois lancers de votre dé d'arts martiaux.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long. Tant que vous n'avez aucune utilisation disponible, vous pouvez dépenser 2 points ki pour utiliser à nouveau cette fonctionnalité.","name_en":"Breath of the Dragon"},{"name":"Ailes déployées","level":6,"desc":"Au niveau 6, lorsque vous utilisez votre Pas du Vent, vous pouvez déployer des ailes draconiques spectrales depuis votre dos qui disparaissent à la fin de votre tour. Tant que les ailes existent, vous avez une vitesse de vol égale à votre vitesse de marche.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Wings Unfurled"},{"name":"Aspect du Wyrm","level":11,"desc":"Au niveau 11, le pouvoir de votre esprit draconique rayonne désormais de vous, protégeant vos alliés ou inspirant la peur chez vos ennemis. Par une action bonus, vous pouvez créer une aura de puissance draconique qui rayonne à 3 mètres de vous pendant 1 minute. Pendant toute la durée, vous bénéficiez de l'un des effets suivants de votre choix :\n• Présence effrayante. Lorsque vous créez cette aura, et par une action bonus lors des tours suivants, vous pouvez choisir une créature au sein de l'aura. La cible doit réussir un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de ki ou avoir peur de vous pendant 1 minute. La cible peut répéter le jet de sauvegarde à la fin de chacun de ses tours, mettant ainsi fin à l'effet sur elle-même en cas de réussite.\n• Résistance. Choisissez un type de dégâts lorsque vous activez cette aura : acide, froid, feu, foudre ou poison. Vous et vos alliés dans l’aura avez une résistance à ces dégâts.\n\nUne fois que vous avez créé cette aura, vous ne pouvez plus la recréer avant d’avoir terminé un long repos, à moins que vous ne dépensiez 3 points de ki pour la recréer.","name_en":"Aspect of the Wyrm"},{"name":"Aspect ascendant","level":17,"desc":"Au niveau 17, votre esprit draconique atteint son apogée. Vous bénéficiez des avantages suivants :\n• Augmenter la respiration. Lorsque vous utilisez votre Souffle du Dragon, vous pouvez dépenser 1 point de ki pour augmenter sa forme et sa puissance. L'expiration de l'énergie draconique devient soit un cône de 60 pieds, soit une ligne de 90 pieds de large (votre choix), et chaque créature dans cette zone subit des dégâts égaux à quatre lancers de votre dé d'arts martiaux en cas d'échec, ou la moitié de dégâts en cas de réussite.\n• Vision aveugle. Vous bénéficiez d'une vision aveugle jusqu'à 10 pieds. Dans cette plage, vous pouvez effectivement voir tout ce qui ne se trouve pas derrière une couverture totale, même si vous êtes aveuglé ou dans l’obscurité. De plus, vous pouvez voir une créature invisible dans cette portée, à moins que la créature ne réussisse à se cacher de vous.\n• Fureur explosive. Lorsque vous activez votre Aspect du Wyrm, une fureur draconique explose de vous. Choisissez n'importe quel nombre de créatures que vous pouvez voir dans votre aura. Chacune de ces créatures doit réussir un jet de sauvegarde de Dextérité contre votre DD de sauvegarde de ki ou subir 3d10 dégâts d'acide, de froid, de feu, de foudre ou de poison (votre choix).","name_en":"Ascendant Aspect"}],"name_en":"Way of the Ascendant Dragon","_translated":true},{"index":"paladin-conquest","name":"Paladin : Serment de conquête","class":"paladin","source":"Xanathar's Guide to Everything","subclass_flavor":"Le Serment de Conquête appelle les paladins qui recherchent la gloire au combat et la soumission de leurs ennemis. Il ne suffit pas à ces paladins de rétablir l’ordre. Ils doivent écraser les forces du chaos. Parfois appelés chevaliers tyrans ou marchands de fer, ceux qui prêtent ce serment se rassemblent en ordres sinistres qui servent les dieux ou les philosophies de guerre et de puissance bien ordonnée.","desc":"","features":[{"name":"Principes de conquête","level":null,"desc":"Un paladin qui prête ce serment a les principes de la conquête gravés sur le haut du bras.\n\nÉteignez la flamme de l’espoir. Il ne suffit pas de vaincre un ennemi au combat. Votre victoire doit être si écrasante que la volonté de combattre de vos ennemis soit brisée à jamais. Une lame peut mettre fin à une vie. La peur peut mettre fin à un empire.\n\nRègle avec une poigne de fer. Une fois que vous avez vaincu, ne tolérez aucune dissidence. Votre parole fait loi. Ceux qui y obéissent seront favorisés. Ceux qui le défieront seront punis comme exemple pour tous ceux qui pourraient le suivre.\n\nLa force avant tout. Vous gouvernerez jusqu'à ce qu'un plus fort surgisse. Ensuite, vous devez devenir plus puissant et relever le défi, ou tomber à votre propre ruine.","name_en":"Tenets of Conquest"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts de serment de conquête\nNiveau Paladin | Sorts\n3ème | Armure d'Agathys, Commandement\n5ème | Tenir une personne, une arme spirituelle\n9ème | Accorder la malédiction, la peur\n13e | Bête dominante, peau de pierre\n17e | Cloudkill, dominer la personne","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Présence conquérante. Vous pouvez utiliser votre Channel Divinity pour dégager une présence terrifiante. Par une action, vous forcez chaque créature de votre choix que vous pouvez voir dans un rayon de 9 mètres autour de vous à effectuer un jet de sauvegarde de Sagesse. En cas d'échec, une créature a peur de vous pendant 1 minute. La créature effrayée peut répéter ce jet de sauvegarde à la fin de chacun de ses tours, mettant ainsi fin à l'effet sur elle-même en cas de réussite.\n• Frappe guidée. Vous pouvez utiliser votre Channel Divinity pour frapper avec une précision surnaturelle. Lorsque vous effectuez un jet d'attaque, vous pouvez utiliser votre Canal Divinité pour gagner un bonus de +10 au jet. Vous faites ce choix après avoir vu le jet, mais avant que le DM ne vous dise si l'attaque réussit ou rate.","name_en":"Channel Divinity"},{"name":"Aura de conquête","level":7,"desc":"À partir du niveau 7, vous dégagez constamment une aura menaçante tant que vous n'êtes pas incapable d'agir. L'aura s'étend à 3 mètres de vous dans toutes les directions, mais pas à travers une couverture totale.\n\nSi une créature a peur de vous, sa vitesse est réduite à 0 tant qu'elle est dans l'aura, et cette créature subit des dégâts psychiques égaux à la moitié de votre niveau de paladin si elle commence son tour là-bas.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of Conquest"},{"name":"Réprimande méprisante","level":15,"desc":"À partir du niveau 15, ceux qui osent vous frapper sont punis psychiquement pour leur audace. Chaque fois qu'une créature vous frappe avec une attaque, cette créature subit des dégâts psychiques égaux à votre modificateur de Charisme (minimum de 1) si vous n'êtes pas incapable d'agir.","name_en":"Scornful Rebuke"},{"name":"Conquérant invincible","level":20,"desc":"Au niveau 20, vous acquérez la capacité d’exploiter des prouesses martiales extraordinaires. Par une action, vous pouvez devenir comme par magie un avatar de conquête, bénéficiant des avantages suivants pendant 1 minute :\n• Vous avez une résistance à tous les dégâts.\n• Lorsque vous effectuez l'action Attaque à votre tour, vous pouvez effectuer une attaque supplémentaire dans le cadre de cette action.\n• Vos attaques avec des armes de mêlée infligent un coup critique sur un résultat de 19 ou 20 au d20.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Invincible Conqueror"}],"name_en":"Paladin: Oath of Conquest","_translated":true},{"index":"paladin-devotion","name":"Paladin : Serment de dévotion","class":"paladin","source":"Player's Handbook","subclass_flavor":"Le serment de dévotion lie un paladin aux idéaux les plus élevés de justice, de vertu et d'ordre. Parfois appelés cavaliers, chevaliers blancs ou guerriers sacrés, ces paladins répondent à l'idéal du chevalier en armure étincelante, agissant avec honneur dans la poursuite de la justice et du bien commun. Ils se soumettent aux normes de conduite les plus élevées et certains, pour le meilleur ou pour le pire, imposent aux mêmes normes le reste du monde. Beaucoup de ceux qui prêtent ce serment sont dévoués aux dieux de la loi et du bien et utilisent les principes de leurs dieux comme mesure de leur dévotion. Ils considèrent les anges – les parfaits serviteurs du bien – comme leurs idéaux et incorporent des images d’ailes angéliques dans leurs casques ou leurs armoiries.","desc":"","features":[{"name":"Principes de dévotion","level":null,"desc":"Bien que les mots exacts et les restrictions du Serment de Dévotion varient, les paladins de ce serment partagent ces principes.\n\nHonnêteté. Ne mentez pas et ne trichez pas. Que ta parole soit ta promesse.\n\nCourage. N’ayez jamais peur d’agir, même si la prudence est de mise.\n\nCompassion. Aidez les autres, protégez les faibles et punissez ceux qui les menacent. Faites preuve de miséricorde envers vos ennemis, mais tempérez-la avec sagesse.\n\nHonneur. Traitez les autres avec équité et laissez vos actes honorables leur servir d’exemple. Faites le plus de bien possible en causant le moins de mal possible.\n\nDevoir. Soyez responsable de vos actes et de leurs conséquences, protégez ceux qui vous sont confiés et obéissez à ceux qui ont une juste autorité sur vous.","name_en":"Tenets of Devotion"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts de serment de dévotion\nNiveau Paladin | Sorts\n3ème | Protection contre le mal et le bien, sanctuaire\n5ème | Petite Restauration, Zone de Vérité\n9ème | Balise d'espoir, dissipe la magie\n13e | Liberté de circulation, gardienne de la foi\n17e | Commune, grève des flammes","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Arme sacrée. Par une action, vous pouvez imprégner une arme que vous tenez d’énergie positive, en utilisant votre Channel Divinity. Pendant 1 minute, vous ajoutez votre modificateur de Charisme aux jets d'attaque effectués avec cette arme (avec un bonus minimum de +1). L'arme émet également une lumière vive dans un rayon de 20 pieds et une lumière faible 20 pieds au-delà. Si l’arme n’est pas déjà magique, elle le devient pour la durée. Vous pouvez mettre fin à cet effet à votre tour dans le cadre de n'importe quelle autre action. Si vous ne tenez plus ou ne portez plus cette arme, ou si vous perdez connaissance, cet effet prend fin.\n• Transformez l'Impie. En guise d'action, vous présentez votre symbole sacré et prononcez une prière censurant les démons et les morts-vivants, en utilisant votre canal divinité. Chaque démon ou mort-vivant qui peut vous voir ou vous entendre dans un rayon de 9 mètres autour de vous doit effectuer un jet de sauvegarde de Sagesse. Si la créature échoue à son jet de sauvegarde, elle est retournée pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Une créature transformée doit passer son tour à essayer de s'éloigner le plus possible de vous, et elle ne peut pas volontairement se déplacer vers un espace situé à moins de 9 mètres de vous. Il ne peut pas non plus accepter de réactions. Pour son action, il peut utiliser uniquement l'action Dash ou tenter d'échapper à un effet qui l'empêche de bouger. S'il n'y a nulle part où se déplacer, la créature peut utiliser l'action Esquiver.","name_en":"Channel Divinity"},{"name":"Aura de dévotion","level":7,"desc":"À partir du niveau 7, vous et les créatures amies situées à moins de 3 mètres de vous ne pouvez plus être charmés tant que vous êtes conscient.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of Devotion"},{"name":"Pureté de l'Esprit","level":15,"desc":"À partir du niveau 15, vous êtes toujours sous l’effet d’un sort Protection contre le Mal et le Bien.","name_en":"Purity of Spirit"},{"name":"Nimbus sacré","level":20,"desc":"Au niveau 20, par une action, vous pouvez émettre une aura de soleil. Pendant 1 minute, une lumière vive brille autour de vous dans un rayon de 9 mètres, et une lumière faible brille 9 mètres au-delà.\n\nChaque fois qu'une créature ennemie commence son tour sous une lumière vive, elle subit 10 dégâts radiants.\n\nDe plus, pendant toute la durée, vous bénéficiez d'un avantage aux jets de sauvegarde contre les sorts lancés par des démons ou des morts-vivants.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Holy Nimbus"}],"name_en":"Paladin: Oath of Devotion","_translated":true},{"index":"paladin-glory","name":"Paladin : Serment de gloire","class":"paladin","source":"Mythic Odysseys of Theros, Tasha's Cauldron of Everything","subclass_flavor":"","desc":"Les Paladins qui prêtent le Serment de Gloire croient qu'eux et leurs compagnons sont destinés à atteindre la gloire grâce à des actes d'héroïsme. Ils s'entraînent assidûment et encouragent leurs compagnons afin qu'ils soient tous prêts lorsque le destin les appelle.","features":[{"name":"Principes de gloire","level":null,"desc":"Les principes du Serment de Gloire poussent un paladin à tenter des actes héroïques qui pourraient un jour briller dans la légende.\n\nLes actions plutôt que les mots. Efforcez-vous d’être connu par des actes glorieux, pas par des mots.\n\nLes défis ne sont que des tests. Affrontez les difficultés avec courage et encouragez vos alliés à les affronter avec vous.\n\nAffûtez le corps. Comme la pierre brute, votre corps doit être travaillé pour que son potentiel se réalise.\n\nDisciplinez l’âme. Vous devez faire preuve de discipline pour surmonter vos échecs qui menacent de ternir votre gloire et celle de vos amis.","name_en":"Tenets Of Glory"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts de serment de gloire\nNiveau Paladin | Sorts\n3ème | Trait de guidage, héroïsme\n5ème | Améliorer la capacité, arme magique\n9ème | Hâte, protection contre l'énergie\n13e | Contrainte, Liberté De Mouvement\n17e | Commune, grève des flammes","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes. Consultez la fonctionnalité de classe Sacred Oath pour savoir comment fonctionne Channel Divinity.\n• Athlète hors pair. En tant qu'action bonus, vous pouvez utiliser votre Channel Divinity pour augmenter vos qualités athlétiques. Pendant les 10 prochaines minutes, vous avez l'avantage aux tests de Force (Athlétisme) et de Dextérité (Acrobatie) ; vous pouvez porter, pousser, traîner et soulever deux fois plus de poids que d'habitude ; et la distance de vos sauts en longueur et en hauteur augmente de 10 pieds (cette distance supplémentaire coûte du mouvement normalement).\n• Châtiment inspirant. Immédiatement après avoir infligé des dégâts à une créature avec votre fonction Châtiment divin, vous pouvez utiliser votre Canalisation de la Divinité comme une action bonus et distribuer des points de vie temporaires aux créatures de votre choix dans un rayon de 9 mètres autour de vous, qui peuvent vous inclure. Le nombre total de points de vie temporaires est égal à 2d8 + votre niveau dans cette classe, répartis entre les créatures choisies comme bon vous semble.","name_en":"Channel Divinity"},{"name":"Aura d'empressement","level":7,"desc":"Au niveau 7, vous dégagez une aura qui vous remplit, vous et vos compagnons, d'une vitesse surnaturelle, vous permettant de courir en formation sur un champ de bataille. Votre vitesse de marche augmente de 10 pieds. De plus, si vous n'êtes pas incapable d'agir, la vitesse de marche de tout allié qui commence son tour à moins de 1,50 mètre de vous augmente de 10 pieds jusqu'à la fin de ce tour.\n\nLorsque vous atteignez le niveau 18 dans cette classe, la portée de l'aura augmente jusqu'à 3 mètres.","name_en":"Aura of Alacrity"},{"name":"Défense glorieuse","level":null,"desc":"Lorsque vous atteignez le niveau 15, vous pouvez transformer la défense en une frappe soudaine. Lorsque vous ou une autre créature que vous pouvez voir à moins de 3 mètres de vous êtes touché par un jet d'attaque, vous pouvez utiliser votre réaction pour accorder un bonus à la CA de la cible contre cette attaque, la faisant potentiellement rater. Le bonus est égal à votre modificateur de Charisme (minimum de +1). Si l'attaque échoue, vous pouvez lancer une attaque avec votre arme contre l'attaquant dans le cadre de cette réaction, à condition que l'attaquant soit à portée de votre arme.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Charisme (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Glorious Defense"},{"name":"Légende vivante","level":20,"desc":"Au niveau 20, vous pouvez vous enrichir des légendes – vraies ou exagérées – de vos grandes actions. Par une action bonus, vous bénéficiez des avantages suivants pendant 1 minute :\n• Vous bénéficiez d'une présence surnaturelle qui vous permet d'obtenir un avantage à tous les tests de Charisme.\n• Une fois à chacun de vos tours, lorsque vous effectuez une attaque avec une arme et que vous la ratez, vous pouvez faire en sorte que cette attaque frappe à la place.\n• Si vous échouez à un jet de sauvegarde, vous pouvez utiliser votre réaction pour le relancer. Vous devez utiliser ce nouveau jet.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort de niveau 5 pour l'utiliser à nouveau.","name_en":"Living Legend"}],"name_en":"Paladin: Oath of Glory","_translated":true},{"index":"paladin-redemption","name":"Paladin : Serment de rédemption","class":"paladin","source":"Xanathar's Guide to Everything","subclass_flavor":"Le Serment de Rédemption place le paladin sur un chemin difficile, qui oblige le guerrier sacré à n'utiliser la violence qu'en dernier recours. Les paladins qui se consacrent à ce serment croient que n’importe qui peut être racheté et que le chemin de la bienveillance et de la justice est accessible à tous. Ces paladins affrontent des créatures maléfiques dans l'espoir de les transformer vers la lumière, et les paladins ne les tuent que lorsqu'un tel acte sauvera clairement d'autres vies. Les paladins qui suivent cette voie sont appelés rédempteurs.","desc":"","features":[{"name":"Principes de rédemption","level":null,"desc":"Les principes du Serment de Rédemption imposent au paladin un haut niveau de paix et de justice.\n\nPaix. La violence est une arme de dernier recours. La diplomatie et la compréhension sont les voies d’une paix durable.\n\nInnocence. Tous les gens commencent leur vie dans un état d’innocence, et c’est leur environnement ou l’influence des forces obscures qui les pousse au mal. En donnant le bon exemple et en travaillant à panser les blessures d’un monde profondément imparfait, vous pouvez mettre n’importe qui sur la bonne voie.\n\nPatience. Le changement prend du temps. Ceux qui ont suivi le chemin des méchants doivent recevoir des rappels pour qu’ils restent honnêtes et fidèles. Une fois que vous avez semé la graine de la justice dans une créature, vous devez travailler jour après jour pour lui permettre de survivre puis de s’épanouir.\n\nSagesse. Votre cœur et votre esprit doivent rester clairs, car vous finirez par être obligé d’admettre votre défaite. Bien que toutes les créatures puissent être rachetées, certaines sont si loin sur le chemin du mal que vous n’avez d’autre choix que de mettre fin à leurs jours pour le plus grand bien. Une telle action doit être soigneusement pesée et ses conséquences pleinement comprises, mais une fois que vous avez pris la décision, suivez-la en sachant que votre chemin est juste.","name_en":"Tenets of Redemption"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts du Serment de Rédemption\nNiveau Paladin | Sorts\n3ème | Sanctuaire, Sommeil\n5ème | Calmer les émotions, tenir la personne\n9ème | Contresort, motif hypnotique\n13e | Sphère résiliente d'Otiluke, peau de pierre\n17e | Tenez le monstre, le mur de force","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Émissaire de la Paix. Vous pouvez utiliser votre Channel Divinity pour augmenter votre présence avec un pouvoir divin. Par une action bonus, vous vous accordez un bonus de +5 aux tests de Charisme (Persuasion) pendant les 10 prochaines minutes.\n• Réprimandez les violents. Vous pouvez utiliser votre Channel Divinity pour réprimander ceux qui recourent à la violence. Immédiatement après qu'un attaquant à moins de 9 mètres de vous inflige des dégâts avec une attaque contre une créature autre que vous, vous pouvez utiliser votre réaction pour forcer l'attaquant à effectuer un jet de sauvegarde de Sagesse. En cas d'échec, l'attaquant subit des dégâts radiants égaux aux dégâts qu'il vient d'infliger. En cas de sauvegarde réussie, les dégâts sont réduits de moitié.","name_en":"Channel Divinity"},{"name":"Aura du Gardien","level":7,"desc":"À partir du niveau 7, vous pouvez protéger vos alliés au détriment de votre propre santé. Lorsqu'une créature à moins de 3 mètres de vous subit des dégâts, vous pouvez utiliser votre réaction pour subir ces dégâts par magie, au lieu que cette créature les subisse. Cette fonctionnalité ne transfère aucun autre effet qui pourrait accompagner les dégâts, et ces dégâts ne peuvent en aucun cas être réduits.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of the Guardian"},{"name":"Esprit protecteur","level":15,"desc":"À partir du niveau 15, une présence sacrée panse vos blessures au combat. Vous récupérez des points de vie égaux à 1d6 + la moitié de votre niveau de paladin si vous terminez votre tour en combat avec moins de la moitié de vos points de vie restants et que vous n'êtes pas incapable d'agir.","name_en":"Protective Spirit"},{"name":"Émissaire de la Rédemption","level":20,"desc":"Au niveau 20, vous devenez un avatar de la paix, ce qui vous confère deux avantages :\n• Vous avez une résistance à tous les dégâts infligés par d'autres créatures (leurs attaques, sorts et autres effets).\n• Chaque fois qu'une créature vous frappe avec une attaque, elle subit des dégâts radiants égaux à la moitié des dégâts que vous subissez de l'attaque.\n\nSi vous attaquez une créature, lancez un sort sur elle ou lui infligez des blessures par un autre moyen que cette fonctionnalité, aucun des avantages ne fonctionne contre cette créature tant que vous n'avez pas terminé un repos long.","name_en":"Emissary of Redemption"}],"name_en":"Paladin: Oath of Redemption","_translated":true},{"index":"paladin-ancients","name":"Paladin : Serment des Anciens","class":"paladin","source":"Player's Handbook","subclass_flavor":"Le Serment des Anciens est aussi vieux que la race des elfes et les rituels des druides. Parfois appelés chevaliers féeriques, chevaliers verts ou chevaliers à cornes, les paladins qui prêtent ce serment se sont rangés du côté de la lumière dans la lutte cosmique contre les ténèbres parce qu'ils aiment les choses belles et vivifiantes du monde, pas nécessairement parce qu'ils croient aux principes d'honneur, de courage et de justice. Ils ornent leur armure et leurs vêtements d'images d'objets en croissance - feuilles, bois ou fleurs - pour refléter leur engagement à préserver la vie et la lumière dans le monde.","desc":"","features":[{"name":"Principes des Anciens","level":null,"desc":"Les principes du Serment des Anciens ont été préservés pendant d'innombrables siècles. Ce serment met l'accent sur les principes du bien avant toute préoccupation de loi ou de chaos. Ses quatre principes centraux sont simples.\n\nAllumez la Lumière. Par vos actes de miséricorde, de gentillesse et de pardon, allumez la lumière de l’espoir dans le monde, repoussant le désespoir.\n\nAbritez la Lumière. Là où il y a du bien, de la beauté, de l’amour et du rire dans le monde, opposez-vous à la méchanceté qui voudrait les avaler. Là où la vie s’épanouit, opposez-vous aux forces qui la rendraient stérile.\n\nPréservez votre propre lumière. Délectez-vous du chant et du rire, de la beauté et de l'art. Si vous laissez la lumière mourir dans votre propre cœur, vous ne pourrez pas la préserver dans le monde.\n\nSoyez la Lumière. Soyez un phare glorieux pour tous ceux qui vivent dans le désespoir. Laissez la lumière de votre joie et de votre courage briller dans toutes vos actions.","name_en":"Tenets of the Ancients"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSerment des sorts des Anciens\nNiveau Paladin | Sorts\n3ème | Frappe prenante, Parler avec les animaux\n5ème | Rayon de lune, pas brumeux\n9ème | Croissance des plantes, protection contre l'énergie\n13e | Tempête de verglas, peau de pierre\n17e | Communiquer avec la nature, Tree Stride","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• La colère de la nature. Vous pouvez utiliser votre Channel Divinity pour invoquer des forces primitives afin de piéger un ennemi. Par une action, vous pouvez faire surgir des vignes spectrales et atteindre une créature à moins de 3 mètres de vous que vous pouvez voir. La créature doit réussir un jet de sauvegarde de Force ou de Dextérité (au choix) ou être retenue. Bien qu'elle soit retenue par les vignes, la créature répète le jet de sauvegarde à la fin de chacun de ses tours. En cas de succès, il se libère et les vignes disparaissent.\n• Transformez les infidèles. Vous pouvez utiliser votre canal divinité pour prononcer des mots anciens qui sont douloureux à entendre pour les fées et les démons. Par une action, vous présentez votre symbole sacré, et chaque fée ou démon à moins de 9 mètres de vous et qui peut vous entendre doit effectuer un jet de sauvegarde de Sagesse. En cas d'échec de la sauvegarde, la créature est retournée pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Une créature transformée doit passer son tour à essayer de s'éloigner le plus possible de vous, et elle ne peut pas volontairement se déplacer vers un espace situé à moins de 9 mètres de vous. Il ne peut pas non plus accepter de réactions. Pour son action, il peut utiliser uniquement l'action Dash ou tenter d'échapper à un effet qui l'empêche de bouger. S'il n'y a nulle part où se déplacer, la créature peut utiliser l'action Esquiver. Si la véritable forme de la créature est masquée par une illusion, un changement de forme ou un autre effet, cette forme est révélée pendant sa transformation.","name_en":"Channel Divinity"},{"name":"Aura de protection","level":7,"desc":"À partir du niveau 7, la magie ancienne pèse si lourdement sur vous qu'elle forme une protection surnaturelle. Vous et les créatures amies situées à moins de 3 mètres de vous avez une résistance aux dégâts des sorts.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of Warding"},{"name":"Sentinelle éternelle","level":15,"desc":"À partir du niveau 15, lorsque vous êtes réduit à 0 point de vie et que vous n'êtes pas tué sur le coup, vous pouvez choisir de tomber à 1 point de vie à la place. Une fois que vous avez utilisé cette capacité, vous ne pouvez plus l'utiliser avant d'avoir terminé un long repos.\n\nDe plus, vous ne souffrez d’aucun des inconvénients de la vieillesse et vous ne pouvez pas vieillir comme par magie.","name_en":"Undying Sentinel"},{"name":"Champion aîné","level":20,"desc":"Au niveau 20, vous pouvez prendre la forme d’une ancienne force de la nature, en prenant l’apparence de votre choix. Par exemple, votre peau peut devenir verte ou prendre une texture semblable à celle d'une écorce, vos cheveux peuvent devenir feuillus ou mousseux, ou vous pouvez faire pousser des bois ou une crinière semblable à un lion.\n\nGrâce à votre action, vous subissez une transformation. Pendant 1 minute, vous bénéficiez des avantages suivants :\n• Au début de chacun de vos tours, vous regagnez 10 points de vie.\n• Chaque fois que vous lancez un sort de paladin ayant un temps d'incantation de 1 action, vous pouvez le lancer en utilisant une action bonus à la place.\n• Les créatures ennemies à moins de 3 mètres de vous ont un désavantage aux jets de sauvegarde contre vos sorts de paladin et vos options de canalisation de la divinité.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Elder Champion"}],"name_en":"Paladin: Oath of the Ancients","_translated":true},{"index":"paladin-crown","name":"Paladin : Serment de la Couronne","class":"paladin","source":"Sword Coast Adventurer's Guide","subclass_flavor":"Le serment de la Couronne est prêté aux idéaux de la civilisation, qu'il s'agisse de l'esprit d'une nation, de la fidélité à un souverain ou du service rendu à une divinité de la loi et de la gouvernance. Les paladins qui prêtent ce serment se consacrent au service de la société et, en particulier, des lois justes qui maintiennent la cohésion de la société. Ces paladins sont les gardiens vigilants des murs, luttant contre les marées chaotiques de la barbarie qui menacent de détruire tout ce que la civilisation a construit, et sont communément appelés gardiens, exemplaires ou sentinelles. Souvent, les paladins qui prêtent ce serment sont membres d'un ordre de chevalerie au service d'une nation ou d'un souverain, et prêtent serment dans le cadre de leur admission dans les rangs de l'ordre.","desc":"","features":[{"name":"Principes de la Couronne","level":null,"desc":"Les principes du serment de la Couronne sont souvent fixés par le souverain auquel son serment est prêté, mais mettent généralement l'accent sur les principes suivants.\n\nLoi. La loi est primordiale. C’est le mortier qui maintient ensemble les pierres de la civilisation et il doit être respecté.\n\nLoyauté. Votre parole est votre lien. Sans loyauté, les serments et les lois n’ont aucun sens.\n\nCourage. Vous devez être prêt à faire ce qui doit être fait pour le bien de l’ordre, même face à des obstacles insurmontables. Si vous n’agissez pas, qui le fera ?\n\nResponsabilité. Vous devez faire face aux conséquences de vos actes et vous êtes responsable de remplir vos devoirs et obligations.","name_en":"Tenets of the Crown"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSerment des sorts de la couronne\nNiveau Paladin | Sorts\n3ème | Commandement, duel forcé\n5ème | Lien de protection, zone de vérité\n9ème | Aura de vitalité, gardiens spirituels\n13e | Bannissement, gardien de la foi\n17e | Cercle de pouvoir, Geas","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Défi des champions. Par une action bonus, vous lancez un défi qui oblige d'autres créatures à se battre avec vous. Chaque créature de votre choix que vous pouvez voir à moins de 9 mètres de vous doit effectuer un jet de sauvegarde de Sagesse. En cas d'échec, une créature ne peut pas volontairement s'éloigner de plus de 9 mètres de vous. Cet effet prend fin sur la créature si vous êtes incapable d'agir ou mourez ou si la créature est à plus de 9 mètres de vous.\n• Renversez la tendance. Par une action bonus, vous pouvez renforcer les créatures blessées avec votre Channel Divinity. Chaque créature de votre choix qui peut vous entendre à moins de 9 mètres de vous récupère des points de vie égaux à 1d6 + votre modificateur de Charisme (minimum de 1) si elle n'a pas plus de la moitié de ses points de vie.","name_en":"Channel Divinity"},{"name":"L'allégeance divine","level":7,"desc":"À partir du niveau 7, lorsqu'une créature à moins de 1,50 mètre de vous subit des dégâts, vous pouvez utiliser votre réaction pour substituer par magie votre propre santé à celle de la créature ciblée, empêchant ainsi cette créature de subir les dégâts. Au lieu de cela, vous subissez les dégâts. Ces dommages ne peuvent en aucun cas être réduits ou évités.","name_en":"Divine Allegiance"},{"name":"Saint inflexible","level":15,"desc":"À partir du niveau 15, vous bénéficiez d’un avantage aux jets de sauvegarde pour éviter d’être paralysé ou étourdi.","name_en":"Unyielding Saint"},{"name":"Champion Exalté","level":20,"desc":"Au niveau 20, votre présence sur le champ de bataille est une source d'inspiration pour ceux qui se consacrent à votre cause. Vous pouvez utiliser votre action pour bénéficier des avantages suivants pendant 1 heure :\n• Vous avez une résistance aux dégâts contondants, perçants et tranchants des armes non magiques.\n• Vos alliés ont un avantage aux jets de sauvegarde contre la mort lorsqu'ils se trouvent à moins de 9 mètres de vous.\n• Vous avez un avantage aux jets de sauvegarde de Sagesse, tout comme vos alliés à moins de 9 mètres de vous.\n\nCet effet prend fin plus tôt si vous êtes frappé d'incapacité ou si vous mourez. Une fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Exalted Champion"}],"name_en":"Paladin: Oath of the Crown","_translated":true},{"index":"paladin-watchers","name":"Paladin : Serment des Veilleurs","class":"paladin","source":"Tasha's Cauldron of Everything","subclass_flavor":"Le Serment des Veilleurs oblige les paladins à protéger les royaumes mortels des prédations de créatures extraplanaires, dont beaucoup peuvent dévaster les soldats mortels. Ainsi, les Veilleurs aiguisent leur esprit, leur esprit et leur corps pour devenir les armes ultimes contre de telles menaces.","desc":"","features":[{"name":"Principes des observateurs","level":null,"desc":"Un paladin qui prête le Serment des Veilleurs jure de protéger les royaumes mortels des menaces d'un autre monde.\n\nVigilance. Les menaces auxquelles vous faites face sont rusées, puissantes et subversives. Soyez toujours attentif à leur corruption.\n\nLoyauté. N'acceptez jamais de cadeaux ou de faveurs de la part d'amis ou de ceux qui voyagent avec eux. Restez fidèle à votre ordre, à vos camarades et à votre devoir.\n\nDiscipline. Vous êtes le bouclier contre les terreurs sans fin qui se cachent au-delà des étoiles. Votre lame doit être toujours tranchante et votre esprit désireux de survivre à ce qui se trouve au-delà.","name_en":"Tenets of the Watchers"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSerment des sorts des observateurs\nNiveau Paladin | Sorts\n3ème | Alarme, détection de magie\n5ème | Moonbeam, voir l'invisibilité\n9ème | Contresort, non-détection\n13e | Aura de pureté, bannissement\n17e | Tenir le monstre, scrutation","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes. Consultez la fonctionnalité de classe Sacred Oath pour savoir comment fonctionne Channel Divinity.\n• Volonté de l'Observateur. Vous pouvez utiliser votre Channel Divinity pour investir votre présence du pouvoir protecteur de votre foi. Par une action, vous pouvez choisir un nombre de créatures que vous pouvez voir dans un rayon de 9 mètres autour de vous, jusqu'à un nombre égal à votre modificateur de Charisme (au minimum une créature). Pendant 1 minute, vous et les créatures choisies avez un avantage aux jets de sauvegarde d'Intelligence, de Sagesse et de Charisme.\n• Abjurez l'extraplanaire. Vous pouvez utiliser votre Channel Divinity pour fustiger les êtres surnaturels. Par une action, vous présentez votre symbole sacré et chaque aberration, céleste, élémentaire, féerique ou démoniaque à moins de 9 mètres de vous et qui peut vous entendre, vous devez effectuer un jet de sauvegarde de Sagesse. En cas d'échec de la sauvegarde, la créature est retournée pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Une créature transformée doit passer son tour à essayer de s'éloigner le plus possible de vous, et elle ne peut pas volontairement terminer son mouvement dans un espace situé à moins de 9 mètres de vous. Pour son action, il peut utiliser uniquement l'action Dash ou tenter d'échapper à un effet qui l'empêche de bouger. S'il n'y a nulle part où se déplacer, la créature peut effectuer l'action Esquiver.","name_en":"Channel Divinity"},{"name":"Aura de la Sentinelle","level":7,"desc":"Au niveau 7, vous dégagez une aura de vigilance alors que vous n'êtes pas incapable d'agir. Lorsque vous et toute créature de votre choix à moins de 3 mètres de vous lancez un jet d'initiative, vous gagnez tous un bonus d'initiative égal à votre bonus de maîtrise.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of the Sentinel"},{"name":"Réprimande vigilante","level":15,"desc":"Au niveau 15, vous avez appris à châtier quiconque ose user de séduction contre vous et vos protections. Chaque fois que vous ou une créature que vous pouvez voir à moins de 9 mètres de vous réussissez un jet de sauvegarde d'Intelligence, de Sagesse ou de Charisme, vous pouvez utiliser votre réaction pour infliger 2d8 + les dégâts de force de votre modificateur de Charisme à la créature qui a forcé le jet de sauvegarde.","name_en":"Vigilant Rebuke"},{"name":"Rempart mortel","level":20,"desc":"Au niveau 20, vous manifestez une étincelle de pouvoir divin pour défendre les royaumes mortels. Par une action bonus, vous bénéficiez des avantages suivants pendant 1 minute :\n• Vous obtenez une vision vraie avec une portée de 120 pieds.\n• Vous avez un avantage aux jets d'attaque contre les aberrations, les célestes, les élémentaires, les fées et les démons.\n• Lorsque vous touchez une créature avec un jet d'attaque et lui infligez des dégâts, vous pouvez également la forcer à effectuer un jet de sauvegarde de Charisme contre votre DD de sauvegarde de sort. En cas d'échec, la créature est bannie comme par magie dans son plan d'existence d'origine si elle n'y est pas actuellement. En cas de sauvegarde réussie, la créature ne peut pas être bannie par cette fonctionnalité pendant 24 heures.\n\nUne fois que vous avez utilisé cette action bonus, vous ne pouvez plus l'utiliser avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort de niveau 5 pour l'utiliser à nouveau.","name_en":"Mortal Bulwark"}],"name_en":"Paladin: Oath of the Watchers","_translated":true},{"index":"paladin-vengeance","name":"Paladin : Serment de vengeance","class":"paladin","source":"Player's Handbook","subclass_flavor":"Le serment de vengeance est un engagement solennel à punir ceux qui ont commis un péché grave. Lorsque les forces du mal massacrent des villageois sans défense, lorsqu'un peuple entier se retourne contre la volonté des dieux, lorsqu'une guilde de voleurs devient trop violente et trop puissante, lorsqu'un dragon se déchaîne dans la campagne, dans des moments comme ceux-ci, des paladins se lèvent et prêtent serment de vengeance pour réparer ce qui n'a pas fonctionné. Pour ces paladins – parfois appelés vengeurs ou chevaliers noirs – leur propre pureté n'est pas aussi importante que de rendre la justice.","desc":"","features":[{"name":"Principes de vengeance","level":null,"desc":"Les principes du Serment de Vengeance varient selon le paladin, mais tous tournent autour de la punition des malfaiteurs par tous les moyens nécessaires. Les paladins qui respectent ces principes sont prêts à sacrifier même leur propre droiture pour rendre justice à ceux qui font le mal, c'est pourquoi les paladins sont souvent d'alignement neutre ou loyalement neutre. Les principes fondamentaux des principes sont extrêmement simples.\n\nCombattez le plus grand mal. Face au choix entre combattre mes ennemis jurés ou combattre un mal moindre, je choisis le mal le plus grand.\n\nPas de pitié pour les méchants. Les ennemis ordinaires pourraient gagner ma miséricorde, mais pas mes ennemis jurés.\n\nPar tous les moyens nécessaires. Mes scrupules ne peuvent pas m’empêcher d’exterminer mes ennemis.\n\nRestitution. Si mes ennemis sèment la ruine dans le monde, c’est parce que je n’ai pas réussi à les arrêter. Je dois aider ceux qui ont été blessés par leurs méfaits.","name_en":"Tenets of Vengeance"},{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts du Serment de Vengeance\nNiveau Paladin | Sorts\n3ème | Bane, marque du chasseur\n5ème | Tenez la personne, Misty Step\n9ème | Hâte, protection contre l'énergie\n13e | Bannissement, porte dimensionnelle\n17e | Tenir le monstre, scrutation","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Abjurer l'ennemi. En guise d'action, vous présentez votre symbole sacré et prononcez une prière de dénonciation, en utilisant votre Divinité Canal. Choisissez une créature que vous pouvez voir à moins de 60 pieds de vous. Cette créature doit effectuer un jet de sauvegarde de Sagesse, à moins qu'elle ne soit immunisée contre la peur. Les démons et les morts-vivants sont désavantagés lors de ce jet de sauvegarde. En cas d'échec, la créature est effrayée pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Tant qu'elle est effrayée, la vitesse de la créature est de 0 et elle ne peut bénéficier d'aucun bonus à sa vitesse. En cas de sauvegarde réussie, la vitesse de la créature est réduite de moitié pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts.\n• Vœu d'inimitié. Par une action bonus, vous pouvez prononcer un vœu d'inimitié contre une créature que vous pouvez voir à moins de 3 mètres de vous, en utilisant votre Canal Divinité. Vous bénéficiez d'un avantage aux jets d'attaque contre la créature pendant 1 minute ou jusqu'à ce qu'elle tombe à 0 point de vie ou tombe inconsciente.","name_en":"Channel Divinity"},{"name":"Vengeur implacable","level":7,"desc":"Au niveau 7, votre concentration surnaturelle vous aide à bloquer la retraite d'un ennemi. Lorsque vous touchez une créature avec une attaque d'opportunité, vous pouvez vous déplacer jusqu'à la moitié de votre vitesse immédiatement après l'attaque et dans le cadre de la même réaction. Ce mouvement ne provoque pas d'attaques d'opportunité.","name_en":"Relentless Avenger"},{"name":"Âme de vengeance","level":15,"desc":"À partir du niveau 15, l'autorité avec laquelle vous prononcez votre vœu d'inimitié vous confère un plus grand pouvoir sur votre ennemi. Lorsqu'une créature sous l'effet de votre Vœu d'inimitié effectue une attaque, vous pouvez utiliser votre réaction pour lancer une attaque au corps à corps avec une arme contre cette créature si elle est à portée.","name_en":"Soul of Vengeance"},{"name":"Ange vengeur","level":20,"desc":"Au niveau 20, vous pouvez prendre la forme d’un vengeur angélique. Grâce à votre action, vous subissez une transformation. Pendant 1 heure, vous bénéficiez des avantages suivants :\n• Des ailes poussent dans votre dos et vous confèrent une vitesse de vol de 60 pieds.\n• Vous dégagez une aura de menace dans un rayon de 9 mètres. La première fois qu'une créature ennemie entre dans l'aura ou y commence son tour au cours d'un combat, la créature doit réussir un jet de sauvegarde de Sagesse ou avoir peur de vous pendant 1 minute ou jusqu'à ce qu'elle subisse des dégâts. Les jets d'attaque contre la créature effrayée ont un avantage.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Avenging Angel"}],"name_en":"Paladin: Oath of Vengeance","_translated":true},{"index":"paladin-oathbreaker","name":"Paladin : Briseur de serment","class":"paladin","source":"Dungeon Master's Guide","subclass_flavor":"Un briseur de serment est un paladin qui rompt ses serments sacrés pour poursuivre une sombre ambition ou servir une puissance maléfique. Quelle que soit la lumière qui brûlait dans le cœur du paladin, elle s'est éteinte. Il ne reste que l'obscurité.","desc":"","features":[{"name":"Sorts de serment","level":null,"desc":"Vous gagnez des sorts de serment aux niveaux de paladin indiqués.\nSorts de briseur de serment\nNiveau Paladin | Sorts\n3ème | Réprimande infernale, infliger des blessures\n5ème | Couronne de folie, ténèbres\n9ème | Animer les morts, accorder la malédiction\n13e | Fléau, Confusion\n17e | Contagion, personne dominante","name_en":"Oath Spells"},{"name":"Canal Divinité","level":3,"desc":"Lorsque vous prêtez ce serment au niveau 3, vous obtenez les deux options de canalisation divine suivantes.\n• Contrôlez les morts-vivants. Par une action, vous ciblez une créature mort-vivante que vous pouvez voir à moins de 9 mètres de vous. La cible doit effectuer un jet de sauvegarde de Sagesse. En cas d'échec de la sauvegarde, la cible doit obéir à vos ordres pendant les prochaines 24 heures, ou jusqu'à ce que vous utilisiez à nouveau cette option Channel Divinity. Un mort-vivant dont le niveau de défi est égal ou supérieur à votre niveau de paladin est immunisé contre cet effet.\n• Aspect épouvantable. Par une action, vous canalisez les émotions les plus sombres et les concentrez en une explosion de menace magique. Chaque créature de votre choix à moins de 9 mètres de vous doit effectuer un jet de sauvegarde de Sagesse si elle peut vous voir. En cas d'échec, la cible a peur de vous pendant 1 minute. Si une créature effrayée par cet effet termine son tour à plus de 9 mètres de vous, elle peut tenter un autre jet de sauvegarde de Sagesse pour mettre fin à l'effet sur elle.","name_en":"Channel Divinity"},{"name":"Aura de haine","level":7,"desc":"À partir du niveau 7, vous, ainsi que tous les démons et morts-vivants à moins de 3 mètres de vous, bénéficiez d'un bonus aux jets de dégâts des armes en mêlée égal à votre modificateur de Charisme (minimum de +1). Une créature ne peut bénéficier de cette fonctionnalité que d'un seul paladin à la fois.\n\nAu niveau 18, la portée de cette aura passe à 9 mètres.","name_en":"Aura of Hate"},{"name":"Résistance surnaturelle","level":15,"desc":"Au niveau 15, vous gagnez la résistance aux dégâts contondants, perçants et tranchants des armes non magiques.","name_en":"Supernatural Resistance"},{"name":"Seigneur de l'effroi","level":20,"desc":"Au niveau 20, vous pouvez, par une action, vous entourer d'une aura de tristesse qui dure 1 minute. L'aura réduit toute lumière vive dans un rayon de 9 mètres autour de vous pour atténuer la lumière. Chaque fois qu'un ennemi effrayé par vous commence son tour dans l'aura, il subit 4d10 dégâts psychiques. De plus, vous et toutes les créatures de votre choix dans l’aura êtes enveloppés dans une ombre plus profonde. Les créatures qui dépendent de la vue ont un désavantage aux jets d'attaque contre les créatures drapées dans cette ombre.\n\nTant que dure l'aura, vous pouvez utiliser une action bonus pendant votre tour pour amener les ombres de l'aura à attaquer une créature. Lancez une attaque magique au corps à corps contre la cible. Si l'attaque réussit, la cible subit des dégâts nécrotiques égaux à 3d10 + votre modificateur de Charisme.\n\nAprès avoir activé l'aura, vous ne pouvez plus le faire avant d'avoir terminé un long repos.","name_en":"Dread Lord"}],"name_en":"Paladin: Oathbreaker","_translated":true},{"index":"ranger-beast-master","name":"Ranger : Conclave des Maîtres des Bêtes","class":"ranger","source":"Player's Handbook","subclass_flavor":"L'archétype Beast Master incarne une amitié entre les races civilisées et les bêtes du monde. Unis dans leur concentration, la bête et le rôdeur travaillent comme un seul homme pour combattre les ennemis monstrueux qui menacent à la fois la civilisation et la nature sauvage. Imiter l’archétype Beast Master signifie s’engager envers cet idéal, en travaillant en partenariat avec un animal comme compagnon et ami.","desc":"","features":[{"name":"Compagnon du Ranger","level":3,"desc":"Au niveau 3, vous gagnez un compagnon bête qui vous accompagne dans vos aventures et est entraîné à combattre à vos côtés. Choisissez une bête qui n'est pas plus grande que Medium et qui a un indice de défi de 1/4 ou moins (l'annexe D du Manuel du joueur présente les statistiques du faucon, du dogue et de la panthère à titre d'exemples). Ajoutez votre bonus de maîtrise à la CA, aux jets d'attaque et de dégâts de la bête, ainsi qu'à tous les jets de sauvegarde et compétences qu'elle maîtrise. Son maximum de points de vie est égal à son maximum normal ou à quatre fois votre niveau de rôdeur, selon le plus élevé des deux. Comme toute créature, la bête peut dépenser des dés de vie pendant un court repos.\n\nLa bête obéit à vos ordres du mieux qu’elle peut. Il prend son tour à votre initiative. À votre tour, vous pouvez ordonner verbalement à la bête où se déplacer (aucune action de votre part). Vous pouvez utiliser votre action pour lui ordonner verbalement d'effectuer l'action Attaque, Dash, Désengagement ou Aide. Si vous ne donnez pas de commande, la bête effectue l’action Esquive. Une fois que vous disposez de la fonction Extra Attack, vous pouvez effectuer vous-même une attaque avec une arme lorsque vous commandez à la bête d'effectuer l'action d'attaque. Lorsque vous parcourez votre terrain préféré avec uniquement la bête, vous pouvez vous déplacer furtivement à un rythme normal.\n\nSi vous êtes frappé d'incapacité ou absent, la bête agit seule, en se concentrant sur votre protection et sur elle-même. La bête n'a jamais besoin de votre commandement pour utiliser sa réaction, comme lors d'une attaque d'opportunité.\n\nSi la bête meurt, vous pouvez en obtenir une autre en passant 8 heures en vous liant magiquement à une autre bête qui ne vous est pas hostile, soit du même type de bête qu'avant, soit une bête différente.","name_en":"Ranger's Companion"},{"name":"Compagnon primordial (facultatif)","level":null,"desc":"Cette fonctionnalité de 3ème niveau remplace la fonctionnalité Compagnon du Ranger.\n\nVous invoquez par magie une bête primitive, qui tire sa force de votre lien avec la nature. La bête est amicale avec vous et vos compagnons et obéit à vos ordres. Choisissez son bloc de statistiques - Bête de la Terre, Bête de la Mer ou Bête du Ciel - qui utilise votre bonus de maîtrise (PB) à plusieurs endroits. Vous déterminez également le type d’animal qu’est la bête, en choisissant un type approprié pour le bloc de statistiques. Quel que soit le type que vous choisissez, la bête porte des marques primitives, indiquant son origine mystique.\n\nEn combat, la bête agit pendant votre tour. Il peut se déplacer et utiliser sa réaction tout seul, mais la seule action qu'il effectue est l'action Esquiver, à moins que vous n'effectuiez une action bonus à votre tour pour lui ordonner d'effectuer une autre action. Cette action peut être une action dans son bloc de statistiques ou une autre action. Vous pouvez également sacrifier une de vos attaques lorsque vous effectuez l'action d'Attaque pour ordonner à la bête d'effectuer l'action d'Attaque. Si\nvous êtes incapable d'agir, la bête peut entreprendre n'importe quelle action de son choix, pas seulement Esquiver.\n\nSi la bête est morte au cours de la dernière heure, vous pouvez utiliser votre action pour la toucher et dépenser un emplacement de sort de niveau 1 ou supérieur. La bête revient à la vie après 1 minute avec tous ses points de vie restaurés. Lorsque vous terminez un long repos, vous pouvez invoquer une autre bête primitive. La nouvelle bête apparaît dans un espace inoccupé à moins de 1,50 mètre de vous, et vous choisissez son bloc de statistiques et son apparence. Si vous possédez déjà une bête issue de cette fonctionnalité, elle disparaît lorsque la nouvelle bête apparaît. La bête disparaît également si vous mourez.\nBête du pays\nBête moyenne\nClasse d'armure : 13 + PB (armure naturelle)\nPoints de vie : 5 + cinq fois votre niveau de rôdeur (la bête a un nombre de dés de vie [d8] égal à votre niveau de rôdeur)\nVitesse : 40 pieds, montée de 40 pieds.\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n14 (+2) | 14 (+2) | 15 (+2) | 8 (−1) | 14 (+2) | 11 (+0)\nSens : vision dans le noir à 18 pieds, perception passive 12\nLangues : comprend les langues que vous parlez\nDéfi : –\nBonus de compétence (PB) : équivaut à votre bonus\nCharge : si la bête se déplace d'au moins 20 pieds tout droit vers une cible et la frappe ensuite avec une attaque de masse au cours du même tour, la cible subit 1d6 dégâts tranchants supplémentaires. Si la cible est une créature, elle doit réussir un jet de sauvegarde de Force contre votre DD de sauvegarde de sort ou être mise à terre.\nLien primordial : vous pouvez ajouter votre bonus de compétence à n'importe quel test de capacité ou jet de sauvegarde effectué par la bête.\nActions\nMaul. Attaque au corps à corps avec une arme : votre modificateur d'attaque de sort pour toucher, atteindre 1,50 m, une cible. Touché : 1d8 + 2 + PB de dégâts tranchants.\nBête de la mer\nBête moyenne\nClasse d'armure : 13 + PB (armure naturelle)\nPoints de vie : 5 + cinq fois votre niveau de rôdeur (la bête a un nombre de dés de vie [d8] égal à votre niveau de rôdeur)\nVitesse : 5 pieds, nage 60 pieds.\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n14 (+2) | 14 (+2) | 15 (+2) | 8 (−1) | 14 (+2) | 11 (+0)\nSens : vision dans le noir à 18 pieds, perception passive 12\nLangues : comprend les langues que vous parlez\nDéfi : –\nBonus de compétence (PB) : équivaut à votre bonus\nAmphibie : La bête peut respirer à la fois de l'air et de l'eau.\nLien primordial : vous pouvez ajouter votre bonus de compétence à n'importe quel test de capacité ou jet de sauvegarde effectué par la bête.\nActions\nFrappe contraignante. Attaque au corps à corps avec une arme : votre modificateur d'attaque de sort pour toucher, atteindre 1,50 m, une cible. Touché : 1d6 + 2 + PB de dégâts perçants ou contondants (au choix), et la cible est agrippée (le DD d'évasion est égal au DD de votre sauvegarde de sort). Jusqu'à la fin de cette lutte, la bête ne peut pas utiliser cette attaque sur une autre cible.\nBête du ciel\nPetite bête\nClasse d'armure : 13 + PB (armure naturelle)\nPoints de vie : 4 + quatre fois votre niveau de rôdeur (la bête a un nombre de dés de vie [d6s] égal à votre niveau de rôdeur)\nVitesse : 10 pieds, vol 60 pieds.\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n6 (-2) | 16 (+3) | 13 (+1) | 8 (−1) | 14 (+2) | 11 (+0)\nSens : vision dans le noir à 18 pieds, perception passive 12\nLangues : comprend les langues que vous parlez\nDéfi : –\nBonus de compétence (PB) : équivaut à votre bonus\nSurvol : La bête ne provoque pas d'attaques d'opportunité lorsqu'elle vole hors de portée d'un ennemi.\nLien primordial : vous pouvez ajouter votre bonus de compétence à n'importe quel test de capacité ou jet de sauvegarde effectué par la bête.\nActions\nDéchiqueter. Attaque au corps à corps avec une arme : votre modificateur d'attaque de sort pour toucher, atteindre 1,50 m, une cible. Touché : 1d4 + 3 + PB dégâts tranchants.","name_en":"Primal Companion (Optional)"},{"name":"Formation exceptionnelle","level":7,"desc":"À partir du niveau 7, à n’importe lequel de vos tours où votre compagnon bête n’attaque pas, vous pouvez utiliser une action bonus pour ordonner à la bête d’effectuer l’action Dash, Se désengager ou Aider à son tour. De plus, les attaques de la bête sont désormais considérées comme magiques dans le but de vaincre la résistance et l’immunité aux attaques et dégâts non magiques.","name_en":"Exceptional Training"},{"name":"Fureur bestiale","level":11,"desc":"À partir du niveau 11, lorsque vous commandez à votre compagnon bête d’effectuer l’action Attaque, la bête peut effectuer deux attaques, ou elle peut effectuer l’action Multi-attaque si elle possède cette action.","name_en":"Bestial Fury"},{"name":"Partager des sorts","level":15,"desc":"À partir du niveau 15, lorsque vous lancez un sort vous ciblant, vous pouvez également affecter votre compagnon bête avec le sort si la bête se trouve à moins de 9 mètres de vous.","name_en":"Share Spells"}],"name_en":"Ranger: Beast Master Conclave","_translated":true},{"index":"ranger-drakewarden","name":"Ranger : Garde-Drake","class":"ranger","source":"Fizban's Treasury of Dragons","subclass_flavor":"Votre connexion au monde naturel prend la forme d’un esprit draconique, qui peut se manifester sous forme physique sous la forme d’un dragon. À mesure que vos pouvoirs grandissent, votre drake grandit également, passant d'un petit compagnon à quatre pattes à une majestueuse créature ailée suffisamment grande et forte pour que vous puissiez la chevaucher. En chemin, vous gagnez une part croissante du pouvoir impressionnant des dragons.","desc":"Votre connexion au monde naturel prend la forme d’un esprit draconique, qui peut se manifester sous forme physique sous la forme d’un dragon. À mesure que vos pouvoirs grandissent, votre drake grandit également, passant d'un petit compagnon à quatre pattes à une majestueuse créature ailée suffisamment grande et forte pour que vous puissiez la chevaucher. En chemin, vous gagnez une part croissante du pouvoir impressionnant des dragons.\n\nConsidérez la source de l’esprit draconique avec lequel vous êtes lié. La table Drakewarden Origin propose des exemples.","features":[{"name":"Cadeau draconique","level":3,"desc":"Au niveau 3, le lien que vous partagez avec votre drake crée une connexion avec l'espèce draconique, vous permettant de comprendre et de renforcer votre présence.\n\nVous bénéficiez des avantages suivants :\n• Thaumaturgie. Vous apprenez le cantrip Thaumaturgie, qui est un sort de rôdeur pour vous.\n• Langue des Dragons. Vous apprenez à parler, lire et écrire le draconique ou une autre langue de votre choix.","name_en":"Draconic Gift"},{"name":"Compagnon Drake","level":3,"desc":"Au niveau 3, par une action, vous pouvez invoquer comme par magie le drake qui vous est lié. Il apparaît dans un espace inoccupé de votre choix à moins de 9 mètres de vous.\n\nLe drake est amical avec vous et vos compagnons et obéit à vos ordres. Consultez ses statistiques de jeu dans le bloc de statistiques Drake Companion qui l'accompagne, qui utilise votre bonus de compétence (PB) à plusieurs endroits. Chaque fois que vous invoquez le drake, choisissez un type de dégâts répertorié dans son trait Essence draconique. Vous pouvez déterminer les caractéristiques cosmétiques du drake, comme sa couleur, la texture de ses écailles, ou tout effet visible de son Essence Draconique ; votre choix n'a aucun effet sur ses statistiques de jeu.\n\nAu combat, le drake partage votre nombre d'initiatives, mais il prend son tour immédiatement après le vôtre. Il peut se déplacer et utiliser sa réaction tout seul, mais la seule action qu'il entreprend à son tour est l'action d'Esquive, à moins que vous n'effectuiez une action bonus à votre tour pour lui ordonner d'effectuer une autre action. Cette action peut être une action dans son bloc de statistiques ou une autre action. Si vous êtes frappé d'incapacité, le drake peut entreprendre n'importe quelle action de son choix, pas seulement Esquiver.\n\nLe drake reste jusqu'à ce qu'il soit réduit à 0 point de vie, jusqu'à ce que vous utilisiez cette fonctionnalité pour invoquer à nouveau le drake, ou jusqu'à votre mort. Tout ce que le drake portait ou transportait est laissé derrière lui lorsque le drake disparaît.\n\nUne fois que vous avez invoqué le drake, vous ne pouvez plus le faire avant d'avoir terminé un long repos, à moins que vous ne dépensiez un emplacement de sort de niveau 1 ou supérieur pour l'invoquer.\nCompagnon Drake\nPetit dragon\nClasse d'armure : 14 + PB (armure naturelle)\nPoints de vie : 5 + cinq fois votre niveau de rôdeur (le drake a un nombre de dés de vie [d10s] égal à votre niveau de rôdeur)\nVitesse : 40 pieds.\nSTR | DEX | ESCROQUER | INT | SIE | CHA\n16 (+3) | 12 (+1) | 15 (+2) | 8 (−1) | 14 (+2) | 8 (−1)\nJets de sauvegarde : Dex +1 plus PB, Sag +2 plus PB\nImmunités aux dégâts : déterminées par le trait Essence draconique du drake\nSens : vision dans le noir à 18 pieds, perception passive 12\nLangues : draconique\nDéfi : le bonus de compétence (PB) est égal à votre bonus\nEssence draconique. Lorsque vous invoquez le drake, choisissez un type de dégâts : acide, froid, feu, foudre ou poison. Le type choisi détermine l’immunité aux dégâts du drake et les dégâts de son trait Infused Strikes.\nActions\nMordez. Attaque au corps à corps avec une arme : +3 plus PB pour toucher, atteignez 1,50 m, une cible. Touché : 1d6 plus dégâts perforants PB.\nRéactions\nFrappes infusées. Lorsqu'une autre créature à moins de 9 mètres du drake et qu'elle peut voir touche une cible avec une attaque avec une arme, le drake imprègne la frappe de son essence, faisant subir à la cible 1d6 dégâts supplémentaires du type déterminé par son essence draconique.","name_en":"Drake Companion"},{"name":"Lien de croc et d'écaille","level":7,"desc":"Au niveau 7, le lien que vous partagez avec votre drake s’intensifie, vous protégeant et attisant la fureur du drake. Lorsque vous invoquez votre drake, il lui pousse des ailes sur le dos et gagne une vitesse de vol égale à sa vitesse de marche.\n\nDe plus, lorsque votre drake est invoqué, vous et le drake bénéficiez des avantages suivants :\n\nMont Drake. Le canard atteint une taille moyenne. Reflétant votre lien spécial, vous pouvez utiliser le drake comme monture si votre taille est moyenne ou inférieure. Pendant que vous conduisez votre drake, il ne peut pas utiliser la vitesse de vol de cette fonctionnalité.\n\nCroc Magique. L’attaque de Morsure du drake inflige 1d6 dégâts supplémentaires du type choisi pour l’essence draconique du drake.\n\nRésistance. Vous gagnez une résistance au type de dégâts choisi pour l’essence draconique du drake.","name_en":"Bond of Fang and Scale"},{"name":"Le souffle de Drake","level":11,"desc":"Au niveau 11, par une action, vous pouvez expirer un cône de 9 mètres de souffle dommageable ou faire expirer votre drake. Choisissez des dégâts d’acide, de froid, de feu, de foudre ou de poison (votre choix ne doit pas nécessairement correspondre à l’essence draconique de votre drake). Chaque créature dans le cône doit effectuer un jet de sauvegarde de Dextérité contre votre DD de sauvegarde de sort, subissant 8d6 dégâts en cas d'échec, ou la moitié de ces dégâts en cas de réussite.\n\nCes dégâts passent à 10d6 lorsque vous atteignez le niveau 15 dans cette classe.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus le faire avant d'avoir terminé un repos long, à moins que vous ne dépensiez un emplacement de sort de niveau 3 ou supérieur pour l'utiliser à nouveau.","name_en":"Drake’s Breath"},{"name":"Lien parfait","level":15,"desc":"Au niveau 15, votre lien avec votre drake atteint le summum de sa puissance. Pendant que votre drake est invoqué, vous et le drake bénéficiez des avantages suivants :\n\nMorsure puissante. L’attaque de Morsure du drake inflige 1d6 dégâts supplémentaires du type choisi pour son Essence Draconique (pour un total de 2d6 dégâts supplémentaires).\n\nGrand Drake. Le canard atteint une taille de grande taille. Lorsque vous chevauchez votre drake, il n'est plus interdit d'utiliser la vitesse de vol de Bond of Fang and Scale.\n\nRésistance réflexive. Lorsque vous ou le drake subissez des dégâts alors que vous êtes à moins de 9 pieds l'un de l'autre, vous pouvez utiliser votre réaction pour vous donner, à vous-même ou au drake, une résistance à cette instance de dégâts. Vous pouvez utiliser cette réaction un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Perfected Bond"}],"name_en":"Ranger: Drakewarden","_translated":true},{"index":"ranger-fey-wanderer","name":"Ranger : Fey Wanderer","class":"ranger","source":"Tasha's Cauldron of Everything","subclass_flavor":"Une mystique féerique vous entoure, grâce à la bénédiction d'un archfée, aux fruits brillants que vous avez mangés d'un arbre parlant, à la source magique dans laquelle vous avez nagé ou à tout autre événement de bon augure. Quelle que soit la manière dont vous avez acquis votre magie féerique, vous êtes désormais un Fey Wanderer, un rôdeur qui représente à la fois le royaume des mortels et celui des fées. Tandis que vous parcourez le multivers, votre rire joyeux illumine le cœur des opprimés et vos prouesses martiales sèment la terreur chez vos ennemis, car grande est la gaieté des fées et terrible est leur fureur.","desc":"","features":[{"name":"Frappes épouvantables","level":3,"desc":"Au niveau 3, vous pouvez augmenter vos frappes d'armes avec une magie effrayante, tirée des creux sombres du Feywild. Lorsque vous touchez une créature avec une arme, vous pouvez infliger 1d4 dégâts psychiques supplémentaires à la cible, qui ne peut subir ces dégâts supplémentaires qu'une seule fois par tour.\n\nLes dégâts supplémentaires augmentent à 1d6 lorsque vous atteignez le niveau 11 dans cette classe.","name_en":"Dreadful Strikes"},{"name":"Magie du Vagabond Fey","level":3,"desc":"Également au niveau 3, vous apprenez un sort supplémentaire lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts Fey Wanderer. Chaque sort compte pour vous comme un sort de rôdeur, mais il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez.\nSorts Fey Wanderer | \nNiveau Ranger | Sort\n3ème | Personne de charme\n5ème | Étape brumeuse\n9ème | Dissiper la magie\n13e | Porte dimensionnelle\n17e | Induire en erreur\n\nVous possédez également une bénédiction surnaturelle provenant d’un allié féerique ou d’un lieu de pouvoir féerique. Choisissez votre bénédiction dans le tableau Feywild Gifts ou déterminez-la au hasard.\nCadeaux Feywild | \nd6 | Cadeau\n1 | Des papillons illusoires voltigent autour de vous pendant que vous prenez un repos court ou long.\n2 | Des fleurs fraîches et saisonnières poussent de vos cheveux à chaque aube.\n3 | Vous sentez légèrement la cannelle, la lavande, la muscade ou une autre herbe ou épice réconfortante.\n4 | Votre ombre danse alors que personne ne la regarde directement.\n5 | Des cornes ou des bois poussent de votre tête.\n6 | Votre peau et vos cheveux changent de couleur pour correspondre à la saison à chaque aube.","name_en":"Fey Wanderer Magic"},{"name":"Glamour d'un autre monde","level":3,"desc":"De plus, au niveau 3, vos qualités féeriques vous confèrent un charme surnaturel. En conséquence, chaque fois que vous effectuez un test de Charisme, vous gagnez un bonus au test égal à votre modificateur de Sagesse (minimum de +1).\n\nDe plus, vous maîtrisez l’une des compétences suivantes de votre choix : Tromperie, Performance ou Persuasion.","name_en":"Otherworldly Glamour"},{"name":"Torsion séduisante","level":7,"desc":"À partir du niveau 7, la magie du Feywild garde votre esprit. Vous avez l'avantage aux jets de sauvegarde contre le fait d'être charmé ou effrayé.\n\nDe plus, chaque fois que vous ou une créature que vous pouvez voir à moins de 120 pieds de vous réussissez un jet de sauvegarde contre le charme ou l'effroi, vous pouvez utiliser votre réaction pour forcer une autre créature que vous pouvez voir à moins de 120 pieds de vous à effectuer un jet de sauvegarde de Sagesse contre le DD de votre sort. Si la sauvegarde échoue, la cible est charmée ou effrayée par vous (au choix) pendant 1 minute. La cible peut répéter le jet de sauvegarde à la fin de chacun de ses tours, mettant ainsi fin à l'effet sur elle-même en cas de réussite.","name_en":"Beguiling Twist"},{"name":"Renforts Fey","level":11,"desc":"Au niveau 11, les cours royales du Feywild vous ont béni avec l'aide d'êtres féeriques : vous connaissez le sort Summon Fey. Il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez, et vous pouvez le lancer sans composant matériel. Vous pouvez également le lancer une fois sans utiliser d'emplacement de sort, et vous retrouvez la possibilité de le faire lorsque vous terminez un repos long.\n\nChaque fois que vous commencez à lancer le sort, vous pouvez le modifier pour qu'il ne nécessite pas de concentration. Si vous le faites, la durée du sort devient 1 minute pour ce lancement.","name_en":"Fey Reinforcements"},{"name":"Vagabond brumeux","level":null,"desc":"Lorsque vous atteignez le niveau 15, vous pouvez entrer et sortir du Feywild pour vous déplacer en un clin d'œil : vous pouvez lancer Misty Step sans dépenser d'emplacement de sort. Vous pouvez le faire un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.\n\nDe plus, chaque fois que vous lancez Misty Step, vous pouvez amener avec vous une créature volontaire que vous pouvez voir à moins de 1,50 mètre de vous. Cette créature se téléporte vers un espace inoccupé de votre choix à moins de 1,50 mètre de votre espace de destination.","name_en":"Misty Wanderer"}],"name_en":"Ranger: Fey Wanderer","_translated":true},{"index":"ranger-gloom-stalker","name":"Ranger : Conclave des Traqueurs Gloom","class":"ranger","source":"Xanathar's Guide to Everything","subclass_flavor":"Les traqueurs de l'obscurité sont chez eux dans les endroits les plus sombres : au plus profond de la terre, dans les ruelles sombres, dans les forêts vierges et partout où la lumière faiblit. La plupart des gens entrent dans de tels endroits avec appréhension, mais un traqueur des ténèbres s'aventure hardiment dans les ténèbres, cherchant à tendre une embuscade aux menaces avant qu'elles n'atteignent le reste du monde. De tels rôdeurs se trouvent souvent dans l'Outreterre, mais ils iront partout où le mal se cache dans l'ombre.","desc":"","features":[{"name":"Magie du Traqueur des Ténèbres","level":3,"desc":"À partir du niveau 3, vous apprenez un sort supplémentaire lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts de Gloom Stalker. Le sort compte comme un sort de rôdeur pour vous, mais il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez.\nSorts de traqueur des ténèbres\nNiveau Ranger | Sorts\n3ème | Se déguiser\n5ème | Tour de corde\n9ème | Peur\n13e | Une plus grande invisibilité\n17e | Apparent","name_en":"Gloom Stalker Magic"},{"name":"Embusqué de l'effroi","level":3,"desc":"Au niveau 3, vous maîtrisez l'art de l'embuscade. Vous pouvez vous accorder un bonus à vos jets d'initiative égal à votre modificateur de Sagesse.\n\nAu début de votre premier tour de chaque combat, votre vitesse de marche augmente de 3 mètres, et ce jusqu'à la fin de ce tour. Si vous effectuez l'action Attaque à ce tour, vous pouvez effectuer une attaque avec une arme supplémentaire dans le cadre de cette action. Si cette attaque réussit, la cible subit 1d8 dégâts supplémentaires du type de dégâts de l'arme.","name_en":"Dread Ambusher"},{"name":"Vue ombrale","level":3,"desc":"Au niveau 3, vous bénéficiez de la vision dans le noir jusqu'à une portée de 18 mètres. Si vous avez déjà la vision dans le noir de votre race, sa portée augmente de 9 mètres.\n\nVous savez également échapper aux créatures qui dépendent de la vision dans le noir. Dans l'obscurité, vous êtes invisible pour toute créature qui s'appuie sur la vision dans le noir pour vous voir dans cette obscurité.","name_en":"Umbral Sight"},{"name":"Esprit de fer","level":7,"desc":"Au niveau 7, vous avez perfectionné votre capacité à résister aux pouvoirs altérant l’esprit de votre proie. Vous gagnez la maîtrise des jets de sauvegarde de Sagesse. Si vous possédez déjà cette compétence, vous gagnez à la place la maîtrise des jets de sauvegarde d'Intelligence ou de Charisme (au choix).","name_en":"Iron Mind"},{"name":"Rafale de traqueur","level":11,"desc":"Au niveau 11, vous apprenez à attaquer avec une vitesse si inattendue que vous pouvez transformer un échec en une autre frappe. Une fois à chacun de vos tours, lorsque vous ratez une attaque avec une arme, vous pouvez effectuer une autre attaque avec une arme dans le cadre de la même action.","name_en":"Stalker's Flurry"},{"name":"Esquive ténébreuse","level":15,"desc":"À partir du niveau 15, vous pouvez esquiver de manière imprévue, avec des volutes d'ombre surnaturelle autour de vous. Chaque fois qu'une créature effectue un jet d'attaque contre vous et n'a pas d'avantage sur ce jet, vous pouvez utiliser votre réaction pour lui imposer un désavantage. Vous devez utiliser cette fonctionnalité avant de connaître le résultat du jet d'attaque.","name_en":"Shadowy Dodge"}],"name_en":"Ranger: Gloom Stalker Conclave","_translated":true},{"index":"ranger-horizon-walker","name":"Ranger : Conclave Horizon Walker","class":"ranger","source":"Xanathar's Guide to Everything","subclass_flavor":"Les marcheurs de l'horizon protègent le monde contre les menaces provenant d'autres plans ou cherchant à ravager le royaume des mortels avec une magie surnaturelle. Ils recherchent des portails planaires et les surveillent, s'aventurant vers les plans intérieurs et extérieurs selon les besoins pour poursuivre leurs ennemis. Ces rôdeurs sont également les amis de toutes les forces du multivers – en particulier les dragons, les fées et les élémentaires bienveillants – qui s'efforcent de préserver la vie et l'ordre des plans.","desc":"","features":[{"name":"Horizon Walker Magie","level":3,"desc":"À partir du niveau 3, vous apprenez un sort supplémentaire lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts Horizon Walker. Le sort compte comme un sort de rôdeur pour vous, mais il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez.\nSorts de marcheur de l'horizon\nNiveau Ranger | Sorts\n3ème | Protection contre le mal et le bien\n5ème | Étape brumeuse\n9ème | Hâte\n13e | Bannissement\n17e | Cercle de téléportation","name_en":"Horizon Walker Magic"},{"name":"Détecter le portail","level":3,"desc":"Au niveau 3, vous gagnez la capacité de ressentir par magie la présence d'un portail planaire. Par une action, vous détectez la distance et la direction du portail planaire le plus proche dans un rayon de 1,6 km de vous.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.\n\nVoir la section « Voyage planaire » dans le chapitre 2 du Guide du maître du donjon pour des exemples de portails planaires.","name_en":"Detect Portal"},{"name":"Guerrier planaire","level":3,"desc":"Au niveau 3, vous apprenez à puiser dans l'énergie du multivers pour augmenter vos attaques.\n\nPar une action bonus, choisissez une créature que vous pouvez voir à moins de 9 mètres de vous. La prochaine fois que vous toucherez cette créature ce tour-ci avec une attaque avec une arme, tous les dégâts infligés par l'attaque deviennent des dégâts de force, et la créature subit 1d8 dégâts de force supplémentaires dus à l'attaque. Lorsque vous atteignez le niveau 11 dans cette classe, les dégâts supplémentaires passent à 2d8.","name_en":"Planar Warrior"},{"name":"Étape éthérée","level":7,"desc":"Au niveau 7, vous apprenez à traverser le plan Éthéré. Par une action bonus lors de votre tour, vous pouvez lancer le sort Éthéré avec cette fonctionnalité, sans dépenser d'emplacement de sort, mais le sort se termine à la fin du tour en cours.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un repos court ou long.","name_en":"Ethereal Step"},{"name":"Frappe à distance","level":11,"desc":"Au niveau 11, vous gagnez la capacité de passer entre les plans en un clin d'œil. Lorsque vous utilisez l'action Attaque, vous pouvez vous téléporter jusqu'à 3 mètres avant chaque attaque dans un espace inoccupé que vous pouvez voir.\n\nSi vous attaquez au moins deux créatures différentes avec l'action, vous pouvez effectuer une attaque supplémentaire contre une troisième créature.","name_en":"Distant Strike"},{"name":"Défense spectrale","level":15,"desc":"Au niveau 15, votre capacité à vous déplacer entre les plans vous permet de vous faufiler à travers les limites planaires pour réduire les dégâts qui vous sont causés pendant la bataille. Lorsque vous subissez des dégâts suite à une attaque, vous pouvez utiliser votre réaction pour vous conférer une résistance à tous les dégâts de cette attaque pendant ce tour.","name_en":"Spectral Defense"}],"name_en":"Ranger: Horizon Walker Conclave","_translated":true},{"index":"ranger-hunter","name":"Ranger : Conclave des Chasseurs","class":"ranger","source":"Player's Handbook","subclass_flavor":"Certains rangers cherchent à maîtriser les armes pour mieux protéger la civilisation des terreurs de la nature. Les membres du Hunter Conclave apprennent des techniques de combat spécialisées à utiliser contre les menaces les plus terribles, des ogres déchaînés et des hordes d'orcs aux géants imposants et aux dragons terrifiants.","desc":"","features":[{"name":"La proie du chasseur","level":3,"desc":"Au niveau 3, vous gagnez l'une des fonctionnalités suivantes de votre choix.\n• Tueur de colosses. Votre ténacité peut épuiser les ennemis les plus puissants. Lorsque vous touchez une créature avec une attaque avec une arme, la créature subit 1d8 dégâts supplémentaires si elle est inférieure à son maximum de points de vie. Vous ne pouvez infliger ces dégâts supplémentaires qu’une seule fois par tour.\n• Tueur de géant. Lorsqu'une créature de taille Large ou plus grande à moins de 1,50 mètre de vous vous touche ou vous manque avec une attaque, vous pouvez utiliser votre réaction pour attaquer cette créature immédiatement après son attaque, à condition que vous puissiez voir la créature.\n• Brise-horde. Une fois à chacun de vos tours, lorsque vous effectuez une attaque avec une arme, vous pouvez effectuer une autre attaque avec la même arme contre une créature différente qui se trouve à moins de 1,50 mètre de la cible d'origine et à portée de votre arme.","name_en":"Hunter's Prey"},{"name":"Tactiques défensives","level":7,"desc":"Au niveau 7, vous obtenez l'une des fonctionnalités suivantes de votre choix.\n• Échapper à la Horde. Les attaques d’opportunité contre vous sont lancées avec un désavantage.\n• Défense multi-attaques. Lorsqu'une créature vous frappe avec une attaque, vous gagnez un bonus de +4 à la CA contre toutes les attaques ultérieures effectuées par cette créature pour le reste du tour.\n• Volonté d'Acier. Vous avez un avantage aux jets de sauvegarde contre la peur.","name_en":"Defensive Tactics"},{"name":"Multi-attaque","level":11,"desc":"Au niveau 11, vous obtenez l'une des fonctionnalités suivantes de votre choix.\n• Volée. Vous pouvez utiliser votre action pour effectuer une attaque à distance contre n’importe quel nombre de créatures à moins de 3 mètres d’un point que vous pouvez voir à portée de votre arme. Vous devez avoir des munitions pour chaque cible, comme d'habitude, et vous effectuez un jet d'attaque séparé pour chaque cible.\n• Attaque tourbillonnante. Vous pouvez utiliser votre action pour effectuer des attaques au corps à corps contre n'importe quel nombre de créatures à moins de 1,50 mètre de vous, avec un jet d'attaque distinct pour chaque cible.","name_en":"Multiattack"},{"name":"Défense supérieure du chasseur","level":15,"desc":"Au niveau 15, vous obtenez l'une des fonctionnalités suivantes de votre choix.\n• Évasion. Lorsque vous êtes soumis à un effet, comme le souffle enflammé d'un dragon rouge ou un sort d'éclair, qui vous permet d'effectuer un jet de sauvegarde de Dextérité pour ne subir que la moitié des dégâts, vous ne subissez aucun dégât si vous réussissez un jet de sauvegarde, et seulement la moitié des dégâts si vous échouez.\n• Tenez-vous à contre-courant. Lorsqu'une créature hostile vous manque lors d'une attaque au corps à corps, vous pouvez utiliser votre réaction pour forcer cette créature à répéter la même attaque contre une autre créature (autre qu'elle-même) de votre choix.\n• Esquive étrange. Lorsqu’un attaquant que vous pouvez voir vous frappe avec une attaque, vous pouvez utiliser votre réaction pour réduire de moitié les dégâts de l’attaque contre vous.","name_en":"Superior Hunter's Defense"}],"name_en":"Ranger: Hunter Conclave","_translated":true},{"index":"ranger-monster-slayer","name":"Ranger : Conclave des tueurs de monstres","class":"ranger","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous vous êtes consacré à traquer les créatures de la nuit et les détenteurs de magie sinistre. Un tueur de monstres recherche des vampires, des dragons, des fées maléfiques, des démons et d'autres menaces magiques. Formés aux techniques surnaturelles pour vaincre de tels monstres, les tueurs sont experts dans l’art de déterrer et de vaincre de puissants ennemis mystiques.","desc":"","features":[{"name":"Magie du tueur de monstres","level":3,"desc":"À partir du niveau 3, vous apprenez un sort supplémentaire lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts de Monster Slayer. Le sort compte comme un sort de rôdeur pour vous, mais il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez.\nSorts de tueur de monstres\nNiveau Ranger | Sorts\n3ème | Protection contre le mal et le bien\n5ème | Zone de vérité\n9ème | Cercle magique\n13e | Bannissement\n17e | Tenir le monstre","name_en":"Monster Slayer Magic"},{"name":"Le sens du chasseur","level":3,"desc":"Au niveau 3, vous gagnez la capacité d'observer une créature et de discerner par magie la meilleure façon de la blesser. Par une action, choisissez une créature que vous pouvez voir à moins de 60 pieds de vous. Vous saurez immédiatement si la créature possède des immunités aux dégâts, des résistances ou des vulnérabilités et de quoi il s'agit. Si la créature est cachée à la magie divinatoire, vous sentez qu’elle n’a aucune immunité aux dégâts, aucune résistance ou vulnérabilité.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois). Vous en récupérez toutes les utilisations dépensées lorsque vous terminez un long repos.","name_en":"Hunter's Sense"},{"name":"La proie du tueur","level":3,"desc":"À partir du niveau 3, vous pouvez concentrer votre colère sur un ennemi, augmentant ainsi les dégâts que vous lui infligez. Par une action bonus, vous désignez une créature que vous pouvez voir dans un rayon de 20 mètres autour de vous comme cible de cette fonctionnalité. La première fois à chaque tour que vous touchez cette cible avec une attaque avec une arme, l'arme lui inflige 1d6 dégâts supplémentaires.\n\nCet avantage dure jusqu'à la fin d'un repos court ou long. Cela se termine plus tôt si vous désignez une créature différente.","name_en":"Slayer's Prey"},{"name":"Défense surnaturelle","level":7,"desc":"Au niveau 7, vous gagnez une résilience supplémentaire contre les assauts de vos proies sur votre esprit et votre corps. Chaque fois que la cible de votre Slayer's Prey vous oblige à effectuer un jet de sauvegarde et chaque fois que vous effectuez un test de capacité pour échapper au grappin de cette cible, ajoutez 1d6 à votre jet.","name_en":"Supernatural Defense"},{"name":"Némésis du magicien","level":11,"desc":"Au niveau 11, vous acquérez la capacité de contrecarrer la magie de quelqu'un d'autre. Lorsque vous voyez une créature lancer un sort ou se téléporter à moins de 20 mètres de vous, vous pouvez utiliser votre réaction pour essayer de la déjouer comme par magie. La créature doit réussir un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de sort, sinon son sort ou sa téléportation échoue et est gaspillé.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Magic-User's Nemesis"},{"name":"Compteur de tueur","level":15,"desc":"Au niveau 15, vous gagnez la capacité de contre-attaquer lorsque votre proie tente de vous saboter. Si la cible de votre proie de tueur vous oblige à effectuer un jet de sauvegarde, vous pouvez utiliser votre réaction pour effectuer une attaque avec une arme contre la proie. Vous effectuez cette attaque immédiatement avant d'effectuer le jet de sauvegarde. Si l’attaque réussit, votre sauvegarde réussit automatiquement, en plus des effets normaux de l’attaque.","name_en":"Slayer's Counter"}],"name_en":"Ranger: Monster Slayer Conclave","_translated":true},{"index":"ranger-swarmkeeper","name":"Ranger : gardien de l'essaim","class":"ranger","source":"Tasha's Cauldron of Everything","subclass_flavor":"Ressentant un lien profond avec l'environnement qui les entoure, certains rangers s'étendent grâce à leur connexion magique avec le monde et se lient à un essaim d'esprits de la nature. L'essaim devient une force puissante au combat, ainsi qu'une compagnie utile pour le ranger. Certains Swarmkeepers sont des parias ou des ermites, restant seuls et avec leurs essaims plutôt que de faire face à l'inconfort des autres. D’autres Swarmkeepers aiment bâtir des communautés dynamiques qui travaillent pour le bénéfice mutuel de tous ceux qu’ils considèrent comme faisant partie de leur essaim.","desc":"","features":[{"name":"Essaim rassemblé","level":3,"desc":"Au niveau 3, un essaim d'esprits de la nature intangibles s'est lié à vous et peut vous aider au combat. Tant que vous êtes en vie, l’essaim reste dans votre espace, rampant sur vous ou volant et voltigeant autour de vous dans votre espace. Vous déterminez son apparence, ou vous générez son apparence en lançant un jet sur la table d'apparence de l'essaim.\nApparition d'un essaim | \nd4 | Apparence\n1 | Essaimage d'insectes\n2 | Brûlures miniatures des rameaux\n3 | Oiseaux flottants\n4 | Pixies ludiques\n\nUne fois à chacun de vos tours, vous pouvez demander à l'essaim de vous aider de l'une des manières suivantes, immédiatement après avoir touché une créature avec une attaque :\n• La cible de l'attaque subit 1d6 dégâts perforants de la nuée.\n• La cible de l'attaque doit réussir un jet de sauvegarde de Force contre votre DD de sauvegarde de sort ou être déplacée par l'essaim jusqu'à 15 pieds horizontalement dans la direction de votre choix.\n• Vous êtes déplacé par l'essaim de 1,50 mètre horizontalement dans la direction de votre choix.","name_en":"Gathered Swarm"},{"name":"Magie des gardiens d'essaims","level":3,"desc":"Également au niveau 3, vous apprenez le cantrip Mage Hand si vous ne le connaissez pas déjà. Lorsque vous le lancez, la main prend la forme de vos esprits de la nature grouillants.\n\nVous apprenez également un sort supplémentaire de niveau 1 ou supérieur lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts de Swarmkeeper. Chaque sort compte pour vous comme un sort de rôdeur, mais il ne compte pas dans le nombre de sorts de rôdeur que vous connaissez.\nSorts de gardien d’essaim | \nNiveau Ranger | Sort\n3ème | Feu féerique, main de mage\n5ème | Web\n9ème | Forme gazeuse\n13e | Œil arcanique\n17e | Peste d'insectes","name_en":"Swarmkeeper Magic"},{"name":"Marée se tordant","level":7,"desc":"À partir du niveau 7, vous pouvez condenser une partie de votre essaim en une masse concentrée qui vous élève. Par une action bonus, vous gagnez une vitesse de vol de 3 mètres et pouvez planer. Cet effet dure 1 minute ou jusqu'à ce que vous soyez incapable d'agir.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Writhing Tide"},{"name":"Puissant essaim","level":11,"desc":"Au niveau 11, votre Essaim rassemblé devient plus puissant des manières suivantes :\n• Les dégâts de Gathered Swarm augmentent à 1d8.\n• Si une créature échoue à son jet de sauvegarde contre le déplacement de la nuée rassemblée, vous pouvez également faire en sorte que la nuée la jette à terre.\n• Lorsque vous êtes déplacé par Gathered Swarm, il vous offre une demi-couverture jusqu'au début de votre prochain tour.","name_en":"Mighty Swarm"},{"name":"Dispersion en essaim","level":null,"desc":"Lorsque vous atteignez le niveau 15, vous pouvez vous désincorporer dans votre essaim, évitant ainsi le danger. Lorsque vous subissez des dégâts, vous pouvez utiliser votre réaction pour vous conférer une résistance à ces dégâts. Vous disparaissez dans votre essaim puis vous téléportez dans un espace inoccupé que vous pouvez voir à moins de 9 mètres de vous, où vous réapparaissez avec l'essaim.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Swarming Dispersal"}],"name_en":"Ranger: Swarmkeeper","_translated":true},{"index":"rogue-arcane-trickster","name":"Voleur : le filou des arcanes","class":"rogue","source":"Player's Handbook","subclass_flavor":"Certains voleurs améliorent leurs compétences de furtivité et d'agilité grâce à la magie, apprenant des tours d'enchantement et d'illusion. Ces voleurs comprennent des pickpockets et des cambrioleurs, mais aussi des farceurs, des fauteurs de troubles et un nombre important d'aventuriers.","desc":"","features":[{"name":"Lancement de sorts","level":10,"desc":"Lorsque vous atteignez le niveau 3, vous augmentez vos prouesses martiales grâce à la capacité de lancer des sorts.\n\nVous apprenez trois petits sorts : Mage Hand et deux autres petits sorts de votre choix dans la liste des sorts de l'assistant. Vous apprenez un autre sort mineur de sorcier de votre choix au niveau 10.\n\nLe tableau de lancement de sorts Arcane Trickster indique le nombre d'emplacements de sorts dont vous disposez pour lancer vos sorts de sorcier de niveau 1 et supérieur. Pour lancer l'un de ces sorts, vous devez dépenser un emplacement du niveau du sort ou supérieur. Vous récupérez tous les emplacements de sorts dépensés lorsque vous terminez un repos long.\n\nPar exemple, si vous connaissez le sort Charme de personne de niveau 1 et que vous disposez d'un emplacement de sort de niveau 1 et de niveau 2, vous pouvez lancer Charme de personne en utilisant l'un ou l'autre emplacement.\n\nVous connaissez trois sorts de sorcier de niveau 1 de votre choix, dont deux que vous devez choisir parmi les sorts d'enchantement et d'illusion de la liste des sorts de sorcier.\n\nLa colonne Sorts connus du tableau de lancement de sorts Arcane Trickster indique quand vous apprenez plus de sorts de sorcier de niveau 1 ou supérieur. Chacun de ces sorts doit être un sort d'enchantement ou d'illusion de votre choix, et doit être d'un niveau pour lequel vous disposez d'emplacements de sorts. Par exemple, lorsque vous atteignez le niveau 7 dans cette classe, vous pouvez apprendre un nouveau sort de niveau 1 ou 2.\n\nLes sorts que vous apprenez aux niveaux 8, 14 et 20 peuvent provenir de n’importe quelle école de magie.\n\nÀ chaque fois que vous gagnez un niveau dans cette classe, vous pouvez remplacer l'un des sorts de sorcier que vous connaissez par un autre sort de votre choix dans la liste des sorts de sorcier. Le nouveau sort doit être d'un niveau pour lequel vous disposez d'emplacements de sort, et il doit s'agir d'un sort d'enchantement ou d'illusion, à moins que vous ne remplaciez le sort que vous avez obtenu au niveau 3, 8, 14 ou 20 dans n'importe quelle école de magie.\n\nL'intelligence est votre capacité à lancer des sorts pour vos sorts de sorcier, puisque vous apprenez vos sorts grâce à une étude et une mémorisation dédiées. Vous utilisez votre Intelligence chaque fois qu'un sort fait référence à votre capacité de lancer des sorts. De plus, vous utilisez votre modificateur d'Intelligence lorsque vous définissez le DD du jet de sauvegarde pour un sort de sorcier que vous lancez et lorsque vous effectuez un jet d'attaque avec celui-ci.\n\nDD de sauvegarde des sorts = 8 + votre bonus de maîtrise + votre modificateur d'Intelligence\n\nModificateur d'attaque des sorts = votre bonus de maîtrise + votre modificateur d'Intelligence","name_en":"Spellcasting"},{"name":"Legerdemain de la main du mage","level":3,"desc":"À partir du niveau 3, lorsque vous lancez Main de Mage, vous pouvez rendre la main spectrale invisible et vous pouvez effectuer les tâches supplémentaires suivantes avec :\n• Vous pouvez ranger un objet que la main tient dans un récipient porté ou transporté par une autre créature.\n• Vous pouvez récupérer un objet dans un conteneur porté ou transporté par une autre créature.\n• Vous pouvez utiliser les outils des voleurs pour crocheter les serrures et désamorcer les pièges à distance.\n\nVous pouvez effectuer l'une de ces tâches sans être remarqué par une créature si vous réussissez un test de Dextérité (Tour de passe-passe) contesté par le test de Sagesse (Perception) de la créature.\n\nDe plus, vous pouvez utiliser l'action bonus accordée par votre Action Cunning pour contrôler la main.","name_en":"Mage Hand Legerdemain"},{"name":"Embuscade magique","level":9,"desc":"À partir du niveau 9, si vous êtes caché d'une créature lorsque vous lancez un sort sur elle, la créature est désavantagée à tous les jets de sauvegarde qu'elle effectue contre le sort ce tour-ci.","name_en":"Magical Ambush"},{"name":"Filou polyvalent","level":13,"desc":"Au niveau 13, vous gagnez la capacité de distraire les cibles avec votre Main de Mage. Par une action bonus lors de votre tour, vous pouvez désigner une créature à moins de 1,50 mètre de la main spectrale créée par le sort. Cela vous donne un avantage aux jets d'attaque contre cette créature jusqu'à la fin du tour.","name_en":"Versatile Trickster"},{"name":"Voleur de sorts","level":17,"desc":"Au niveau 17, vous acquérez la capacité de voler par magie à un autre lanceur de sorts les connaissances nécessaires pour lancer un sort.\n\nImmédiatement après qu'une créature a lancé un sort qui vous cible ou vous inclut dans sa zone d'effet, vous pouvez utiliser votre réaction pour forcer la créature à effectuer un jet de sauvegarde avec son modificateur de capacité de lancement de sorts. Le DD est égal à votre DD de sauvegarde de sorts. En cas d'échec, vous annulez l'effet du sort contre vous et vous volez la connaissance du sort s'il est au moins de niveau 1 et d'un niveau que vous pouvez lancer (il n'est pas nécessaire qu'il s'agisse d'un sort de sorcier). Pendant les 8 prochaines heures, vous connaissez le sort et pouvez le lancer en utilisant vos emplacements de sorts. La créature ne peut pas lancer ce sort avant que les 8 heures ne soient écoulées.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Spell Thief"}],"name_en":"Rogue: Arcane Trickster","_translated":true},{"index":"rogue-assassin","name":"Voleur : Assassin","class":"rogue","source":"Player's Handbook","subclass_flavor":"Vous concentrez votre formation sur l’art sinistre de la mort. Ceux qui adhèrent à cet archétype sont divers : des tueurs à gages, des espions, des chasseurs de primes et même des prêtres spécialement oints et formés pour exterminer les ennemis de leur divinité. La furtivité, le poison et le déguisement vous aident à éliminer vos ennemis avec une efficacité mortelle.","desc":"","features":[{"name":"Compétences bonus","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous gagnez la maîtrise du kit de déguisement et du kit de l'empoisonneur.","name_en":"Bonus Proficiencies"},{"name":"Assassiner","level":3,"desc":"À partir du niveau 3, vous êtes le plus meurtrier lorsque vous faites tomber vos ennemis. Vous avez un avantage aux jets d'attaque contre toute créature qui n'a pas encore pris son tour dans le combat. De plus, tout coup porté contre une créature surprise est un coup critique.","name_en":"Assassinate"},{"name":"Expertise en infiltration","level":9,"desc":"À partir du niveau 9, vous pouvez infailliblement vous créer de fausses identités. Vous devez passer sept jours et 25 po pour établir l’histoire, la profession et les affiliations d’une identité. Vous ne pouvez pas établir une identité qui appartient à quelqu'un d'autre. Par exemple, vous pourriez acquérir des vêtements appropriés, des lettres d'introduction et un certificat d'apparence officielle pour vous établir en tant que membre d'une maison de commerce d'une ville éloignée afin de pouvoir vous insinuer en compagnie d'autres riches marchands.\n\nPar la suite, si vous adoptez la nouvelle identité comme déguisement, d’autres créatures croient que vous êtes cette personne jusqu’à ce qu’on leur donne une raison évidente de ne pas le faire.","name_en":"Infiltration Expertise"},{"name":"Imposteur","level":13,"desc":"Au niveau 13, vous acquérez la capacité d’imiter de manière infaillible le discours, l’écriture et le comportement d’une autre personne. Vous devez passer au moins trois heures à étudier ces trois composantes du comportement de la personne, à écouter la parole, à examiner l'écriture manuscrite et à observer les manières.\n\nVotre ruse est indiscernable pour l’observateur occasionnel. Si une créature méfiante soupçonne que quelque chose ne va pas, vous avez l'avantage à tous les tests de Charisme (Tromperie) que vous effectuez pour éviter d'être détecté.","name_en":"Impostor"},{"name":"Frappe mortelle","level":17,"desc":"À partir du niveau 17, vous devenez un maître de la mort instantanée. Lorsque vous attaquez et frappez une créature surprise, elle doit effectuer un jet de sauvegarde de Constitution (DD 8 + votre modificateur de Dextérité + votre bonus de maîtrise). En cas d'échec, doublez les dégâts de votre attaque contre la créature.","name_en":"Death Strike"}],"name_en":"Rogue: Assassin","_translated":true},{"index":"rogue-inquisitive","name":"Voleur : curieux","class":"rogue","source":"Xanathar's Guide to Everything","subclass_flavor":"En tant que curieux archétypal, vous excellez dans l’art d’extirper les secrets et de percer les mystères. Vous comptez sur votre sens aigu du détail, mais aussi sur votre capacité aiguisée à lire les paroles et les actes d’autres créatures pour déterminer leur véritable intention. Vous excellez à vaincre les créatures qui se cachent parmi les gens ordinaires et s’en prennent à eux, et votre maîtrise des traditions et votre œil aiguisé vous rendent bien équipé pour exposer et mettre fin aux maux cachés.","desc":"","features":[{"name":"L'oreille pour la tromperie","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous développez une oreille attentive pour déceler les mensonges. Chaque fois que vous effectuez un test de Sagesse (Perspicacité) pour déterminer si une créature ment, traitez un résultat de 7 ou moins sur le d20 comme un 8.","name_en":"Ear for Deceit"},{"name":"Le souci du détail","level":3,"desc":"À partir du niveau 3, vous pouvez utiliser une action bonus pour effectuer un test de Sagesse (Perception) afin de repérer une créature ou un objet caché ou pour effectuer un test d'Intelligence (Enquête) pour découvrir ou déchiffrer des indices.","name_en":"Eye for Detail"},{"name":"Des combats perspicaces","level":3,"desc":"Au niveau 3, vous acquérez la capacité de déchiffrer les tactiques d'un adversaire et de développer une contre-attaque. Par une action bonus, vous effectuez un test de Sagesse (Perspicacité) contre une créature que vous pouvez voir et qui n'est pas incapable d'agir, contesté par le test de Charisme (Tromperie) de la cible. Si vous réussissez, vous pouvez utiliser votre attaque sournoise contre cette cible même si vous n'avez pas d'avantage au jet d'attaque, mais pas si vous avez un désavantage.\n\nCet avantage dure 1 minute ou jusqu'à ce que vous utilisiez avec succès cette fonctionnalité contre une cible différente.","name_en":"Insightful Fighting"},{"name":"Oeil stable","level":9,"desc":"Au niveau 9, vous bénéficiez d'un avantage à n'importe quel test de Sagesse (Perception) ou d'Intelligence (Enquête) si vous ne vous déplacez pas à plus de la moitié de votre vitesse au cours du même tour.","name_en":"Steady Eye"},{"name":"Oeil infaillible","level":13,"desc":"Au niveau 13, vos sens sont presque impossibles à déjouer. En tant qu'action, vous ressentez la présence d'illusions, de changeurs de forme qui ne sont pas dans leur forme originale et d'autres magies conçues pour tromper les sens dans un rayon de 9 mètres autour de vous, à condition que vous ne soyez pas aveuglé ou assourdi. Vous sentez qu’un effet tente de vous tromper, mais vous n’obtenez aucun aperçu de ce qui est caché ni de sa véritable nature.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre modificateur de Sagesse (au minimum une fois), et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Unerring Eye"},{"name":"L'œil pour la faiblesse","level":17,"desc":"Au niveau 17, vous apprenez à exploiter les faiblesses d'une créature en étudiant attentivement ses tactiques et ses mouvements. Tant que votre fonction Combat perspicace s'applique à une créature, vos dégâts d'attaque sournoise contre cette créature augmentent de 3d6.","name_en":"Eye for Weakness"}],"name_en":"Rogue: Inquisitive","_translated":true},{"index":"rogue-mastermind","name":"Voleur : cerveau","class":"rogue","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous vous concentrez sur les gens, sur leur influence et leurs secrets. De nombreux espions, courtisans et intrigants suivent cet archétype, menant une vie d’intrigues. Les mots sont vos armes aussi souvent que les couteaux ou le poison, et les secrets et les faveurs font partie de vos trésors préférés.","desc":"","features":[{"name":"Maître de l'intrigue","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous maîtrisez le kit de déguisement, le kit de contrefaçon et un ensemble de jeu de votre choix. Vous apprenez également deux langues de votre choix.\n\nDe plus, vous pouvez imiter de manière infaillible les schémas de parole et l'accent d'une créature que vous entendez parler pendant au moins 1 minute, ce qui vous permet de vous faire passer pour un locuteur natif d'un pays particulier, à condition que vous connaissiez la langue.","name_en":"Master of Intrigue"},{"name":"Maître de Tactique","level":3,"desc":"À partir du niveau 3, vous pouvez utiliser l’action Aide comme action bonus. De plus, lorsque vous utilisez l'action Aide pour aider un allié à attaquer une créature, la cible de cette attaque peut se trouver à moins de 9 mètres de vous, au lieu de 1,50 mètre de vous, si la cible peut vous voir ou vous entendre.","name_en":"Master of Tactics"},{"name":"Manipulateur perspicace","level":9,"desc":"À partir du niveau 9, si vous passez au moins 1 minute à observer ou à interagir avec une autre créature en dehors du combat, vous pouvez apprendre certaines informations sur ses capacités par rapport aux vôtres. Le DM vous indique si la créature est votre égale, supérieure ou inférieure en ce qui concerne deux des caractéristiques suivantes de votre choix :\n• Score d'intelligence\n• Indice de sagesse\n• Score de charisme\n• Niveaux de classe (le cas échéant)\n\nAu choix du MD, vous pourriez également réaliser que vous connaissez un morceau de l'histoire de la créature ou l'un de ses traits de personnalité, le cas échéant.","name_en":"Insightful Manipulator"},{"name":"Mauvaise orientation","level":13,"desc":"À partir du niveau 13, vous pouvez parfois faire subir à une autre créature une attaque qui vous est destinée. Lorsque vous êtes ciblé par une attaque alors qu'une créature à moins de 1,50 mètre de vous vous accorde une couverture contre cette attaque, vous pouvez utiliser votre réaction pour que l'attaque cible cette créature à votre place.","name_en":"Misdirection"},{"name":"Âme de tromperie","level":17,"desc":"À partir du niveau 17, vos pensées ne peuvent plus être lues par télépathie ou par d'autres moyens, sauf si vous l'autorisez. Vous pouvez présenter de fausses pensées en effectuant un test de Charisme (Tromperie) contesté par le test de Sagesse (Perspicacité) du lecteur d'esprit.\n\nDe plus, peu importe ce que vous dites, la magie qui déterminerait si vous dites la vérité indique que vous dites la vérité si vous le souhaitez, et vous ne pouvez pas être obligé de dire la vérité par magie.","name_en":"Soul of Deceit"}],"name_en":"Rogue: Mastermind","_translated":true},{"index":"rogue-phantom","name":"Voleur : Fantôme","class":"rogue","source":"Tasha's Cauldron of Everything","subclass_flavor":"De nombreux voleurs marchent sur une ligne ténue entre la vie et la mort, risquant leur propre vie et ôtant celle des autres. En s'aventurant sur cette ligne, certains voleurs découvrent un lien mystique avec la mort elle-même. Ces voleurs prennent la connaissance des morts et se plongent dans l'énergie négative, devenant finalement comme des fantômes. Les guildes de voleurs les considèrent comme des collecteurs d'informations et des espions très efficaces.","desc":"","features":[{"name":"Murmures des morts","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, les échos de ceux qui sont morts s'accrochent à vous. Chaque fois que vous terminez un repos court ou long, vous pouvez acquérir une compétence ou un outil de votre choix, car une présence fantomatique partage ses connaissances avec vous. Vous perdez cette compétence lorsque vous utilisez cette fonctionnalité pour choisir une autre compétence qui vous manque.","name_en":"Whispers of the Dead"},{"name":"Gémissements de la tombe","level":3,"desc":"Au niveau 3, lorsque vous rapprochez quelqu'un de la tombe, vous pouvez également canaliser le pouvoir de la mort pour nuire à quelqu'un d'autre. Immédiatement après avoir infligé vos dégâts d'attaque sournoise à une créature pendant votre tour, vous pouvez cibler une deuxième créature que vous pouvez voir à moins de 9 mètres de la première créature. Lancez la moitié du nombre de dés d'attaque sournoise correspondant à votre niveau (arrondi au supérieur), et la deuxième créature subit des dégâts nécrotiques égaux au total du lancer, tandis que les gémissements des morts résonnent autour d'elle pendant un instant.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Wails from the Grave"},{"name":"Les jetons des défunts","level":9,"desc":"Au niveau 9, lorsqu'une vie se termine en votre présence, vous pouvez arracher un jeton à l'âme qui s'en va, un fragment de son essence vitale qui prend une forme physique : en réaction lorsqu'une créature que vous pouvez voir meurt à moins de 9 mètres de vous, vous pouvez ouvrir votre main libre et y faire apparaître un petit bijou, un bijou d'âme. Le MD détermine la forme du bijou ou vous demande de lancer un jet sur le tableau des bibelots du manuel du joueur pour le générer.\n\nVous pouvez avoir un nombre maximum de bibelots d'âme égal à votre bonus de maîtrise, et vous ne pouvez pas en créer un tant que vous avez atteint votre maximum.\n\nVous pouvez utiliser les bibelots d’âme des manières suivantes :\n• Tant qu'un bijou d'âme est sur vous, vous avez un avantage aux jets de sauvegarde contre la mort et aux jets de sauvegarde de Constitution, car votre vitalité est renforcée par l'essence vitale contenue dans l'objet.\n• Lorsque vous infligez des dégâts d'Attaque sournoise pendant votre tour, vous pouvez détruire l'un de vos bibelots d'âme qui se trouve sur vous, puis utiliser immédiatement Wails from the Grave, sans dépenser d'utilisation de cette fonctionnalité.\n• Par une action, vous pouvez détruire l'un de vos bibelots d'âme, peu importe où il se trouve. Ce faisant, vous pouvez poser une question à l’esprit associé au bijou. L'esprit vous apparaît et vous répond dans une langue qu'il a connue de son vivant. Il n'a aucune obligation d'être honnête et il répond le plus brièvement possible, désireux d'être libre. L'esprit ne sait que ce qu'il a connu dans la vie, tel que déterminé par le DM.","name_en":"Tokens of the Departed"},{"name":"Marche des fantômes","level":13,"desc":"Au niveau 13, vous pouvez entrer partiellement dans le royaume des morts, devenant comme un fantôme. Par une action bonus, vous prenez une forme spectrale. Sous cette forme, vous avez une vitesse de vol de 10 pieds, vous pouvez planer et les jets d'attaque ont un désavantage contre vous. Vous pouvez également vous déplacer à travers des créatures et des objets comme s'il s'agissait d'un terrain difficile, mais vous subissez 1d10 dégâts de force si vous terminez votre tour à l'intérieur d'une créature ou d'un objet.\n\nVous restez sous cette forme pendant 10 minutes ou jusqu'à ce que vous y mettiez fin sous forme d'action bonus. Pour utiliser à nouveau cette fonctionnalité, vous devez terminer un long repos ou détruire l'un de vos bibelots d'âme dans le cadre de l'action bonus que vous utilisez pour activer Ghost Walk.","name_en":"Ghost Walk"},{"name":"L'ami de la mort","level":17,"desc":"Au niveau 17, votre association avec la mort est devenue si étroite que vous bénéficiez des avantages suivants :\n• Lorsque vous utilisez vos Lamentations de la Tombe, vous pouvez désormais infliger des dégâts nécrotiques à la première et à la deuxième créature.\n• À la fin d'un long repos, un bijou d'âme apparaît dans votre main si vous n'en avez pas, car les esprits des morts sont attirés vers vous.","name_en":"Death's Friend"}],"name_en":"Rogue: Phantom","_translated":true},{"index":"rogue-scout","name":"Voleur : éclaireur","class":"rogue","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous êtes doué pour la furtivité et survivez loin des rues d'une ville, ce qui vous permet d'éclairer vos compagnons lors des expéditions. Les voleurs qui adoptent cet archétype sont chez eux dans la nature, parmi les barbares et les rôdeurs, et de nombreux éclaireurs servent d'yeux et d'oreilles aux bandes de guerre. Embusqué, espion, chasseur de primes : ce ne sont là que quelques-uns des rôles que les scouts assument lorsqu'ils parcourent le monde.","desc":"","features":[{"name":"Tirailleur","level":3,"desc":"Dès le niveau 3, vous êtes difficile à cerner lors d'un combat. Vous pouvez vous déplacer jusqu'à la moitié de votre vitesse en réaction lorsqu'un ennemi termine son tour à moins de 1,50 mètre de vous. Ce mouvement ne provoque pas d’attaques d’opportunité.","name_en":"Skirmisher"},{"name":"Survivaliste","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous gagnez la maîtrise des compétences Nature et Survie si vous ne les possédez pas déjà. Votre bonus de maîtrise est doublé pour tout test de capacité que vous effectuez et qui utilise l'une ou l'autre de ces compétences.","name_en":"Survivalist"},{"name":"Mobilité supérieure","level":9,"desc":"Au niveau 9, votre vitesse de marche augmente de 3 mètres. Si vous avez une vitesse de montée ou de nage, cette augmentation s'applique également à cette vitesse.","name_en":"Superior Mobility"},{"name":"Maître d'embuscade","level":13,"desc":"À partir du niveau 13, vous excellez dans l’art de mener des embuscades et d’agir en premier dans un combat.\n\nVous avez l'avantage aux jets d'initiative. De plus, la première créature que vous touchez lors du premier round d'un combat devient plus facile à frapper pour vous et les autres ; les jets d'attaque contre cette cible ont un avantage jusqu'au début de votre prochain tour.","name_en":"Ambush Master"},{"name":"Frappe soudaine","level":17,"desc":"À partir du niveau 17, vous pouvez frapper à une vitesse mortelle. Si vous effectuez l'action Attaque à votre tour, vous pouvez effectuer une attaque supplémentaire en tant qu'action bonus. Cette attaque peut bénéficier de votre attaque sournoise même si vous l'avez déjà utilisée ce tour-ci, mais vous ne pouvez pas utiliser votre attaque sournoise contre la même cible plus d'une fois par tour.","name_en":"Sudden Strike"}],"name_en":"Rogue: Scout","_translated":true},{"index":"rogue-soulknife","name":"Voleur : Couteau d'âme","class":"rogue","source":"Tasha's Cauldron of Everything","subclass_flavor":"La plupart des assassins frappent avec des armes physiques, et de nombreux cambrioleurs et espions utilisent les outils des voleurs pour infiltrer des lieux sécurisés. En revanche, un Soulknife frappe et s'infiltre dans l'esprit, franchissant les barrières physiques et psychiques. Ces voleurs découvrent un pouvoir psionique en eux-mêmes et le canalisent pour accomplir leur travail espiègle. Ils trouvent facilement un emploi en tant que membres de guildes de voleurs, même si les voleurs se méfient souvent d'eux, qui se méfient de quiconque utilise d'étranges pouvoirs mentaux pour mener leurs affaires. La plupart des gouvernements seraient également heureux d’employer un Soulknife comme espion.","desc":"","features":[{"name":"Pouvoir psionique","level":3,"desc":"À partir du niveau 3, vous abritez en vous une source d’énergie psionique. Cette énergie est représentée par vos dés d’Énergie Psionique, qui sont chacun un d6. Vous disposez d'un nombre de ces dés égal à deux fois votre bonus de maîtrise, et ils alimentent divers pouvoirs psioniques dont vous disposez, qui sont détaillés ci-dessous.\n\nCertains de vos pouvoirs dépensent le dé d'énergie psionique qu'ils utilisent, comme spécifié dans la description d'un pouvoir, et vous ne pouvez pas utiliser un pouvoir s'il nécessite que vous utilisiez un dé lorsque vos dés sont tous dépensés. Vous récupérez tous vos dés d'énergie psionique dépensés lorsque vous terminez un repos long. De plus, par une action bonus, vous pouvez récupérer un dé d'énergie psionique dépensé, mais vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.\n\nLorsque vous atteignez certains niveaux dans cette classe, la taille de vos dés d'énergie psionique augmente : au niveau 5 (d8), au niveau 11 (d10) et au niveau 17 (d12).\n\nLes pouvoirs ci-dessous utilisent vos dés d'énergie psionique.\n\nTalent renforcé par le Psi. Lorsque votre entraînement non psionique échoue, votre pouvoir psionique peut vous aider : si vous échouez à un test de capacité en utilisant une compétence ou un outil que vous maîtrisez, vous pouvez lancer un dé d'énergie psionique et ajouter le nombre obtenu au test, transformant potentiellement l'échec en succès. Vous dépensez le dé uniquement si le jet réussit.\n\nMurmures psychiques. Vous pouvez établir une communication télépathique entre vous et les autres – parfaite pour une infiltration silencieuse. Par une action, choisissez une ou plusieurs créatures que vous pouvez voir, jusqu'à un nombre de créatures égal à votre bonus de maîtrise, puis lancez un dé d'énergie psionique. Pendant un nombre d'heures égal au nombre obtenu, les créatures choisies peuvent vous parler par télépathie, et vous pouvez leur parler par télépathie. Pour envoyer ou recevoir un message (aucune action requise), vous et l'autre créature devez être à moins de 1 mile l'un de l'autre. Une créature ne peut pas utiliser cette télépathie si elle ne parle aucune langue, et une créature peut mettre fin à la connexion télépathique à tout moment (aucune action requise). Vous et la créature n’avez pas besoin de parler une langue commune pour vous comprendre.\n\nLa première fois que vous utilisez ce pouvoir après chaque long repos, vous ne dépensez pas le dé d'énergie psionique. Toutes les autres fois où vous utilisez le pouvoir, vous dépensez le dé.","name_en":"Psionic Power"},{"name":"Lames psychiques","level":3,"desc":"Également au niveau 3, vous pouvez manifester votre pouvoir psionique sous la forme de lames scintillantes d'énergie psychique. Chaque fois que vous effectuez l’action Attaque, vous pouvez manifester une lame psychique depuis votre main libre et effectuer l’attaque avec cette lame. Cette lame magique est une arme de mêlée simple dotée de la finesse et des propriétés de lancer. Il a une portée normale de 60 pieds et pas de longue portée, et en cas de coup, il inflige des dégâts psychiques égaux à 1d6 plus le modificateur de capacité que vous avez utilisé pour le jet d'attaque. La lame disparaît immédiatement après avoir touché ou manqué sa cible, et elle ne laisse aucune marque sur sa cible si elle inflige des dégâts.\n\nAprès avoir attaqué avec la lame, vous pouvez effectuer une attaque au corps à corps ou à distance avec une deuxième lame psychique comme action bonus au même tour, à condition que votre autre main soit libre de la créer. Le dé de dégâts de cette attaque bonus est de 1d4, au lieu de 1d6.","name_en":"Psychic Blades"},{"name":"Lames d'âme","level":9,"desc":"À partir du niveau 9, vos Lames Psychiques sont désormais une expression de votre âme imprégnée de psi, vous donnant ces pouvoirs qui utilisent vos dés d'énergie psionique :\n\nFrappes à tête chercheuse. Si vous effectuez un jet d'attaque avec vos Lames Psychiques et ratez la cible, vous pouvez lancer un dé d'Énergie Psionique et ajouter le nombre obtenu au jet d'attaque. Si cela provoque l'attaque, vous dépensez le dé d'énergie psionique.\n\nTéléportation psychique. Par une action bonus, vous manifestez une de vos Lames Psychiques, dépensez un dé d'Énergie Psionique, lancez-le et lancez la lame sur un espace inoccupé que vous pouvez voir, jusqu'à un nombre de mètres égal à 10 fois le nombre obtenu. Vous vous téléportez ensuite dans cet espace et la lame disparaît.","name_en":"Soul Blades"},{"name":"Voile psychique","level":13,"desc":"Au niveau 13, vous pouvez tisser un voile de statique psychique pour vous masquer. Par une action, vous pouvez devenir comme par magie invisible, ainsi que tout ce que vous portez ou transportez, pendant 1 heure ou jusqu'à ce que vous annuliez cet effet (aucune action requise). Cette invisibilité prend fin immédiatement après que vous avez infligé des blessures à une créature ou que vous avez forcé une créature à effectuer un jet de sauvegarde.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus le faire avant d'avoir terminé un long repos, à moins que vous ne dépensiez un dé d'énergie psionique pour utiliser à nouveau cette fonctionnalité.","name_en":"Psychic Veil"},{"name":"Déchirer l'esprit","level":null,"desc":"Lorsque vous atteignez le niveau 17, vous pouvez balayer votre lame psychique directement dans l'esprit d'une créature. Lorsque vous utilisez vos Lames Psychiques pour infliger des dégâts d'Attaque sournoise à une créature, vous pouvez forcer cette cible à effectuer un jet de sauvegarde de Sagesse (DD égal à 8 + votre bonus de maîtrise + votre modificateur de Dextérité). Si la sauvegarde échoue, la cible est étourdie pendant 1 minute. La cible étourdie peut refaire le jet de sauvegarde à la fin de chacun de ses tours, mettant ainsi fin à l'effet sur elle-même en cas de réussite.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus le faire avant d'avoir terminé un long repos, à moins que vous ne dépensiez trois dés d'énergie psionique pour l'utiliser à nouveau.","name_en":"Rend Mind"}],"name_en":"Rogue: Soulknife","_translated":true},{"index":"rogue-swashbuckler","name":"Voleur : Swashbuckler","class":"rogue","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous concentrez votre formation sur l’art du bois, en misant sur la vitesse, l’élégance et le charme à parts égales. Même si certains guerriers sont des brutes vêtues d'armures lourdes, votre méthode de combat ressemble presque à une performance. Les duellistes et les pirates appartiennent généralement à cet archétype.","desc":"","features":[{"name":"Jeu de jambes fantaisie","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous apprenez à porter une frappe puis à vous enfuir sans représailles. Pendant votre tour, si vous effectuez une attaque au corps à corps contre une créature, cette créature ne peut pas effectuer d'attaques d'opportunité contre vous pour le reste de votre tour.","name_en":"Fancy Footwork"},{"name":"Audace rakish","level":3,"desc":"Dès le niveau 3, votre confiance vous propulse au combat. Vous pouvez vous accorder un bonus à vos jets d'initiative égal à votre modificateur de Charisme.\n\nVous bénéficiez également d'une façon supplémentaire d'utiliser votre attaque sournoise ; vous n'avez pas besoin d'un avantage au jet d'attaque pour utiliser votre attaque sournoise contre une créature si vous êtes à moins de 1,50 mètre d'elle, qu'aucune autre créature n'est à moins de 1,50 mètre de vous et que vous n'avez pas de désavantage au jet d'attaque. Toutes les autres règles de l'attaque sournoise s'appliquent toujours à vous.","name_en":"Rakish Audacity"},{"name":"Panache","level":9,"desc":"Au niveau 9, votre charme devient extraordinairement séduisant. Par une action, vous pouvez effectuer un test de Charisme (Persuasion) contesté par le test de Sagesse (Perspicacité) d'une créature. La créature doit être capable de vous entendre et vous devez partager une langue tous les deux.\n\nSi vous réussissez le test et que la créature vous est hostile, elle a un désavantage aux jets d'attaque contre des cibles autres que vous et ne peut pas effectuer d'attaques d'opportunité contre des cibles autres que vous. Cet effet dure 1 minute, jusqu'à ce qu'un de vos compagnons attaque la cible ou l'affecte avec un sort, ou jusqu'à ce que vous et la cible soyez à plus de 60 pieds l'un de l'autre.\n\nSi vous réussissez le test et que la créature ne vous est pas hostile, elle est charmée par vous pendant 1 minute. Bien que charmé, il vous considère comme une connaissance amicale. Cet effet prend fin immédiatement si vous ou vos compagnons lui faites quelque chose de nuisible.","name_en":"Panache"},{"name":"Manœuvre élégante","level":13,"desc":"À partir du niveau 13, vous pouvez utiliser une action bonus pendant votre tour pour obtenir un avantage lors du prochain test de Dextérité (Acrobatie) ou de Force (Athlétisme) que vous effectuez au cours du même tour.","name_en":"Elegant Maneuver"},{"name":"Maître duelliste","level":17,"desc":"Dès le niveau 17, votre maîtrise de la lame vous permet de transformer l'échec en succès au combat. Si vous ratez un jet d'attaque, vous pouvez le relancer avec avantage. Une fois cela fait, vous ne pourrez plus utiliser cette fonctionnalité tant que vous n'aurez pas terminé un repos court ou long.","name_en":"Master Duelist"}],"name_en":"Rogue: Swashbuckler","_translated":true},{"index":"rogue-thief","name":"Voleur : Voleur","class":"rogue","source":"Player's Handbook","subclass_flavor":"Vous perfectionnez vos compétences dans les arts du vol. Les cambrioleurs, bandits, voleurs de bourses et autres criminels suivent généralement cet archétype, tout comme les voleurs qui préfèrent se considérer comme des chercheurs de trésors, des explorateurs, des fouilleurs et des enquêteurs professionnels. En plus d'améliorer votre agilité et votre furtivité, vous acquérez des compétences utiles pour fouiller dans des ruines antiques, lire des langues inconnues et utiliser des objets magiques que vous ne pourriez normalement pas utiliser.","desc":"","features":[{"name":"Des mains rapides","level":3,"desc":"À partir du niveau 3, vous pouvez utiliser l'action bonus accordée par votre action de ruse pour effectuer un test de Dextérité (tour de passe-passe), utiliser les outils de vos voleurs pour désamorcer un piège ou ouvrir une serrure, ou encore effectuer l'action Utiliser un objet.","name_en":"Fast Hands"},{"name":"Travail au deuxième étage","level":3,"desc":"Lorsque vous choisissez cet archétype au niveau 3, vous gagnez la capacité de grimper plus vite que la normale ; grimper ne vous coûte plus de mouvement supplémentaire.\n\nDe plus, lorsque vous effectuez un saut en courant, la distance que vous parcourez augmente d'un nombre de pieds égal à votre modificateur de Dextérité.","name_en":"Second-Story Work"},{"name":"Furtivité suprême","level":9,"desc":"À partir du niveau 9, vous avez un avantage lors d'un test de Dextérité (Furtivité) si vous ne vous déplacez pas à plus de la moitié de votre vitesse au cours du même tour.","name_en":"Supreme Sneak"},{"name":"Utiliser un appareil magique","level":13,"desc":"Au niveau 13, vous en savez suffisamment sur le fonctionnement de la magie pour pouvoir improviser l'utilisation d'objets même lorsqu'ils ne vous sont pas destinés. Vous ignorez toutes les exigences de classe, de race et de niveau concernant l’utilisation des objets magiques.","name_en":"Use Magic Device"},{"name":"Les réflexes du voleur","level":null,"desc":"Lorsque vous atteignez le niveau 17, vous êtes devenu adepte de l'art de tendre des embuscades et d'échapper rapidement au danger. Vous pouvez jouer deux tours au cours du premier round de n'importe quel combat. Vous prenez votre premier tour à votre initiative normale et votre deuxième tour à votre initiative moins 10. Vous ne pouvez pas utiliser cette fonctionnalité lorsque vous êtes surpris.","name_en":"Thief's Reflexes"}],"name_en":"Rogue: Thief","_translated":true},{"index":"sorcerer-aberrant-mind","name":"Sorcier : Esprit aberrant","class":"sorcerer","source":"Tasha's Cauldron of Everything","subclass_flavor":"Une influence extraterrestre a enroulé ses vrilles autour de votre esprit, vous donnant un pouvoir psionique. Vous pouvez désormais toucher d’autres esprits avec ce pouvoir et modifier le monde qui vous entoure en l’utilisant pour contrôler l’énergie magique du multivers. Ce pouvoir rayonnera-t-il de vous comme un phare d’espoir pour les autres ? Ou serez-vous une source de terreur pour ceux qui ressentent l’attaque de votre esprit et sont témoins des étranges manifestations de votre puissance ?","desc":"","features":[{"name":"Sorts psioniques","level":1,"desc":"À partir du niveau 1, vous apprenez des sorts supplémentaires lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts psioniques. Chacun de ces sorts compte pour vous comme un sort de sorcier, mais il ne compte pas dans le nombre de sorts de sorcier que vous connaissez.\n\nChaque fois que vous gagnez un niveau de sorcier, vous pouvez remplacer un sort que vous avez gagné grâce à cette fonctionnalité par un autre sort du même niveau. Le nouveau sort doit être un sort de divination ou d'enchantement de la liste des sorts de sorcier, démoniste ou sorcier.\nSorts psioniques\nNiveau Sorcier | Sorts\n1er | Armes de Hadar, Murmures dissonantes, Slivoïde mental\n3ème | Calmer les émotions, détecter les pensées\n5ème | Faim de Hadar, Envoi\n7ème | Tentacules noires d'Evard, invocation d'aberration\n9ème | Lien télépathique de Rary, télékinésie","name_en":"Psionic Spells"},{"name":"Discours télépathique","level":1,"desc":"À partir du 1er niveau, vous pouvez établir une connexion télépathique entre votre esprit et celui d’un autre. Par une action bonus, choisissez une créature que vous pouvez voir à moins de 9 mètres de vous. Vous et la créature choisie pouvez vous parler par télépathie tant que vous êtes tous les deux à un nombre de kilomètres l'un de l'autre égal à votre modificateur de Charisme (minimum de 1 mile). Pour vous comprendre, vous devez chacun parler mentalement dans une langue que l’autre connaît.\n\nLa connexion télépathique dure un nombre de minutes égal à votre niveau de sorcier. Il se termine plus tôt si vous êtes frappé d'incapacité ou mourez ou si vous utilisez cette capacité pour établir une connexion avec une autre créature.","name_en":"Telepathic Speech"},{"name":"Sorcellerie Psionique","level":6,"desc":"À partir du niveau 6, lorsque vous lancez un sort de niveau 1 ou supérieur à partir de votre fonction Sorts psioniques, vous pouvez le lancer en dépensant un emplacement de sort comme d'habitude ou en dépensant un nombre de points de sorcellerie égal au niveau du sort. Si vous lancez le sort en utilisant des points de sorcellerie, il ne nécessite aucune composante verbale ou somatique, et il ne nécessite aucune composante matérielle, à moins qu'elles ne soient consommées par le sort.","name_en":"Psionic Sorcery"},{"name":"Défenses psychiques","level":6,"desc":"Au niveau 6, vous gagnez une résistance aux dégâts psychiques et vous avez un avantage aux jets de sauvegarde contre le charme ou l'effroi.","name_en":"Psychic Defenses"},{"name":"Révélation dans la chair","level":14,"desc":"À partir du niveau 14, vous pouvez libérer la vérité aberrante cachée en vous. Par une action bonus, vous pouvez dépenser 1 ou plusieurs points de sorcellerie pour transformer magiquement votre corps pendant 10 minutes. Pour chaque point de sorcellerie que vous dépensez, vous pouvez gagner l'un des avantages suivants de votre choix, dont les effets durent jusqu'à la fin de la transformation :\n• Vous pouvez voir n'importe quelle créature invisible dans un rayon de 20 mètres autour de vous, à condition qu'elle ne soit pas à couvert. Vos yeux deviennent également noirs ou deviennent des vrilles sensorielles se tordant.\n• Vous gagnez une vitesse de vol égale à votre vitesse de marche et pouvez planer. Pendant que vous volez, votre peau scintille de mucus ou brille d’une lumière surnaturelle.\n• Vous gagnez une vitesse de nage égale à deux fois votre vitesse de marche et vous pouvez respirer sous l'eau. De plus, des branchies poussent à partir de votre cou ou se déploient derrière vos oreilles, vos doigts deviennent palmés ou des cils se tordent qui s'étendent à travers vos vêtements.\n• Votre corps, ainsi que tout équipement que vous portez ou transportez, devient gluant et souple. Vous pouvez vous déplacer dans n'importe quel espace aussi étroit que 1 pouce sans vous serrer, et vous pouvez dépenser 1,50 mètre de mouvement pour échapper aux contraintes non magiques ou être agrippé.","name_en":"Revelation in Flesh"},{"name":"Implosion déformée","level":18,"desc":"Au niveau 18, vous pouvez libérer votre pouvoir aberrant en tant qu'anomalie de déformation spatiale. Par une action, vous pouvez vous téléporter dans un espace inoccupé que vous pouvez voir à moins de 120 pieds de vous. Immédiatement après votre disparition, chaque créature à moins de 9 mètres de l'espace que vous avez quitté doit effectuer un jet de sauvegarde de Force contre votre DD de sauvegarde de sort. En cas d'échec, une créature subit 3d10 dégâts de force et est tirée directement vers l'espace que vous avez laissé, se terminant dans un espace inoccupé aussi proche que possible de votre ancien espace. En cas de sauvegarde réussie, la créature subit deux fois moins de dégâts et n'est pas tirée.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus le faire avant d'avoir terminé un long repos, à moins que vous ne dépensiez 5 points de sorcellerie pour l'utiliser à nouveau.","name_en":"Warping Implosion"}],"name_en":"Sorcerer: Aberrant Mind","_translated":true},{"index":"sorcerer-clockwork-soul","name":"Sorcier : Âme mécanique","class":"sorcerer","source":"Tasha's Cauldron of Everything","subclass_flavor":"La force cosmique de l’ordre vous a imprégné de magie. Ce pouvoir provient de Mechanus ou d'un royaume similaire, un plan d'existence entièrement façonné par l'efficacité d'une horloge. Vous, ou quelqu'un de votre lignée, avez peut-être été mêlé aux machinations des modrons, les êtres ordonnés qui habitent Mechanus. Peut-être que votre ancêtre a même participé à la Grande Marche de Modron. Quelle que soit son origine en vous, le pouvoir de l'ordre peut paraître étrange aux autres, mais pour vous, il fait partie d'un vaste et glorieux système.","desc":"","features":[{"name":"Magie mécanique","level":null,"desc":"Vous apprenez des sorts supplémentaires lorsque vous atteignez certains niveaux dans cette classe, comme indiqué dans le tableau des sorts mécaniques. Chaque sort compte pour vous comme un sort de sorcier, mais il ne compte pas dans le nombre de sorts de sorcier que vous connaissez.\n\nChaque fois que vous gagnez un niveau de sorcier, vous pouvez remplacer un sort que vous avez gagné grâce à cette fonctionnalité par un autre sort du même niveau. Le nouveau sort doit être un sort d'abjuration ou de transmutation de la liste des sorts de sorcier, démoniste ou sorcier.\nSorts d’horlogerie | \nNiveau Sorcier | Sorts\n1er | Alarme, protection contre le mal et le bien\n3ème | Aide, moindre restauration\n5ème | Dissipation de la magie, protection contre l'énergie\n7ème | Liberté de mouvement, invocation de construction\n9ème | Grande Restauration, Mur de Force\n\nDe plus, consultez le tableau des Manifestations de l'Ordre et choisissez ou déterminez au hasard la manière dont votre connexion à l'ordre se manifeste pendant que vous lancez l'un de vos sorts de sorcier.\nManifestations de l'Ordre | \nd6 | Manifestation\n1 | Des roues dentées spectrales planent derrière vous.\n2 | Les aiguilles d’une horloge tournent dans vos yeux.\n3 | Votre peau brille d’un éclat cuivré.\n4 | Des équations flottantes et des objets géométriques recouvrent votre corps.\n5 | Votre concentration de lancement de sorts prend temporairement la forme d’un petit mécanisme d’horlogerie.\n6 | Le tic-tac des engrenages ou la sonnerie d'une horloge peuvent être entendus par vous et les personnes affectées par votre magie.","name_en":"Clockwork Magic"},{"name":"Restaurer l'équilibre","level":1,"desc":"Dès le niveau 1, votre connexion au plan de l’ordre absolu vous permet d’égaliser les moments chaotiques. Lorsqu'une créature que vous pouvez voir à moins de 20 mètres de vous est sur le point de lancer un d20 avec un avantage ou un désavantage, vous pouvez utiliser votre réaction pour éviter que le jet ne soit affecté par un avantage ou un désavantage.\n\nVous pouvez utiliser cette fonctionnalité un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Restore Balance"},{"name":"Bastion du Droit","level":6,"desc":"À partir du niveau 6, vous pouvez puiser dans la grande équation de l’existence pour imprégner une créature d’un bouclier d’ordre scintillant. Par une action, vous pouvez dépenser 1 à 5 points de sorcellerie pour créer une protection magique autour de vous ou d'une autre créature que vous pouvez voir à moins de 9 mètres de vous. La protection dure jusqu'à ce que vous ayez terminé un long repos ou jusqu'à ce que vous utilisiez à nouveau cette fonctionnalité.\n\nLa balise est représentée par un nombre de d8 égal au nombre de points de sorcellerie dépensés pour la créer. Lorsque la créature protégée subit des dégâts, elle peut dépenser un certain nombre de ces dés, les lancer et réduire les dégâts subis du total lancé sur ces dés.","name_en":"Bastion of Law"},{"name":"Transe de l'Ordre","level":14,"desc":"À partir du niveau 14, vous acquérez la capacité d’aligner votre conscience sur les calculs sans fin de Mechanus. Par une action bonus, vous pouvez entrer dans cet état pendant 1 minute. Pendant toute la durée du sort, les jets d'attaque contre vous ne peuvent pas bénéficier d'un avantage, et chaque fois que vous effectuez un jet d'attaque, un test de capacité ou un jet de sauvegarde, vous pouvez traiter un jet de 9 ou moins sur le d20 comme un 10.\n\nUne fois que vous avez utilisé cette action bonus, vous ne pouvez plus l'utiliser avant d'avoir terminé un repos long, à moins que vous ne dépensiez 5 points de sorcellerie pour l'utiliser à nouveau.","name_en":"Trance of Order"},{"name":"Cavalcade mécanique","level":18,"desc":"Au niveau 18, vous invoquez des esprits de l'ordre pour dissiper le désordre autour de vous. Par une action, vous invoquez les esprits dans un cube de 9 mètres provenant de vous. Les esprits ressemblent à des modrons ou à d'autres constructions de votre choix. Les esprits sont intangibles et invulnérables, et ils créent les effets suivants dans le cube avant de disparaître :\n• Les esprits restaurent jusqu'à 100 points de vie, répartis à votre guise entre n'importe quel nombre de créatures de votre choix dans le cube.\n• Tous les objets endommagés entièrement dans le cube sont réparés instantanément.\n• Chaque sort de niveau 6 ou inférieur se termine sur les créatures et objets de votre choix dans le cube.\n\nUne fois que vous avez utilisé cette action, vous ne pouvez plus l’utiliser avant d’avoir terminé un long repos, à moins que vous ne dépensiez 7 points de sorcellerie pour l’utiliser à nouveau.","name_en":"Clockwork Cavalcade"}],"name_en":"Sorcerer: Clockwork Soul","_translated":true},{"index":"sorcerer-divine-soul","name":"Sorcier : Âme divine","class":"sorcerer","source":"Xanathar's Guide to Everything","subclass_flavor":"Parfois, l’étincelle magique qui alimente un sorcier vient d’une source divine qui scintille dans l’âme. Avoir une âme aussi bénie est un signe que votre magie innée pourrait provenir d’un lien familial lointain mais puissant avec un être divin. Peut-être que votre ancêtre était un ange, transformé en mortel et envoyé combattre au nom d’un dieu. Ou bien votre naissance pourrait s’aligner sur une ancienne prophétie, vous désignant comme un serviteur des dieux ou un vaisseau choisi de la magie divine.","desc":"","features":[{"name":"Magie divine","level":null,"desc":"Votre lien avec le divin vous permet d'apprendre des sorts normalement associés à la classe clerc. Lorsque votre fonction de lancement de sorts vous permet d'apprendre un sort mineur de sorcier ou un sort de sorcier de niveau 1 ou supérieur, vous pouvez choisir le nouveau sort dans la liste des sorts de clerc ou dans la liste des sorts de sorcier. Sinon, vous devez obéir à toutes les restrictions de sélection du sort, et celui-ci devient pour vous un sort de sorcier.\n\nDe plus, choisissez une affinité pour la source de votre pouvoir divin : le bien, le mal, la loi, le chaos ou la neutralité. Vous apprenez un sort supplémentaire basé sur cette affinité, comme indiqué ci-dessous. C'est un sort de sorcier pour vous, mais il ne compte pas dans votre nombre de sorts de sorcier connus. Si vous remplacez ce sort ultérieurement, vous devez le remplacer par un sort de la liste des sorts de clerc.\nAffinité | Sort\nBon | Guérir les blessures\nMal | Infliger des blessures\nDroit | Bénir\nChaos | Fléau\nNeutralité | Protection contre le mal et le bien","name_en":"Divine Magic"},{"name":"Favorisé par les dieux","level":1,"desc":"Dès le niveau 1, le pouvoir divin protège votre destin. Si vous échouez à un jet de sauvegarde ou ratez un jet d'attaque, vous pouvez lancer 2d4 et l'ajouter au total, modifiant éventuellement le résultat.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Favored by the Gods"},{"name":"Guérison habilitée","level":6,"desc":"À partir du niveau 6, l’énergie divine qui vous traverse peut activer des sorts de guérison. Chaque fois que vous ou un allié à moins de 1,50 mètre de vous lancez des dés pour déterminer le nombre de points de vie qu'un sort restaure, vous pouvez dépenser 1 point de sorcellerie pour relancer n'importe quel nombre de ces dés une fois, à condition que vous ne soyez pas incapable d'agir. Vous ne pouvez utiliser cette fonctionnalité qu'une seule fois par tour.","name_en":"Empowered Healing"},{"name":"Forme angélique","level":14,"desc":"À partir du niveau 14, vous pouvez utiliser une action bonus pour manifester une paire d'ailes spectrales depuis votre dos. Tant que les ailes sont présentes, vous disposez d’une vitesse de vol de 30 pieds. Les ailes durent jusqu'à ce que vous soyez incapable d'agir, que vous mouriez ou que vous les rejetiez par une action bonus.\n\nL'affinité que vous avez choisie pour votre fonction Magie Divine détermine l'apparence des ailes spectrales : des ailes d'aigle pour le bien ou la loi, des ailes de chauve-souris pour le mal ou le chaos et des ailes de libellule pour la neutralité.","name_en":"Angelic Form"},{"name":"Récupération surnaturelle","level":18,"desc":"Au niveau 18, vous gagnez la capacité de surmonter des blessures graves. Par une action bonus, lorsqu'il vous reste moins de la moitié de vos points de vie, vous pouvez récupérer un nombre de points de vie égal à la moitié de votre maximum de points de vie.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Unearthly Recovery"}],"name_en":"Sorcerer: Divine Soul","_translated":true},{"index":"sorcerer-draconic-bloodline","name":"Sorcier : Lignée Draconique","class":"sorcerer","source":"Player's Handbook","subclass_flavor":"Votre magie innée vient de la magie draconique mêlée à votre sang ou à celui de vos ancêtres. Le plus souvent, les sorciers ayant cette origine font remonter leur descendance à un puissant sorcier des temps anciens qui a conclu un marché avec un dragon ou qui aurait même pu revendiquer un parent dragon. Certaines de ces lignées sont bien établies dans le monde, mais la plupart sont obscures. N'importe quel sorcier peut être le premier d'une nouvelle lignée, à la suite d'un pacte ou d'une autre circonstance exceptionnelle.","desc":"","features":[{"name":"Ancêtre Dragon","level":1,"desc":"Au niveau 1, vous choisissez un type de dragon comme ancêtre. Le type de dégâts associé à chaque dragon est utilisé par les fonctionnalités que vous gagnerez plus tard.\nAscendance draconique\nCouleur du dragon | Type de dommage\nNoir | Acide\nBleu | Foudre\nLaiton | Feu\nBronze | Foudre\nCuivre | Acide\nOr | Feu\nVert | Poison\nRouge | Feu\nArgent | Froid\nBlanc | Froid\n\nVous pouvez parler, lire et écrire le draconique. De plus, chaque fois que vous effectuez un test de Charisme lorsque vous interagissez avec des dragons, votre bonus de maîtrise est doublé s'il s'applique au test.","name_en":"Dragon Ancestor"},{"name":"Résilience draconique","level":1,"desc":"À mesure que la magie circule dans votre corps, elle fait émerger les traits physiques de vos ancêtres dragons. Au 1er niveau, votre maximum de points de vie augmente de 1 et augmente à nouveau de 1 à chaque fois que vous gagnez un niveau dans cette classe.\n\nDe plus, certaines parties de votre peau sont recouvertes d’une fine couche d’écailles ressemblant à celles d’un dragon. Lorsque vous ne portez pas d'armure, votre CA est égale à 13 + votre modificateur de Dextérité.","name_en":"Draconic Resilience"},{"name":"Affinité élémentaire","level":6,"desc":"À partir du niveau 6, lorsque vous lancez un sort qui inflige des dégâts du type associé à votre ascendance draconique, ajoutez votre modificateur de Charisme à un jet de dégâts de ce sort. En même temps, vous pouvez dépenser 1 point de sorcellerie pour gagner en résistance à ce type de dégâts pendant 1 heure.","name_en":"Elemental Affinity"},{"name":"Ailes de dragon","level":14,"desc":"Au niveau 14, vous obtenez la capacité de faire pousser une paire d'ailes de dragon depuis votre dos, gagnant ainsi une vitesse de vol égale à votre vitesse actuelle. Vous pouvez créer ces ailes comme une action bonus pendant votre tour. Ils durent jusqu'à ce que vous les rejetiez comme une action bonus à votre tour.\n\nVous ne pouvez pas manifester vos ailes lorsque vous portez une armure à moins que l'armure ne soit conçue pour les accueillir, et les vêtements non conçus pour accueillir vos ailes peuvent être détruits lorsque vous les manifestez.","name_en":"Dragon Wings"},{"name":"Présence draconique","level":18,"desc":"À partir du niveau 18, vous pouvez canaliser la présence redoutable de votre ancêtre dragon, provoquant la stupéfaction ou la peur chez ceux qui vous entourent. Par une action, vous pouvez dépenser 5 points de sorcellerie pour utiliser ce pouvoir et dégager une aura de crainte ou de peur (au choix) jusqu'à une distance de 60 pieds. Pendant 1 minute ou jusqu'à ce que vous perdiez votre concentration (comme si vous lanciez un sort de concentration), chaque créature hostile qui commence son tour dans cette aura doit réussir un jet de sauvegarde de Sagesse ou être charmée (si vous avez choisi la crainte) ou effrayée (si vous avez choisi la peur) jusqu'à la fin de l'aura. Une créature qui réussit ce jet de sauvegarde est immunisée contre votre aura pendant 24 heures.","name_en":"Draconic Presence"}],"name_en":"Sorcerer: Draconic Bloodline","_translated":true},{"index":"sorcerer-shadow-magic","name":"Sorcier : Magie de l'Ombre","class":"sorcerer","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous êtes une créature de l'ombre, car votre magie innée vient de Shadowfell elle-même. Vous pourriez retracer votre lignée jusqu'à une entité de cet endroit, ou peut-être avez-vous été exposé à son énergie déchue et transformé par elle.","desc":"","features":[{"name":"bizarreries du sorcier de l'ombre","level":null,"desc":"À votre discrétion, vous pouvez choisir ou lancer un jet sur le tableau des bizarreries du sorcier de l'ombre pour créer une bizarrerie pour votre personnage.\nd6 | Bizarre\n1 | Vous êtes toujours glacial au toucher.\n2 | Lorsque vous dormez, vous ne semblez pas respirer (même si vous devez quand même respirer pour survivre).\n3 | Vous saignez à peine, même si vous êtes gravement blessé.\n4 | Votre cœur bat une fois par minute. Cet événement surprend parfois.\n5 | Vous avez du mal à vous rappeler que les êtres vivants et les cadavres doivent être traités différemment.\n6 | Vous avez cligné des yeux. Une fois. La semaine dernière.","name_en":"Shadow Sorcerer Quirks"},{"name":"Les yeux du noir","level":1,"desc":"Dès le 1er niveau, vous disposez d'une vision dans le noir avec une portée de 120 pieds.\n\nLorsque vous atteignez le niveau 3 dans cette classe, vous apprenez le sort des ténèbres, qui ne compte pas dans votre nombre de sorts de sorcier connus. De plus, vous pouvez le lancer en dépensant 2 points de sorcellerie ou en dépensant un emplacement de sort. Si vous le lancez avec des points de sorcellerie, vous pouvez voir à travers les ténèbres créées par le sort.","name_en":"Eyes of the Dark"},{"name":"Force de la tombe","level":1,"desc":"Dès le niveau 1, votre existence dans un état crépusculaire entre la vie et la mort vous rend difficile à vaincre. Lorsque les dégâts vous réduisent à 0 point de vie, vous pouvez faire un jet de sauvegarde de Charisme (DD 5 + les dégâts subis). En cas de réussite, vous chutez à 1 point de vie. Vous ne pouvez pas utiliser cette fonctionnalité si vous êtes réduit à 0 point de vie par des dégâts radiants ou par un coup critique.\n\nUne fois le jet de sauvegarde réussi, vous ne pouvez plus utiliser cette fonctionnalité tant que vous n'avez pas terminé un repos long.","name_en":"Strength of the Grave"},{"name":"Chien de mauvais présage","level":6,"desc":"Au niveau 6, vous obtenez la capacité d'invoquer une créature des ténèbres hurlante pour harceler vos ennemis. Par une action bonus, vous pouvez dépenser 3 points de sorcellerie pour invoquer un chien de mauvais augure afin de cibler une créature que vous pouvez voir à moins de 120 pieds de vous. Le chien utilise les statistiques du loup terrible, avec les modifications suivantes :\n• Le chien est de taille Medium, pas Large, et il compte comme une monstruosité, pas comme une bête.\n• Il apparaît avec un nombre de points de vie temporaires égal à la moitié de votre niveau de sorcier.\n• Il peut se déplacer à travers d'autres créatures et objets comme s'il s'agissait d'un terrain difficile. Le chien subit 5 dégâts de force s'il termine son tour à l'intérieur d'un objet.\n• Au début de son tour, le chien connaît automatiquement l'emplacement de sa cible. Si la cible était cachée, elle n'est plus cachée au chien.\n\nLe chien apparaît dans un espace inoccupé de votre choix à moins de 9 mètres de la cible. Lancez l'initiative pour le chien. A son tour, il ne peut se déplacer vers sa cible que par la route la plus directe, et il ne peut utiliser son action que pour attaquer sa cible. Le chien peut lancer des attaques d’opportunité, mais uniquement contre sa cible. De plus, tant que le chien se trouve à moins de 1,50 mètre de la cible, celle-ci est désavantagée aux jets de sauvegarde contre tout sort que vous lancez. Le chien disparaît s'il est réduit à 0 point de vie, si sa cible est réduite à 0 point de vie ou au bout de 5 minutes.","name_en":"Hound of Ill Omen"},{"name":"Promenade dans l'ombre","level":14,"desc":"Au niveau 14, vous gagnez la capacité de passer d’une ombre à une autre. Lorsque vous êtes dans une faible lumière ou dans l'obscurité, par une action bonus, vous pouvez vous téléporter jusqu'à 120 pieds dans un espace inoccupé que vous pouvez voir et qui est également dans une faible lumière ou dans l'obscurité.","name_en":"Shadow Walk"},{"name":"Forme ombrale","level":18,"desc":"À partir du niveau 18, vous pouvez dépenser 6 points de sorcellerie comme action bonus pour vous transformer en une forme sombre. Sous cette forme, vous avez une résistance à tous les dégâts, à l'exception des dégâts de force et des dégâts radiants, et vous pouvez vous déplacer à travers d'autres créatures et objets comme s'il s'agissait d'un terrain difficile. Vous subissez 5 dégâts de force si vous terminez votre tour à l'intérieur d'un objet.\n\nVous restez sous cette forme pendant 1 minute. Il se termine plus tôt si vous êtes frappé d'incapacité, si vous mourez ou si vous le rejetez comme une action bonus.","name_en":"Umbral Form"}],"name_en":"Sorcerer: Shadow Magic","_translated":true},{"index":"sorcerer-storm-sorcery","name":"Sorcier : Sorcellerie des Tempêtes","class":"sorcerer","source":"Sword Coast Adventurer's Guide, Xanathar's Guide to Everything","subclass_flavor":"Votre magie innée vient du pouvoir de l’air élémentaire. Beaucoup de personnes possédant ce pouvoir peuvent faire remonter leur magie à une expérience de mort imminente provoquée par la Grande Pluie, mais peut-être êtes-vous né pendant un vent hurlant si puissant que les gens en racontent encore des histoires, ou votre lignée pourrait inclure l'influence de puissantes créatures aériennes telles que les vaati ou les djinns. Quoi qu’il en soit, la magie de la tempête imprègne votre être.","desc":"","features":[{"name":"Haut-parleur à vent","level":null,"desc":"La magie arcanique que vous commandez est imprégnée d’air élémentaire. Vous pouvez parler, lire et écrire Primordial. Connaître cette langue permet de comprendre et d'être compris par ceux qui parlent ses dialectes : Aquan, Auran, Ignan et Terran.","name_en":"Wind Speaker"},{"name":"Magie tumultueuse","level":1,"desc":"À partir du niveau 1, vous pouvez utiliser une action bonus pendant votre tour pour provoquer des rafales tourbillonnantes d'air élémentaire qui vous entourent brièvement, immédiatement avant ou après avoir lancé un sort de niveau 1 ou supérieur. Cela vous permet de voler jusqu'à 10 pieds sans provoquer d'attaques d'opportunité.","name_en":"Tempestuous Magic"},{"name":"Cœur de la tempête","level":6,"desc":"Au niveau 6, vous gagnez la résistance aux dégâts de foudre et de tonnerre. De plus, chaque fois que vous commencez à lancer un sort de niveau 1 ou supérieur qui inflige des dégâts de foudre ou de tonnerre, une magie orageuse jaillit de vous. Cette éruption fait que les créatures de votre choix que vous pouvez voir à moins de 3 mètres de vous subissent des dégâts de foudre ou de tonnerre (à choisir à chaque activation de cette capacité) égaux à la moitié de votre niveau de sorcier.","name_en":"Heart of the Storm"},{"name":"Guide des tempêtes","level":6,"desc":"Au niveau 6, vous gagnez la capacité de contrôler subtilement la météo autour de vous.\n\nS'il pleut, vous pouvez utiliser une action pour empêcher la pluie de tomber dans une sphère de 6 mètres de rayon centrée sur vous. Vous pouvez mettre fin à cet effet par une action bonus.\n\nS'il y a du vent, vous pouvez utiliser une action bonus à chaque tour pour choisir la direction dans laquelle le vent souffle dans une sphère de 100 pieds de rayon centrée sur vous. Le vent souffle dans cette direction jusqu’à la fin de votre prochain tour. Cette fonctionnalité ne modifie pas la vitesse du vent.","name_en":"Storm Guide"},{"name":"Fureur de la tempête","level":14,"desc":"À partir du niveau 14, lorsque vous êtes touché par une attaque au corps à corps, vous pouvez utiliser votre réaction pour infliger des dégâts de foudre à l'attaquant. Les dégâts sont égaux à votre niveau de sorcier. L'attaquant doit également effectuer un jet de sauvegarde de Force contre le DD de votre sort de sorcier. En cas d'échec, l'attaquant est poussé en ligne droite jusqu'à 20 pieds de vous.","name_en":"Storm's Fury"},{"name":"Âme du vent","level":18,"desc":"Au niveau 18, vous gagnez l’immunité contre les dégâts de foudre et de tonnerre.\n\nVous gagnez également une vitesse de vol magique de 60 pieds. Par une action, vous pouvez réduire votre vitesse de vol à 9 mètres pendant 1 heure et choisir un nombre de créatures dans un rayon de 9 mètres autour de vous égal à 3 + votre modificateur de Charisme. Les créatures choisies gagnent une vitesse de vol magique de 9 mètres pendant 1 heure. Une fois que vous réduisez votre vitesse de vol de cette manière, vous ne pouvez plus le faire avant d'avoir terminé un repos court ou long.","name_en":"Wind Soul"}],"name_en":"Sorcerer: Storm Sorcery","_translated":true},{"index":"sorcerer-wild-magic","name":"Sorcier : Magie sauvage","class":"sorcerer","source":"Player's Handbook","subclass_flavor":"Votre magie innée vient des forces sauvages du chaos qui sous-tendent l’ordre de la création. Vous avez peut-être été exposé à une forme de magie brute, peut-être à travers un portail planaire menant aux Limbes, aux plans élémentaires ou au mystérieux Royaume lointain. Peut-être avez-vous été béni par une puissante créature féerique ou marqué par un démon. Ou votre magie pourrait être un hasard de votre naissance, sans cause ni raison apparente. Quelle que soit la manière dont elle s’est produite, cette magie chaotique bouillonne en vous, attendant une issue.","desc":"","features":[{"name":"Déferlement de magie sauvage","level":1,"desc":"À partir du moment où vous choisissez cette origine au niveau 1, votre lancement de sorts peut déclencher des vagues de magie indomptée. Une fois par tour, le DM peut vous faire lancer un d20 immédiatement après avoir lancé un sort de sorcier de niveau 1 ou supérieur. Si vous obtenez un 1, lancez un jet sur la table Wild Magic Surge pour créer un effet magique. Si cet effet est un sort, il est trop sauvage pour être affecté par votre métamagie, et s'il nécessite normalement de la concentration, il ne nécessite pas de concentration dans ce cas ; le sort dure toute sa durée.","name_en":"Wild Magic Surge"},{"name":"Marées du chaos","level":1,"desc":"À partir du niveau 1, vous pouvez manipuler les forces du hasard et du chaos pour obtenir l’avantage lors d’un jet d’attaque, d’un test de caractéristique ou d’un jet de sauvegarde. Une fois cela fait, vous devez terminer un long repos avant de pouvoir utiliser à nouveau cette fonctionnalité.\n\nÀ tout moment avant que vous réutilisiez cette fonctionnalité, le DM peut vous demander de lancer un jet sur la table Wild Magic Surge immédiatement après avoir lancé un sort de sorcier de niveau 1 ou supérieur. Vous retrouvez alors l’usage de cette fonctionnalité.","name_en":"Tides of Chaos"},{"name":"Pliez la chance","level":6,"desc":"À partir du niveau 6, vous avez la capacité de renverser le destin en utilisant votre magie sauvage. Lorsqu'une autre créature que vous pouvez voir effectue un jet d'attaque, un test de capacité ou un jet de sauvegarde, vous pouvez utiliser votre réaction et dépenser 2 points de sorcellerie pour lancer 1d4 et appliquer le nombre obtenu sous forme de bonus ou de malus (votre choix) au jet de la créature. Vous pouvez le faire après que la créature ait lancé le jet, mais avant que les effets du jet ne se produisent.","name_en":"Bend Luck"},{"name":"Chaos contrôlé","level":14,"desc":"Au niveau 14, vous gagnez un minimum de contrôle sur les poussées de votre magie sauvage. Chaque fois que vous lancez un lancer sur la table Wild Magic Surge, vous pouvez lancer deux fois et utiliser l'un ou l'autre nombre.","name_en":"Controlled Chaos"},{"name":"Bombardement de sorts","level":18,"desc":"À partir du niveau 18, l’énergie néfaste de vos sorts s’intensifie. Lorsque vous lancez des dégâts pour un sort et que vous lancez le nombre le plus élevé possible sur l'un des dés, choisissez l'un de ces dés, lancez-le à nouveau et ajoutez ce jet aux dégâts. Vous ne pouvez utiliser cette fonctionnalité qu’une seule fois par tour.\nDéferlement de magie sauvage\nd100 | Effet | d100 | Effet\n01-02 | Lancez sur cette table au début de chacun de vos tours pendant la minute suivante, en ignorant ce résultat lors des lancers suivants. | 51-52 | Un bouclier spectral plane près de vous pendant la minute suivante, vous accordant un bonus de +2 à la CA et une immunité au missile magique.\n03-04 | Pendant la minute suivante, vous pouvez voir n'importe quelle créature invisible si vous avez une ligne de vue vers elle. | 53-54 | Vous êtes immunisé contre l’intoxication alcoolique pendant les 5d6 prochains jours.\n05-06 | Un modron choisi et contrôlé par le DM apparaît dans un espace inoccupé à moins de 1,50 mètre de vous, puis disparaît 1 minute plus tard. | 55-56 | Vos cheveux tombent mais repoussent en 24 heures.\n07-08 | Vous lancez Boule de feu comme un sort de niveau 3 centré sur vous-même. | 57-58 | Pendant la minute suivante, tout objet inflammable que vous touchez et qui n'est pas porté ou transporté par une autre créature s'enflamme.\n09-10 | Vous lancez Magic Missile comme un sort de niveau 5. | 59-60 | Vous récupérez votre emplacement de sort dépensé le plus bas niveau.\n11-12 | Lancez un d10. Votre taille change d'un nombre de pouces égal au rouleau. Si le résultat est impair, vous rétrécissez. Si le résultat est pair, vous grandissez. | 61-62 | Pendant la minute suivante, vous devez crier lorsque vous parlez.\n13-14 | Vous lancez Confusion centrée sur vous-même. | 63-64 | Vous lancez Fog Cloud centré sur vous-même.\n15-16 | Pendant la minute suivante, vous regagnez 5 points de vie au début de chacun de vos tours. | 65-66 | Jusqu'à trois créatures que vous choisissez dans un rayon de 9 mètres autour de vous subissent 4d10 dégâts de foudre.\n17-18 | Vous faites pousser une longue barbe faite de plumes qui reste jusqu'à ce que vous éternuiez, moment auquel les plumes explosent de votre visage. | 67-68 | Vous êtes effrayé par la créature la plus proche jusqu'à la fin de votre prochain tour.\n19-20 | Vous lancez Grease centré sur vous-même. | 69-70 | Chaque créature à moins de 9 mètres de vous devient invisible pendant la minute suivante. L'invisibilité prend fin sur une créature lorsqu'elle attaque ou lance un sort.\n21-22 | Les créatures ont un désavantage aux jets de sauvegarde par rapport au prochain sort que vous lancerez dans la minute suivante et qui implique un jet de sauvegarde. | 71-72 | Vous gagnez une résistance à tous les dégâts pendant la minute suivante.\n23-24 | Votre peau prend une teinte bleue vibrante. Un sort Supprimer la malédiction peut mettre fin à cet effet. | 73-74 | Une créature aléatoire dans un rayon de 20 mètres autour de vous est empoisonnée pendant 1d4 heures.\n25-26 | Un œil apparaît sur votre front pendant la minute suivante. Pendant ce temps, vous bénéficiez d’un avantage aux tests de Sagesse (Perception) qui reposent sur la vue. | 75-76 | Vous brillez d’une lumière vive dans un rayon de 9 mètres pendant la minute suivante. Toute créature qui termine son tour à moins de 1,50 mètre de vous est aveuglée jusqu'à la fin de son prochain tour.\n27-28 | Pendant la minute suivante, tous vos sorts avec un temps d'incantation de 1 action ont un temps d'incantation de 1 action bonus. | 77-78 | Vous lancez Polymorphe sur vous-même. Si vous échouez au jet de sauvegarde, vous vous transformez en mouton pour toute la durée du sort.\n29-30 | Vous vous téléportez jusqu'à 60 pieds vers un espace inoccupé de votre choix que vous pouvez voir. | 79-80 | Des papillons et des pétales de fleurs illusoires flottent dans les airs à moins de 3 mètres de vous pendant la minute suivante.\n31-32 | Vous êtes transporté dans le plan Astral jusqu'à la fin de votre prochain tour, après quoi vous retournez dans l'espace que vous occupiez précédemment ou dans l'espace inoccupé le plus proche si cet espace est occupé. | 81-82 | Vous pouvez effectuer une action supplémentaire immédiatement.\n33-34 | Maximisez les dégâts du prochain sort dommageable que vous lancerez dans la minute suivante. | 83-84 | Chaque créature dans un rayon de 9 mètres autour de vous subit 1d10 dégâts nécrotiques. Vous récupérez des points de vie égaux à la somme des dégâts nécrotiques infligés.\n35-36 | Lancez un d10. Votre âge change d'un nombre d'années égal au rôle. Si le jet est impair, vous rajeunissez (minimum 1 an). Si le résultat est pair, vous vieillissez. | 85-86 | Vous lancez Image miroir.\n37-38 | 1d6 flumphs contrôlés par le MD apparaissent dans des espaces inoccupés à moins de 20 mètres de vous et ont peur de vous. Ils disparaissent après 1 minute. | 87-88 | Vous lancez Vol sur une créature aléatoire à moins de 60 pieds de vous.\n39-40 | Vous récupérez 2d10 points de vie. | 89-90 | Vous devenez invisible pendant la minute suivante. Pendant ce temps, les autres créatures ne peuvent pas vous entendre. L'invisibilité prend fin si vous attaquez ou lancez un sort.\n41-42 | Vous vous transformez en plante en pot jusqu'au début de votre prochain tour. En tant que plante, vous êtes incapable d’agir et êtes vulnérable à tous les dommages. Si vous tombez à 0 point de vie, votre pot se brise et votre forme revient. | 91-92 | Si vous mourez dans la minute qui suit, vous revenez immédiatement à la vie comme grâce au sort Réincarnation.\n43-44 | Pendant la minute suivante, vous pouvez vous téléporter jusqu'à 20 pieds comme action bonus à chacun de vos tours. | 93-94 | Votre taille augmente d’une catégorie de taille pendant la minute suivante.\n45-46 | Vous lancez Lévitation sur vous-même. | 95-96 | Vous et toutes les créatures à moins de 9 mètres de vous devenez vulnérables aux dégâts perçants pendant la minute suivante.\n47-48 | Une licorne contrôlée par le DM apparaît dans un espace à moins de 1,50 mètre de vous, puis disparaît 1 minute plus tard. | 97-98 | Vous êtes entouré d’une musique faible et éthérée pendant la minute suivante.\n49-50 | Vous ne pouvez pas parler pendant la minute suivante. Chaque fois que vous essayez, des bulles roses sortent de votre bouche. | 99-00 | Vous récupérez tous les points de sorcellerie dépensés.","name_en":"Spell Bombardment"}],"name_en":"Sorcerer: Wild Magic","_translated":true},{"index":"warlock-eldritch-invocations","name":"Invocations surnaturelles","class":"warlock","source":"Player's Handbook\nPrerequisite: eldritch blast cantrip","subclass_flavor":"Condition préalable:","desc":"","features":[{"name":"Explosion angoissante","level":null,"desc":"Lorsque vous lancez une explosion surnaturelle, ajoutez votre modificateur de Charisme aux dégâts qu'elle inflige en cas de coup.","name_en":"Agonizing Blast"},{"name":"Armure des ombres","level":null,"desc":"Vous pouvez lancer une armure de mage sur vous-même à volonté, sans dépenser d'emplacement de sort ni de composants matériels.","name_en":"Armor of Shadows"},{"name":"Étape ascendante","level":null,"desc":"Vous pouvez lancer Lévitation sur vous-même à volonté, sans dépenser d'emplacement de sort ni de composants matériels.","name_en":"Ascendant Step"},{"name":"Aspect de la Lune","level":null,"desc":"Vous n’avez plus besoin de dormir et vous ne pouvez en aucun cas être forcé de dormir. Pour bénéficier des bienfaits d’un long repos, vous pouvez consacrer les 8 heures à des activités légères, comme lire votre Livre des Ombres et surveiller.","name_en":"Aspect of the Moon"},{"name":"Discours de la bête","level":null,"desc":"Vous pouvez lancer parler avec les animaux à volonté, sans dépenser d'emplacement de sort.","name_en":"Beast Speech"},{"name":"Influence séduisante","level":null,"desc":"Vous maîtrisez les compétences de tromperie et de persuasion.","name_en":"Beguiling Influence"},{"name":"Murmures envoûtantes","level":null,"desc":"Prérequis : 7ème niveau\n\nVous pouvez lancer la contrainte une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Bewitching Whispers"},{"name":"Lien du Talisman","level":null,"desc":"Pendant que quelqu'un d'autre porte votre talisman, vous pouvez utiliser votre action pour vous téléporter vers l'espace inoccupé le plus proche de lui, à condition que vous soyez tous les deux sur le même plan d'existence. Le porteur de votre talisman peut faire la même chose, en utilisant son action pour se téléporter vers vous. La téléportation peut être utilisée un nombre de fois égal à votre bonus de maîtrise, et toutes les utilisations dépensées sont restaurées lorsque vous terminez un repos long.","name_en":"Bond of the Talisman"},{"name":"Livre des secrets anciens","level":null,"desc":"Prérequis : fonctionnalité Pacte du Tome\n\nVous pouvez désormais inscrire des rituels magiques dans votre Livre des Ombres. Choisissez deux sorts de 1er niveau qui ont l'étiquette rituelle dans la liste de sorts de n'importe quelle classe (les deux ne doivent pas nécessairement provenir de la même liste). Les sorts apparaissent dans le livre et ne comptent pas dans le nombre de sorts que vous connaissez. Avec votre Livre des Ombres en main, vous pouvez lancer les sorts choisis sous forme de rituels. Vous ne pouvez pas lancer de sorts sauf sous forme de rituels, à moins que vous ne les ayez appris par d'autres moyens. Vous pouvez également lancer un sort de démoniste que vous connaissez comme rituel s'il porte l'étiquette rituelle.\n\nAu cours de vos aventures, vous pouvez ajouter d'autres sorts rituels à votre Livre des Ombres. Lorsque vous trouvez un tel sort, vous pouvez l'ajouter au livre si le niveau du sort est égal ou inférieur à la moitié de votre niveau de démoniste (arrondi au supérieur) et si vous avez le temps de transcrire le sort. Pour chaque niveau du sort, le processus de transcription prend 2 heures et coûte 50 po pour les encres rares nécessaires à son inscription.","name_en":"Book of Ancient Secrets"},{"name":"Chaînes de Carceri","level":null,"desc":"Vous pouvez lancer Hold Monster à volonté – en ciblant un céleste, un démon ou un élémentaire – sans dépenser d'emplacement de sort ou de composants matériels. Vous devez terminer un long repos avant de pouvoir utiliser à nouveau cette invocation sur la même créature.","name_en":"Chains of Carceri"},{"name":"Cape de mouches","level":null,"desc":"En guise d'action bonus, vous pouvez vous entourer d'une aura magique qui ressemble à des mouches bourdonnantes. L'aura s'étend à 1,50 mètre de vous dans toutes les directions, mais pas à travers une couverture totale. Cela dure jusqu'à ce que vous soyez frappé d'incapacité ou que vous le rejetiez comme une action bonus.\n\nL'aura vous accorde un avantage sur les tests de Charisme (Intimidation) mais un désavantage sur tous les autres tests de Charisme. Toute autre créature qui commence son tour dans l'aura subit des dégâts de poison égaux à votre modificateur de Charisme (minimum de 0 dégâts).\n\nUne fois que vous avez utilisé cette invocation, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Cloak of Flies"},{"name":"La vue du diable","level":null,"desc":"Vous pouvez voir normalement dans l'obscurité, à la fois magique et non magique, jusqu'à une distance de 120 pieds.","name_en":"Devil's Sight"},{"name":"Mot épouvantable","level":null,"desc":"Vous pouvez lancer de la confusion une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Dreadful Word"},{"name":"Esprit surnaturel","level":null,"desc":"","name_en":"Eldritch Mind"},{"name":"Vue surnaturelle","level":null,"desc":"Vous pouvez lancer la détection de magie à volonté, sans dépenser d'emplacement de sort ni de composants matériels.","name_en":"Eldritch Sight"},{"name":"Châtiment surnaturel","level":null,"desc":"Une fois par tour, lorsque vous touchez une créature avec votre arme du pacte, vous pouvez dépenser un emplacement de sort de démoniste pour infliger 1d8 dégâts de force supplémentaires à la cible, plus 1d8 supplémentaires par niveau de l'emplacement de sort, et vous pouvez mettre la cible à terre si elle est énorme ou plus petite.","name_en":"Eldritch Smite"},{"name":"Lance surnaturelle","level":null,"desc":"Lorsque vous lancez une explosion mystique, sa portée est de 300 pieds.","name_en":"Eldritch Spear"},{"name":"Yeux du gardien des runes","level":null,"desc":"Vous pouvez lire tous les écrits.","name_en":"Eyes of the Rune Keeper"},{"name":"Scribe lointain","level":null,"desc":"Une nouvelle page apparaît dans votre Livre des Ombres. Avec votre permission, une créature peut utiliser son action pour écrire son nom sur cette page, qui peut contenir un nombre de noms égal à votre bonus de maîtrise.\n\nVous pouvez lancer le sort d'envoi, en ciblant une créature dont le nom est sur la page, sans utiliser d'emplacement de sort et sans utiliser de composants matériels. Pour ce faire, vous devez écrire le message sur la page. La cible entend le message dans son esprit et si elle répond, son message apparaît sur la page plutôt que dans votre esprit. L'écriture disparaît au bout d'1 minute.\n\nPar une action, vous pouvez effacer comme par magie un nom sur la page en le touchant.","name_en":"Far Scribe"},{"name":"Vigueur diabolique","level":null,"desc":"Vous pouvez vous lancer une fausse vie à volonté en tant que sort de niveau 1, sans dépenser d'emplacement de sort ni de composants matériels.","name_en":"Fiendish Vigor"},{"name":"Regard de deux esprits","level":null,"desc":"Vous pouvez utiliser votre action pour toucher un humanoïde consentant et percevoir à travers ses sens jusqu'à la fin de votre prochain tour. Tant que la créature est sur le même plan d'existence que vous, vous pouvez utiliser votre action lors des tours suivants pour maintenir cette connexion, prolongeant ainsi la durée jusqu'à la fin de votre prochain tour. Tout en percevant à travers les sens de l'autre créature, vous bénéficiez de tous les sens spéciaux possédés par cette créature, et vous êtes aveuglé et assourdi par rapport à votre propre environnement.","name_en":"Gaze of Two Minds"},{"name":"Regard fantomatique","level":null,"desc":"Par une action, vous gagnez la capacité de voir à travers des objets solides dans une portée de 9 mètres. Dans cette plage, vous avez la vision dans le noir si vous ne l’avez pas déjà. Cette vue spéciale dure 1 minute ou jusqu'à la fin de votre concentration (comme si vous vous concentriez sur un sort). Pendant ce temps, vous percevez les objets comme des images fantomatiques et transparentes.\n\nUne fois que vous avez utilisé cette invocation, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Ghostly Gaze"},{"name":"Don des profondeurs","level":null,"desc":"Vous pouvez respirer sous l’eau et vous gagnez une vitesse de nage égale à votre vitesse de marche.\n\nVous pouvez également lancer la respiration aquatique sans dépenser d’emplacement de sort. Vous retrouvez la capacité de le faire lorsque vous terminez un repos long.","name_en":"Gift of the Depths"},{"name":"Don des éternels","level":null,"desc":"Chaque fois que vous regagnez des points de vie alors que votre familier se trouve à moins de 100 pieds de vous, considérez tous les dés lancés pour déterminer les points de vie que vous regagnez comme ayant lancé leur valeur maximale pour vous.","name_en":"Gift of the Ever-Living Ones"},{"name":"Don des Protecteurs","level":null,"desc":"Une nouvelle page apparaît dans votre Livre des Ombres. Avec votre permission, une créature peut utiliser son action pour écrire son nom sur cette page, qui peut contenir un nombre de noms égal à votre bonus de maîtrise.\n\nLorsqu'une créature dont le nom est sur la page est réduite à 0 point de vie mais n'est pas tuée sur le coup, la créature tombe comme par magie à 1 point de vie. Une fois cette magie déclenchée, aucune créature ne peut en bénéficier tant que vous n'avez pas terminé un repos long.\n\nPar une action, vous pouvez effacer comme par magie un nom sur la page en le touchant.","name_en":"Gift of the Protectors"},{"name":"Emprise de Hadar","level":null,"desc":"Une fois à chacun de vos tours, lorsque vous touchez une créature avec votre explosion surnaturelle, vous pouvez déplacer cette créature en ligne droite de 10 pieds plus près de vous.","name_en":"Grasp of Hadar"},{"name":"Arme du Pacte améliorée","level":null,"desc":"Vous pouvez utiliser n'importe quelle arme que vous invoquez avec votre fonction Pacte de la Lame comme foyer de lancement de sorts pour vos sorts de démoniste.\n\nDe plus, l'arme bénéficie d'un bonus de +1 à ses jets d'attaque et de dégâts, sauf s'il s'agit d'une arme magique qui possède déjà un bonus à ces jets.\n\nEnfin, l'arme que vous invoquez peut être un arc court, un arc long, une arbalète légère ou une arbalète lourde.","name_en":"Improved Pact Weapon"},{"name":"Investissement du Chain Master","level":null,"desc":"Lorsque vous lancez Trouver un familier, vous infusez au familier invoqué une mesure de votre pouvoir surnaturel, accordant à la créature les avantages suivants :\n• Le familier gagne soit une vitesse de vol, soit une vitesse de nage (au choix) de 40 pieds.\n• Par une action bonus, vous pouvez ordonner au familier d'effectuer l'action Attaque.\n• Les attaques avec les armes du familier sont considérées comme magiques dans le but de vaincre l'immunité et la résistance aux attaques non magiques.\n• Si le familier force une créature à effectuer un jet de sauvegarde, elle utilise le DD de sauvegarde de vos sorts.\n• Lorsque le familier subit des dégâts, vous pouvez utiliser votre réaction pour lui accorder une résistance contre ces dégâts.","name_en":"Investment of the Chain Master"},{"name":"Lance de léthargie","level":null,"desc":"Une fois à chacun de vos tours, lorsque vous touchez une créature avec votre explosion surnaturelle, vous pouvez réduire la vitesse de cette créature de 10 pieds jusqu'à la fin de votre prochain tour.","name_en":"Lance of Lethargy"},{"name":"Buveur de vie","level":null,"desc":"Lorsque vous touchez une créature avec votre arme du pacte, la créature subit des dégâts nécrotiques supplémentaires égaux à votre modificateur de Charisme (minimum 1).","name_en":"Lifedrinker"},{"name":"Sortilège exaspérant","level":null,"desc":"Par une action bonus, vous provoquez une perturbation psychique autour de la cible maudite par votre sortilège ou par une de vos capacités de démoniste, comme la malédiction de Hexblade et le signe de mauvais présage. Ce faisant, vous infligez des dégâts psychiques à la cible maudite et à chaque créature de votre choix située à moins de 1,50 mètre d'elle. Les dégâts psychiques sont égaux à votre modificateur de Charisme (minimum de 1 dégât). Pour utiliser cette invocation, vous devez être capable de voir la cible maudite et elle doit se trouver à moins de 9 pieds de vous.","name_en":"Maddening Hex"},{"name":"Masque aux multiples visages","level":null,"desc":"Vous pouvez lancer un déguisement à volonté, sans dépenser d'emplacement de sort.","name_en":"Mask of Many Faces"},{"name":"Maître des myriades de formes","level":null,"desc":"Vous pouvez lancer une modification de soi à volonté, sans dépenser d'emplacement de sort.","name_en":"Master of Myriad Forms"},{"name":"Les serviteurs du chaos","level":null,"desc":"Vous pouvez lancer une conjuration élémentaire une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Minions of Chaos"},{"name":"Enliser l'esprit","level":null,"desc":"Vous pouvez lancer un sort lent une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Mire the Mind"},{"name":"Visions brumeuses","level":null,"desc":"Vous pouvez lancer une image silencieuse à volonté, sans dépenser d'emplacement de sort ni de composants matériels.","name_en":"Misty Visions"},{"name":"Un avec des ombres","level":null,"desc":"Lorsque vous vous trouvez dans une zone de faible luminosité ou d'obscurité, vous pouvez utiliser votre action pour devenir invisible jusqu'à ce que vous bougez ou entrepreniez une action ou une réaction.","name_en":"One with Shadows"},{"name":"Saut d'un autre monde","level":null,"desc":"Vous pouvez lancer saut à volonté, sans dépenser d'emplacement de sort.","name_en":"Otherworldly Leap"},{"name":"Protection du Talisman","level":null,"desc":"Lorsque le porteur de votre talisman échoue à un jet de sauvegarde, il peut ajouter un d4 au jet, transformant potentiellement la sauvegarde en succès. Cet avantage peut être utilisé un nombre de fois égal à votre bonus de maîtrise, et toutes les utilisations dépensées sont restaurées lorsque vous terminez un repos long.","name_en":"Protection of the Talisman"},{"name":"Réprimande du Talisman","level":null,"desc":"Lorsque le porteur de votre talisman est touché par un attaquant que vous pouvez voir à moins de 9 mètres de vous, vous pouvez utiliser votre réaction pour infliger des dégâts psychiques à l'attaquant égaux à votre bonus de maîtrise et le pousser jusqu'à 3 mètres du porteur du talisman.","name_en":"Rebuke of the Talisman"},{"name":"Maléfice implacable","level":null,"desc":"Votre malédiction crée un lien temporaire entre vous et votre cible. En tant qu'action bonus, vous pouvez vous téléporter comme par magie jusqu'à 9 mètres dans un espace inoccupé que vous pouvez voir à moins de 1,50 mètre de la cible maudite par votre sortilège ou par une de vos capacités de démoniste, comme la malédiction de Hexblade et le signe de mauvais présage. Pour vous téléporter de cette manière, vous devez pouvoir voir la cible maudite.","name_en":"Relentless Hex"},{"name":"Explosion repoussante","level":null,"desc":"Lorsque vous touchez une créature avec une explosion surnaturelle, vous pouvez la pousser jusqu'à 10 pieds de vous en ligne droite.","name_en":"Repelling Blast"},{"name":"Sculpteur de chair","level":null,"desc":"Vous pouvez lancer une métamorphose une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Sculptor of Flesh"},{"name":"Linceul d'Ombre","level":null,"desc":"Vous pouvez lancer l'invisibilité à volonté, sans dépenser d'emplacement de sort.","name_en":"Shroud of Shadow"},{"name":"Signe de mauvais présage","level":null,"desc":"Vous pouvez lancer une malédiction d'octroi une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Sign of Ill Omen"},{"name":"Voleur des Cinq Destins","level":null,"desc":"Vous pouvez lancer le fléau une fois en utilisant un emplacement de sort de démoniste. Vous ne pouvez plus recommencer avant d'avoir terminé un long repos.","name_en":"Thief of Five Fates"},{"name":"Lame assoiffée","level":null,"desc":"Vous pouvez attaquer avec votre arme du pacte deux fois, au lieu d'une, chaque fois que vous effectuez l'action Attaque pendant votre tour.","name_en":"Thirsting Blade"},{"name":"Tombeau de Lévistus","level":null,"desc":"En réaction lorsque vous subissez des dégâts, vous pouvez vous ensevelir dans la glace, qui fond à la fin de votre prochain tour. Vous gagnez 10 points de vie temporaires par niveau de démoniste, qui subissent autant de dégâts déclencheurs que possible. Immédiatement après avoir subi des dégâts, vous devenez vulnérable aux dégâts de feu, votre vitesse est réduite à 0 et vous êtes frappé d'incapacité. Ces effets, y compris les points de vie temporaires restants, prennent tous fin lorsque la glace fond.\n\nUne fois que vous avez utilisé cette invocation, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Tomb of Levistus"},{"name":"L'évasion du filou","level":null,"desc":"Vous pouvez lancer Liberté de mouvement une fois sur vous-même sans dépenser d'emplacement de sort. Vous retrouvez la capacité de le faire lorsque vous terminez un repos long.","name_en":"Trickster's Escape"},{"name":"Servitude éternelle","level":null,"desc":"Vous pouvez lancer des morts animés sans utiliser d'emplacement de sort. Une fois que vous l'avez fait, vous ne pouvez plus le lancer de cette manière tant que vous n'avez pas terminé un long repos.","name_en":"Undying Servitude"},{"name":"Visions de royaumes lointains","level":null,"desc":"Vous pouvez lancer Œil arcanique à volonté, sans dépenser d’emplacement de sort.","name_en":"Visions of Distant Realms"},{"name":"Voix du maître de la chaîne","level":null,"desc":"Vous pouvez communiquer par télépathie avec votre familier et percevoir à travers ses sens tant que vous êtes sur le même plan d'existence. De plus, tout en percevant à travers les sens de votre familier, vous pouvez également parler à travers votre familier avec votre propre voix, même si votre familier est normalement incapable de parler.","name_en":"Voice of the Chain Master"},{"name":"Les murmures de la tombe","level":null,"desc":"Vous pouvez lancer parler avec les morts à volonté, sans dépenser d'emplacement de sort.","name_en":"Whispers of the Grave"},{"name":"Vue de sorcière","level":null,"desc":"Vous pouvez voir la véritable forme de n'importe quel changeur de forme ou créature dissimulée par une illusion ou une magie de transmutation tant que la créature se trouve à moins de 9 mètres de vous et dans votre champ de vision.","name_en":"Witch Sight"},{"name":"Pistolero arcanique","level":null,"desc":"Vous pouvez créer une arme de pacte qui est une arme de poing ou un bras long, et vous pouvez transformer une arme de poing ou un bras long magique en votre arme de pacte.","name_en":"Arcane Gunslinger"},{"name":"Maléfice brûlant","level":null,"desc":"Par une action bonus, vous faites subir à une cible maudite par la malédiction de votre Hexblade des dégâts de feu égaux à votre modificateur de Charisme (minimum de 1).","name_en":"Burning Hex"},{"name":"Phare de Caïphon","level":null,"desc":"L'étoile violette Caiphon est le destin tragique des marins inexpérimentés. Ceux qui utilisent sa lumière trompeuse pour guider leurs voyages finissent invariablement par se ruiner. Vous maîtrisez les compétences de Déception et de Discrétion, et vous avez un avantage aux jets d'attaque contre les créatures charmées.","name_en":"Caiphon's Beacon"},{"name":"Sort de glace","level":null,"desc":"Par une action bonus, vous faites tourbillonner du givre autour d'une cible maudite par la malédiction de votre Hexblade, infligeant des dégâts de froid à chacun de vos ennemis à moins de 1,50 mètre de la cible. Les dégâts de froid sont égaux à votre modificateur de Charisme (minimum de 1).","name_en":"Chilling Hex"},{"name":"Chronique de la Reine Corbeau","level":null,"desc":"Vous pouvez placer la main d'un cadavre ou un appendice similaire sur votre Livre des Ombres et poser une question à haute voix. Au bout d'1 minute, la réponse apparaît écrite avec du sang dans votre livre. La réponse est fournie par l'esprit de la créature morte au meilleur de ses connaissances et est traduite dans la langue de votre choix. Vous devez utiliser cette capacité dans la minute qui suit la mort d'une créature, et une créature donnée ne peut se voir poser qu'une seule question de cette manière.","name_en":"Chronicle of the Raven Queen"},{"name":"Griffe d'Acamar","level":null,"desc":"Vous pouvez créer un fléau de plomb noir à l’aide de votre fonction Pacte de la Lame. La tête du fléau est sculptée pour ressembler à une paire de tentacules agrippants. L'arme a la propriété de portée. Lorsque vous touchez une créature avec, vous pouvez dépenser un emplacement de sort pour infliger 2d8 dégâts nécrotiques supplémentaires à la cible par niveau de sort, et vous pouvez réduire la vitesse de la créature à 0 pied jusqu'à la fin de votre prochain tour.","name_en":"Claw of Acamar"},{"name":"Porteur de malédiction","level":null,"desc":"Vous pouvez créer une épée à deux mains forgée en argent, avec des runes noires gravées sur sa lame, en utilisant votre fonction Pacte de la Lame. Si vous réduisez une cible maudite par la malédiction de votre Hexblade à 0 point de vie avec cette épée, vous pouvez immédiatement changer la cible de la malédiction en une autre créature. Ce changement ne prolonge pas la durée de la malédiction.\n\nLorsque vous touchez une créature avec cette arme, vous pouvez dépenser un emplacement de sort pour infliger 2d8 dégâts tranchants supplémentaires à la cible par niveau de sort, et vous pouvez réduire la vitesse de la créature à 0 pied jusqu'à la fin de votre prochain tour.","name_en":"Curse Bringer"},{"name":"Armure surnaturelle","level":null,"desc":"Par une action, vous pouvez toucher une armure qui n'est portée par personne et l'enfiler instantanément, à condition que vous ne portiez pas déjà d'armure. Vous maîtrisez cette armure jusqu'à ce qu'elle soit retirée.","name_en":"Eldritch Armor"},{"name":"Cadeau du Seigneur Vert","level":null,"desc":"Le Seigneur Vert supervise un royaume verdoyant où règne un été éternel. Votre âme est liée à son pouvoir. Chaque fois que vous regagnez des points de vie, vous considérez tous les dés lancés pour déterminer les points de vie que vous regagnez comme ayant lancé leur valeur maximale.","name_en":"Green Lord's Gift"},{"name":"Baiser de Méphistophélès","level":null,"desc":"Lorsque vous touchez une créature avec votre explosion surnaturelle, vous pouvez lancer une boule de feu comme une action bonus en utilisant un emplacement de sort de démoniste. Le sort doit être centré sur la créature que vous avez touchée avec une explosion surnaturelle.","name_en":"Kiss of Mephistopheles"},{"name":"Masse de Dispater","level":null,"desc":"Lorsque vous créez votre arme du pacte sous forme de masse, elle se manifeste sous la forme d'une masse de fer forgée à Dis, le deuxième des Neuf Enfers. Lorsque vous frappez une créature avec, vous pouvez dépenser un emplacement de sort pour infliger 2d8 dégâts de force supplémentaires à la cible par niveau de sort, et vous pouvez mettre la cible à terre si elle est énorme ou plus petite.","name_en":"Mace of Dispater"},{"name":"Sortilège exaspérant","level":null,"desc":"Par une action bonus, vous provoquez une perturbation psychique autour de la cible maudite par votre sortilège ou par une de vos capacités de démoniste, comme la malédiction de Hexblade et le signe de mauvais présage. Lorsque vous faites cela, vous infligez des dégâts psychiques à la cible et à chaque créature de votre choix à moins de 1,50 mètre d'elle. Les dégâts psychiques sont égaux à votre modificateur de Charisme (minimum de 0 dégâts).","name_en":"Maddening Hex"},{"name":"Arc de lune","level":null,"desc":"Vous pouvez créer un arc long en utilisant votre fonction Pacte de la Lame. Lorsque vous retirez sa ficelle et tirez, il crée une flèche de bois blanc, qui disparaît au bout d'une minute. Vous avez l'avantage aux jets d'attaque contre les lycanthropes avec l'arc. Lorsque vous touchez une créature avec, vous pouvez dépenser un emplacement de sort pour infliger 2d8 dégâts radiants supplémentaires à la cible par niveau de sort.","name_en":"Moonbow"},{"name":"Chemin du chercheur","level":null,"desc":"Le Chercheur vous invite à voyager à la recherche de connaissances, et rien ne peut vous empêcher de suivre ce chemin. Vous ignorez les terrains difficiles, avez un avantage à tous les tests pour échapper à un grappin, des menottes ou des cordes, et un avantage aux jets de sauvegarde contre la paralysie.","name_en":"Path of the Seeker"},{"name":"Bénédiction de la Reine Corbeau","level":null,"desc":"Lorsque vous obtenez un coup critique avec votre sort magique d'explosion mystique, choisissez vous-même ou un allié que vous pouvez voir à moins de 9 mètres de vous. La créature choisie peut immédiatement dépenser un dé de vie pour récupérer des points de vie égaux au jet + le modificateur de Constitution de la créature (minimum 1 point de vie).","name_en":"Raven Queen's Blessing"},{"name":"Discours du chercheur","level":null,"desc":"Votre quête de connaissances vous permet de maîtriser n'importe quelle langue parlée. Lorsque vous effectuez un repos long, vous pouvez choisir deux langues. Vous acquérez la capacité de parler, lire et écrire les langues choisies jusqu'à la fin de votre prochain repos long.","name_en":"Seeker's Speech"},{"name":"Linceul d'Oulban","level":null,"desc":"L'étoile bleu-blanc Ulban maintient une présence inconstante parmi les étoiles, apparaissant uniquement pour annoncer un sinistre présage. Par une action, vous pouvez devenir invisible pendant 1 minute. Si vous attaquez, infligez des dégâts ou forcez une créature à faire un jet de sauvegarde, vous devenez visible à la fin du tour en cours.","name_en":"Shroud of Ulban"},{"name":"Arme du Pacte supérieure","level":null,"desc":"Vous pouvez utiliser n'importe quelle arme que vous invoquez avec votre fonction Pacte de la Lame comme foyer de lancement de sorts pour vos sorts de démoniste.\n\nDe plus, l'arme compte comme une arme magique avec un bonus de +2 à ses jets d'attaque et de dégâts, sauf s'il s'agit déjà d'une arme magique que vous avez transformée en arme de votre pacte.","name_en":"Superior Pact Weapon"},{"name":"Arme du Pacte ultime","level":null,"desc":"Vous pouvez utiliser n'importe quelle arme que vous invoquez avec votre fonction Pacte de la Lame comme foyer de lancement de sorts pour vos sorts de démoniste.\n\nDe plus, l'arme compte comme une arme magique avec un bonus de +3 à ses jets d'attaque et de dégâts, sauf s'il s'agit déjà d'une arme magique que vous avez transformée en arme de votre pacte.","name_en":"Ultimate Pact Weapon"}],"name_en":"Eldritch Invocations","_translated":true},{"index":"warlock-archfey","name":"Démoniste : L'Archfey","class":"warlock","source":"Player's Handbook","subclass_flavor":"Votre patron est un seigneur ou une dame des fées, une créature légendaire qui détient des secrets oubliés avant la naissance des races mortelles. Les motivations de cet être sont souvent impénétrables, et parfois fantaisistes, et peuvent impliquer une recherche d'un plus grand pouvoir magique ou le règlement de rancunes séculaires. Les êtres de ce genre incluent le Prince du Givre ; la Reine de l'Air et des Ténèbres, dirigeante de la Cour Gloaming ; Titania de la Cour d'Été ; son épouse Obéron, le Seigneur Vert ; Hyrsam, le prince des fous ; et les vieilles sorcières.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"L'Archfey vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus d'Archfey\nNiveau de sort | Sorts\n1er | Feu féerique, sommeil\n2ème | Émotions calmes, force fantasmatique\n3ème | Clignement des yeux, croissance des plantes\n4ème | Dominez la bête, plus grande invisibilité\n5ème | Dominer la personne, semblant","name_en":"Expanded Spell List"},{"name":"Présence féerique","level":1,"desc":"À partir du niveau 1, votre patron vous confère la capacité de projeter la présence séduisante et redoutable des fées. Par une action, vous pouvez amener chaque créature d'un cube de 10 pieds provenant de vous à effectuer un jet de sauvegarde de Sagesse contre le DD de sauvegarde de votre sort de démoniste. Les créatures qui échouent à leur jet de sauvegarde sont toutes charmées ou effrayées par vous (votre choix) jusqu'à la fin de votre prochain tour.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Fey Presence"},{"name":"Évasion brumeuse","level":6,"desc":"À partir du niveau 6, vous pouvez disparaître dans un nuage de brume en réponse à un mal. Lorsque vous subissez des dégâts, vous pouvez utiliser votre réaction pour devenir invisible et vous téléporter jusqu'à 60 pieds dans un espace inoccupé que vous pouvez voir. Vous restez invisible jusqu'au début de votre prochain tour ou jusqu'à ce que vous attaquiez ou lanciez un sort.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Misty Escape"},{"name":"Défenses séduisantes","level":10,"desc":"À partir du niveau 10, votre patron vous apprend à retourner contre eux la magie mentale de vos ennemis. Vous êtes immunisé contre le charme, et lorsqu'une autre créature tente de vous charmer, vous pouvez utiliser votre réaction pour tenter de retourner le charme sur cette créature. La créature doit réussir un jet de sauvegarde de Sagesse contre le DD de sauvegarde de votre sort de démoniste ou être charmée par vous pendant 1 minute ou jusqu'à ce que la créature subisse des dégâts.","name_en":"Beguiling Defenses"},{"name":"Délire sombre","level":14,"desc":"À partir du niveau 14, vous pouvez plonger une créature dans un royaume illusoire. Par une action, choisissez une créature que vous pouvez voir dans un rayon de 20 mètres autour de vous. Il doit effectuer un jet de sauvegarde de Sagesse contre le DD de sauvegarde de votre sort de démoniste. En cas d'échec, il est charmé ou effrayé par vous (au choix) pendant 1 minute ou jusqu'à ce que votre concentration soit brisée (comme si vous vous concentriez sur un sort). Cet effet se termine plus tôt si la créature subit des dégâts.\n\nJusqu'à la fin de cette illusion, la créature pense qu'elle est perdue dans un royaume brumeux dont vous choisissez l'apparence. La créature ne peut voir et entendre qu'elle-même, vous et l'illusion.\n\nVous devez terminer un repos court ou long avant de pouvoir utiliser à nouveau cette fonctionnalité.","name_en":"Dark Delirium"}],"name_en":"Warlock: The Archfey","_translated":true},{"index":"warlock-celestial","name":"Démoniste : Le Céleste","class":"warlock","source":"Xanathar's Guide to Everything","subclass_flavor":"Votre patron est un être puissant des plans supérieurs. Vous vous êtes lié à une ancienne entité empyrée, solaire, ki-rin, licorne ou autre qui réside dans les plans du bonheur éternel. Votre pacte avec cet être vous permet de ressentir le moindre contact de la lumière sacrée qui illumine le multivers.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"Le Céleste vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus célestes\nNiveau de sort | Sorts\n1er | Guérir les blessures, boulon de guidage\n2ème | Sphère enflammée, restauration mineure\n3ème | Lumière du jour, revivifier\n4ème | Gardien de la Foi, Mur de Feu\n5ème | Frappe de flammes, restauration supérieure","name_en":"Expanded Spell List"},{"name":"Cantrips bonus","level":1,"desc":"Au niveau 1, vous apprenez les sorts mineurs Lumière et Flamme sacrée. Ils comptent pour vous comme des sorts mineurs de démoniste, mais ils ne comptent pas dans votre nombre de sorts mineurs connus.","name_en":"Bonus Cantrips"},{"name":"Lumière de guérison","level":1,"desc":"Au niveau 1, vous gagnez la capacité de canaliser l’énergie céleste pour soigner les blessures. Vous disposez d’une réserve de d6 que vous dépensez pour alimenter cette guérison. Le nombre de dés dans la réserve est égal à 1 + votre niveau de démoniste.\n\nPar une action bonus, vous pouvez soigner une créature que vous pouvez voir à moins de 20 mètres de vous, en dépensant des dés de la piscine. Le nombre maximum de dés que vous pouvez dépenser en même temps est égal à votre modificateur de Charisme (minimum d'un dé). Lancez les dés que vous dépensez, additionnez-les et restaurez un nombre de points de vie égal au total.\n\nVotre réserve récupère tous les dés dépensés lorsque vous terminez un repos long.","name_en":"Healing Light"},{"name":"Âme Radieuse","level":6,"desc":"À partir du niveau 6, votre lien avec le Céleste vous permet de servir de conduit à l'énergie rayonnante. Vous avez une résistance aux dégâts radiants, et lorsque vous lancez un sort qui inflige des dégâts radiants ou de feu, vous ajoutez votre modificateur de Charisme à un jet de dégâts radiants ou de feu de ce sort contre l'une de ses cibles.","name_en":"Radiant Soul"},{"name":"Résistance céleste","level":10,"desc":"À partir du niveau 10, vous gagnez des points de vie temporaires chaque fois que vous terminez un repos court ou long. Ces points de vie temporaires sont égaux à votre niveau de démoniste + votre modificateur de Charisme. De plus, choisissez jusqu'à cinq créatures que vous pouvez voir à la fin du reste. Ces créatures gagnent chacune des points de vie temporaires égaux à la moitié de votre niveau de démoniste + votre modificateur de Charisme.","name_en":"Celestial Resistance"},{"name":"Vengeance brûlante","level":14,"desc":"À partir du niveau 14, l’énergie rayonnante que vous canalisez vous permet de résister à la mort. Lorsque vous devez effectuer un jet de sauvegarde contre la mort au début de votre tour, vous pouvez à la place vous remettre sur pied avec une explosion d'énergie rayonnante. Vous récupérez des points de vie égaux à la moitié de votre maximum de points de vie, puis vous vous relevez si vous le souhaitez. Chaque créature de votre choix qui se trouve à moins de 9 mètres de vous subit des dégâts radiants égaux à 2d8 + votre modificateur de Charisme, et est aveuglée jusqu'à la fin du tour en cours.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l’utiliser tant que vous n’avez pas terminé un long repos.","name_en":"Searing Vengeance"}],"name_en":"Warlock: The Celestial","_translated":true},{"index":"warlock-fathomless","name":"Démoniste : L'Insondable","class":"warlock","source":"Tasha's Cauldron of Everything","subclass_flavor":"Vous avez conclu un pacte avec les profondeurs. Une entité de l'océan, le plan élémentaire de l'eau, ou une autre mer d'un autre monde, vous permet désormais de puiser dans son pouvoir thalassique. Est-ce qu’il vous utilise simplement pour en apprendre davantage sur les royaumes terrestres, ou veut-il que vous ouvriez les vannes cosmiques et noyiez le monde ?","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"The Fathomless vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus insondables\nNiveau de sort | Sorts\n1er | Créer ou détruire de l'eau, Thunderwave\n2ème | Coup de vent, silence\n3ème | Éclair, tempête de neige fondue\n4ème | Contrôler l'eau, invoquer un élémental (eau uniquement)\n5ème | Bigby's Hand (apparaît comme un tentacule), Cone of Cold","name_en":"Expanded Spell List"},{"name":"Tentacule des profondeurs","level":1,"desc":"Au niveau 1, vous pouvez invoquer par magie un tentacule spectral qui frappe vos ennemis. Par une action bonus, vous créez un tentacule de 3 mètres de long en un point que vous pouvez voir à moins de 18 mètres de vous. Le tentacule dure 1 minute ou jusqu'à ce que vous utilisiez cette fonctionnalité pour créer un autre tentacule.\n\nLorsque vous créez le tentacule, vous pouvez lancer une attaque au corps à corps contre une créature à moins de 3 mètres de lui. En cas de coup, la cible subit 1d8 dégâts de froid et sa vitesse est réduite de 3 mètres jusqu'au début de votre prochain tour. Lorsque vous atteignez le niveau 10 dans cette classe, les dégâts passent à 2d8.\n\nEn guise d'action bonus pendant votre tour, vous pouvez déplacer le tentacule jusqu'à 9 mètres et répéter l'attaque.\n\nVous pouvez invoquer le tentacule un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Tentacle of the Deep"},{"name":"Cadeau de la mer","level":1,"desc":"Au niveau 1 également, vous gagnez une vitesse de nage de 40 pieds et vous pouvez respirer sous l'eau.","name_en":"Gift of the Sea"},{"name":"Âme océanique","level":6,"desc":"Au niveau 6, vous êtes désormais encore plus à l'aise dans les profondeurs. Vous gagnez en résistance aux dégâts du froid. De plus, lorsque vous êtes complètement immergé, toute créature également entièrement immergée peut comprendre votre discours, et vous pouvez comprendre le leur.","name_en":"Oceanic Soul"},{"name":"Bobine de gardien","level":6,"desc":"Au niveau 6, votre Tentacule des Profondeurs peut vous défendre ainsi que les autres, s'interposant entre eux et leur nuire. Lorsque vous ou une créature que vous pouvez voir subissez des dégâts à moins de 3 mètres du tentacule, vous pouvez utiliser votre réaction pour choisir l'une de ces créatures et réduire les dégâts infligés à cette créature de 1d8. Lorsque vous atteignez le niveau 10 dans cette classe, les dégâts réduits par le tentacule passent à 2d8.","name_en":"Guardian Coil"},{"name":"Tentacules saisissantes","level":10,"desc":"À partir du niveau 10, vous apprenez le sort Tentacules noires d'Evard. Cela compte comme un sort de démoniste pour vous, mais cela ne compte pas dans le nombre de sorts que vous connaissez. Vous pouvez également le lancer une fois sans utiliser d'emplacement de sort, et vous retrouvez la possibilité de le faire lorsque vous terminez un repos long.\n\nChaque fois que vous lancez ce sort, la magie de votre patron vous renforce, vous accordant un nombre de points de vie temporaires égal à votre niveau de démoniste. De plus, les dégâts ne peuvent pas briser votre concentration sur ce sort.","name_en":"Grasping Tentacles"},{"name":"Plongée insondable","level":null,"desc":"Lorsque vous atteignez le niveau 14, vous pouvez ouvrir par magie des conduits temporaires vers des destinations aquatiques. Par une action, vous pouvez vous téléporter ainsi que jusqu'à cinq autres créatures volontaires que vous pouvez voir à moins de 9 mètres de vous. Au milieu d'un tourbillon de tentacules, vous disparaissez tous puis réapparaissez jusqu'à 1,6 km dans un plan d'eau que vous avez vu (de la taille d'un étang ou plus) ou à moins de 9 mètres de celui-ci, chacun de vous apparaissant dans un espace inoccupé à moins de 9 mètres des autres.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Fathomless Plunge"}],"name_en":"Warlock: The Fathomless","_translated":true},{"index":"warlock-fiend","name":"Démoniste : le démon","class":"warlock","source":"Player's Handbook","subclass_flavor":"Vous avez conclu un pacte avec un démon des plans inférieurs de l'existence, un être dont les objectifs sont mauvais, même si vous luttez contre ces objectifs. De tels êtres désirent la corruption ou la destruction de toutes choses, y compris vous-même. Les démons suffisamment puissants pour forger un pacte incluent des seigneurs démons tels que Demogorgon, Orcus, Fraz'Urb-luu et Baphomet ; des archidiables tels qu'Asmodée, Dispater, Méphistophélès et Bélial ; des démons des fosses et des balors particulièrement puissants ; et les ultroloths et autres seigneurs des yugoloths.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"Le Fiend vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus de démon\nNiveau de sort | Sorts\n1er | Mains brûlantes, commandement\n2ème | Cécité/Surdité, Rayon Brûlant\n3ème | Boule de feu, nuage puant\n4ème | Bouclier de feu, mur de feu\n5ème | Frappe de flamme, sacré","name_en":"Expanded Spell List"},{"name":"Bénédiction du Ténébreux","level":1,"desc":"À partir du niveau 1, lorsque vous réduisez une créature hostile à 0 point de vie, vous gagnez des points de vie temporaires égaux à votre modificateur de Charisme + votre niveau de démoniste (minimum de 1).","name_en":"Dark One's Blessing"},{"name":"La chance du Ténébreux","level":6,"desc":"À partir du niveau 6, vous pouvez faire appel à votre patron pour modifier le destin en votre faveur. Lorsque vous effectuez un test de capacité ou un jet de sauvegarde, vous pouvez utiliser cette fonctionnalité pour ajouter un d10 à votre jet. Vous pouvez le faire après avoir vu le jet initial mais avant que l'un des effets du jet ne se produise.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Dark One's Own Luck"},{"name":"Résilience diabolique","level":10,"desc":"À partir du niveau 10, vous pouvez choisir un type de dégâts lorsque vous terminez un repos court ou long. Vous gagnez en résistance à ce type de dégâts jusqu'à ce que vous en choisissiez un autre avec cette fonctionnalité. Les dégâts causés par les armes magiques ou les armes en argent ignorent cette résistance.","name_en":"Fiendish Resilience"},{"name":"Traversez l'enfer","level":14,"desc":"À partir du niveau 14, lorsque vous touchez une créature avec une attaque, vous pouvez utiliser cette fonctionnalité pour transporter instantanément la cible à travers les plans inférieurs. La créature disparaît et se précipite dans un paysage cauchemardesque.\n\nÀ la fin de votre prochain tour, la cible retourne dans la case qu'elle occupait précédemment, ou dans la case inoccupée la plus proche. Si la cible n’est pas un démon, elle subit 10d10 dégâts psychiques lorsqu’elle se remet de son horrible expérience.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Hurl Through Hell"}],"name_en":"Warlock: The Fiend","_translated":true},{"index":"warlock-the-genie","name":"Démoniste : le génie","class":"warlock","source":"Tasha's Cauldron of Everything","subclass_flavor":"Vous avez conclu un pacte avec l’un des types de génies les plus rares, un noble génie. De telles entités gouvernent de vastes fiefs sur les plans élémentaires et ont une grande influence sur les génies inférieurs et les créatures élémentaires. Les génies nobles ont des motivations variées, mais la plupart sont arrogants et exercent un pouvoir qui rivalise avec celui des divinités inférieures. Ils prennent plaisir à renverser la situation sur les mortels, qui enchaînent souvent les génies en servitude, et concluent facilement des pactes qui étendent leur portée.","desc":"","features":[{"name":"Liste de sorts étendue","level":1,"desc":"Au niveau 1, le Génie vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Le tableau des sorts étendus de génie affiche les sorts de génie qui sont ajoutés à la liste des sorts de démoniste pour vous, ainsi que les sorts associés dans le tableau au type de votre patron : dao, djinni, éfrit ou marid.\nSorts étendus de génie\nNiveau de sort | Sorts de génie | Sorts Dao | Sorts Djinni | Sorts d’Éfrit | Sorts Marids\n1er | Détecter le mal et le bien | Sanctuaire | Onde d'orage | Mains brûlantes | Nuage de brouillard\n2ème | Force fantasmatique | Croissance en pointe | Coup de vent | Rayon brûlant | Flou\n3ème | Créer de la nourriture et de l'eau | Fondre dans la pierre | Mur de vent | Boule de feu | Tempête de neige fondue\n4ème | Tueur fantasmatique | Forme de pierre | Une plus grande invisibilité | Bouclier de feu | Contrôler l'eau\n5ème | Création | Mur de pierre | Semblant | Frappe de flamme | Cône de froid\n9ème | Souhait | — | — | — | —","name_en":"Expanded Spell List"},{"name":"Le vaisseau du génie","level":1,"desc":"Au 1er niveau également, votre patron vous offre un vaisseau magique qui vous confère une mesure de la puissance du génie. Le vaisseau est un objet minuscule et vous pouvez l'utiliser comme foyer de lancement de sorts pour vos sorts de démoniste. Vous décidez quel est l'objet, ou vous pouvez déterminer de quoi il s'agit au hasard en lançant un jet sur la table du Récipient du Génie.\nLe vaisseau du génie\nd6 | Navire\n1 | Lampe à huile\n2 | Urne\n3 | Bague avec compartiment\n4 | Flacon bouché\n5 | Statuette creuse\n6 | Lanterne ornée\n\nPendant que vous touchez le récipient, vous pouvez l'utiliser des manières suivantes :\n• Répit en bouteille : par une action, vous pouvez disparaître comme par magie et entrer dans votre vaisseau, qui reste dans l'espace que vous avez quitté. L'intérieur du vaisseau est un espace extradimensionnel en forme de cylindre de 20 pieds de rayon et 20 pieds de haut, et ressemble à votre vaisseau. L'intérieur est aménagé avec des coussins et des tables basses et offre une température confortable. À l'intérieur, vous pouvez entendre la zone autour de votre navire comme si vous étiez dans son espace. Vous pouvez rester à l'intérieur du navire jusqu'à un nombre d'heures égal à deux fois votre bonus de maîtrise. Vous quittez le vaisseau plus tôt si vous utilisez une action bonus pour partir, si vous mourez ou si le vaisseau est détruit. Lorsque vous quittez le vaisseau, vous apparaissez dans l'espace inoccupé le plus proche de celui-ci. Tous les objets laissés dans le vaisseau y restent jusqu'à leur exécution, et si le vaisseau est détruit, tout objet qui y est stocké apparaît sans danger dans les espaces inoccupés les plus proches de l'ancien espace du vaisseau. Une fois que vous entrez dans le navire, vous ne pouvez plus y entrer avant d'avoir terminé un long repos.\n• Colère du Génie : Une fois à chacun de vos tours lorsque vous frappez avec un jet d'attaque, vous pouvez infliger des dégâts supplémentaires à la cible égaux à votre bonus de maîtrise. Le type de ces dégâts est déterminé par votre patron : contondant (dao), tonnerre (djinni), feu (éfrit) ou froid (marid).\n\nLa CA du vaisseau est égale à votre DD de sauvegarde de sorts. Ses points de vie sont égaux à votre niveau de démoniste plus votre bonus de maîtrise, et il est immunisé contre le poison et les dégâts psychiques.\n\nSi le vaisseau est détruit ou si vous le perdez, vous pouvez effectuer une cérémonie d'une heure pour recevoir un remplaçant de votre patron. Cette cérémonie peut être célébrée lors d'un repos court ou long, et le vaisseau précédent est détruit s'il existe encore. Le vaisseau disparaît dans une explosion de puissance élémentaire lorsque vous mourez.","name_en":"Genie's Vessel"},{"name":"Don élémentaire","level":6,"desc":"Au niveau 6, vous commencez à adopter les caractéristiques de votre patron. Vous avez désormais une résistance à un type de dégâts déterminé par le type de votre patron : contondant (dao), tonnerre (djinni), feu (éfrit) ou froid (marid).\n\nDe plus, en guise d'action bonus, vous pouvez vous attribuer une vitesse de vol de 9 mètres qui dure 10 minutes, pendant lesquelles vous pouvez planer. Vous pouvez utiliser cette action bonus un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.","name_en":"Elemental Gift"},{"name":"Navire sanctuaire","level":10,"desc":"Au niveau 10, lorsque vous entrez dans votre vaisseau du génie via la fonction de répit en bouteille, vous pouvez désormais choisir jusqu'à cinq créatures volontaires que vous pouvez voir à moins de 9 mètres de vous, et les créatures choisies sont attirées dans le vaisseau avec vous.\n\nPar une action bonus, vous pouvez éjecter n'importe quel nombre de créatures du vaisseau, et tout le monde est éjecté si vous partez ou mourez ou si le vaisseau est détruit.\n\nDe plus, toute personne (y compris vous) qui reste à bord du vaisseau pendant au moins 10 minutes bénéficie de l'avantage de terminer un court repos, et n'importe qui peut ajouter votre bonus de maîtrise au nombre de points de vie qu'il regagne s'il dépense des dés de vie dans le cadre d'un court repos.","name_en":"Sanctuary Vessel"},{"name":"Souhait limité","level":14,"desc":"Au niveau 14, vous suppliez votre patron de vous accorder un petit vœu. Par une action, vous pouvez exprimer votre désir à votre vaisseau de génie, en demandant l'effet d'un sort de niveau 6 ou inférieur et ayant un temps d'incantation de 1 action. Le sort peut provenir de la liste de sorts de n'importe quelle classe, et vous n'avez pas besoin de remplir les conditions de ce sort, y compris les composants coûteux : le sort prend simplement effet dans le cadre de cette action.\n\nUne fois que vous avez utilisé cette fonctionnalité, vous ne pouvez plus l'utiliser avant d'avoir terminé 1d4 repos longs.","name_en":"Limited Wish"}],"name_en":"Warlock: The Genie","_translated":true},{"index":"warlock-great-old-one","name":"Warlock : Le Grand Ancien","class":"warlock","source":"Player's Handbook","subclass_flavor":"Votre patron est une entité mystérieuse dont la nature est totalement étrangère au tissu de la réalité. Il pourrait provenir du Royaume Lointain, de l'espace au-delà de la réalité, ou il pourrait s'agir de l'un des dieux les plus anciens connus uniquement dans les légendes. Ses motivations sont incompréhensibles pour les mortels, et ses connaissances si immenses et anciennes que même les plus grandes bibliothèques pâlissent en comparaison des vastes secrets qu’elles recèlent. Le Grand Ancien ignore peut-être votre existence ou est totalement indifférent à votre égard, mais les secrets que vous avez appris vous permettent d'en tirer votre magie.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"Le Grand Ancien vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus du Grand Ancien\nNiveau de sort | Sorts\n1er | Murmures dissonantes, rire hideux de Tasha\n2ème | Détecter les pensées, force fantasmatique\n3ème | Clairvoyance, Envoi\n4ème | Dominez la bête, les tentacules noires d'Evard\n5ème | Personne dominante, télékinésie","name_en":"Expanded Spell List"},{"name":"Esprit éveillé","level":1,"desc":"Dès le niveau 1, vos connaissances extraterrestres vous donnent la possibilité de toucher l'esprit d'autres créatures. Vous pouvez parler par télépathie à toute créature que vous pouvez voir à moins de 9 mètres de vous. Vous n'avez pas besoin de partager une langue avec la créature pour qu'elle comprenne vos paroles télépathiques, mais la créature doit être capable de comprendre au moins une langue.","name_en":"Awakened Mind"},{"name":"Salle entropique","level":6,"desc":"Au niveau 6, vous apprenez à vous protéger magiquement contre les attaques et à transformer l'attaque ratée d'un ennemi en porte-bonheur pour vous-même. Lorsqu'une créature effectue un jet d'attaque contre vous, vous pouvez utiliser votre réaction pour imposer un désavantage à ce jet. Si l'attaque vous manque, votre prochain jet d'attaque contre la créature a un avantage si vous le faites avant la fin de votre prochain tour.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Entropic Ward"},{"name":"Bouclier de pensée","level":10,"desc":"À partir du niveau 10, vos pensées ne peuvent plus être lues par télépathie ou par d'autres moyens, sauf si vous l'autorisez. Vous avez également une résistance aux dégâts psychiques, et chaque fois qu'une créature vous inflige des dégâts psychiques, cette créature subit le même nombre de dégâts que vous.","name_en":"Thought Shield"},{"name":"Créer un esclave","level":14,"desc":"Au niveau 14, vous obtenez la capacité d'infecter l'esprit d'un humanoïde avec la magie extraterrestre de votre patron. Vous pouvez utiliser votre action pour toucher un humanoïde incapable. Cette créature est ensuite charmée par vous jusqu'à ce qu'un sort Supprimer la malédiction soit lancé sur elle, que la condition charmée en soit supprimée ou que vous utilisiez à nouveau cette fonctionnalité.\n\nVous pouvez communiquer par télépathie avec la créature charmée tant que vous êtes tous les deux sur le même plan d'existence.","name_en":"Create Thrall"}],"name_en":"Warlock: The Great Old One","_translated":true},{"index":"warlock-hexblade","name":"Démoniste : La Hexblade","class":"warlock","source":"Xanathar's Guide to Everything","subclass_flavor":"Vous avez conclu un pacte avec une entité mystérieuse de Shadowfell – une force qui se manifeste dans des armes magiques sensibles taillées dans la matière de l'ombre. La puissante épée Blackrazor est la plus remarquable de ces armes, qui se sont répandues dans le multivers au fil des âges. La force obscure derrière ces armes peut offrir du pouvoir aux sorciers qui concluent des pactes avec elle. De nombreux démonistes à lame hexagonale créent des armes qui imitent celles formées dans Shadowfell. D’autres renoncent à ces armes, se contentant d’intégrer la magie noire de ce plan dans leurs sorts.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"L'Hexblade vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus Hexblade\nNiveau de sort | Sorts\n1er | Bouclier, Châtiment courroucé\n2ème | Flou, Branding Smite\n3ème | Clignotement, arme élémentaire\n4ème | Tueur fantasmatique, Châtiment stupéfiant\n5ème | Banishing Smite, Cône de froid","name_en":"Expanded Spell List"},{"name":"La malédiction de Hexblade","level":1,"desc":"À partir du niveau 1, vous acquérez la capacité de lancer une malédiction funeste sur quelqu'un. Par une action bonus, choisissez une créature que vous pouvez voir à moins de 9 mètres de vous. La cible est maudite pendant 1 minute. La malédiction prend fin plus tôt si la cible meurt, si vous mourez ou si vous êtes frappé d'incapacité. Jusqu'à la fin de la malédiction, vous bénéficiez des avantages suivants :\n• Vous bénéficiez d'un bonus aux jets de dégâts contre la cible maudite. Le bonus est égal à votre bonus de compétence.\n• Tout jet d'attaque que vous effectuez contre la cible maudite est un coup critique sur un résultat de 19 ou 20 sur le d20.\n• Si la cible maudite meurt, vous récupérez des points de vie égaux à votre niveau de démoniste + votre modificateur de Charisme (minimum de 1 point de vie).\n\nVous ne pouvez plus utiliser cette fonctionnalité tant que vous n'avez pas terminé un repos court ou long.","name_en":"Hexblade's Curse"},{"name":"Guerrier maléfique","level":1,"desc":"Au niveau 1, vous acquérez l’entraînement nécessaire pour vous armer efficacement pour le combat. Vous maîtrisez les armures moyennes, les boucliers et les armes martiales.\n\nL’influence de votre patron vous permet également de canaliser mystiquement votre volonté à travers une arme particulière. Chaque fois que vous terminez un repos long, vous pouvez toucher une arme que vous maîtrisez et qui n'a pas la propriété à deux mains. Lorsque vous attaquez avec cette arme, vous pouvez utiliser votre modificateur de Charisme, au lieu de Force ou de Dextérité, pour les jets d'attaque et de dégâts. Cet avantage dure jusqu'à la fin d'un repos long. Si vous obtenez plus tard la fonctionnalité Pacte de la Lame, cet avantage s'étend à chaque arme du pacte que vous invoquez avec cette fonctionnalité, quel que soit le type d'arme.","name_en":"Hex Warrior"},{"name":"Spectre maudit","level":6,"desc":"À partir du niveau 6, vous pouvez maudire l'âme d'une personne que vous tuez, la liant temporairement à votre service. Lorsque vous tuez un humanoïde, vous pouvez faire sortir son esprit de son cadavre sous la forme d'un spectre, dont les statistiques se trouvent dans le Manuel des Monstres. Lorsque le spectre apparaît, il gagne des points de vie temporaires égaux à la moitié de votre niveau de démoniste. Lancez un jet d'initiative pour le spectre, qui a ses propres tours. Il obéit à vos ordres verbaux et gagne un bonus spécial à ses jets d'attaque égal à votre modificateur de Charisme (minimum de +0).\n\nLe spectre reste à votre service jusqu'à la fin de votre prochain long repos, après quoi il disparaît dans l'au-delà.\n\nUne fois que vous avez lié un spectre avec cette fonctionnalité, vous ne pouvez plus l'utiliser avant d'avoir terminé un long repos.","name_en":"Accursed Specter"},{"name":"Armure d'hexagones","level":10,"desc":"Au niveau 10, votre hexagone devient plus puissant. Si la cible maudite par votre Malédiction de Hexblade vous frappe avec un jet d'attaque, vous pouvez utiliser votre réaction pour lancer un d6. Sur 4 ou plus, l'attaque vous manque, quel que soit son jet.","name_en":"Armor of Hexes"},{"name":"Maître des hexagones","level":14,"desc":"À partir du niveau 14, vous pouvez propager la malédiction de votre Hexblade d'une créature tuée à une autre créature. Lorsque la créature maudite par la malédiction de votre Hexblade meurt, vous pouvez appliquer la malédiction à une autre créature que vous pouvez voir à moins de 9 mètres de vous, à condition que vous ne soyez pas incapable d'agir. Lorsque vous appliquez la malédiction de cette manière, vous ne récupérez pas de points de vie suite à la mort de la créature précédemment maudite.","name_en":"Master of Hexes"}],"name_en":"Warlock: The Hexblade","_translated":true},{"index":"warlock-undead","name":"Démoniste : les morts-vivants","class":"warlock","source":"Van Richten's Guide to Ravenloft","subclass_flavor":"Vous avez conclu un pacte avec un être immortel, une créature qui défie le cycle, la vie et la mort, abandonnant sa coquille mortelle pour pouvoir poursuivre éternellement ses ambitions insondables. Pour de tels êtres, le temps et la moralité sont des choses éphémères, des préoccupations de ceux pour qui les grains de sable se précipitent encore dans le sablier de la vie. Ayant été eux-mêmes mortels, ces anciens morts-vivants connaissent de première main les chemins de l’ambition et les routes menant aux portes de la mort. Ils partagent avec empressement ces connaissances profanes, ainsi que d’autres secrets, avec ceux qui exercent leur volonté parmi les vivants.","desc":"","features":[{"name":"Liste de sorts étendue","level":1,"desc":"Au niveau 1, les morts-vivants vous permettent de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus des morts-vivants\nNiveau de sort | Sorts\n1er | Fléau, fausse vie\n2ème | Cécité/Surdité, Force Fantasmatique\n3ème | Phantom Steed, parlez avec les morts\n4ème | Quartier de la mort, plus grande invisibilité\n5ème | Coquille anti-vie, Cloudkill","name_en":"Expanded Spell List"},{"name":"Forme d'effroi","level":1,"desc":"Au niveau 1, vous manifestez un aspect du terrible pouvoir de votre patron. Par une action bonus, vous vous transformez pendant 1 minute. Vous bénéficiez des avantages suivants pendant votre transformation :\n• Vous gagnez des points de vie temporaires égaux à 1d10 + votre niveau de démoniste.\n• Une fois à chacun de vos tours, lorsque vous touchez une créature avec une attaque, vous pouvez la forcer à faire un jet de sauvegarde de Sagesse, et si le jet de sauvegarde échoue, la cible a peur de vous jusqu'à la fin de votre prochain tour.\n• Vous êtes immunisé contre la peur.\n\nVous pouvez vous transformer un nombre de fois égal à votre bonus de maîtrise, et vous récupérez toutes les utilisations dépensées lorsque vous terminez un repos long.\n\nL'apparence de votre Forme d'effroi reflète certains aspects de votre patron. Par exemple, votre forme pourrait être un linceul d'ombres formant la couronne et les robes de votre patronne liche, ou votre corps pourrait briller de glyphes provenant d'anciens rites funéraires et être entouré de vents du désert, suggérant votre patronne momie.","name_en":"Form of Dread"},{"name":"Tombe touchée","level":6,"desc":"Au niveau 6, les pouvoirs de votre protecteur ont un effet profond sur votre corps et votre magie. Vous n’avez pas besoin de manger, de boire ou de respirer.\n\nDe plus, une fois à chacun de vos tours, lorsque vous frappez une créature avec une attaque et que vous lancez des dégâts contre la créature, vous pouvez remplacer le type de dégâts par des dégâts nécrotiques. Pendant que vous utilisez votre Forme d'effroi, vous pouvez lancer un dé de dégâts supplémentaire pour déterminer les dégâts nécrotiques subis par la cible.","name_en":"Grave Touched"},{"name":"Coque nécrotique","level":10,"desc":"Au niveau 10, votre connexion à la non-vie et à l'énergie nécrotique sature désormais votre corps. Vous avez une résistance aux dommages nécrotiques. Si vous êtes transformé à l’aide de votre Forme d’effroi, vous devenez immunisé contre les dégâts nécrotiques.\n\nDe plus, lorsque vous êtes réduit à 0 point de vie, vous pouvez utiliser votre réaction pour tomber à 1 point de vie et provoquer une éruption d'énergie mortelle dans votre corps. Chaque créature de votre choix se trouvant à moins de 9 mètres de vous subit des dégâts nécrotiques égaux à 2d10 + votre niveau de démoniste. Vous gagnez alors 1 niveau d'épuisement. Une fois que vous avez utilisé cette réaction, vous ne pouvez plus la faire avant d’avoir terminé 1d4 repos longs.","name_en":"Necrotic Husk"},{"name":"Projection spirituelle","level":14,"desc":"Au niveau 14, votre esprit peut se détacher de votre forme physique. Par une action, vous pouvez projeter votre esprit depuis votre corps. Le corps que vous laissez derrière vous est inconscient et dans un état d’animation suspendue.\n\nVotre esprit ressemble à votre forme mortelle dans presque tous les sens, reproduisant les statistiques du jeu mais pas vos biens. Tout dommage ou autre effet qui s’applique à votre esprit ou à votre corps physique affecte l’autre. Votre esprit peut rester hors de votre corps jusqu'à 1 heure ou jusqu'à ce que votre concentration soit brisée (comme si vous vous concentriez sur un sort). Lorsque votre projection se termine, votre esprit retourne dans votre corps ou votre corps se téléporte comme par magie dans l’espace de votre esprit (votre choix).\n\nEn projetant votre esprit, vous bénéficiez des avantages suivants :\n• Votre esprit et votre corps gagnent en résistance aux dégâts contondants, perçants et tranchants.\n• Lorsque vous lancez un sort de l'école de conjuration ou de nécromancie, le sort ne nécessite pas de composants verbaux ou somatiques ni de composants matériels dépourvus de coût en or.\n• Vous avez une vitesse de vol égale à votre vitesse de marche et pouvez planer. Vous pouvez vous déplacer à travers les créatures et les objets comme s'il s'agissait d'un terrain difficile, mais vous subissez 1d10 dégâts de force si vous terminez votre tour à l'intérieur d'une créature ou d'un objet.\n• Pendant que vous utilisez votre Forme d'Epouvante, une fois à chacun de vos tours lorsque vous infligez des dégâts nécrotiques à une créature, vous récupérez des points de vie égaux à la moitié du montant des dégâts nécrotiques infligés.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus le faire avant d’avoir terminé un long repos.","name_en":"Spirit Projection"}],"name_en":"Warlock: The Undead","_translated":true},{"index":"warlock-undying","name":"Démoniste : l'immortel","class":"warlock","source":"Sword Coast Adventurer's Guide","subclass_flavor":"La mort n’a aucune emprise sur votre protecteur, qui a percé les secrets de la vie éternelle, même si un tel prix – comme tout pouvoir – a un prix. Une fois mortels, les Immortels ont vu les vies des mortels passer comme les saisons, comme le scintillement de jours et de nuits sans fin. Il a les secrets des âges à partager, les secrets de la vie et de la mort. Les êtres de cette sorte incluent Vecna, Seigneur de la Main et de l'Œil ; le redoutable Iuz ; la reine-liche Vol; la Cour éternelle d'Aerenal ; Vlaakith, reine-liche des githyanki ; et le sorcier immortel Fistandantalus.","desc":"","features":[{"name":"Liste de sorts étendue","level":null,"desc":"The Undying vous permet de choisir parmi une liste étendue de sorts lorsque vous apprenez un sort de démoniste. Les sorts suivants sont ajoutés à la liste des sorts de démoniste pour vous.\nSorts étendus éternels\nNiveau de sort | Sorts\n1er | Fausse vie, rayon de maladie\n2ème | Cécité/Surdité, Silence\n3ème | Feindre la mort, parler aux morts\n4ème | Aura de vie, quartier de la mort\n5ème | Contagion, légende","name_en":"Expanded Spell List"},{"name":"Parmi les morts","level":1,"desc":"À partir du niveau 1, vous apprenez le cantrip Spare the Dying, qui compte pour vous comme un cantrip de démoniste. Vous bénéficiez également d'un avantage aux jets de sauvegarde contre n'importe quelle maladie.\n\nDe plus, les morts-vivants ont du mal à vous faire du mal. Si un mort-vivant vous cible directement avec une attaque ou un sort nuisible, cette créature doit effectuer un jet de sauvegarde de Sagesse contre votre DD de sauvegarde de sort (un mort-vivant n'a pas besoin d'effectuer le jet de sauvegarde lorsqu'il vous inclut dans un effet de zone, comme l'explosion d'une boule de feu). En cas d'échec, la créature doit choisir une nouvelle cible ou renoncer à cibler quelqu'un à votre place, ce qui risque de gaspiller l'attaque ou le sort. En cas de sauvegarde réussie, la créature est immunisée contre cet effet pendant 24 heures. Un mort-vivant est également immunisé contre cet effet pendant 24 heures si vous le ciblez avec une attaque ou un sort nuisible.","name_en":"Among the Dead"},{"name":"Défier la mort","level":6,"desc":"À partir du niveau 6, vous pouvez vous donner de la vitalité lorsque vous trompez la mort ou lorsque vous aidez quelqu'un d'autre à la tromper. Vous pouvez récupérer des points de vie égaux à 1d8 + votre modificateur de Constitution (minimum de 1 point de vie) lorsque vous réussissez un jet de sauvegarde contre la mort ou lorsque vous stabilisez une créature avec Spare the Dying.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un long repos.","name_en":"Defy Death"},{"name":"Nature éternelle","level":10,"desc":"À partir du niveau 10, vous pouvez retenir votre souffle indéfiniment et vous n'avez pas besoin de nourriture, d'eau ou de sommeil, même si vous avez toujours besoin de repos pour réduire l'épuisement et que vous bénéficiez toujours de repos courts et longs.\n\nDe plus, vous vieillissez plus lentement. Tous les 10 ans qui passent, votre corps ne vieillit que d’un an et vous êtes immunisé contre le vieillissement magique.","name_en":"Undying Nature"},{"name":"Vie indestructible","level":null,"desc":"Lorsque vous atteignez le niveau 14, vous découvrez certains des véritables secrets des Immortels. A votre tour, vous pouvez utiliser une action bonus pour récupérer des points de vie égaux à 1d8 + votre niveau de démoniste. De plus, si vous remettez en place une partie de votre corps coupée lorsque vous utilisez cette fonction, la partie se rattache.\n\nUne fois que vous utilisez cette fonctionnalité, vous ne pouvez plus l'utiliser tant que vous n'avez pas terminé un repos court ou long.","name_en":"Indestructible Life"}],"name_en":"Warlock: The Undying","_translated":true},{"index":"wizard-artificer-ua","name":"Artificier (UA)","class":"wizard","source":"Unearthed Arcana 1 - Eberron","subclass_flavor":"","desc":"Les artificiers sont un élément clé du monde d'Eberron. Ils illustrent l’évolution de la magie, d’une force sauvage et imprévisible à une force de plus en plus accessible au grand public. Les objets magiques font partie de la vie quotidienne des Cinq Nations du Khorvaire ; avec un artificier dans votre groupe, ils font partie de chaque expédition d'aventure.","features":[{"name":"Infuser des potions","level":2,"desc":"Dès le niveau 2, vous pouvez produire des potions magiques. Vous passez 10 minutes à concentrer votre magie sur une fiole d’eau banale et dépensez un emplacement de sort pour la transformer en potion. Une fois que vous avez dépensé un emplacement de sort pour créer une potion, vous ne pouvez pas récupérer cet emplacement tant que la potion n'est pas consommée ou après 1 semaine, moment auquel la potion perd son efficacité. Vous pouvez créer jusqu'à trois potions à la fois ; la création d'une quatrième potion fait perdre immédiatement sa puissance à la plus ancienne potion actuellement active. Si cette potion a été consommée, ses effets prennent immédiatement fin.\n\nL'emplacement de sort que vous dépensez détermine le type de potion que vous pouvez créer. Voir le chapitre 7 du Dungeon Master’s Guide pour les règles complètes sur les potions.\nEmplacement de sort | Potion créée\n1er | Escalade, croissance ou guérison\n2ème | Lecture dans les pensées ou guérison supérieure\n3ème | Invisibilité, guérison supérieure ou respiration aquatique\n4ème | Résistance","name_en":"Infuse Potions"},{"name":"Infuser des parchemins","level":2,"desc":"Au niveau 2, vous pouvez également puiser dans vos réserves d'énergie magique pour créer des parchemins de sorts. Vous pouvez utiliser votre capacité Arcane Recovery pour créer un parchemin au lieu de récupérer les emplacements de sorts dépensés.\n\nVous devez terminer un court repos, puis passer 10 minutes avec du parchemin, une plume et de l'encre pour créer un parchemin de sorts contenant un sort choisi parmi ceux que vous connaissez. Soustrayez le niveau du sort du total des niveaux d’emplacements que vous récupérez en utilisant Arcane Recovery. Cette réduction de votre récupération arcanique s’applique jusqu’à ce que vous utilisiez le parchemin, puis que vous terminiez un long repos.","name_en":"Infuse Scrolls"},{"name":"Infuser des armes et des armures","level":6,"desc":"À partir du niveau 6, vous pouvez produire des armes et armures magiques. Vous passez 10 minutes à concentrer votre magie sur une arme banale, une armure, un bouclier ou un paquet de vingt pièces de munitions, et dépensez un emplacement de sort pour lui insuffler de l'énergie magique. L'objet magique conserve son amélioration pendant 8 heures ou jusqu'à son utilisation (dans le cas des munitions magiques). Vous ne pouvez infuser qu’un seul élément à la fois ; si vous en infusez un deuxième, le premier perd immédiatement sa puissance. Une fois que vous avez dépensé un emplacement de sort pour créer un tel objet, vous ne pouvez pas récupérer cet emplacement jusqu'à ce que l'objet devienne non magique.\n\nL'emplacement de sort que vous dépensez détermine le type d'arme, d'armure ou de bouclier que vous pouvez créer.\nEmplacement de sort | Article créé\n2ème | +1 munition (20 pièces)\n3ème | +1 arme ou +1 bouclier\n4ème | +1 armure\n5ème | Arme +2 ou munitions +2 (20 pièces)\n6ème | +2 armure","name_en":"Infuse Weapons and Armor"},{"name":"Artificier supérieur","level":10,"desc":"À partir du niveau 10, vous pouvez créer une deuxième arme magique, une armure, un bouclier ou un paquet de munitions en utilisant votre capacité Infuser des armes et des armures. Si vous tentez d'infuser un troisième élément, le plus ancien perd immédiatement sa puissance.\n\nVous pouvez également créer une potion ou un parchemin supplémentaire en utilisant Infuse Potions ou Infuse Scrolls.","name_en":"Superior Artificer"},{"name":"Maître artificier","level":null,"desc":"En atteignant le niveau 14, votre maîtrise de la magie arcanique vous permet de produire une variété d'objets magiques. Vous pouvez créer un seul objet choisi dans les tableaux d’objets magiques A et B du chapitre 7 du Dungeon Master’s Master’s Guide. Il vous faut 1 semaine pour produire un tel objet, et vous devez vous reposer pendant 1 mois avant d'utiliser cette capacité pour fabriquer un autre objet.","name_en":"Master Artificer"}],"name_en":"Artificer (UA)","_translated":true}];